/* characters q16 (125 mục) — R2.6 bồi tiểu sử Xích Hồn Tử */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["characters"]={"updatedAt":"2026-07-17","count":125,"chars":[{"id":"vuong-lam","name":"Vương Lâm","tabs":{"kinhLich":[{"mucCt":"ky","text":"Cầm Khai Thiên Phủ dung nhập huyết mạch Đạo cổ chém khe không gian phá tan hư ảnh Thanh Long, dùng Đạo cổ bất diệt thể chống đỡ hợp kích tứ đại chiến tướng Không Huyền hậu kỳ. Dùng cánh tay phải (cánh tay Diệp Mịch) phát Tê Thiên lực tàn sát hàng loạt tiên nhân không chút kháng cự. Ra lệnh u Minh thú phóng sương mù thiên đạo nuốt khoảng bảy tám mươi tiên nhân, chỉ còn lại năm người. Thầm thở dài vì thiên đạo chưa hoàn chỉnh, u Minh thú rất khó nuốt được Chiến lão quỷ. Cưỡi u Minh thú hướng về Côn Hư.","anchor":"Tu vi của các ngươi còn chưa hoàn toàn khôi phục, chỉ khoảng Không Huyền hậu kỳ mà thôi","bridge":true,"khoang":"@c1633"},{"mucCt":"ky","text":"Cưỡi U Minh thú, dùng ngọc giản Nạp Đa đưa hơn ngàn năm trước để tìm tọa độ Ngũ Hành tinh. Dung hợp với thiên đạo qua U Minh thú, nhận ra Ngũ Hành tinh không thuộc động phủ giới mà được tu sĩ bên ngoài dùng thần thông mang từ Tiên Cương đại lục tới. Dùng giọng nói truyền xuyên quầng sáng vào Ngũ Hành tinh khiến mọi sinh linh chấn động, xưng ước hẹn năm xưa với Nạp Đa. Phó tông chủ Duẫn Đông Thân từ chối cho vào, cảnh báo sẽ khởi động Ngũ Hành Quy Nhất trận. Một luồng thần thức bá đạo từ bên trong thách thức: qua được Ngũ Hành trận thì cứ vào. Bất chấp cảnh báo, bước thẳng vào quầng sáng ngũ sắc, chịu liên tiếp công kích từ lực lượng Ngũ Hành.","anchor":"Nạp Đa hôm nay Vương mỗ tới đây vì ước hẹn năm xưa","bridge":true,"khoang":"@c1634"},{"mucCt":"ky","text":"Vương Lâm bước mười bốn bước rưỡi xâm nhập quầng sáng Ngũ Hành, đối mặt trận thứ nhất Đại địa thổ trận. Dùng thân thể Đạo cổ tung chín quyền đánh nát chín mặt người bùn đất. Bị đệ nhị biến hai mặt đất ép chặt không khe hở nhưng thong thả đấm vỡ từ bên trong bước ra. Thu luôn trận linh của Đại địa thổ trận — dúm bùn đất tỏa linh khí dày đặc — khiến bốn trưởng lão và Nạp Đa đều chấn động. Ngẩng đầu nhìn thẳng vào mặt gương quan sát của bốn trưởng lão. Xác định Ngũ Hành tinh là biến số ẩn giấu thứ hai ngoài Thiên Vận Tử, bất lợi cho việc tìm hồn thứ ba, tự tin khi muốn chạy không ai cản nổi.","anchor":"Hắn có thân thể mạnh mẽ của Đạo cổ, làm sao chút thần thông này có thể phá vỡ được","bridge":true,"khoang":"@c1635"},{"mucCt":"ky","text":"Thu nhúm thổ linh (thổ bổn nguyên) trong Ngũ Hành đại trận, hiện có hai nhúm thổ linh trong không gian trữ vật. Suy tính thu đủ bốn bổn nguyên còn lại ngoài hỏa bổn nguyên để tăng tu vi, tự hỏi Ngũ Hành quy nhất có thể sản sinh bổn nguyên mới không. Bước vào Ngũ Hành hỏa trận hoàn toàn thoải mái nhờ hỏa bổn nguyên. Chín con hỏa Kỳ Lân phủ phục trước hắn, toàn bộ ngọn lửa ngưng tụ thành người khổng lồ hỏa diễm cao mấy ngàn trượng quỳ gối sùng kính. Từ đầu đến cuối không mở miệng, không thi triển thần thông, chỉ đứng đó như bậc quân vương.","anchor":"Hắn chỉ đứng đó, giống như là một bậc quân vương đi trở lại đất nước mình, có thể dùng một ánh mắt mà khiến tất cả con dân phải quỳ lạy.","bridge":true,"khoang":"@c1636"},{"mucCt":"ky","text":"Đứng trên đỉnh đầu người khổng lồ lửa chỉ huy nó cùng chín con Kỳ Lân phá sập Ngũ Hành hỏa trận, cảnh tượng chuyển sang thủy trận. Bị Thủy Tướng dùng bốn bức tường nước vạn trượng và trường thương nước mưa huyễn hóa nhấn chìm trong biển cùng người khổng lồ lửa. Bất ngờ xuất hiện sau lưng Thủy Tướng, vỗ chưởng truyền lực lượng bổn nguyên và khí tức hủy diệt Đạo cổ khiến ngũ tạng hắn tan nát, xương cốt chia lìa, phun máu bị đánh bay, nhưng áo giáp phóng sinh cơ khôi phục thương thế cho Thủy Tướng. Dùng cấm chế bổn nguyên tự hình thành quy tắc nhìn thấu bí mật áo giáp: tu vi Thủy Tướng không tới bước thứ ba, áo giáp cho sức mạnh bước ba nhưng điều khiển ngược lại người mặc. Bị tu sĩ Quy Nhất tông xuyên tạc là kẻ giết toàn tộc họ Đằng vì tham bảo vật, vô ơn với Nạp Đa.","anchor":"tay phải đột nhiên vỗ lên người Thủy Tướng","bridge":true,"khoang":"@c1637"},{"mucCt":"ky","text":"Bị Thủy Tướng nhốt trong quả cầu nước khổng lồ do thần thông Càn Khôn Nhất Tích tạo ra, nhưng hoàn toàn có thể thoát hoặc giết đối phương dễ dàng. Quyết định ở lại bên trong cảm ngộ thủy bổn nguyên — cơ hội cực hiếm nâng bổn nguyên từ bảy đạo lên tám đạo. Dùng tơ máu trong đồng tử (cấm chế bổn nguyên hóa thành quy tắc) quan sát ghi nhớ mọi biến hóa của thủy bổn nguyên. Trước đó chỉ liếc mắt đã nhìn ra bí ẩn lớn nhất của áo giáp Thủy Tướng, yêu cầu cởi giáp đổi mạng bị từ chối, tuyên bố không nương tay với kẻ xâm nhập. Huyền La Đại Thiên Tôn quan sát từ ngoài xác nhận Vương Lâm có huyết mạch Đạo cổ, tiên nhân thuật, bảy đạo bổn nguyên, nhận xét là Đạo tiên song tu — chưa từng thấy trên bất cứ ai.","anchor":"Ta nếu muốn rời khỏi nơi này rất dễ dàng, thậm chí trong nháy mắt đánh chết Thủy Tướng cũng dễ như trở bàn tay","bridge":true,"khoang":"@c1638"},{"mucCt":"ky","text":"Bị thủy cầu Càn Khôn Nhất Tích của Thủy Tướng đè ép nhưng lợi dụng toàn bộ quá trình để minh ngộ thủy bổn nguyên, quan sát ba triệu tám ngàn vạn lần biến hóa. Lấy giọt nước thủy bổn nguyên Thiên Vận Tử từng cho ra làm chìa khóa hoàn tất minh ngộ. Ra lệnh ngưng, toàn bộ thủy cầu tự co rút từ hai trăm trượng xuống năm trượng rồi ngưng tụ thành giọt nước thủy tinh trên lòng bàn tay, tiêu tán vào tay. Ôm quyền khom lưng vái Thủy Tướng nói đại ân như vậy xin nhận một vái. Phất tay áo gây cuồng phong tống toàn bộ thần thức Nạp Đa và tu sĩ Quy Nhất tông ra khỏi trận pháp, chỉ giữ lại Thủy Tướng một mình trong thủy trận.","anchor":"Đại ân như vậy, xin nhận của Vương mỗ một vái!","bridge":true,"khoang":"@c1639"},{"mucCt":"ky","text":"Sau khi hấp thu Càn Khôn Nhất Tích, Vương Lâm có được mầm mống thủy bổn nguyên — bổn nguyên thứ tám, thuộc thực bổn nguyên cần dung hợp nhiều lần mới đại thành. Cứu mạng Thủy Tướng bằng cách truyền sinh cơ vào mi tâm, tạo tấm màng ngăn hồn phách khỏi áo giáp, rồi dùng huyết kiếm chém đứt tia máu liên kết tách hoàn chỉnh áo giáp ra. Tuyên bố nguyên tắc ân thì trả, không giết kẻ có ân. Khi kẻ lạ từ dòng xoáy vươn cánh tay khô héo đoạt áo giáp, Vương Lâm bùng nổ toàn lực — bảy bổn nguyên dung hợp thành tu vi Không Linh hậu kỳ cộng Đạo cổ huyết mạch dung nhập thân thể — một bước đạp nát cánh tay kẻ kia, xương gãy vụn, cánh tay nổ tung. Thu áo giáp và trường thương vào tay áo. Bị kẻ lạ nhận ra là tu sĩ cổ quốc, người cổ tộc.","anchor":"Đây là nguyên tắc làm người của Vương mỗ!","bridge":true,"khoang":"@c1640"},{"mucCt":"ky","text":"Thu hồi áo giáp, đối chưởng Đệ Cửu lão tổ Quy Nhất tông qua dòng xoáy, chỉ lùi ba bước trong khi lão tổ bị bẻ gãy cánh tay phun máu. Chủ động bước vào Ngũ Hành mộc trận, dùng thuật Tê Thiên xé thiên địa thành hai nửa phá tan lá cây bao vây. Ép mộc linh quy phục bằng tuyên bố thần phục hoặc bị hủy diệt, thu được tinh thể xanh biếc ngưng tụ từ sinh cơ mộc linh. Phá nốt Ngũ Hành kim trận cuối cùng, toàn bộ Ngũ Hành đại trận tan rã. Đang muốn bước vào Ngũ Hành tinh thì sững lại phát hiện tinh cầu chuyển động — Cửu Chuyển Tâm Luân kích hoạt.","anchor":"Trong mắt hắn Ngũ Hành tinh không ngờ lại chuyển động!","bridge":true,"khoang":"@c1641"},{"mucCt":"ky","text":"Bị mắc kẹt trong trận pháp Cửu Chuyển Tâm Luân bên cạnh Ngũ Hành tinh, trải qua chín chuyển. Tâm thần hao tổn cực độ, phun máu tươi, toàn thân nổi gân xanh, xúc động và điên cuồng tràn ngập. Cố phân tích cơ chế nhưng càng suy tư càng không thể tĩnh tâm, chuyển thứ sáu tới chín nhanh chóng trôi qua. Tới đệ cửu chuyển, nhắm mắt ngộ ra bản chất trận pháp: mọi thứ chuyển động đều do tâm mình không tĩnh, tâm động cho nên thần động, thân động, Ngũ Hành tinh xoay chỉ là phản chiếu tâm bất tĩnh. Lập tức tĩnh lặng, tơ máu tiêu tán, điên cuồng tiêu tán, xúc động tiêu tán, tâm như nước giếng cổ không chút gợn sóng, chuyển động bắt đầu chậm lại, bước đầu phá giải trận pháp.","anchor":"Hai mắt Vương Lâm tiêu tán tơ máu, vẻ điên cuồng tiêu tán, xúc động tiêu tán, chỉ còn lại sự bình tĩnh như nước giếng cổ không chút gợn sóng","bridge":true,"khoang":"@c1642"},{"mucCt":"ky","text":"Trong đệ cửu chuyển, nhận ra Chân Giả bổn nguyên vô dụng vì tất cả đều từ tâm, sáng tạo phương pháp mới: thân tĩnh dẫn hồn tĩnh dẫn thần tĩnh dẫn tâm tĩnh, chín nhịp thở phá hoàn toàn Cửu Chuyển Tâm Luân. Không rời trận mà phản kích, dùng nguyên lý tâm động thì tinh động vẽ vòng tròn ngược chiều kim đồng hồ nghịch chuyển Ngũ Hành tinh, đảo ngược trận pháp đánh ngược tu sĩ Quy Nhất tông. Tu sĩ thường hôn mê ở đệ tứ chuyển, Nạp Đa cũng hôn mê ở đệ tứ chuyển, lão già kim bào chống tới đệ thất chuyển mới suy kiệt. Ba lão già trong tháp phải xuất thủ phá trận. Sau khi trận pháp bị phá, một thân bạch y hiện thân trên bầu trời Ngũ Hành tinh.","anchor":"Cả đời hắn tu đạo cứ mỗi lần chịu thiệt là đều trả lại gấp bội","bridge":true,"khoang":"@c1643"},{"mucCt":"ky","text":"Xuất hiện trên bầu trời Ngũ Hành tinh sau nghịch động Cửu Chuyển Tâm Luân, chủ động khiêu chiến ba tu sĩ Tiên Cương. Triệu hư ảnh Đạo Cổ đội trời đạp đất hộ thể rồi cố ý để nó sụp đổ tạo sóng xung kích quét lui ba người. Giao chiến ngang sức với Vân Dật Phong — bị sáu đóa hoa đen từ Lục Hoa Ấn khắc lên cánh tay phải gây rữa nát, nhờ Đạo Cổ bất diệt thể khôi phục nhanh hơn đối thủ vài nhịp thở. Lợi dụng khoảng hở đánh quyền phá sập tháp từ tầng một tới tầng bốn, chỉ còn ba tầng gốc lơ lửng. Mục đích là bức hết lực lượng ẩn giấu lộ diện, xác định sức mạnh thật sự của chiếc đinh thứ hai sau Thiên Vận Tử để lên kế hoạch tìm hồn thứ ba.","anchor":"Hắn muốn xem nơi này rốt cục tồn tại cường giả tới bậc nào","bridge":true,"khoang":"@c1644"},{"mucCt":"ky","text":"Xông vào Ngũ Hành đại trận Cửu Chuyển Tâm Luân trong tháp cao Quy Nhất tông, đối đầu lão già tóc bạc tầng ba (Không Huyền trung kỳ bước ba). Dùng Nhân Quả ấn hút bổn nguyên roi nhưng roi hấp thu sinh cơ bổ sung lại. Bị roi quất trúng bảy tấc trước thân, lui mấy bước phải nén máu tươi. Rút Côn Cực tiên dùng làm roi đánh roi đối roi, nhờ huyết mạch Đạo cổ, bảy đạo bổn nguyên trong phân thân và cánh tay Diệp Mịch, khí lực áp đảo giật đứt roi lão già. Khi lão già khoác áo giáp Quy Nhất tông triệu mộc nhân khổng lồ mấy ngàn trượng đánh tới, bình tĩnh kích hoạt Đạo cổ bất diệt thể bao phủ toàn thân chủ động chịu đòn. Mục đích thật là thăm dò lực lượng tu sĩ bên ngoài, không phải chém giết.","anchor":"Roi, Vương mỗ cũng có!","bridge":true,"khoang":"@c1645"},{"mucCt":"ky","text":"Rút lui an toàn khỏi Ngũ Hành tinh trên lưng U Minh thú đã huyễn hóa vô hình, áp chế thương thế rồi trở về Côn Hư. Đối phương không dám đuổi theo. Phân tích tu vi lão già họ Mã có thể mạnh hơn Chưởng Tôn, đã trải qua mấy lần huyền kiếp. Nhận ra bộ áo giáp tầng nhất tháp cao rất có thể thuộc về lão già họ Mã, nếu mặc vào tu vi sẽ khủng khiếp khó lường. Hắn vẫn còn hậu thủ là cây cung của Lý Quảng chưa dùng.","anchor":"Hắn còn có cây cung của Lý Quảng, dù không muốn dùng nhưng nếu thật sự có nguy cơ thì sẽ không do dự mà xuất ra","bridge":true,"khoang":"@c1646"},{"mucCt":"ky","text":"Cưỡi U Minh thú chữa thương sau trận chiến, xác nhận Quy Nhất tông là lực lượng cướp đoạt hồn thứ ba đã bị bức ra toàn bộ, quyết tâm tự mình tham gia tìm kiếm hồn thứ ba. Rời Ngũ Hành tinh qua trận pháp ngân hà vào tiên giới. Trước khi vào, do tính cẩn thận đột ngột quay người chất vấn và vung gió lốc bảy đạo bổn nguyên thăm dò kẻ theo dõi, thực chất đề phòng lão già họ Mã bám theo. Bị Huyền La Đại Thiên Tôn bí mật theo sau nhưng không phát hiện. Trở về tiên giới đứng trước ngọn núi bế quan cũ, thần sắc ảm đạm tràn ngập nhung nhớ bi ai — hôm nay là một ngày đặc biệt mà mỗi năm hắn đều cố bận rộn để quên đi.","anchor":"Mỗi năm tới ngày này hắn đều muốn khiến cho mình quên đi, cũng làm cho mình bận rộn đủ mọi thứ để không thể nhớ nhung","bridge":true,"khoang":"@c1647"},{"mucCt":"ky","text":"Trong ngày kỷ niệm gặp Lý Mộ Uyển, Vương Lâm dùng tấm buồm mặt quỷ che thân ngồi một mình trên ngọn núi trong động phủ giới, uống rượu mạnh nhưng không xoa dịu được nỗi đau. Hắn mở Tỵ Thiên Quan vuốt ve khuôn mặt Lý Mộ Uyển đang hôn mê, rơi lệ, xác nhận một phần hồn phách của nàng đã bị mất và thề sẽ thu hồi bằng mọi giá bất kể trong tay ai. Hắn nhắc việc đã tiếp nhận Lý Thiến Mai, xin lỗi Uyển Nhi, thề cả đời không dính tới tình cảm nào nữa. Hắn thi triển thần thông Mặt quỷ nhập huyễn, mộng ảo ngàn năm — đặt tay lên mi tâm mình và mi tâm Lý Mộ Uyển, đưa thần thức vào mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại. Trong mộng, hắn cứu nàng khỏi trưởng lão dâm tà Tuyên Vũ Viên, chỉ liếc mắt phá tan tám phi kiếm và giết kẻ địch, ôm nàng, rồi mỉm cười nhìn nàng sợ hãi rời đi, ẩn nỗi đau dưới nụ cười. Hắn cảm nhận thời gian ở động phủ giới không còn dài, sắp tới Tiên Cương đại lục.","anchor":"Uyển Nhi.nhanh thôi, ta sẽ tới Tiên Cương đại lục.ở đó ta nhất định có biện pháp khiến nàng thức tỉnh","bridge":true,"khoang":"@c1648"},{"mucCt":"ky","text":"Ngồi suốt đêm dưới trăng bên Lý Mộ Uyển trong Tỵ Thiên Quan, sáng sớm thu Tỵ Thiên Quan lại và thì thầm với Uyển Nhi. Xác định hướng tìm hồn thứ ba có thể lần đầu mối từ đạo nhân bảy màu và Chiến lão quỷ. Triệu Thanh Thủy tới, nghe nàng thừa nhận bản thân là một phách của Thất Thải Tiên Tôn. Cam kết sẽ giết hoặc phong ấn hồn thứ ba, không cho phép hồn cắn nuốt thất phách. Điểm mi tâm triệu ra Hồn Phiên mặt quỷ phóng đại mười trượng, cắn nuốt cả hai người, đưa thần thức vào thời vạn cổ khi Thất Thải Tiên Tôn bị phân chia ba hồn bảy phách để truy tìm hồn thứ ba.","anchor":"cuốn động thần thức của cả hai tiến vào trong năm tháng từ thời vạn cổ, trong tích tắc khi Thất Thải Tiên Tôn bị phân chia ba hồn bảy phách","bridge":true,"khoang":"@c1649"},{"mucCt":"ky","text":"Vương Lâm dùng Thanh Thủy dẫn đường, mượn tấm buồm mặt quỷ chủ động tiến vào huyễn cảnh động phủ giới. Trong tầng một, chứng kiến Thanh Thủy tàn sát hoàng cung báo đại cừu, đồng cảm sâu sắc vì bóng lưng nhuộm máu giống chính hắn ở Đằng gia năm đó. Hắn gọi sư huynh, an ủi Thanh Thủy, rồi kích hoạt hắc khí chuyển sang tầng hai. Trong tầng hai, chứng kiến Thất Thải Tiên Tôn bị Liên Đạo Phi oanh kích vỡ nát, ba hồn bảy phách tán ra bốn phương. Hắn là nguồn gốc mọi vật nơi đây nên hiểu rõ hơn lần đạo nhân bảy màu vào trước. Quan sát bốn phách đầu tiên tiến vào luân hồi: phách đỏ đậm chủ sát chính là Thanh Thủy, phách xanh chứa toàn bộ tu vi chính là Tư Đồ Nam, phách cam chứa chính khí lương tri chính là Thanh Lâm, phách vàng đại biểu khí vận cơ duyên chính là Tham Lang. Minh ngộ rằng thiên tư biến hóa kinh người của Tư Đồ Nam là do hắn là phách của Thất Thải Tiên Tôn.","anchor":"Hắn là nguồn gốc của mọi vật nơi này, cho nên so với lần đó hắn đã hiểu ra không ít","bridge":true,"khoang":"@c1650"},{"mucCt":"ky","text":"Chứng kiến phách thứ năm (lục) tiêu tán, nhận ra thân ảnh bên trong là Tán Linh Thượng nhân, tâm thần rung động dữ dội. Phách thứ sáu (lam) tiêu tán, sắc mặt tái nhợt khi nhận ra thân ảnh chính là Mộc Băng Mi — phách do tình cảm yêu hận của Thất Thải Tiên Tôn với Phàn San Mộng hóa thành. Phách thứ bảy (tím) quá mờ ảo, không nhìn rõ ai nhưng mơ hồ cảm giác đã gặp qua. Sau khi thất phách tiêu tán, tam hồn bay đi ba hướng: hồn thứ nhất hóa thành đạo nhân bảy màu nhận thần thông Tiên Tôn bay ra giới ngoại, hồn thứ hai luân hồi thành mãnh thú gặp Chiến lão quỷ đang độ huyền kiếp thất bại — đây là tiên duyên Chiến lão quỷ. Truy đuổi hồn thứ ba xuyên nhiều tinh vực: Triệu Hà → Côn Hư (lượn vòng) → Vân Hải, chứng kiến hồn thứ ba luân hồi nhiều lần thành mãng xà, thư sinh phàm nhân, đại thụ, tu sĩ Kết Đan. Hồn thứ ba luân hồi thành Tô Đạo tại Chu Tước Tinh, Triệu quốc — phàm nhân đại nho cả đời không tu đạo. Phát hiện nhân quả sâu xa: trong Mộng Đạo của mình đã được Tô Đạo nhận làm đệ tử nhưng chỉ thấy quả mà không tìm ra nhân. Cuối cùng chứng kiến hồn thứ ba tại Thanh Linh tinh, La Thiên Tinh Vực, luân hồi thành cá mấy trăm lần trong cùng con sông, cho tới khi ngư ông câu được — ngư ông nói vợ sắp sinh, ám chỉ hồn thứ ba chờ cơ hội đầu thai.","anchor":"Hắn nằm mơ cũng không nghĩ tới không ngờ cả nàng cũng là do một phách của Thất Thải Tiên Tôn biến thành","bridge":true,"khoang":"@c1651"},{"mucCt":"ky","text":"Chứng kiến kiếp luân hồi cuối cùng của hồn thứ ba, thấy Tạ Thanh chào đời, chấn động nhận ra hồn thứ ba chính là đệ tử của mình. Ngộ ra vòng nhân quả tuần hoàn: năm đó điểm hóa Tạ Thanh nhận đệ tử kết nhân quả, trong Mộng Đạo gặp Tô Đạo làm sư phụ — hiện thực Tạ Thanh là đệ tử Vương Lâm, Mộng Đạo Vương Lâm là đệ tử Tô Đạo. Đối mặt câu hỏi giết hay không giết hồn thứ ba. Lùi ba bước phá sập toàn bộ huyễn cảnh, trở về hiện thực trong động phủ giới cùng Thanh Thủy, sắc mặt tái nhợt, ánh mắt đấu tranh.","anchor":"Hồn thứ ba là hắn.","bridge":true,"khoang":"@c1652"},{"mucCt":"ky","text":"Xác nhận hồn thứ ba của Thất Thải Tiên Tôn chính là đệ tử Tạ Thanh, thống khổ do dự không thể tự tay ra tay với đệ tử. Suy luận phách thứ bảy không nằm trong thiên đạo hiện tại (U Minh thú nuốt Thiên Vận Tử nhưng không có khí tức phách thứ bảy), chứng minh thiên đạo chưa hoàn chỉnh, nghi Thiên Vận Tử áo xám có thể mang phách thứ bảy. Liệt kê sáu phách đã biết: Thanh Thủy, Tư Đồ Nam, Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh thượng nhân. Được Huyền La Đại Thiên Tôn điểm chỉ, giác ngộ khái niệm biến số — bốn phách (Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh) đã qua luân hồi trở thành thân thể độc lập tách biệt khỏi Thất Thải Tiên Tôn, trong khi Thanh Thủy và Tư Đồ Nam chưa xảy ra biến số. Nhận ra nếu nắm được lực lượng biến số trong thiên đạo có thể khiến hồn thứ ba Tạ Thanh độc lập, ngăn tam hồn dung hợp. Một bước biến càn khôn tới La Thiên Tinh Vực, dựa nhân quả sư đồ cảm nhận Tạ Thanh đang ở tu chân tinh phía đông La Thiên, hướng đó mà đi.","anchor":"Nếu có thể nắm được lực lượng này trong tay thì có thể khiến cho hồn thứ ba độc lập","bridge":true,"khoang":"@c1653"},{"mucCt":"ky","text":"Tới tu chân tinh phía đông La Thiên, gặp lại đệ tử Tạ Thanh tại u cốc hoa lan. Đau đớn khi biết Tạ Thanh chính là hồn thứ ba của Thất Thải Tiên Tôn và sắp chết. Nhớ lại cảnh quen biết Tạ Thanh, so sánh với Thập Tam — đều là đệ tử của mình. Từng nói với Thanh Thủy phải giết hồn thứ ba nhưng lúc này không thể vì đau đớn như phải giết con. Phẫn nộ chất vấn trời, tuyên thề cả đời muốn diệt trời bất kể trời động phủ giới hay Tiên Cương đại lục. Toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang khí tức Không Diệt — lần đầu sơ hiện, khiến Huyền La Đại Thiên Tôn kinh hãi. Sau khi Tạ Thanh khí tuyệt thân vong, bước tới thu lấy hồn thứ ba từ thất khiếu. Khi nắm hồn thứ ba, thiên địa biến sắc, tứ đại tinh vực ầm vang, giới ngoại cũng kinh thiên.","anchor":"Vương Lâm ta từ trong luân hồi thiên kiếp tìm được vận mệnh của chính mình","bridge":true,"khoang":"@c1654"},{"mucCt":"ky","text":"Chứng kiến đệ tử Tạ Thanh gọi tiếng sư tôn cuối cùng rồi mỉm cười qua đời trong sơn cốc đầy thu lan trên tu chân tinh La Thiên. Phẫn nộ với thiên ý trêu người, tuyên bố sẵn sàng hủy diệt thiên không nếu thiên ý không tôn trọng ý niệm. Xác nhận hồn thứ ba xuất hiện trong thi thể Tạ Thanh, coi nó là đệ tử chứ không phải Thất Thải Tiên Tôn, thề sẽ giúp Tạ Thanh ngưng tụ thành hồn thức tỉnh trí nhớ. Nhắm mắt dung nhập hồn thứ ba vào cơ thể, kích hoạt trung tâm động phủ mở ra, toàn bộ động phủ giới chấn động.","anchor":"Có vi sư ở đây, ngươi chắc chắn có thể ngưng tụ thành hồn một lần nữa, thức tỉnh trí nhớ","bridge":true,"khoang":"@c1655"},{"mucCt":"ky","text":"Nhận ra đại môn trung tâm động phủ (từng bị thiên đạo đánh vỡ ở chiến trường ngoại vực Chu Tước Tinh) ngưng tụ lại hoàn chỉnh trước tu chân tinh. Cúi nhìn thi thể Tạ Thanh quỳ trong sơn cốc, bi ai thì thào rồi dùng thu lan an táng nàng thành ngôi mộ, khiến từ đó mỗi mùa thu hoa lan ngập tràn tu chân tinh vô danh. Nghe Chiến lão quỷ cam đoan an toàn cho tiên giới và hứa mở đường Tiên Cương đại lục, nghe đạo nhân bảy màu hứa cho thê tử sống lại và tặng toàn bộ động phủ giới, nhưng không đáp, không động tâm vì quan hệ với Tạ Thanh, Thanh Thủy, Tư Đồ Nam. Nhắm mắt đợi quần hùng tới đủ rồi mở mắt tuyên bố mọi người đều muốn hồn này, giơ tay phải phô bày hồn thứ ba lấp lóe u quang trước mặt hàng loạt cường giả.","anchor":"Những người đáng tới cũng đã tới rồi.các người đơn giản đều muốn hồn này","bridge":true,"khoang":"@c1656"},{"mucCt":"ky","text":"Trước mặt tất cả tu sĩ, Vương Lâm tuyên bố đây là cuộc săn hồn thứ ba, cảnh cáo kẻ nào muốn giết hắn lấy hồn thì phải chuẩn bị bị giết. Hắn dùng hồn thứ ba mở đại môn động phủ — chỉ người có hồn thứ ba mới làm được — cánh cửa tách đôi, cơn lốc cực mạnh đẩy lùi tất cả trừ hắn, rồi bước vào khi cửa mới mở ba phần. Bên trong, hắn nhận ra trung tâm động phủ chính là cánh cửa thông tới Tiên Cương đại lục. Thông qua trí nhớ hồn thứ ba bị Tạ Thanh phong ấn, hắn biết bí mật sát chiêu cuối cùng của Thất Thải Tiên Tôn mà không ai khác biết, nhưng cần tích đủ sát lục mới dùng được. Hắn lên kế hoạch dùng ba trăm tàn nguyên giới để giết đối thủ yếu, tích lũy sức mạnh cho trận quyết chiến cuối cùng với đạo nhân bảy màu và Chiến lão quỷ. Cuối cùng bước vào giọt sương trên đóa hoa khổng lồ, phát hiện bên trong là một vùng tinh không tỏa ánh sáng như ngọc, tràn ngập tinh vân.","anchor":"Đây là một cuộc săn hồn! Hoặc các ngươi là thợ săn, hoặc ta là thợ săn","bridge":true,"khoang":"@c1657"},{"mucCt":"ky","text":"Vương Lâm dung nhập vào đại đỉnh trung tâm động phủ, khuôn mặt hiện trên mặt đỉnh bị hắc khí bao quanh. Bên trong phát hiện đóa hoa vàng năm cánh mang ba trăm giọt sương, mỗi giọt là một thế giới thất bại của Thất Thải Tiên Tôn khi sáng tạo động phủ giới. Nhờ ký ức hồn thứ ba hiểu rõ lai lịch ba trăm tàn giới và phân loại ba loại (tiên thú biến dị, phàm nhân sinh sôi, không sinh linh). Tản thần thức lục soát chín tu chân tinh trong tàn giới loại ba, không tìm thấy gì. Sau nửa canh giờ phát hiện sóng gợn vô hình lan từ ngọn núi trọc hình kiếm trên tu chân tinh thứ năm, dò xét nhưng núi hoàn toàn bình thường. Thử truyền thần niệm vào ngọn núi để định quy tắc, thiên địa ầm vang, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ, quyết định thay đổi cách thức.","anchor":"Ta là người đầu tiên tới nơi này, định ra quy tắc","bridge":true,"khoang":"@c1658"},{"mucCt":"ky","text":"Ngồi trên đỉnh núi tu chân tinh trong tàn giới, ngưng tụ thành công quy tắc cấm phi hành (duy nhất trong nhiều quy tắc đã thử). Dùng huyết kiếm xuyên mi tâm giết lão già Thất Đạo Tông đầu tiên, sau đó hồn thứ ba bắt quyết tế huyết mạch và thần hồn nạn nhân cho thân thể kia — cánh tay đen kịt phủ hắc khí xuất hiện chụp bắt rồi biến mất. Năm ngày đắm chìm dung hợp ký ức hồn thứ ba. Ngày thứ sáu phục kích giết ba đệ tử Thất Đạo Tông (một Không Niết sơ kỳ, hai thiên nhân ngũ suy) trong chưa tới ba nhịp thở. Phát hiện dòng xoáy mới xuất hiện, bên trong là một nữ tử bí ẩn.","anchor":"Giết ba người không cần tới ba nhịp thở!","bridge":true,"khoang":"@c1659"},{"mucCt":"ky","text":"Nhận ra Tử Hà xuất hiện từ dòng xoáy, chủ động phóng huyết kiếm tấn công thăm dò, hai bên ngang sức. Bố trí kế tâm lý nhiều tầng: giả vờ vội vã rời đi như bị thương, khi Tử Hà phóng phi kiếm tím thử sức thì cố ý bộc phát sáu đạo bổn nguyên chấn nát phi kiếm rồi cười lạnh bỏ đi, dụ nàng suy luận ngược rằng hắn đang giấu thương tích. Tử Hà mắc bẫy, thu ngọc giản truyền tin, bước ra khỏi dòng xoáy truy đuổi, mất đường rút lui. Quy tắc tàn giới phát tác khiến thân thể nàng rơi vụt xuống, Vương Lâm lập tức quay người bộc phát huyết quang, huyết kiếm đánh thẳng mi tâm Tử Hà, máu đen phun ra từ ngực nàng, trọng thương.","anchor":"bỏ qua trạng thái giả trọng thương, tu vi trong nháy mắt bộc phát, bảy đạo bổn nguyên từ cấm chế bổn nguyên thì sáu đạo đồng loạt vờn quanh thân thể","bridge":true,"khoang":"@c1660"},{"mucCt":"ky","text":"Dùng huyết kiếm xuyên ngực Tử Hà, thi triển liên hoàn sáu đạo bổn nguyên (hỏa, lôi điện, sinh tử, nhân quả, chân giả, sát lục) đánh trọng thương cả thân thể lẫn nguyên thần nàng. Thi triển Định thân thuật một chỉ định thân, định thần, định hồn, rồi điểm chín chỉ phong ấn đại thành, thu Tử Hà vào tay áo, bắt sống thay vì giết vì trên người nàng còn nhiều thứ khiến hắn hứng thú. Toàn bộ chiến đấu không quá mười nhịp thở. Rời tàn giới trước, xông qua dòng xoáy vào một tàn giới khác nơi Bạch Hổ chiến tướng đã thiết lập quy tắc. Dùng thần thức quét toàn tinh không, nhận ra quy tắc đã tồn tại, chủ động đứng yên giữ mình ngoài quy tắc. Giả vờ tạo dòng xoáy rời đi để thử phản ứng Bạch Hổ, từ đó tìm ra đáp án. Nghe Bạch Hổ đề nghị đánh cuộc cược hồn thứ ba đổi nô bộc vạn năm, bề ngoài bình tĩnh nhưng khóe miệng lộ nụ cười.","anchor":"Thần sắc Vương Lâm bình tĩnh, chỉ là trên mặt lại lộ ra một tia mỉm cười mà người khác khó có thể phát hiện","bridge":true,"khoang":"@c1661"},{"mucCt":"ky","text":"Vương Lâm phân tích quy tắc bàn cờ trên tu chân tinh thứ ba, nhận ra Đạo Cổ truyền thừa của mình cũng có lực lượng huyết mạch, phối hợp tu vi còn mạnh hơn Bạch Hổ. Tiến vào tàn giới, huyết mạch bộc phát khiến lực áp chế phân tán cho ba người, phá vỡ tính toán của Bạch Hổ, đồng thời nới lỏng áp chế cho nam tử Ngũ Hành tinh. Thần thức dung nhập binh lính, chiến đấu trên chiến trường trăm vạn đại quân, giết địch binh tích hắc khí ngưng tụ thành giáp đen toàn thân rồi hắc mã, cưỡi ngựa lao thẳng về phía tướng lãnh bạch giáp của Bạch Hổ. Diệt mười hắc giáp binh trong nửa nén hương. Ý thức rõ thời gian cấp bách vì đạo nhân bảy màu đang truy tới.","anchor":"hắc khí bên ngoài thân thể Vương Lâm liền ngưng tụ co rút lại, bất ngờ hóa thành một bộ áo giáp màu đen","bridge":true,"khoang":"@c1662"},{"mucCt":"ky","text":"Trong ván cờ giới, Vương Lâm hóa chiến tướng hắc giáp đối đầu chiến tướng bạch giáp của Bạch Hổ Thánh Hoàng. Lần va chạm đầu, trường đao đối trường thương cùng hủy, hai ngựa va đầu chết, hư ảnh Đạo cổ Vương Lâm (không phải Diệp Mịch) hiện ra. Bạch Hổ từ chối nhận thua, giết gần mười vạn binh lính không phân địch ta để tái tạo lực lượng. Vương Lâm chọn thôn phệ chiến tướng kim giáp (tu sĩ Ngũ Hành tinh) bằng bản năng thôn hồn, lập tức tăng mạnh, tái tạo giáp mũ giáp, dưới thân ngưng tụ hắc long thay ngựa. Quyết chiến lần hai, một đao kèm hư ảnh Đạo cổ chẻ đôi chiến tướng bạch giáp từ mi tâm. Tuyên bố thu Bạch Hổ làm nô bộc. Bổn tôn cảm nhận nguy cơ mãnh liệt, hợp nhất với phân thân, nuốt toàn bộ khí tức bạch giáp, ngưng tụ đại đao đạt lực lượng giới hạn tàn giới, giơ đao chờ sẵn. Tay trái bắt quyết hóa ô lửa nhỏ rồi biến mất.","anchor":"Một đao này đã đạt tới lực lượng giới hạn của giới này!","bridge":true,"khoang":"@c1663"},{"mucCt":"ky","text":"Ngưng tụ toàn bộ tu vi vào một đao, hấp thu cơn lốc hắc khí, áo giáp, toàn bộ binh lính trên bàn cờ Bạch Hổ, đánh tan quy tắc Bạch Hổ khiến Bạch Hổ phun máu. Đường đao mượn quy tắc cả tàn giới xuyên tinh không vạn trượng chém thẳng đạo nhân bảy màu, đánh vỡ hai cánh Thất Thải Đạo Liên, lực lượng trùng kích phá hủy bảy tu chân tinh, tàn giới hủy diệt hoàn toàn. Khi đạo nhân phản công bằng năm cánh hoa còn lại, dùng Phần Giới Cổ Tán đã bí mật huyễn hóa sẵn bằng tay trái (tiêu hao sinh cơ) biến thành ô lửa chặn đỡ, nương lực trùng kích lùi ba bước dung hợp dòng xoáy thoát thân. Trước khi rời đi kịp hạ mệnh lệnh đầu tiên cho Bạch Hổ chiến tướng: bắt tu sĩ Ngũ Hành tinh vì có chỗ quan trọng cần dùng.","anchor":"Đây chính là mệnh lệnh đầu tiên Vương Lâm giao cho Bạch Hổ chiến tướng.","bridge":true,"khoang":"@c1664"},{"mucCt":"ky","text":"Bị đạo nhân bảy màu truy kích xuyên ba trăm tàn giới, dùng thuật Tê Thiên (lực cánh tay Diệp Mịch) xé hư không phá dòng xoáy xóa dấu vết. Phát hiện tàn giới có mãnh thú ngủ say, ghi nhớ vị trí không kích thích. Bày kế trong kế: kế thứ nhất cố ý khiến tấm màn ngăn cách các giới sắp sụp đổ để đối phương tập trung đối phó; kế thứ hai dùng tấm buồm mặt quỷ biến thành tu chân tinh tầm thường, kết hợp lặp hành động xuyên giới cả trăm lần tạo thói quen tiềm thức cho kẻ truy kích. Lừa thoát tất cả kẻ truy kích kể cả đạo nhân bảy màu và Chiến lão quỷ. Đi ngược hướng quay lại tàn giới mãnh thú, quyết định dùng Tam mệnh thuật phản kích, bắt quyết áp tay lên mặt đất bắt đầu chuẩn bị.","anchor":"việc Vương Lâm hành động lặp đi lặp lại cả trăm lần, xuyên qua tấm màn ngăn cách các giới cả trăm lần khiến người truy kích có thói quen theo tiềm thức","bridge":true,"khoang":"@c1665"},{"mucCt":"ky","text":"Trên tu chân tinh sa mạc cát vàng cuối cùng, Vương Lâm phát hiện Mục Ngư dưới lòng đất đã nuốt hết các tu chân tinh khác trong tinh vực. Hắn lần lượt bố trí bảy tầng mai phục: Phần Giới Cổ Tán vô hình che phủ thiên địa, Thất Thải Đạo Thương cắm xuống mặt đất, bổn tôn Đạo Cổ triệu hồi Khai Thiên Phủ toàn lực rồi ẩn đi, buồm mặt quỷ hút gần nửa máu tươi tạo ảo cảnh, U Minh thú ẩn sương mù, vòng máu kích Mục Ngư dưới lòng đất, cung Lý Quảng triệu hồi bằng huyết mạch tiên nhân cuối cùng. Tiêu hao gần nửa máu tươi và cực nhiều tinh lực, thần sắc uể oải. Sau đó đốt hương đen phát tín hiệu, khống chế Tử Hà truyền thần niệm vào ngọc giản truyền âm rồi vỡ vụn làm mồi nhử. Mục tiêu không phải giết mà là trọng thương một trong hai kẻ thù (đạo nhân bảy màu hoặc Chiến lão quỷ) để phá thế cân bằng lực lượng giữa hai bên.","anchor":"Bảy tầng mai phục, tạo thành một cái bẫy kinh thiên!","bridge":true,"khoang":"@c1666"},{"mucCt":"ky","text":"Phân thân ngồi trên tu chân tinh cát vàng, tay cầm cung Lý Quảng uốn cong như trăng non chờ đợi. Lấy hồn thứ ba từ mi tâm phóng thích toàn bộ khí tức làm mồi nhử, tuyên bố ai tới gần một trượng được lấy hồn. Đốt chiến hương dẫn dụ đệ tử Thất Đạo Tông, ngọc giản Tử Hà vỡ triệu tập ba chiến tướng. Đạo nhân bảy màu, Chiến lão quỷ, tam đại chiến tướng và các tu sĩ đều lao vào tinh cầu. Kích hoạt Phần Giới Cổ Tán — lần đầu bất chấp tất cả thi triển, cổ tán khổng lồ hiện ra chống trời biến bầu trời thành biển lửa đỏ rực, đóng cửa quan ngăn đường lui. Dung nhập hỏa bổn nguyên vào cổ tán, hư hỏa thiêu đốt tâm thần tu sĩ bên trong. Thu ba thành giết ba đệ tử Thất Đạo Tông chưa đạt bước thứ ba. Thu sáu thành khiến tam đại chiến tướng đồng loạt sắc mặt đại biến. Cố ý dùng lực cổ tán ngăn Lam Mộng Đạo Tôn ở bên ngoài để bảo vệ.","anchor":"Phần Giới Cổ Tán từ khi Vương Lâm học được đây là lần đầu tiên hắn bất chấp tất cả thi triển ra!","bridge":true,"khoang":"@c1667"},{"mucCt":"ky","text":"Thi triển Phần Giới Cổ Tán đạt cực hạn tám thành, sức sống tuôn ra điên cuồng, toàn thân già nua quá nửa. Tung đệ nhị phục trường thương bảy màu phá tan hoàn toàn đài sen bảy màu của đạo nhân bảy màu. Bổn tôn ngàn trượng hiện ra cầm Khai Thiên Phủ vung về phía bảy màu, cố ý để búa vỡ bạo phát toàn bộ uy lực. Tung đệ tứ phục Quỷ Kiếm Huyết Phàm vây khốn Chiến lão quỷ khiến hắn mê man bất động. Triệu hồi U Minh Thú nuốt hàng loạt đệ tử Thất Đạo Tông và lục phi, khiến đạo nhân bảy màu hoảng sợ khoảnh khắc thay cho Định Thân Thuật. Vỗ tay lên mặt đất dùng mật thuật Bạch Hổ kết hợp phương pháp thao túng lực lượng học từ đệ nhị Chu Tước kích thích Mục Ngư biến dị thức tỉnh, vòng tròn máu nổ tung bao vây bảy màu. Cả phân thân lẫn bổn tôn đều trọng thương nghiêm trọng, nhờ Đạo Cổ bất diệt thể dung hợp hồi phục nhưng vẫn cực kỳ suy nhược.","anchor":"Hắn chính là chủ trận, còn bố trí mai phục, nhưng lại gặp phải thương thế mức này, có thể thấy được đạo nhân bảy màu hùng mạnh như thế nào!","bridge":true,"khoang":"@c1668"},{"mucCt":"ky","text":"Nắm thời cơ đạo nhân bảy màu bị tám con Mục Ngư vây đánh, Vương Lâm kéo cung Lý Quảng bắn tiễn thứ nhất xuyên qua hào quang bảy màu đâm trúng ngực đối thủ, nhưng bảy màu kịp túm đuôi tên nên không bị xuyên thủng. Sức phản lực khiến Vương Lâm khóe miệng tràn máu, tu chân tinh vỡ vụn. Mũi tên bị bảy màu rút ra liền tiêu tan và tự quay về dây cung, Vương Lâm lập tức kéo cung bắn tiễn thứ hai.","anchor":"tay phải cầm cây cung của Lý Quảng giơ mạnh lên tay trái kéo dây cung","bridge":true,"khoang":"@c1669"},{"mucCt":"ky","text":"Bắn tiễn thứ hai từ cung Lý Quảng xuyên thủng ngực đạo nhân bảy màu gây trọng thương. Kim quang huyết mạch tiên nhân trong đồng tử gần như tiêu tan, chỉ còn đủ sức cho một cung cuối. Bắn tiễn thứ ba va chạm chín mặt trời nổ tung, tạo sức mạnh hủy diệt ba trăm tàn giới, kim quang huyết mạch tiên nhân hoàn toàn tiêu tan. Đã chuẩn bị từ trước, bấm quyết triệu hồi Liên Đạo Phi từ không gian trữ vật ra phía trước làm lá chắn chống lực hủy diệt. Liên Đạo Phi có tiên nhân bất diệt thể hoàn chỉnh, chắn toàn bộ mà lông tóc không hư tổn. Sự xuất hiện của Liên Đạo Phi khiến đạo nhân bảy màu lần đầu tiên bỏ chạy, toàn trường chấn động.","anchor":"Vương Lâm hiểu rõ bản thân chỉ còn lại sức mạnh cho một cung, cũng là một cung cuối cùng","bridge":true,"khoang":"@c1670"},{"mucCt":"ky","text":"Thu được ba con Mục Ngư trong ba trăm giới đang sụp đổ, mất con thứ tư vào tay Huyền La Đại Thiên Tôn (tổng cộng mất sáu con). Hư trương thanh thế bằng lời thách thức về lực bắn cung Lý Quảng, khiến Chiến lão quỷ do dự không đuổi theo, đây là kết quả hài lòng nhất trong bảy tầng sát cục. Dẫn người điên vào dòng xoáy rời ba trăm giới, bị trọng thương phun máu. Tiến vào đệ nhị hoa của Ngũ hoa bát môn — thế giới hoàn toàn đóng băng do Thất Thải Tiên Tôn tạo dựa trên ký ức về Đông Lâm tông. Gặp nữ Cổ Thần Vân Na, được nàng nhận là chủ nhân mới vì mang phân hồn Thất Thải Tiên Tôn, được đề nghị dung hợp tâm thần huyết cuối cùng của Diệp Mịch để chữa thương.","anchor":"Hắn năm đó khi giết Hướng gia lão tổ ở La Thiên Tinh Vực đã từng cảm nhận được khí tức này","bridge":true,"khoang":"@c1671"},{"mucCt":"ky","text":"Được nữ Cổ Thần trao giọt nguyên thần huyết cuối cùng của Diệp Mịch, kiểm tra bằng thần thức rồi vỗ vào mi tâm hấp thu. Nguyên thần huyết đầy đủ khiến thân thể phình to hơn trăm trượng, xương cốt chắc hơn, Đạo cổ lực mạnh mẽ hơn. Nguyên thần Diệp Mịch ngưng tụ thành thực chất rồi hóa khói xông vào thất khiếu mưu đoạt xá, nhưng Vương Lâm có hồn huyết được cổ Tổ tán thành nên Diệp Mịch không thể đối kháng, sau ba canh giờ tiêu tán hoàn toàn thành một bộ phận Đạo cổ truyền thừa. Thương thế hoàn toàn khôi phục, đã có hơn phân nửa Đạo cổ truyền thừa, còn thiếu mắt trái, trái tim hoặc cánh tay trái của Đạo cổ. Đồng ý giúp nữ Cổ Thần rời khỏi động phủ giới.","anchor":"Hắn đã đạt được sự tán thành của cổ Tổ, đạt được hồn huyết","bridge":true,"khoang":"@c1672"},{"mucCt":"ky","text":"Hoàn tất dung hợp giọt máu Cổ Thần cuối cùng, Đạo Cổ lực tràn khắp toàn thân, tinh điểm trên mi tâm và hai mắt ngưng thật, u quang đậm hơn. Cảm ứng sự kêu gọi từ sâu trong tầng băng, bay tới Đông Lâm Trì đóng băng phía sau ngọn núi. Phát hiện cánh tay trái khổng lồ của Diệp Mịch phong ấn dưới hồ băng nửa trong suốt. Dùng huyết kiếm đâm tầng băng nhưng bị bật lại, chuyển sang thi triển Đạo Cổ bất diệt chỉ phá băng suốt mấy canh giờ, tạo hố sâu bốn trượng. Thu khối băng chứa lực lượng giống bổn nguyên vào không gian trữ vật. Lộ da tay cánh tay trái Diệp Mịch tỏa khí tức Đạo Cổ nồng đậm, đặt tay trái lên hấp thu ba ngày, cánh tay thu nhỏ hóa làn khói chui vào tay hắn — dung hợp thành công. Nay đã có cả hai cánh tay Diệp Mịch, uy lực thuật Tê Thiên sẽ tăng mạnh. Hứa giúp nữ Cổ Thần rời khỏi nơi này, nói rõ ân oán phân minh.","anchor":"cánh tay trái hóa thành một làn khói chui vào trong tay Vương Lâm","bridge":true,"khoang":"@c1673"},{"mucCt":"ky","text":"Dung hợp hoàn toàn cánh tay trái Diệp Mịch từ khí tức trong hồ băng, cánh tay trở nên thô ráp xuất hiện ký hiệu phức tạp, tinh điểm tam tộc cổ biến hóa kịch liệt, mơ hồ xuất hiện hình ảnh tinh điểm thứ chín. Dùng thuật Tê Thiên với sức mạnh hai tay xé đôi hồ băng và mặt đất, xuyên vào ngũ hoa bát môn qua khe nứt khổng lồ. Đi qua đệ tam hoa đã chết hoàn toàn, từ bỏ kế hoạch mai phục tại đó vì Chiến lão quỷ đa nghi. Tiến vào đệ tứ hoa, phát hiện thế giới bên trong chính là vùng đất cổ mộ nơi năm đó đạt Đạo Cổ truyền thừa, do Thất Thải Tiên Tôn bố trí. Quyết định liều mạng xuống tầng hai cổ mộ để hấp thu trái tim Diệp Mịch, nếu thành công sẽ đạt Cổ Thần cửu tinh và Cổ Ma cửu tinh. Đã nắm toàn bộ bản đồ tầng một, tiến thẳng tới cửa vào tầng hai.","anchor":"Phú quý hiểm trung cầu, cả đời Vương Lâm đều phải chu du trong tử vong","bridge":true,"khoang":"@c1674"},{"mucCt":"ky","text":"Xâm nhập vùng đất cổ mộ, dựa ký ức hồn thứ ba nhận ra khí tức kinh khủng tầng hai chính là Dĩ Ti Chi Khôi — sát chiêu cả đời Thất Thải Tiên Tôn tế luyện, đại thành sau khi giết Diệp Mịch. Tiết lộ mỗi lần giết người đều dùng phương pháp trong ký ức hồn thứ ba để tế hồn, tạo liên lạc kỳ dị với Dĩ Ti Chi Khôi. Suy luận vùng đất cổ mộ rất có khả năng do Thất Thải Tiên Tôn tạo ra để nuôi dưỡng Dĩ Ti Chi Khôi. Đi qua truyền tống trận cổ xưa vào tầng hai, đối mặt Dĩ Ti Chi Khôi hình đầu lâu khổng lồ trên ngọn núi, bị tiếng gầm đẩy lùi ngàn trượng và trào máu dù đã dùng Đạo cổ lực phòng hộ. Nhận ra muốn khống chế Dĩ Ti Chi Khôi phải giết thêm tu sĩ có đại thần thông để tế hồn. Ẩn thân khi đệ tam phi tới, sau đó hiện thân chặn dư âm tiếng gầm cho nàng, lạnh lùng từ chối sự giúp đỡ nhưng đệ tam phi đưa ra chuỗi hạt châu có thể hóa bảy kim môn.","anchor":"Nó chính là Dĩ ti chi khôi!","bridge":true,"khoang":"@c1675"},{"mucCt":"ky","text":"Hỏi tên thật Đường San, biết nàng thuộc Thiên Môn Đạo. Đối đầu ánh mắt Vân Dật Phong khiến hắn lùi nửa bước, nhận thệ huyết thách đấu đường đường chính chính. Dùng quyền Đạo Cổ phá trường đao, sau đó triệu hai cánh tay Diệp Mịch thi triển Tê Thiên Thuật đại thành xé hư không, phá tan hoàn toàn Bát Đao Trảm Thần Hồn. Tuyên bố ngay cả Định Thân Thuật cũng không dùng. Vân Dật Phong thừa nhận thua, thệ huyết hoá lời thề ràng buộc. Cảm nhận ba luồng khí tức quen thuộc tới gần, sai Vân Dật Phong tấn công Chưởng Tôn, phóng huyết kiếm đẩy lùi Chưởng Tôn một bước. Được Đường San thi triển Thất Diện Kim Môn phòng hộ lên người, lần đầu chứng kiến thần thông phòng hộ có thể dùng cho người khác.","anchor":"Thuật Tê Thiên đã đại thành, uy lực của nó cực kỳ kinh người","bridge":true,"khoang":"@c1676"},{"mucCt":"ky","text":"Bị Chưởng Tôn phán đoán đã cạn sức sau ba lần giương cung, không còn dùng được cung Lý Quảng. Thi triển Tê Thiên Thuật chống lại Chưởng diệt tam đạo của Chưởng Tôn, phá được hai tầng đầu nhưng bị kim ấn tầng ba vượt qua. Không hoảng loạn, tỉnh táo lùi ba bước từ xa tới ngay sau lưng Huyền La rồi khoanh chân ngồi xuống, ánh mắt chạm Huyền La trong vô hình — ép Huyền La ra tay. Huyền La chỉ tay biến kim ấn thành pháp bảo thực chất lơ lửng trước mặt Vương Lâm. Nhìn thấy rõ biểu cảm hoảng sợ và cúi đầu của Vân Dật Phong sau sự kiện này.","anchor":"thần sắc không một chút hoảng loạn, cực kỳ tinh tảo","bridge":true,"khoang":"@c1677"},{"mucCt":"ky","text":"Nhận chủ kim ấn vô chủ do Huyền La sáng tạo từ hư ảo, nuốt vào miệng tế luyện trong nguyên thần. Lần đầu tiên hoàn toàn bành trướng thân thể Cổ Thần lên mấy vạn trượng, cùng Thác Sâm phong tỏa trước sau Chưởng Tôn. Phóng hơn mười lá Cổ Tức Diệp phong kín đường lui Chưởng Tôn, thi triển Tê Thiên Thuật xé thiên địa lao tới. Dùng Định Thân Thuật chặn ngụm nguyên thần huyết màu vàng của Chưởng Tôn, phóng huyết kiếm xuyên qua vai Chưởng Tôn khiến hắn phun máu. Lực phản phệ trong cơ thể bộc phát khiến sắc mặt tái nhợt.","anchor":"thân thể hắn lần đầu tiên hoàn toàn bành trưởng","bridge":true,"khoang":"@c1678"},{"mucCt":"ky","text":"Chỉ huy Lam Mộng Đạo Tôn phong ấn Chưởng Tôn ba nhịp thở. Trong ba nhịp thở, dùng Mộng Đạo (mặt quỷ huyễn cảnh) điểm mi tâm Chưởng Tôn, dung hợp hồn rồi tế hồn cho Dĩ Ti, nuốt mất nửa hồn Chưởng Tôn. Bị phản đòn phun máu tươi lui lại. Triệu hồi Dĩ Ti hiện thân lần đầu tiên từ ngọn núi hắc khí, sương đen bao phủ chiến trường, Dĩ Ti đánh bại Chưởng Tôn trong sương mù. Nhận ra Dĩ Ti chưa đạt đỉnh Không Kiếp Sơ Kỳ như ký ức Thất Thải Tiên Tôn miêu tả, chỉ tương đương mấy lần huyền kiếp, cần tế hồn thêm để khống chế. Thu Chưởng Tôn bất tỉnh (còn nửa hồn) vào không gian trữ vật, tuyên bố để cho người điên năm đó thức tỉnh rồi quyết định sống chết.","anchor":"Hồn của ngươi vẫn còn một nửa, ta không giết ngươi, ngươi là nô bộc của người điên năm đó","bridge":true,"khoang":"@c1679"},{"mucCt":"ky","text":"Thương cảm cho Chưởng Tôn — kẻ một đời kiêu hùng nhưng vận mệnh bi thảm, luân hồi nhân quả giống việc năm xưa vây giết Phong Tôn. Cảm tạ đồng minh và kết thúc nhân quả: nói với Lam Mộng Đạo Tôn ân nghĩa đã xong, tuyên bố với Đường San hai bên cân bằng, kết thúc ân oán với Vân Dật Phong. Lao xuống tầng cuối vùng đất cổ mộ qua hố sâu lộ ra sau khi ngọn núi Ác quỷ Dĩ Ti sụp đổ. Chịu đựng cộng hưởng trái tim Diệp Mịch khiến mạch máu căng phồng, ho ra máu. Ngồi khoanh chân trên trái tim khổng lồ, dùng thần niệm thuyết phục Diệp Mịch. Hứa ba điều: hoàn thành di nguyện Diệp Mịch, chiếu cố thân nhân ở Tiên Cương đại lục, tìm mắt trái về cho Diệp Mịch. Trái tim chấp nhận đập cùng nhịp, Đạo Cổ khí tức mênh mông tràn vào cơ thể, tám tinh điểm trên mi tâm xoay tròn, xuất hiện dấu hiệu hình thành tinh điểm thứ chín.","anchor":"Tám tinh điểm trên mi tâm của hắn chợt xoay tròn, mơ hồ xuất hiện dấu hiệu hình thành tinh điểm thứ chín!","bridge":true,"khoang":"@c1680"},{"mucCt":"ky","text":"Tại tầng cuối cùng vùng đất cổ mộ, hấp thu khí tức Đạo cổ từ trái tim Diệp Mịch, nhịp tim dần hòa với nhịp đập trái tim Diệp Mịch. Tinh điểm trên mi tâm trong hai mắt có dấu hiệu hình thành tinh điểm thứ chín. Minh ngộ nguyên lý dùng nhịp tim bản thân dẫn động nhịp tim đối phương, có thể khiến vỡ tim hoặc khống chế. Tính toán sáng tạo thần thông mới kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa. Cuối chương, tiếng tim đập và khí tức Đạo cổ tràn ra khỏi tầng cuối cùng, lan tới chiến trường tầng thứ hai.","anchor":"Tinh điểm trên mi tâm trong hai mắt điên cuồng xoay chuyển, không ngờ đều có dấu hiệu hình thành tinh điểm thứ chín","bridge":true,"khoang":"@c1681"},{"mucCt":"ky","text":"Bước ra từ tầng cuối vùng đất cổ mộ sau khi nhận trọn truyền thừa Diệp Mịch, diện mạo biến đổi hoàn toàn: da phủ ký hiệu, đôi mắt màu bạc (ngân mục), mi tâm chín tinh điểm, mắt phải chín ma tinh, mắt trái tám yêu tinh đang chảy máu. Dùng ngân mục nhìn qua chỗ Huyền La Đại Thiên Tôn, mơ hồ thấy được điều người khác không thấy. Dùng thần thông Tâm Động Lôi Âm — tiếng tim đập ầm ầm khuếch tán thành âm thanh duy nhất thiên địa — đặt bàn tay đen kịt lên ngực Huyền Vũ chiến tướng đánh bay. Chủ động bảo Lam Mộng và lão Mã nghỉ ngơi, tự mình đảm đương trận chiến với Chiến lão quỷ đã dung hợp hồn phách Thất Thải Tiên Tôn. Tiếng tim đập dẫn động trái tim Chiến lão quỷ khiến hắn đau đớn phải áp chế.","anchor":"trái tim trong thân thể Vương Lâm ầm ầm vang lên, âm thanh kinh thiên động địa","bridge":true,"khoang":"@c1682"},{"chuong":"@c1683","importance":"normal","mucCt":"ky","tieuDe":"Lần đầu thi triển Đạo Cổ Vô Tiên","text":"Chuyển hóa toàn bộ tu vi thành khí tức Đạo cổ, tuyên bố tiếp nối trận chiến năm xưa giữa Diệp Mịch và Thất Thải Tiên Tôn. Dùng Tâm Động Lôi Âm khống chế nhịp tim Chiến lão quỷ suýt khiến tim hắn tan vỡ. Ngưng tụ chín tinh điểm Cổ Thần và mười bảy tinh điểm yêu ma vào quyền Đạo cổ đấu bảy chữ Chiến của Chiến lão quỷ, sáu chữ vỡ nhưng chữ cuối nổ khiến hắn khạc máu. Lần lượt thi triển ba bước: Thần Chấn binh tu liệt vị (Cổ Thần cửu tinh xoay thiên địa), Yêu Thuật phong hỏa thành sơn (Cổ Yêu bát tinh tạo lốc phong hỏa), Ma Đạo sinh tử nghịch động (Cổ Ma cửu tinh biến sức sống thành tử khí). Cuối cùng dung hợp tam tộc thành tuyệt chiêu Đạo Cổ Vô Tiên, triệu ra hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, hóa đá toàn bộ cổ mộ từ tầng một đến tầng cuối cùng Chiến lão quỷ và hai hồn Thất Thải Tiên Tôn. Nhận ra dung nhan đầu lâu quen thuộc từ huyết mạch, chính là Cổ Tổ. Dù dốc sức, Chiến lão quỷ vẫn phá hóa đá thoát thân. Kiệt sức khạc máu, tự nhận vẫn không phải đối thủ do thiếu mắt trái khiến Cổ Yêu chưa đạt cửu tinh. Quyết định đi tìm đệ ngũ hoa, mở cửa lớn động phủ, mượn sức mạnh Tiên Cương phong ấn Chiến lão quỷ.","anchor":"Cố gắng thi triển Đạo cổ vô tiên, hay là để cho hắn chạy thoát"},{"mucCt":"ky","text":"Vương Lâm bước vào thử thách cuối cùng ở trung tâm động phủ, tiến vào đệ ngũ hoa của Ngũ Hoa Bát Môn trận. Hồn thứ ba (ký ức cả đời Thất Thải Tiên Tôn) tạo thành thế giới bảy màu, Vương Lâm hóa thành hình dạng Tô Đạo (Thất Thải Tiên Tôn thời trẻ), mặc đạo bào xanh có lực phòng hộ chống đòn toàn lực tu sĩ vấn Đỉnh, đeo ngọc bội trong suốt. Đã ở trong thế giới này hơn hai tháng mà chưa tìm được chân môn. Nhận ra hình dạng hiện tại giống pho tượng bảy màu lấy từ Tham Lang, chỉ thiếu vẻ tang thương. Cảm giác bản thân chưa hoàn toàn dung hợp với hồn thứ ba ở mức độ sâu. Khi thanh niên đồng môn phụng mệnh đại sư huynh tới bắt nạt, Vương Lâm dùng ánh mắt uy áp khiến đối phương hồn bay phách tán, rồi túm cổ nhấc lên cảnh cáo, không để lịch sử bắt nạt lặp lại. Dẫn thanh niên lên đỉnh núi tới đại điện, nơi gần trăm tu sĩ tụ tập cung nghênh sư tôn xuất quan, trời đổ mưa lớn ngay khi hắn bước vào sân.","anchor":"Không được trêu chọc ta, không một lần nào nữa, rõ chưa?","bridge":true,"khoang":"@c1684"},{"text":"Trong thế giới ký ức hồn thứ ba (danh phận Tô Đạo tại Đông Lâm Tông), được sư tôn gọi vào đại điện cùng Chu Lập để tranh tư cách học Vân Đạo Thiên Thuật. Quyết định nghịch chuyển ký ức thay vì thuận theo (vì nếu dung hợp hoàn toàn, Tạ Thanh sẽ vĩnh viễn không thức tỉnh). Bùng phát sát khí đáp trả ánh mắt uy hiếp của Chu Lập, chỉ tám nhịp thở hoàn thành vận chuyển vân khí, mây mù hóa rồng nuốt sạch sương mù Chu Lập khiến hắn phun máu. Được sư tôn chọn làm đệ tử học Vân Đạo Thiên Thuật — đảo ngược hoàn toàn lịch sử gốc. Khi ký ức bị thay đổi, thiên địa vặn vẹo, tám luồng khí tức bát môn bốc lên. Ngộ ra phương pháp cốt lõi: thay đổi ký ức tạo mâu thuẫn hỗn loạn, từ đó cảm nhận vị trí bát môn và tìm cánh cửa thực sự.","anchor":"Mâu thuẫn và hỗn loạn càng lớn thì ta lại càng cảm nhận được rõ ràng, thậm chí có thể từ đó tìm ra được cánh cửa thực sự!","mucCt":"ky","bridge":true,"khoang":"@c1685"},{"mucCt":"ky","text":"Trong thế giới đệ ngũ hoa, Vương Lâm hồi tưởng ký ức hồn thứ ba (Tô Đạo) về quá khứ tại Đông Lâm Tông. Bắt đầu tu luyện Vân Đạo Thiên Thuật do sư tôn Tô Đạo truyền thụ, hấp thu vân khí từ sông, cây cỏ, mây đen trên bình nguyên suốt hơn hai tháng. Mây mù cuối cùng hóa bảy con vân long chui vào thất khiếu, đồng tử biến thành mây mù, đạt tầng thứ chín chỉ kém đại viên mãn. Nhờ quá trình tu luyện không ngừng kích thích ký ức hồn thứ ba, tìm ra vị trí đệ nhất quan trong bát môn. Lao tới vùng rừng rậm, phát hiện đệ nhất quan không phải cây đại thụ mà chính là con mãng xà trăm trượng — trên lưng nó hiện cánh cửa biến ảo. Nắm cổ mãng xà, từng bước tiến về phía cánh cửa.","anchor":"Thời gian hai tháng đã tu luyện Vân Đạo Thiên Thuật này tới tầng thứ chín, chỉ còn kém một chút là đại viên mãn","bridge":true,"khoang":"@c1686"},{"mucCt":"ky","text":"Rời đám cây cối sau khi xác nhận mãng xà là bát môn nhưng không phải cửa thực, quyết định lợi dụng cuộc thi đấu Đông Lâm Tông để nghịch chuyển ký ức hồn thứ ba tìm cửa thật. Được sư tôn chọn làm một trong ba đệ tử dự thi cùng Chu Lập và Tần Mai. Tại quảng trường khai mạc, bình tĩnh trước uy áp của mấy trăm cường giả, thu hút hơn mười ánh mắt chú ý — hoàn toàn đảo ngược kịch bản ký ức cũ khi Tô Đạo chỉ run rẩy cúi đầu. Khi Tần Mai bắt chuyện, mỉm cười thong dong hào hiệp khiến nàng ngạc nhiên. Tiến vào khe Đông Lâm, xuất hiện ở bình nguyên cỏ dại đúng vị trí trong ký ức Thất Thải Tiên Tôn, tự nhủ sẽ thay đổi tất cả.","anchor":"Ta đã tới, tất cả sẽ thay đổi","bridge":true,"khoang":"@c1687"},{"mucCt":"ky","text":"Đóng vai Tô Đạo trong thế giới đệ ngũ hoa (ký ức hồn thứ ba Thất Thải), cướp toàn bộ ngọc bội lệnh bài của các đệ tử cửa thứ nhất tỷ thí Đông Lâm Tông. Đánh bại Côn Bằng khiến hắn vứt ngọc bội bỏ chạy, phá sập núi giết chết Chu Lập. Quét sạch ngọc bội rồi xé trời bước ra ngoài tuyên bố đứng đầu tỷ thí. Hành động nghịch chuyển ký ức khiến hồn thứ ba hỗn loạn rồi hưng phấn, thế giới đệ ngũ hoa sụp đổ hoàn toàn, khí tức bát môn hiển lộ toàn bộ như cột khí bốc lên chín tầng mây. Khi giết Chu Lập đã cảm nhận được vị trí tam môn trong bát môn. Đông Lâm Trì ở hậu sơn là thứ duy nhất không sụp đổ.","anchor":"Ta, Tô Đạo, là người đứng đầu trong cuộc tỷ thí này!","bridge":true,"khoang":"@c1688"},{"mucCt":"ky","text":"Nhập Đông Lâm Trì trong thế giới ký ức đệ ngũ hoa, nước ao bổn nguyên khiến bảy đạo bổn nguyên (hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế) đạt viên mãn và ngưng tụ thành bảy bổn nguyên chân thân hình dáng giống Vương Lâm. Thủy bổn nguyên (đạo thứ tám, đạt được tại Ngũ Hành Tinh) hấp thu toàn bộ nước ao còn lại mà đại thành, ngưng tụ chân thân thứ tám. Tu vi đột phá từ Không Linh hậu kỳ lên Không Linh đỉnh, chỉ cách Không Huyền một bước — cần bổn nguyên thứ chín để cửu cửu quy nhất. Tuy nhiên tu vi này là hư ảo trong ký ức, sẽ tiêu tán khi trở về thực tại, nhưng trải nghiệm và hiểu biết về Đông Lâm Trì là thật. Kêu gọi Tô Đạo (hồn thứ ba) giúp tìm cánh cửa thật, đổi lại hoàn thành tâm nguyện vào Đông Lâm Trì. Dùng Vân Đạo Thiên Thuật cùng tám bổn nguyên chân thân vượt qua Chiến lão quỷ, tới trước đại môn động phủ giới. Dồn toàn bộ Đạo Cổ lực và tám bổn nguyên chân thân đánh ra một chưởng, mở được khe hở trên đại môn khổng lồ, trở thành người đầu tiên mở được đại môn này sau phong bế. Khí tức thần chính Tiên Cương đại lục tràn vào.","anchor":"Tu vi Không Linh hậu kỳ của Vương Lâm ầm ầm tăng mạnh!","bridge":true,"khoang":"@c1689"},{"mucCt":"ky","text":"Kích hoạt hai đạo phong ấn do Tạ Thanh để lại, chờ dung hợp khí tức Tiên Cương đại lục. Dùng tám bổn nguyên chân thân đánh chưởng, lần đầu tiên khiến Chiến lão quỷ cùng lưỡng hồn Thất Thải Tiên Tôn lui bước. Nương lực phản chấn cùng tám bổn nguyên đập cửa, mở rộng đại môn động phủ giới tới gần ba phần. Phóng hai đạo phong ấn phong ấn lưỡng hồn Thất Thải Tiên Tôn, cắt đứt liên hệ chúng với Chiến lão quỷ. Không ngăn cản Chiến lão quỷ lao vào đại môn trước khi chết, thốt lời Tạ Thanh vừa là đệ tử vừa là sư tôn của hắn.","anchor":"Đây là lần đầu tiên Vương Lâm đối mặt với Chiến lão quỷ có thể khiến hắn lui bước!","bridge":true,"khoang":"@c1690"},{"mucCt":"ky","text":"Chứng kiến đại môn động phủ giới mở ra, kim môn hoàng kim nối tới Tiên Cương đại lục. Hồi tưởng hơn hai ngàn năm gian khổ, nhớ Lý Mộ Uyển và Tạ Thanh, hứa sẽ đánh thức Uyển Nhi và làm Tạ Thanh sống lại ở Tiên Cương. Tám bổn nguyên chân thân tiêu tán khi trở lại thân xác, Thủy bổn nguyên chỉ còn chút thành tựu, bảy bổn nguyên ẩn trong thân, trở về trạng thái trước biến hóa Đông Lâm Trì. Tuyên bố xóa bỏ ân oán cũ trong động phủ giới, ôm quyền tiễn biệt tất cả tu sĩ muốn rời đi. Phóng thích Bạch Hổ chiến tướng và tu sĩ trung niên Ngũ Hành Tinh bị giam. Tiễn đoàn Ngũ Hành Tinh, ba chiến tướng Huyền Vũ, Chu Tước, Bạch Hổ, và Đường San qua kim môn. Sau khi mọi người rời đi, ôm quyền vái về phía hư vô, gọi đích danh Huyền La Đại Thiên Tôn lộ diện, nói rõ kẻ này đã bám theo hắn từ Ngũ Hành Tinh tới Tiên Giới rồi tới trung tâm động phủ.","anchor":"Huyền La Đại Thiên Tôn tiền bối, người theo ta một đoạn đường từ Ngũ Hành Tinh tới Tiên Giới, lại tới cả trung tâm của động phủ này","bridge":true,"khoang":"@c1691"},{"mucCt":"ky","text":"Huyền La Đại Thiên Tôn hiện thân giao tiếp trực diện, tự suy đoán đúng cách Vương Lâm biết thân phận mình (thu thần thức tu sĩ Ngũ Hành Tinh, Mục Ngư cảm nhận khí tức). Huyền La tiết lộ thân phận: một trong Cửu Dương, Đại Thiên Tôn của Đạo Cổ nhất mạch tại Tiên Cương đại lục. Huyền La xác định mời Vương Lâm làm đệ tử duy nhất, đặc biệt hài lòng vì hắn chưa từng xin giúp đỡ. Vương Lâm trầm tư chưa đồng ý vì lo cho Uyển Nhi và bằng hữu. Huyền La giải thích quy tắc Tiên Cương đại lục: sinh linh không có huyết mạch sẽ bị hồn phi phách tán, tiếp dẫn giả là lừa gạt. Huyền La tiết lộ hồn Uyển Nhi không hoàn chỉnh, một phần đã biến mất không dấu vết. Vương Lâm chảy huyết lệ tuyệt vọng, tuyên bố thà ở lại động phủ giới vĩnh viễn với Uyển Nhi chứ không một mình tới Tiên Cương. Huyền La đề xuất Thiên Dương luân hồi chuyển thế thuật cho bằng hữu, riêng Uyển Nhi cho năm phần mười cơ hội mang trực tiếp đi, thất bại thì cả hai tử vong. Vương Lâm ghi nhận mang ân Huyền La.","anchor":"ta sở dĩ muốn mở cánh cửa động phủ này, muốn đi tới Tiên Cương đại lục toàn bộ là vì nàng","bridge":true,"khoang":"@c1692"},{"mucCt":"ky","text":"Đứng ngoài kim môn động phủ giới, Vương Lâm tuyên bố nếu không thể đồng sinh với Lý Mộ Uyển thì xin cộng tử, vô hối — đúc kết đạo tâm hơn hai ngàn năm tu đạo. Vái Huyền La thật sâu cảm tạ ân đức đối kháng pháp tắc Tiên Cương. Bay tới Đông Lâm Tinh đã sụp đổ, xé khe không gian bằng lực Tê Thiên, phun tu vi Đạo Cổ phá tầng băng trong thế giới đóng băng đệ nhị hoa để giải cứu hồn phách Vân Na. Vân Na chủ động tách hồn, để lại thân Cổ Thần báo ân, Vương Lâm thu hồn nàng vào Không Gian trữ vật. Cùng Lam Mộng đạo tôn rời chỗ Huyền La, vượt La Thiên hướng về Vân Hải tinh vực đón Phàn San Lộ. Nhớ ra lời hứa cho một hồn phách trong trữ vật tu vi và thân thể, danh tính chưa rõ.","anchor":"không thể đồng sinh vậy thì đành cộng tử ở bên ngoài đại môn của động phủ giới này","bridge":true,"khoang":"@c1693"},{"mucCt":"ky","text":"Trong mười ngày đầu giải quyết việc tồn đọng: giúp Phàn San Lộ mở đại môn rời đi, thu chiếc thuyền khổng lồ (buồm mặt quỷ đã luyện hóa chủ cấm) vào không gian trữ vật, tìm tu chân tinh và nhập hồn phách vào thân thể mới tạo Nguyên Thần. Trở lại Tiên Giới, tản thần niệm bao phủ toàn bộ, thông báo nửa tháng nữa sẽ rời đi, ai muốn đi thì tới tìm hắn nhưng phải chấp nhận chuyển thế đầu thai. Ngồi đả tọa trên ngọn núi bế quan năm đó chờ đợi. Chia bầu rượu với Tư Đồ Nam, hứa nếu không chết nhất định sẽ tìm lại hắn. Nắm tay Lý Thiến Mai, hẹn sẽ tới Tiên Cương đại lục tìm nàng và giải khai ký ức bị che phủ, dù mười năm, trăm năm, ngàn năm. Ngày cuối nhìn Mộc Băng Mi cầm ô trong mưa, nhớ tới Liễu Mi, không thể quên nổi.","anchor":"Nếu ta không chết thì nhất định sẽ tìm tới ngươi","bridge":true,"khoang":"@c1694"},{"mucCt":"ky","text":"Vương Lâm ly biệt Mộc Băng Mi trong mưa, hứa nếu còn sống nhất định sẽ trở về, ngưng tụ bảy đạo bổn nguyên thành thanh kiếm dung hợp khí tức Đạo Cổ tặng cho nàng rồi xoay người rời đi. Trên đường hắn trầm mặc suy nghĩ về các bí ẩn còn lại của động phủ giới: Chu Tước đời đầu ở Điên Lạc, cây kim la bàn Thiên Nghịch, Xích Hồn Tử đã được thả, người thần bí phong ấn ở Tiên Giới — cố ý lưu lại làm chấp niệm để vĩnh viễn không quên quê hương. Mang mấy chục người tới đại môn động phủ trong La Thiên tinh vực gặp Huyền La, cố ý không thông báo rộng rãi để giảm gánh nặng cho Huyền La. Chứng kiến Huyền La triệu hoán Long Hoàng thiên nhất — con rồng thân mấy vạn trượng thu thành cây long tiên huyết sắc, kinh hãi trước uy lực cây tiên.","anchor":"Hắn có cảm giác dù là bản thân cũng không thể thừa nhận lực lượng một tiên này!","bridge":true,"khoang":"@c1695"},{"mucCt":"ky","text":"Nhận mặt trời Đại Thiên Tôn lực từ Huyền La, tâm thần chấn động khi chạm vào. Thi triển Mộng Đạo Thuật lên mọi người kể cả Lý Thiến Mai, uy lực bạo tăng mấy lần gần đạt mức mộng thành thực. Sóng vô hình bao phủ tất cả, mi tâm mọi người xuất hiện ký hiệu cùng tỏa sáng tạo liên hệ để tương lai tìm lại. Vuốt mi tâm lấy một phần ấn ký phong ấn ký ức của Thanh Sương đặt lên trán Chu Dật, tạo liên hệ giữa hai người sau chuyển thế. Xóa ký ức đau khổ cho Chu Dật trước khi để hắn ra đi.","anchor":"ta đã đưa ấn ký phong ấn ký ức của Thanh Sương lên trên người ngươi","bridge":true,"khoang":"@c1696"},{"mucCt":"ky","text":"Tiễn biệt Thập Tam, Tư Đồ Nam, Lý Thiến Mai lần lượt bước vào đại môn chuyển thế đầu thai tới Tiên Cương đại lục. Xin Huyền La thêm năm ngày để đưa thêm người đi đầu thai — quyết định thừa lúc Tam Tôn suy yếu mà lần lượt xử lý. Xuyên trận pháp vào Thái Cổ Tinh Thần giới ngoại, hai tay đồng thời thi triển Tê Thiên Thuật xé đôi tu chân tinh hình trăng lưỡi liềm, đánh vỡ mọi thần thông pháp bảo của Cửu Thiên ma tôn, đặt tay lên mi tâm phong ấn thu vào không gian trữ vật chỉ trong vài nhịp thở. Tiếp tục tìm tới thủy tinh phía tây, tuyên bố đưa Diệu Âm đạo tôn đi đầu thai.","anchor":"Tu vi của hắn sau khi trải qua ngũ hoa bát môn trong trung tâm của động phủ đã đạt tới đỉnh của Không Linh","bridge":true,"khoang":"@c1697"},{"mucCt":"ky","text":"Lần lượt thu phục Diệu Âm đạo tôn dưới đáy biển vàng, Hư Thần thiên tôn ở khu đá vụn phía nam, lão tổ Thương Viên Tộc trong đại điện, cùng toàn bộ toàn năng bước thứ ba còn lại trong giới ngoại Thái Cổ Tinh Thần, phong ấn thu vào Không Gian trữ vật. Dùng hơn mười lá Cổ Tức Diệp phong ấn tinh không quanh tu chân tinh của tất cả bộ tộc, hạn chế tu sĩ suốt đời chỉ tới Toái Niết, không được bước vào tinh không. Tại La Thiên tinh vực, thả tám toàn năng bước thứ ba ra trước Huyền La, dùng cuồng phong cuốn vào đám sương đen trong đại môn, tuyên bố ân oán xóa sạch sau đầu thai. Từ biệt Huyền La, hóa cầu vồng lao vào đại môn hướng tới Tiên Cương đại lục.","anchor":"Ta sẽ không giết hết, nhưng có thể đem tất cả những tu sĩ bước thứ ba trong các tông tộc của Thái Cổ Tinh Thần giới ngoại đưa đi đầu thai!","bridge":true,"khoang":"@c1698"},{"mucCt":"ky","text":"Trên con đường mình rồng, Vương Lâm chính thức gọi Huyền La là sư tôn, xác lập quan hệ sư đồ, thề đem tính mạng bảo vệ Đạo Cổ nhất mạch. Huyền La phun máu Cửu Dương hóa huyết long cuốn Vương Lâm lao vào lỗ hổng trên lớp băng, đưa hắn vào hư vô đối chọi pháp tắc Tiên Cương, hẹn mười năm chờ ở Tiên Cương. Trước khi rời, Vương Lâm thả toàn bộ sinh linh trong Không Gian trữ vật — Hứa Lập Quốc, Lưu Kim Bưu, Văn Thú, Vọng Nguyệt — ngoại trừ người điên, gửi sư tôn đưa tới Tiên Cương. Chứng kiến đàn Văn Thú do Văn Thú Vương cầm đầu phát cuồng lao vào hư vô lột xác, đại bộ phận nổ tung tử vong, lo lắng muốn cứu nhưng bị Huyền La ngăn. Cuối cùng lao ra ngoài khi gần trăm con nổ tung, chứng kiến Văn Thú Vương tiến hóa thành công thân thể to bằng tu chân tinh.","anchor":"Một tiếng sư tôn này có nghĩa là hắn sẽ đem cả tính mạng ra để bảo vệ Đạo Cổ nhất mạch!","bridge":true,"khoang":"@c1699"},{"mucCt":"ky","text":"Cưỡi Văn Vương cùng chín Văn Thú hộ vệ lao vào hư vô hướng Tiên Cương đại lục, chào biệt sư tôn Huyền La. Hành trình dự kiến mười năm, năm đầu có huyết long chỉ phương hướng và giảm áp lực, cảm nhận Huyền La đang hộ tống từ xa trên con đường mình rồng. Năm thứ hai huyết long gần biến mất, áp lực pháp tắc Tiên Cương đè nặng, lực lượng bổn nguyên tiêu hao không thể khôi phục. Năm thứ tư chín Văn Thú không chịu nổi, thu vào Không Gian trữ vật, chỉ Văn Vương duy trì tốc độ. Năm thứ năm lấy Tị Thiên Quan chứa hồn phách Lý Mộ Uyển đặt sau lưng, dùng toàn bộ lực lượng và thân mình làm lá chắn bảo vệ. Trong hư vô nhớ về Mộc Băng Mi cầm ô đứng trong mưa, không còn hận nàng.","anchor":"Hắn hiểu rõ là mình còn chưa chết thì lực lượng này sẽ không chạm tới Lý Mộ Uyển phía sau","bridge":true,"khoang":"@c1700"},{"mucCt":"ky","text":"Đã tiến vào vùng hư không pháp tắc Tiên Cương được sáu đến chín năm, bổn nguyên lực gần khô kiệt, huyết long trên người tiêu tán, ấn ký hồng ảm đạm, chỉ còn dựa thân thể Đạo Cổ chống pháp tắc. Suốt hành trình phải bảo vệ thê tử Lý Mộ Uyển phía sau. Năm thứ tám sắp không chịu nổi, nhận định hành trình là cửu tử nhất sinh, bùng phát toàn bộ Đạo Cổ lực giam cầm Văn Vương cưỡng ép tách ra, phóng chín Vụ thú đưa nó đi, một mình lao về phía trước. Năm thứ chín thân thể mệt mỏi cực hạn, đôi mắt vô thần nhưng ý chí nghịch thiên quật cường vẫn tồn tại, bước từng bước nặng nề như hơn hai ngàn năm trước tại Hằng Nhạc phái.","anchor":"Hơn hai ngàn năm sau, hắn vẫn là Vương Lâm quật cường kia!","bridge":true,"khoang":"@c1701"},{"text":"Trong tầng hư vô giữa động phủ và Tiên Cương đại lục, Vương Lâm tóc tai bù xù mang theo Tị Thiên Quan, từng bước tiến tới bằng ý chí bảo vệ Lý Mộ Uyển dù hồng quang chỉ đường trên mi tâm đã biến mất từ nửa năm trước. Hắn gặp hài cốt lão già mặc tử bào tỏa bạch quang, ấn tay lên ngực thi thể hút sức mạnh kỳ dị lạnh lẽo vào cơ thể, khôi phục bổn nguyên héo rũ cùng một phần sức mạnh Đạo Cổ. Đó là thi thể thứ hai hắn gặp trong mười năm. Một năm sau đó không gặp được thi thể thứ ba, tu vi tiêu hao tới cực hạn như đèn cạn dầu, thần trí bị tàn phá rồi hôn mê không còn khí tức. Trong hôn mê hắn vẫn dùng thân thể bảo vệ chiếc quan tài đã tràn ngập vết nứt. Khi hắn hôn mê, sức ép pháp tắc Tiên Cương tiêu tan, Tam Mệnh Thuật cũng vô dụng, Tị Thiên Quan đổi hướng trôi lạc trong hư vô suốt nhiều năm như những hài cốt.","anchor":"hắn vẫn lấy thân thể để bảo vệ cho quan tài phía sau","bridge":true,"khoang":"@c1702"},{"mucCt":"ky","text":"Thi thể Vương Lâm trôi lơ lửng trong hư vô Tiên Cương suốt mấy chục năm, tay phải bấu chặt quan tài không buông, thân tỏa bạch quang. Văn Thú Vương hi sinh gần hết thân thể đưa giọt máu tươi từ tim hắn vào đài cao hình cánh cung, đài hấp thụ máu cùng bạch quang khắp hư vô rồi hóa thành thân xác đá khổng lồ, bên trong ngưng tụ hư ảnh Vương Lâm — phân thân. Hắn chậm rãi mở mắt, sức mạnh Đạo Cổ hồi phục, bảy đạo bổn nguyên đạt tới đỉnh. Hắn cảm nhận dường như có một Vương Lâm khác cùng tồn tại, nhìn thấy thân xác đá có người giống mình, trở nên hoang mang.","anchor":"Vương Lâm đang ngủ say vài chục năm ở bên ngoài thân xác bằng đá kia chậm rãi mở hai mắt","bridge":true,"khoang":"@c1703"},{"mucCt":"ky","text":"Cảm ứng phân thân trong xác đá, mơ hồ không rõ mình ở trong hay ngoài. Dung hợp thần thức với Văn Thú đọc trọn ký ức: nó lột xác tiến hóa, cắn nuốt chín đồng bọn, hóa mười vạn phần tìm chủ, mang hắn và Lý Mộ Uyển vào hư vô. Cảm động coi Văn Thú như thân nhân, sẵn sàng vì nó đánh đổi tất cả. Chạm xác đá bị lực phản chấn hất ra, xác nhận phân thân đang trưởng thành trong pháp tắc Tiên Cương. Ngộ ra toàn bộ tu vi khôi phục là nhờ phân thân trong xác đá. Liên hệ cấm chế phong thủy từng tiếp xúc ở động phủ giới, coi xác đá như long mạch. Quyết định bỏ ý phá xác đá, để phân thân chờ cơ duyên trưởng thành hoàn toàn. Mang Lý Mộ Uyển trong Tị Thiên Quan, được Văn Thú chở lao về cửa ra hư vô.","anchor":"sở dĩ toàn bộ tu vi được khôi phục đầu là nhờ trong xác đá này tồn tại phân thân của mình","bridge":true,"khoang":"@c1704"},{"mucCt":"ky","text":"Phân thân nằm trong vùng đất sơ khai (một phần thạch đài nơi Tiên Tổ, Cổ Tổ ra đời), đắc mệnh cách ngang Tiên Tổ và Cổ Tổ — vượt qua mọi cực hạn tu vi. Trải khoảng mười ba năm trong hư vô được Văn Thú hóa sương mù cuốn dẫn đường, dồn toàn bộ tu vi bảo vệ Lý Mộ Uyển trên lưng, tự nhận việc mang theo nàng chẳng khác nào từ bỏ huyết mạch. Phỏng đoán sư tôn đã không thể đợi được, quyết tâm tự lực trên Tiên Cương. Đặt mục tiêu đề cao tu vi, tới Đông Lâm Tông tiến vào Đông Lâm Trì cầu phân thân bổn nguyên để đánh một trận với Không Kiếp. Nhớ lại các cố nhân chuyển thế: Tư Đồ Nam, Lưu Kim Bưu, Hứa Lập Quốc, Thanh Thủy, Hồng Điệp, Lý Thiến Mai. Văn Thú kiệt sức hóa sương mù, được thu thành dấu ấn trên cánh tay. Không dám mở Không Gian trữ vật vì nó rất bất ổn như sắp sụp đổ, bên trong có người điên và ngân y nữ tử. Điều tức nửa ngày rồi bạo phát toàn lực, cõng Lý Mộ Uyển xông qua khe hở, thân thể như bị thiêu đốt nhưng mắt sáng ngời, chính thức đặt chân tới Tiên Cương đại lục.","anchor":"Tiên Cương đại lục, Vương Lâm ta đã tới!","bridge":true,"khoang":"@c1705"},{"mucCt":"ky","text":"Nằm chết giả trên ngọn núi sụp, sinh khí tiêu tán hết, bị Khang Nhân (đệ tử Thương Long Tông) phát hiện. Khang Nhân ném ngọc giản uy lực Tịnh Niết nổ trên ngực thử nhưng thân thể hoàn toàn vô tổn. Bị lưới phong ấn bao trùm cả người lẫn Tị Thiên Quan, cuốn về động phủ Khang Nhân tại Thương Long Tông. Bị đưa vào trận luyện khôi lỗi, địa hỏa từ lòng đất không hại nổi mà ngược lại chui vào cơ thể như hưng phấn. Đúng lúc Khang Nhân dùng cạn tài liệu, hai mắt đột nhiên mở ra, ấn ký hình Văn Thú trên tay phải cũng mở bừng mắt lộ vẻ lạnh lùng tàn nhẫn.","anchor":"Đúng lúc này, hai mắt Vương Lâm đột nhiên mở ra!","bridge":true,"khoang":"@c1707"},{"mucCt":"ky","text":"Lần đầu mở mắt trên Tiên Cương đại lục, xem xét Tị Thiên Quan rồi cảm nhận khí tức. Hỏa bổn nguyên dung hợp với địa hỏa Tiên Cương, xảy ra lột xác chưa từng có — trận chiến quyết định ai làm chủ hỏa diễm thiên địa. Nhận ra Khang Nhân bố trí trận pháp luyện mình thành khôi lỗi, khinh thường trận pháp đó. Dùng thần thức thăm dò phát hiện cả dãy núi là phân chi của hệ thống địa hỏa khổng lồ giống hỏa trận. Vỗ tay xuống đất hút toàn bộ địa hỏa dãy núi đổ dồn vào động phủ, trận pháp nổ tung, chín khôi lỗi và hai khôi lỗi gỗ bị phá hủy, Thương Long Tông chấn động, lầu các tan thành mây khói. Phóng u quang bảo vệ Khang Nhân không chết.","anchor":"Hắn ở trong động phủ giới không ai dám nghĩ tới chuyện biến hắn thành khôi lỗi","bridge":true,"khoang":"@c1708"},{"mucCt":"ky","text":"Thức tỉnh trong động phủ Khang Nhân giữa địa hỏa, chỉ một tiếng quát kèm phất tay đánh bay Triệu trưởng lão Không Linh hậu kỳ hơn ngàn trượng, khiến nước mưa lơ lửng không rơi. Dùng thần thức quét ký ức Khang Nhân, nắm được tông chủ Thương Long Tông tu vi Không Huyền sơ kỳ, lão tổ Đỗ Thanh tu vi Không Kiếp sơ kỳ, cả hai đang xuất ngoại. Phát hiện Không Gian trữ vật không thể mở ra ở Tiên Cương đại lục, không lấy được Pháp Bảo lẫn Dĩ Ti khôi lỗi, đối phó tu sĩ Không Kiếp hơi bất lợi. Nhận thấy bổn nguyên ở Tiên Cương có biến hóa, cần làm quen. Quyết định rời đi nhưng bị toàn tông Thương Long Tông tổng lực ngăn cản bằng Đạo Hồn Thuật — cả vạn người đồng thanh tấn công hồn phách. Dùng Tâm Động Lôi Âm đối kháng, rồi ra tay định lấy hồn phách địa hỏa mạch.","anchor":"Lời nói mang theo quy tức, vạn vật bất động","bridge":true,"khoang":"@c1709"},{"mucCt":"ky","text":"Dùng Tâm Động Lôi Âm phản chế Đạo Hồn Thuật của mấy vạn đệ tử Thương Long Tông, nhịp tim hóa lôi đình dẫn động tâm tạng đối phương. Thi triển thuật rút hồn học từ động phủ giới, rút hồn phân mạch địa hỏa dưới dãy núi, triệu hoán hỏa long mấy vạn trượng phá sập toàn bộ ngọn núi chứa động phủ. Cưỡi hỏa long đè bẹp tứ đại trưởng lão — nam tử trung niên bị thiêu cháy hai tay, ba trưởng lão còn lại vỡ thân thể chỉ còn Nguyên Thần — không ai cản nổi nửa bước. Lưu lời lạnh lùng nói tai họa do Thương Long Tông muốn luyện hắn thành khôi lỗi, rồi cưỡi hỏa long bay đi. Phát hiện địa hỏa mạch Thiên Ngưu Châu kết cấu phức tạp giống trận pháp khổng lồ, phong ấn vật gì đó chưa rõ.","anchor":"Lực lượng một người, một tông phái không thể ngăn cản một bước","bridge":true,"khoang":"@c1710"},{"mucCt":"ky","text":"Bay đi trong Tiên Cương đại lục, phát hiện thần thức bị pháp tắc vô hình áp chế chỉ còn một nửa so với động phủ giới, súc địa thành thốn mất tác dụng vì thiên địa nơi đây là thật. Từ trí nhớ Khang Nhân, biết Thiên Ngưu Châu có Quy Nhất Tông và Đại Hồn Môn là hai tông phái tối cường. Than rằng tới chậm, sư tôn Thất Thải đạo nhân hẳn tưởng hắn đã chết sẽ không đợi. Xác định mục tiêu trước mắt: tới Đông Lâm Tông vào Đông Lâm Trì; mục tiêu dài hạn: tới Thất Đạo Tông tìm sư tôn, nếu không còn thì đi Đạo Cổ nhất mạch hoàn thành lời hứa. Sau nửa tháng di chuyển, lập thạch thất bế quan trong vùng núi trùng điệp, dùng cấm chế phong ấn khí tức. Thử mở Không Gian trữ vật — khe chứa vật hỗn tạp vừa hiện ra liền sụp đổ tiêu tán, xác nhận không thể dùng cách cũ ở Tiên Cương. Liệt kê pháp bảo cần lấy: Huyết Kiếm, kim ấn sư tôn, Côn Cực Tiên, Dĩ Ti khôi lỗi, tấm buồm mặt quỷ.","anchor":"Huyết Kiếm cần phải lấy ra. Còn có kim ấn được thần thông sư tôn cô đọng lại.","bridge":true,"khoang":"@c1711"},{"mucCt":"ky","text":"Trong một tháng ẩn nấp tại Thiên Ngưu Châu, hấp thụ tiên khí Tiên Cương nuôi dưỡng toàn thân, nghiên cứu sự khác biệt bổn nguyên giữa động phủ giới và Tiên Cương (hư bổn nguyên không đổi, thực bổn nguyên hỏa/lôi/thủy có chút khác biệt, sát lục và cấm chế bổn nguyên thay đổi ít). Quyết định mở Không Gian trữ vật cũ dù có nguy cơ sụp đổ: khuếch tán tu vi toàn thân khiến động phủ ngưng đọng như bùn lầy, dùng Định Thân Thuật ở tay trái dừng khe trữ vật, thần thức điên cuồng cuốn đồ ra. Lấy được Huyết Kiếm và kim ấn màu vàng nhưng người điên cùng nữ tử áo bạc bị cuốn vào khe biến mất, một số pháp bảo tan vỡ hoặc bị nuốt, ba pháp bảo chưa vỡ bị cuốn đi đã đóng dấu ấn thần thức để tìm lại sau, Dĩ Ti khôi lỗi vẫn còn bên trong. Tạo Không Gian trữ vật mới trên cổ tay phải theo phương pháp Tiên Cương đại lục (dùng huyết mạch cơ thể mở ra), thu Huyết Kiếm và kim ấn vào, luyện tập sử dụng thuần thục. Nghĩ tới Tham Lang, tin rằng Tham Lang đã ở Tiên Cương đại lục, đặt nghi vấn vì sao Tham Lang không cần chuyển thế như Thanh Thủy và Tư Đồ Nam mà có thể rời động phủ giới. Lo Đỗ Thanh tìm đến, tính phải thu xếp cẩn thận để trụ vững.","anchor":"Hắn trơ mắt nhìn Không Gian trữ vật nứt ra vô số khe, người điên cùng với nữ tử áo bạc ở cách những cái khe gần nhất, trực tiếp bị cuốn vào bên trong biển mất không thấy","bridge":true,"khoang":"@c1712"},{"mucCt":"ky","text":"Bế quan trong động phủ trên ngọn núi ở Thiên Ngưu Châu, đã tới Tiên Cương đại lục được một tháng. Luyện hỏa bổn nguyên, ngưng cố thành dấu ấn hình ngọn lửa ở mắt trái, phát hiện hỏa bổn nguyên không hòa hợp với địa hỏa bản địa, lực bài xích rất mạnh. Hồi tưởng ở Thương Long Tông đã cố ý thí nghiệm mức bài xích của địa hỏa — hỏa hồn rời Thương Long Tông liền cắn trả, bị trấn áp rồi dung nhập mặt đất biến mất. Quyết tâm trấn áp dung hợp địa hỏa, Nguyên Thần hóa Hỏa Chu Tước xâm nhập lòng đất, gặp hỏa long (hồn phách địa hỏa) dài mấy vạn trượng. Chủ động nhảy vào miệng hỏa long, từ bên trong hấp thụ và trấn áp hoàn toàn, trên mặt đất đất rung núi chuyển. Hỏa bổn nguyên lớn mạnh đáng kể. Tị Thiên Quan đã thu vào Không Gian trữ vật trong cơ thể.","anchor":"Thứ này đối với ta mà nói đúng là đại bổ hiếm thấy!","bridge":true,"khoang":"@c1713"},{"mucCt":"ky","text":"Xóa sạch cấm chế và đốt động phủ để phi tang rồi rời đi với tốc độ cực nhanh. Nhận ra Tiên Cương đại lục là bảo tàng cho mình vì thân phận ngoại lai từ động phủ giới không được hỏa nơi đây tán thành, chính sự bài xích cho phép hắn nghịch thiên cắn nuốt hồn phách địa hỏa mạch. Tìm thấy phân chi địa hỏa mạch thứ hai ở vùng sơn mạch xanh biếc, đánh một quyền nát đầu hỏa long ngàn trượng có lực lượng ngang tu sĩ Không Linh. Triệu Chu Tước từ mắt trái hút sạch hồn phách hỏa long, Chu Tước bành trướng tới mấy vạn trượng. Hỏa bổn nguyên lớn mạnh thêm, khoảng cách tới bổn nguyên chân thân kéo gần nhanh chóng. Hồi tưởng kịch biến Đông Lâm Trì nơi hắn từng thấy bổn nguyên chân thân xuất hiện khiến thần thông đánh ra hai lần chồng lên. Đạp Chu Tước mấy vạn trượng lao đi tìm địa hỏa mạch tiếp theo.","anchor":"Tiên Cương đại lục đối với ta chẳng những không phải là hiểm địa mà ngược lại còn là một bảo tàng!","bridge":true,"khoang":"@c1714"},{"mucCt":"ky","text":"Cưỡi Chu Tước huyền hóa bay khắp Thiên Ngưu Châu suốt hơn hai mươi ngày, liên tục cắn nuốt hồn phách địa hỏa mạch, từ hai phân chi ban đầu nâng lên tổng mười sáu long hồn, hỏa bổn nguyên vượt quá hai lần so với lúc ở động phủ giới. Sớm biết có Đỗ Thanh truy kích phía sau, phân tích đối phương là lão tổ Thương Long Tông dựa trên ký ức Khang Nhân nhưng không hoàn toàn tin tu vi đối phương đúng Không Kiếp sơ kỳ. Tại phía bắc Thiên Ngưu Châu gặp một mạch con (tử mạch) cường đại tương đương tu sĩ Không Huyền trung kỳ, quyết cắn nuốt, triệu mười sáu hỏa long bao quanh Chu Tước lao vào chiến đấu, tạo cảnh tượng quần long nhất tước thôn địa mạch.","anchor":"Mười sáu hồn của địa hỏa mạch, lấy tên Vương Lâm ta, hiện!","bridge":true,"khoang":"@c1715"},{"mucCt":"ky","text":"Điều khiển Chu Tước và mười sáu hỏa long quấn chặt long hồn địa hỏa mạch, đứng trên đầu hỏa long như đế vương hỏa diễm. Hỏa bổn nguyên tăng mạnh gấp mấy lần, một đạo bổn nguyên tương đương bảy đạo bổn nguyên lúc trong động phủ giới. Đánh ra chưởng ấn va chạm cánh tay gỗ khổng lồ của Đỗ Thanh, mượn toàn bộ lực phản kích của đối thủ truyền xuống hỏa long khiến nó bị thương nặng, đẩy nhanh quá trình cắn nuốt. Nhận định Đỗ Thanh chưa đạt Không Kiếp sơ kỳ, vẫn ở Huyền Kiếp, uy lực không sánh bằng Chiến lão quỷ hoặc Thất Thải đạo nhân. Đáp trả chất vấn rằng đệ tử Thương Long Tông dám đem hắn luyện chế thành khôi lỗi, hắn chỉ hủy sơn môn mà không giết người đã là lưu tay. Liên tiếp thi triển Dịch Linh Ấn (Thế Giới Tông), Thất Thải Thuật (Đông Lâm Tông), Phần Giới Cổ Tán (Tùng Vân Đạo) khiến Đỗ Thanh da đầu tê dại, sắc mặt tái nhợt, hỏi hắn rốt cục là ai.","anchor":"Một đạo bổn nguyên lại có thể tương đương với bảy đạo!","bridge":true,"khoang":"@c1716"},{"mucCt":"ky","text":"Vương Lâm đứng trên đầu long hồn hấp thu bổn nguyên địa hỏa, muốn dọa Đỗ Thanh tự lui nên hỏi có muốn giao thủ không. Khi Đỗ Thanh không lui, hắn lần lượt xuất Hô Phong Hoán Vũ, Tát Đậu Thành Binh, Sơn Băng Địa Liệt rồi thi triển Âm Nguyệt Hữu Tình — thức mở đầu Âm Nguyệt đại pháp thuộc Âm Nguyệt Tông, khiến Đỗ Thanh sụp đổ tinh thần khi nhận ra đây là đại tông thứ tư. Đỗ Thanh liều mạng triển khai ba đạo bổn nguyên, Vương Lâm bung bốn đạo pháp đứng đầu Tiên Cương (Thất Thải Thương, Dịch Linh Ấn, Phần Giới Cổ Tán, Âm Nguyệt Hữu Tình) nhưng bị ba đạo bổn nguyên đè sụp toàn bộ, hỏa long hồn sụp đổ thành hỏa cầu bao phủ hắn. Hắn không mở được Không Gian trữ vật nên không thể thả Dĩ Ti khôi lỗi. Từ trong hỏa cầu, hắn tuyên bố mình không chỉ có một đạo bổn nguyên, khiến Đỗ Thanh chấn động tâm thần.","anchor":"Ngươi cho rằng ta chỉ có một đạo bổn nguyên sao. Ngươi cho rằng ba đạo bổn nguyên của ngươi đã là nhiều sao.","bridge":true,"khoang":"@c1717"},{"mucCt":"ky","text":"Từ trong hỏa cầu hỏa long hồn (mang thân ảnh Chu Tước), Vương Lâm lần lượt triệu hoán bảy đạo bổn nguyên trước mặt Đỗ Thanh: hỏa (thực), lôi (thực, dẫn lôi biến hiện lôi đế chiến xa), sinh tử (hư), nhân quả (hư), chân giả (hư), sát lục (thực, từ mi tâm), cấm chế (thực, tơ máu từ đồng tử). Tổng bảy đạo bổn nguyên — bốn thực ba hư — chưa từng nghe nói ngay cả ở Đại Hồn Môn. Đỗ Thanh liên tục lùi bước, da đầu tê dại, nảy ý bỏ chạy. Vương Lâm phóng kim ấn Đại Thiên Tôn — kim quang vạn trượng, mang khí tức Đại Thiên Tôn — khiến Đỗ Thanh tự thương tâm thần phun máu, hoàn toàn bỏ ý truy sát. Bản thân Vương Lâm cũng ngẩn ra vì không ngờ kim ấn có sức chấn nhiếp lớn đến thế.","anchor":"hắn không ngờ kim ấn này lại có sức mạnh chấn động như vậy","bridge":true,"khoang":"@c1718"},{"mucCt":"ky","text":"Thu kim ấn mang khí tức Đại Thiên Tôn vào miệng, nói \"Không tiễn!\" đuổi Đỗ Thanh. Nhìn thấu tâm tư nịnh hót của Đỗ Thanh nhưng đồng ý cho hộ pháp vì mới tới Tiên Cương cần người bên cạnh và chiếm thế chủ động. Ba ngày hấp thụ hỏa bổn nguyên từ quả cầu lửa do tử mạch biến thành, mười sáu hỏa long dung hợp với quả cầu. Ngày thứ năm bước ra ngoài quả cầu, khoanh chân bấm quyết điều khiển Chu Tước bên trong co rút quả cầu từ mười trượng xuống còn một trượng. Đỗ Thanh nhận định Vương Lâm đang ngưng tụ chân thân bổn nguyên — thứ chỉ có trong truyền thuyết, cả đời hắn chỉ thấy trên lão tổ Đại Hồn Môn.","anchor":"tóc bạc tung bay, Vương Lâm đứng ở bên cạnh quả cầu lửa, khoanh chân ngồi xuống","bridge":true,"khoang":"@c1719"},{"mucCt":"ky","text":"Trong Thiên Ngưu Châu, liên tục bắt quyết đánh ấn ký vào hỏa cầu chứa Chu Tước, quát khẽ khiến hỏa cầu nổ tung, Chu Tước lông bốc cháy hóa hình người bắt đầu ngưng tụ chân thân. Hỏa bổn nguyên không đủ, liều mạng toàn lực chỉ ngưng tụ được hai chân. Lao xuống mặt đất nhấn chưởng triển khai thần thức phạm vi khổng lồ gần bằng động phủ giới, triệu hồi 172 long hồn phân mạch địa hỏa mạch lao vào hỏa cầu, Chu Tước hấp thu ngưng tụ thêm hai cánh tay — tứ chi hoàn thành nhưng còn thiếu thân và đầu. Tiếp tục triệu hồi long hồn hai mạch con, bản thân lao đón long hồn hải long dung nham, giao Đỗ Thanh kiềm chế long hồn kia trong nửa canh giờ.","anchor":"Một trăm bảy mươi hai địa hỏa mạch hồn, đi ra cho ta!","bridge":true,"khoang":"@c1720"},{"mucCt":"ky","text":"Rút Huyết Kiếm chém đứt hỏa long hồn dung nham làm đôi, ném nửa thân vào hỏa cầu. Thi triển kim ấn Đại Thiên Tôn phát kim quang vạn trượng truy bắt hỏa long hồn mạch con thứ hai giam bên trong. Điều khiển Đỗ Thanh đẩy long hồn cuối cùng vào hỏa cầu, bổn nguyên chân thân ngưng tụ hoàn chỉnh thân hình và tứ chi, chỉ còn đầu vẫn thuộc Chu Tước chưa chuyển hóa. Cảm thán 188 phân chi cộng ba mạch con vẫn chưa đủ, tài nguyên động phủ giới căn bản không thể hoàn thành chân thân. Mắt trái biến đổi hiện hai đồng tử thay vì ấn ký ngọn lửa, phía sau xuất hiện hư ảnh ảnh tùy tâm động rồi tự ẩn. Quyết định tới Thương Long Tông ở lại tu luyện. Khi Đỗ Thanh ngầm tăng tốc thăm dò, triệu Văn Vương ra cưỡi đi với tốc độ kinh người bỏ xa Đỗ Thanh.","anchor":"Một trăm tám mươi tám địa hỏa mạch phân chi, ba mạch con mà vẫn không thể hoàn toàn Sá ngưng tụ ra bôn nguyên chân thân","bridge":true,"khoang":"@c1721"},{"mucCt":"ky","text":"Cưỡi Văn Vương bay liên tục nửa tháng tới Thương Long Tông, được Đỗ Thanh nghênh đón làm thượng khách, dẫn vào động phủ hậu sơn. Hỏi Đỗ Thanh về vị trí địa hỏa chủ mạch Thiên Ngưu Châu, được biết chủ mạch nằm ở Đại Hồn Môn, lão tổ là Thanh Ngưu chân nhân có bổn nguyên chân thân. Ghi nhớ cái tên Thanh Ngưu chân nhân. Hỏi thăm về Phàn San Mộng (song kiêu Đại Hồn Môn) và Quy Nhất Tông. Nghe Đỗ Thanh kể lời Vân Dật Phong ca ngợi người tu đạo hơn hai ngàn năm, ánh mắt lóe sáng nhận ra là nói về mình, lập tức nói lảng sang chuyện lôi mạch.","anchor":"Vương Lâm nói lảng ra để tài khác.","bridge":true,"khoang":"@c1722"},{"mucCt":"ky","text":"Hỏi Đỗ Thanh về lôi mạch, biết trong phạm vi bốn châu không có lôi mạch, Đông Lâm Tông thuộc cửu tông thập tam môn ở Đại Thánh Châu. Suy tư kế hoạch ngưng tụ lôi bổn nguyên chân thân, cân nhắc nhờ Đại Hồn Môn hoặc Quy Nhất Tông rồi từ bỏ vì tính cách muốn tự lực. Thử thi triển súc địa thành thốn trên Tiên Cương đại lục nhưng bị áp lực pháp tắc thiên địa ngăn cản, chỉ thuấn di khoảng cách ngắn. Suốt bảy tháng bế quan tản thần thức, mục đích thật là thúc dục tâm thần liên kết với phân thân trong xác đá vùng hư vô. Ép Nguyên Thần khô héo tới cùng cực, cuối tháng thứ bảy phân thân trong xác đá bừng tỉnh mở mắt, gây chấn động khiến Đỗ Thanh sợ hãi kinh hãi.","anchor":"Chuẩn xác mà nói là hắn dùng phương pháp này thúc dục tâm thần tương liên với phân thân trong xác đá ở vùng hư vô","bridge":true,"khoang":"@c1723"},{"mucCt":"ky","text":"Sau bảy tháng tĩnh tọa, phân thân trong hư vô thức tỉnh truyền lại minh ngộ, phá vỡ phép tắc Tiên Cương ràng buộc, thần thức dung nhập thiên địa. Khôi phục thuật Súc Địa Thành Thốn, lần đầu thi triển tùy ý bước tới Thiên Sơn cực tây Thiên Ngưu Châu rồi quay về Thương Long Tông trong chưa hết một nén nhang, tuyết xanh Thiên Sơn dính chân là bằng chứng. Hấp thụ hỏa hồn do đệ tử Thương Long Tông thu được nhưng hỏa ý chí ít nên tác dụng hạn chế, nhận ngọc giản bản đồ tử mạch từ Đỗ Thanh rồi cáo từ. Dùng bảy ngày phá hủy các địa hỏa tử mạch khắp Thiên Ngưu Châu để ngưng tụ hỏa bổn nguyên chân thân, nhận ra phần đầu cần hỏa ý chí chứ không chỉ hỏa bổn nguyên đơn thuần. Ghé di chỉ Thất Đạo Tông, cảm nhận khí tức động phủ giới và Huyền La chờ đợi, nhớ Tư Đồ, Thanh Thủy, Lý Thiến Mai đã chuyển thế đầu thai không rõ ở đâu, bóng lưng hiu quạnh. Cuối cùng tới đỉnh Thiên Sơn dưới tuyết xanh, nhắm mục tiêu Đại Hồn Môn hấp thụ địa hỏa chủ mạch.","anchor":"hắn đã tìm lại được cảm giác của Súc Địa Thành Thốn bên trong động phủ giới","bridge":true,"khoang":"@c1724"}],"nhanMach":[{"ten":"Duẫn Đông Thân","tag":"khac","quanHe":"Phó tông chủ Quy Nhất Tông, từ chối cho Vương Lâm vào gặp Nạp Đa","ghiChu":"@c1634"},{"ten":"Duẫn Đông Thân","tag":"doi-thu","quanHe":"Trưởng lão Quy Nhất tông, từng đối thoại với Vương Lâm trước khi hắn tiến vào Ngũ Hành đại trận","ghiChu":"@c1635"},{"ten":"Thủy Tướng","tag":"doi-thu","quanHe":"Ngũ tiên Thủy Tướng của Quy Nhất tông, đối thủ trong thủy trận","ghiChu":"Bị Vương Lâm đánh bại nhưng nhờ áo giáp hồi phục"},{"ten":"Vân Dật Phong","tag":"doi-thu","quanHe":"Đối thủ ngang sức","ghiChu":"Giao chiến ngang tay tại Ngũ Hành tinh, từng gặp trong thiên kiếp ở viễn cổ tiên vực"},{"ten":"Tạ Đông Minh","tag":"khac","quanHe":"Cha của Tạ Thanh trong kiếp luân hồi cuối cùng — Vương Lâm chứng kiến cảnh hắn sinh con"},{"ten":"Tạ Thanh","tag":"su-mon","quanHe":"Đệ tử, đồng thời là hồn thứ ba của Thất Thải Tiên Tôn","ghiChu":"Xác nhận tại @c1652"},{"ten":"Vân Na","tag":"dong-minh","quanHe":"Nữ Cổ Thần nhận Vương Lâm là chủ nhân mới của Đông Lâm tông, đề nghị dung hợp tâm thần huyết Diệp Mịch","gap":"@c1671"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Đối thủ chuyển thành thuộc hạ qua thệ huyết","ghiChu":"Thua trận đường đường chính chính, thề nghe lệnh Vương Lâm trong vùng trung tâm động phủ"},{"ten":"Tạ Thanh","tag":"ban-be","quanHe":"Tri kỷ, hồn phách ẩn trong thân Vương Lâm","ghiChu":"Vương Lâm từ chối dung hợp hoàn toàn hồn thứ ba để bảo vệ Tạ Thanh"},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh trong ký ức Đông Lâm Tông, khinh thị Tô Đạo","ghiChu":"Bị Vương Lâm dùng sát khí chấn nhiếp, thua trong cuộc tranh tư cách học Vân Đạo Thiên Thuật"},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn trong ký ức Đông Lâm Tông","ghiChu":"Truyền tư cách học Vân Đạo Thiên Thuật cho Vương Lâm (thân phận Tô Đạo)"},{"ten":"Tần Mai","tag":"khac","quanHe":"Đồng môn trong ký ức hồn thứ ba, từng có tình ý với Tô Đạo","ghiChu":"@c1687"},{"ten":"Côn Bằng","tag":"doi-thu","quanHe":"Thiên tài Đông Lâm Tông trong ký ức, bị Vương Lâm đánh bại","ghiChu":"@c1688"},{"ten":"Huyền La Đại Thiên Tôn","tag":"doi-thu","quanHe":"Kẻ bí ẩn bám theo Vương Lâm suốt hành trình từ Ngũ Hành Tinh tới Tiên Giới, bị Vương Lâm gọi đích danh lộ diện","ghiChu":"@c1691"},{"ten":"Huyền La Đại Thiên Tôn","tag":"su-mon","quanHe":"Được mời làm đệ tử duy nhất","ghiChu":"Huyền La là Đại Thiên Tôn Đạo Cổ nhất mạch, một trong Cửu Dương. Vương Lâm mang ân."},{"ten":"Huyền La","tag":"an-nhan","quanHe":"Đại Thiên Tôn đối kháng pháp tắc Tiên Cương giúp mọi người rời đi","ghiChu":"Vương Lâm vái sâu cảm tạ, được Huyền La đánh giá có nhân-nghĩa-tình và chọn bảo vệ Đạo Cổ nhất mạch"},{"ten":"Lý Thiến Mai","tag":"the-thiep","quanHe":"Người yêu, hẹn ước tìm lại trên Tiên Cương đại lục","ghiChu":"Nắm tay nàng hứa sẽ giải khai ký ức bị che phủ @c1694"},{"ten":"Lão tổ Thương Viên Tộc","tag":"doi-thu","quanHe":"Toàn năng bước thứ ba bị Vương Lâm phong ấn bắt đi đầu thai","ghiChu":"@c1698"},{"ten":"Huyền La","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Chính thức bái sư trên con đường mình rồng, Huyền La muốn truyền y bát Đạo Cổ nhất mạch"},{"ten":"Khang Nhân","tag":"doi-thu","quanHe":"Đệ tử Thương Long Tông, người mang Vương Lâm về luyện khôi lỗi","ghiChu":"Khang Nhân phát hiện Vương Lâm chết giả, toan luyện thành khôi lỗi"},{"ten":"Triệu trưởng lão","tag":"doi-thu","quanHe":"Trưởng lão Thương Long Tông xâm nhập động phủ, bị Vương Lâm quát đánh bay trọng thương","gap":"@c1709"},{"ten":"Đỗ Thanh","tag":"doi-thu","quanHe":"Lão tổ Thương Long Tông Không Kiếp sơ kỳ, Vương Lâm biết qua ký ức Khang Nhân, là mối đe dọa tiềm tàng","gap":"@c1709"},{"ten":"Đỗ Thanh","tag":"dong-hanh","quanHe":"Đỗ Thanh lập thệ phù xin hộ pháp, Vương Lâm đồng ý cho theo bên cạnh","ghiChu":"@c1719"},{"ten":"Thanh Ngưu chân nhân","tag":"doi-thu","quanHe":"Lão tổ Đại Hồn Môn, nắm giữ địa hỏa chủ mạch mà Vương Lâm cần tìm","ghiChu":"@c1722"}],"tuViMoc":[{"chuong":"@c1640","canhGioi":"Thủy bổn nguyên (mầm mống — bổn nguyên thứ tám)","text":"Nhờ hấp thu Càn Khôn Nhất Tích, Vương Lâm có được mầm mống thủy bổn nguyên, là thực bổn nguyên thứ tám, cần dung hợp nhiều lần mới đại thành.","importance":"major"},{"chuong":"@c1680","canhGioi":"Đạo Cổ tám tinh điểm (sắp chín)","text":"Sau khi nhận truyền thừa trái tim Diệp Mịch, Đạo Cổ khí tức tràn vào cơ thể, tám tinh điểm trên mi tâm xoay tròn, xuất hiện dấu hiệu hình thành tinh điểm thứ chín.","importance":"minor"},{"chuong":"@c1682","canhGioi":"Ngân Mục (đệ nhất tượng cửu khúc tam tượng)","text":"Hai mắt biến thành ngân mục (mắt bạc) sau truyền thừa Diệp Mịch kết hợp hồn huyết cổ Tổ, đạt đệ nhất tượng trong cửu khúc tam tượng — lưỡng khúc ngân mục kim thân. Ngay Diệp Mịch cũng không có được ngân mục này. Thuộc hệ cổ Tộc, không phải tu vi chính.","importance":"major"},{"chuong":"@c1689","canhGioi":"Không Linh đỉnh (hư ảo)","text":"Tám đạo bổn nguyên ngưng tụ chân thân trong Đông Lâm Trì (thế giới ký ức), tu vi đột phá từ Không Linh hậu kỳ lên Không Linh đỉnh. Tu vi này là hư ảo, sẽ tiêu tán khi rời ký ức, nhưng trải nghiệm thật.","importance":"major"},{"chuong":"@c1697","canhGioi":"Đỉnh Không Linh","text":"Tu vi sau khi trải qua ngũ hoa bát môn trong trung tâm động phủ đạt tới đỉnh Không Linh, truyền thừa Đạo Cổ gần viên mãn, phối hợp bảy bổn nguyên chiến lực ngang Không Huyền Hậu Kỳ.","importance":"major"},{"chuong":"@c1697","canhGioi":"Không Linh đỉnh phong","text":"Tu vi sau khi trải qua ngũ hoa bát môn trong trung tâm động phủ đã đạt đỉnh Không Linh, truyền thừa Đạo Cổ gần viên mãn, phối hợp bảy bổn nguyên cùng thần thông Đạo Cổ, chiến lực ngang Không Huyền Hậu Kỳ.","importance":"minor"}],"diem":[{"text":"Phàm nhân tư chất kém, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, chính thức bước vào con đường tu tiên","chuong":"@c0023"},{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể xuyên Vực Ngoại, tái sinh từ tuyệt cảnh","chuong":"@c0103"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, nền tảng cho toàn bộ con đường thể tu sau này","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một, đạt tam tinh Cổ Thần, xác lập hình thái chiến đấu hoàn chỉnh","chuong":"@c0365"},{"text":"Chính thức thành Đại Thiên Tôn, Đại Thiên Tôn Chi Dương ba màu thực chất hóa trọn vẹn, mười mặt trời hiện trên Tiên Cương","chuong":"@c1939"},{"text":"Diệt Thiên Vận Tử, hồi sinh Lý Mộ Uyển, thu La Bàn Định Giới, đạt cảnh giới Đạp Thiên — hoàn tất hành trình nghịch thiên","chuong":"@c1976"}]},"nguon":["@c1633","@c1634","@c1635","@c1636","@c1637","@c1638","@c1639","@c1640","@c1641","@c1642","@c1643","@c1644","@c1645","@c1646","@c1647","@c1648","@c1649","@c1650","@c1651","@c1652","@c1653","@c1654","@c1655","@c1656","@c1657","@c1658","@c1659","@c1660","@c1661","@c1662","@c1663","@c1664","@c1665","@c1666","@c1667","@c1668","@c1669","@c1670","@c1671","@c1672","@c1673","@c1674","@c1675","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1682","@c1683","@c1684","@c1685","@c1686","@c1687","@c1688","@c1689","@c1690","@c1691","@c1692","@c1693","@c1694","@c1695","@c1696","@c1697","@c1698","@c1699","@c1700","@c1701","@c1702","@c1703","@c1704","@c1705","@c1707","@c1708","@c1709","@c1710","@c1711","@c1712","@c1713","@c1714","@c1715","@c1716","@c1717","@c1718","@c1719","@c1720","@c1721","@c1722","@c1723","@c1724"],"canhGioiCaoNhat":"Thái Sơ cảnh (Tiên Cương)","trangThai":"song","cn":"王林","gioiTinh":"nam","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","aliases":["Vương mỗ"],"vaiTro":"Nhân vật chính — phàm nhân nghịch thiên, Đại Thiên Tôn tam cổ cửu tinh đệ nhất cường giả Tiên Cương","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Sau khi được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh và ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, hắn đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối, vượt Tam Tổn Kiếp tại Tổ Miếu Thủy Cổ, chính thức thành Đại Thiên Tôn, dung "},{"id":"thanh-long","name":"Thanh Long","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Liên thủ thất bại, kinh hãi nhận ra thiên đạo","text":"Tấn công Vương Lâm bằng hư ảnh Thanh Long vạn trượng nhưng bị Khai Thiên Phủ chém tan. Liên thủ cùng ba chiến tướng khác vẫn thất bại. Gầm lên đe dọa sẽ giết sạch tiên giới của Vương Lâm. Run rẩy nhận ra sương mù thiên đạo — thứ năm xưa đã cắn nuốt Liên Đạo Phi.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Kiêng kị Vương Lâm","text":"Từ biển lửa xông ra, nhìn cảnh bảy màu và Chiến lão quỷ chật vật, ánh mắt lộ vẻ kiêng kị chưa từng có đối với Vương Lâm.","anchor":"Thanh Long chiến tướng hít sâu ánh mắt nhìn về phía Vương Lâm lộ ra một vẻ kiêng kị chưa từng có"},{"chuong":"@c1670","importance":"normal","mucCt":"gon","tieuDe":"Tử vong trong vụ nổ hủy diệt","text":"Ở gần trung tâm vụ nổ chín mặt trời va tiễn thứ ba, bị sức mạnh hủy diệt chạm phải, toàn thân tan vỡ, trực tiếp tử vong.","anchor":"Thanh Long chiến tướng ở hơi gần một chút liền bị sức mạnh này chạm phải, lập tức toàn thân ầm ầm tan vỡ, trực tiếp tử vong"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Xưng Thánh Hoàng, chỉnh hợp Tứ Thánh Tông thành một tông và thu thái cổ thánh khí","chuong":"@c1054"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông uy hiếp, bị Thác Sâm trọng thương","chuong":"@c147"},{"text":"Dung hợp hư ảnh Thanh Long đánh lén Vương Lâm thất bại, bị Cổ Tộc Bất Diệt chỉ bức lùi","chuong":"@c1549"},{"text":"Liên thủ cùng ba chiến tướng vẫn bị Khai Thiên Phủ chém tan, kinh hãi nhận ra thiên đạo","chuong":"@c1633"},{"text":"Tử vong trong vụ nổ hủy diệt chín mặt trời va tiễn thứ ba","chuong":"@c1670"}]},"nguon":["@c1633","@c1667","@c1668","@c1670"],"trangThai":"tu-vong","vaiTro":"Tứ đại chiến tướng Viễn cổ Tinh Vực — danh vị Thanh Long trong Tứ Thánh","tinhCach":"hành sự quỷ quyệt, thiên về đánh lén; phân tích chiến cục lạnh lùng, thấu đáo; thận trọng, kiêng kị trước hiểm nguy chưa lường được","blurb":"Thanh Long là một trong Tứ Thánh, thuộc hàng tứ đại chiến tướng từng bị phong ấn tại Viễn cổ Tinh Vực, sau khi thoát phong ấn đã xưng Thánh Hoàng và chỉnh hợp Tứ Thánh Tông thành một tông phái duy nhất. Nhiều lần giao chiến với Vương Lâm — từ đánh lén bằng hư ảnh Thanh Long bất thành đến liên thủ cùng ba chiến tướng khác vẫn thất bại trước Khai Thiên Phủ — và cuối cùng tử vong trong vụ nổ hủy diệt của chín mặt trời va tiễn thứ ba."},{"id":"huyen-vu","name":"Huyền Vũ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Cảm nhận thiên đạo, coi Vương Lâm là chúa tể kinh khủng nhất","text":"Liên thủ tấn công Vương Lâm, triệu hồi hư ảnh Huyền Vũ tràn ngập sóng biển nhưng thất bại. Cảm nhận lực thôn phệ thiên đạo bao phủ toàn thân, trong mắt hắn Vương Lâm đã hóa thành chúa tể kinh khủng nhất.","anchor":"Trong mắt hắn Vương Lâm đã hóa thân thành chúa tể kinh khủng nhất!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Sợ hãi hối hận","text":"Sắc mặt tái nhợt, nghĩ tới thiên đạo của Vương Lâm nổi lên sợ hãi, hối hận đáng lẽ không nên tới nơi này.","anchor":"hắn nghĩ tới thiên đạo của Vương Lâm, trong lòng nổi lên sự sợ hãi, thậm chí hắn còn có chút hối hận, đáng lẽ mình không nên tới nơi này!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Bị gợn sóng cung Lý Quảng đánh trúng","text":"Cùng hai chiến tướng khác bị gợn sóng cung Lý Quảng đánh trúng, đồng loạt phun máu, hoảng sợ lui ra tinh không.","anchor":"tam đại chiến tướng kia ánh mắt lộ ra vẻ hoảng sợ, bọn họ cũng đã từng chứng kiến uy lực của mũi tên này"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Hoảng sợ điên cuồng bỏ chạy khi vụ nổ hủy diệt lan ra, khiếp sợ khi thấy Liên Đạo Phi xuất hiện.","anchor":"hai người Huyền Vũ cùng với Chu Tước đang bỏ chạy kia cũng xoay mạnh người"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Giao chiến với tu sĩ trung niên từ Ngũ Hành tinh, khó phân thắng bại.","anchor":"Huyền Vũ chiến tướng. Chu Tước chiến tướng bất ngờ cũng ở trong đó"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Bị Tâm Động Lôi Âm dẫn động trái tim, bị Vương Lâm đánh bay","text":"Theo lệnh Chiến lão quỷ lao vào tầng cuối giết Vương Lâm, nhanh hơn Chu Tước ba trượng. Khi tới gần bị tiếng tim đập ầm ầm dẫn động trái tim đau đớn như bị bóp nát, rồi bị bàn tay đen kịt của Vương Lâm đặt lên ngực đánh bay, phun máu.","anchor":"đôi tai hắn ầm vang, trái tim đau đớn như bị một bàn tay bóp lấy"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Tạ lỗi Vương Lâm — tặng ngọc giản rồi rời đi","text":"Hồi tưởng Thất Đạo Tông và Thất Thải Tiên Tôn, tạ lỗi với Vương Lâm, đưa một ngọc giản rồi cùng Chu Tước và Bạch Hổ bay vào kim môn rời đi.","anchor":"Vương đạo hữu, chuyện trước kia. ôi"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1667","@c1668","@c1669","@c1670","@c1681","@c1682","@c1691"],"trangThai":"song","aliases":["Huyền Vũ chiến tướng","Huyền Vũ"],"tinhCach":[],"gioiTinh":"nam"},{"id":"chu-tuoc","name":"Chu Tước","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"bridge","mucCt":"gon","text":"Liên thủ tấn công Vương Lâm bằng hư ảnh Chu Tước nhưng thất bại, đứng sững sợ hãi khi nhận ra thiên đạo.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Khiếp sợ trước phục sát","text":"Tâm tư phức tạp nhất trong tam đại chiến tướng, rất khó đè nén sự khiếp sợ trong lòng trước cảnh tượng Vương Lâm bày bố phục sát.","anchor":"Chu Tước chiến tướng có tâm tư phức tạp nhất, lúc này nhìn cảnh tượng trước mắt rất khó đè nén sự khiếp sợ trong lòng"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Cùng Huyền Vũ điên cuồng bỏ chạy, ánh mắt khiếp sợ khi thấy Liên Đạo Phi.","anchor":"hai người Huyền Vũ cùng với Chu Tước đang bỏ chạy kia cũng xoay mạnh người"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bất ngờ xuất hiện, cùng Huyền Vũ chiến tướng giao chiến hai tu sĩ trung niên Ngũ Hành tinh.","anchor":"Chu Tước chiến tướng bất ngờ cũng ở trong đó"},{"chuong":"@c1682","importance":"normal","mucCt":"ky","tieuDe":"Bị ác quỷ Dĩ Ti hút máu héo rũ","text":"Theo lệnh Chiến lão quỷ xâm nhập tầng cuối, cũng bị ảnh hưởng tiếng tim đập vội lui lại. Bị ác quỷ Dĩ Ti từ tầng cuối lao ra đụng trúng, ôm cổ cắn hút máu khiến thân thể nhanh chóng héo rũ, rồi bị đạp nện xuống đất.","anchor":"mang theo nụ cười nanh ác, cắn lên cổ Chu Tước chiến tướng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Cùng Huyền Vũ rời động phủ giới","text":"Cùng Huyền Vũ trầm mặc hồi tưởng Thất Đạo Tông rồi bay vào kim môn rời đi.","anchor":"nhớ cảnh tượng tứ đại chiến tướng bọn họ và Thất Thải Tiên Tôn quen biết"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1667","@c1668","@c1670","@c1681","@c1682","@c1691"],"trangThai":"song","aliases":["Chu Tước chiến tướng","Chu Tước"],"tinhCach":[],"gioiTinh":"nam"},{"id":"bach-ho","name":"Bạch Hổ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"bridge","mucCt":"gon","text":"Liên thủ tấn công Vương Lâm bằng hư ảnh Bạch Hổ nhưng thất bại, đứng sững sợ hãi khi nhận ra thiên đạo.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"normal","mucCt":"ky","chuong":"@c1661","tieuDe":"Thiết lập quy tắc tàn giới, đề nghị đánh cuộc","text":"Là người đầu tiên bước vào tàn giới này nên đã thiết lập toàn bộ quy tắc. Đang lợi dụng cuộc đại chiến trăm vạn quân trên tu chân tinh thứ ba để hấp thu sát khí. Xuất hiện dưới dạng hư ảo trên bầu trời, có sợi dây nối vô hình với viên đại tướng áo giáp trắng cưỡi bạch mã phía dưới. Tự tin chỉ có đạo nhân bảy màu hoặc Chiến lão quỷ mới thoát khỏi quy tắc. Chủ động đề nghị Vương Lâm đánh cuộc: bại thì mất hồn thứ ba, thắng thì Bạch Hổ lấy huyết mạch thề theo lời thề Tiên Cương đại lục cam tâm làm nô bộc vạn năm.","anchor":"Ngươi nếu thắng thì lão phu sẽ dùng lời thề của Tiên Cương đại lục, cam tâm nghe lệnh ngươi, làm nô bộc cho ngươi vạn năm!"},{"mucCt":"ky","text":"Bạch Hổ định ra quy tắc bàn cờ trên tu chân tinh thứ ba, tự tin lợi thế huyết mạch tiên nhân sẽ áp đảo. Khi Vương Lâm tiến vào và bộc lộ huyết mạch Đạo Cổ truyền thừa, Bạch Hổ chấn động vì không ngờ đối phương cũng có lực lượng huyết mạch. Thần thức biến thành tướng lãnh mặc bạch giáp cưỡi bạch mã, phái mười hắc giáp binh tấn công Vương Lâm nhưng đều bị giết sạch trong nửa nén hương. Buộc phải lui lại kéo giãn khoảng cách.","anchor":"Hắn không ngờ lại có lực lượng huyết mạch! Không thể nào.","bridge":true,"khoang":"@c1662"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Tử chiến chặn đại quân Liên Minh, giết nhiều trưởng lão chủ chốt trong đại chiến năm xưa","chuong":"@c0976"},{"text":"Bị phong ấn trong mi tâm pho tượng Cổ Thần tại Viễn cổ Tinh Vực cùng ba chiến tướng khác","chuong":"@c1458"},{"text":"Là người đầu tiên bước vào tàn giới, thiết lập toàn bộ quy tắc tại đó","chuong":"@c1661"},{"text":"Bại trận trước Vương Lâm trong giới cờ, bị uy áp trấn phục vàràng buộc nhận lệnh","chuong":"@c1663"},{"text":"Trọng thương vẫn cõng Chu Tước và Huyền Vũ bỏ chạy, từ chối đầu hàng khi bị truy sát tại Đan Hải","chuong":"@c1749"},{"text":"Được Vương Lâm cứu khỏi hai tu sĩ Lục Ma Châu và cùng hộ pháp phá cấm chế Đan Hải","chuong":"@c1750"}]},"nguon":["@c1633","@c1661","@c1662"],"vaiTro":"Một trong Tứ Thánh Tông — chiến tướng bị phong ấn tại Viễn cổ Tinh Vực, sau theo Vương Lâm","tinhCach":"trực tính, hay trào phúng khi chất vấn; dễ chấn động trước sự kiện bất ngờ; tự tin vào lợi thế huyết mạch tiên nhân; kiên cường, không chịu đầu hàng dù trọng thương","blurb":"Bạch Hổ là một trong bốn chiến tướng thuộc Tứ Thánh Tông, từng tử chiến chặn đại quân Liên Minh trong đại chiến năm xưa. Hắn bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực, sau khi thoát ra đã giao chiến rồi quy phục Vương Lâm, trở thành người thiết lập toàn bộ quy tắc tại tàn giới nhưng cuối cùng bại trận trong giới cờ và bị ràng buộc nhận lệnh. Về sau hắn cùng Chu Tước và Huyền Vũ nhiều lần đồng hành, từng bị truy sát tại Đan Hải và được Vương Lâm cứu giúp."},{"id":"chien-lao-quy","name":"Chiến lão quỷ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"ky","tieuDe":"Thất Thải Tiên Tôn chiếm quyền thân thể, kiêng kỵ thiên đạo","text":"Đứng xa quan sát, sững lại khi u Minh thú mở miệng phóng sương mù thiên đạo. Hồn phách Thất Thải Tiên Tôn trong thân gào thét rồi chiếm quyền kiểm soát thân thể, tỏa ra khí tức riêng. Thất Thải Tiên Tôn kiêng kỵ vì nơi này là động phủ giới — nắm thiên đạo nghĩa là nắm mọi thứ, nhưng nhận định thiên đạo cắn nuốt có cực hạn và tự tin có thủ đoạn chống đỡ. Hỏi Vương Lâm có tìm được hồn thứ ba chưa.","anchor":"Thứ ta định đoạt lấy không ngờ là thiên đạo"},{"importance":"normal","mucCt":"vua","chuong":"@c1649","tieuDe":"Nhận định hồn thứ ba ở La Thiên","text":"Đi theo phía sau tứ đại chiến tướng, bảo trì cân bằng. Nhận định hồn thứ ba có lẽ đang ở La Thiên, nơi hắn ở lâu nhất, không rõ hồn thứ ba là người hay thú.","anchor":"Xem ra có lẽ hồn thứ ba đang ở La Thiên rồi. Thời gian ta ở La Thiên là dài nhất"},{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ tiên duyên với hồn thứ hai Thất Thải Tiên Tôn","text":"Được hé lộ tiên duyên: khi độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát, rơi lên tu chân tinh, gặp con mãnh thú có đôi mắt kỳ dị — chính là hồn thứ hai của Thất Thải Tiên Tôn luân hồi.","anchor":"Hắn độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Đi phía sau tứ đại chiến tướng trong La Thiên Tinh Vực, đôi mắt bừng sáng, nắm rõ thần sắc Vụ thú.","anchor":"Chiến lão quỷ đi phía sau tứ đại chiến tướng, lúc này đôi mắt bừng sáng"},{"importance":"normal","mucCt":"ky","chuong":"@c1655","tieuDe":"Lộ hư ảnh tam hồn Thất Thải Tiên Tôn","text":"Tốc độ nhanh hơn tứ đại chiến tướng, vượt qua bọn họ lao về phía trung tâm động phủ. Thần sắc âm trầm ẩn sợ hãi, biết nếu đạo nhân bảy màu tìm được hồn thứ ba trước thì hắn sẽ bị cắn nuốt tử vong. Bên ngoài thân hắn bất ngờ hiện ra hư ảnh khổng lồ — một trong tam hồn của Thất Thải Tiên Tôn: sương mù làm áo choàng, đôi mắt âm u, tóc bạc phất phơ, che phủ cả mảng tinh không. Quyết nếu đạo nhân bảy màu đạt được hồn thứ ba thì sẽ thừa lúc đối phương tiêu hóa mà liều chết phản kích.","anchor":"Hư ảnh bên ngoài thân thể Chiến lão quỷ chính là một trong tam hồn của Thất Thải Tiên Tôn"},{"mucCt":"vua","text":"Xuất hiện trong tinh không trước đại môn, tóc bạc trắng, hư ảnh áo choàng bao phủ, thở phào vì hồn thứ ba ở Vương Lâm chứ không phải đạo nhân bảy màu. Bị cơn lốc từ đại môn đẩy lui, truyền âm chiêu dụ Vương Lâm: cam đoan an toàn cho tiên giới, hứa mở cánh cửa thông Tiên Cương đại lục, chỉ cần giao hồn thứ ba.","anchor":"ngươi đưa hồn thứ ba cho ta, lão phu cam đoan ngươi và cả tiên giới an toàn","bridge":true,"khoang":"@c1656"},{"mucCt":"vua","text":"Hư ảnh trên người nhìn chằm chằm bóng lưng Vương Lâm biến mất, hàn quang lóe lên. Tuyệt đối không cho phép đạo nhân bảy màu đoạt được hồn thứ ba, theo sát ngay sau tiến vào đại môn.","anchor":"Hắn tuyệt đối không cho phép đạo nhân bảy màu đoạt được hồn thứ ba","bridge":true,"khoang":"@c1657"},{"chuong":"@c1658","importance":"bridge","mucCt":"gon","text":"Theo sau đạo nhân bảy màu dung nhập vào đại đỉnh, khuôn mặt hiện trên sườn đỉnh trông dữ tợn.","anchor":"Sau đó Chiến lão quỷ cũng cất bước, dung nhập vào trong đại đỉnh"},{"chuong":"@c1665","importance":"bridge","mucCt":"gon","text":"Xuất hiện nửa ngày sau tại vị trí dòng xoáy biến mất, thân thể không chút khí tức giống người chết, truy kích theo hướng sai rồi rời đi, bị kế Vương Lâm đánh lừa hoàn toàn.","anchor":"Chiến lão quỷ xuất hiện ở nơi mà dòng xoáy biến mất, thân thể không chút khí tức, giống hệt người chết"},{"mucCt":"vua","text":"Đang theo dõi một đám tu sĩ, khi ngọc giản vỡ liền dừng lại, sắc mặt âm trầm sát khí tỏa ra, quay đầu tới tu chân tinh. Không thể cưỡng lại hồn thứ ba, gần như đồng thời với đạo nhân bảy màu tiến vào tinh cầu, bị Phần Giới Cổ Tán nhốt bên trong.","anchor":"Chiến lão quỷ kia cũng khó có thể nhịn được, gần như cùng với đạo nhân bảy màu đồng thời tiến vào tinh cầu này","bridge":true,"khoang":"@c1667"},{"mucCt":"vua","text":"Thoát biển lửa sau đạo nhân bảy màu, ánh mắt tham lam lao tới hồn thứ ba của Vương Lâm. Bị đệ tứ phục Quỷ Kiếm Huyết Phàm nuốt lấy, lập tức mê man khoanh chân ngồi không cử động.","anchor":"Chiến lão quỷ kia thân thể đột nhiên dừng lại, trong mắt lập tức hiện lên vẻ mê man","bridge":true,"khoang":"@c1668"},{"chuong":"@c1670","importance":"bridge","mucCt":"vua","tieuDe":"Quan sát từ sương mù mặt quỷ","text":"Ở trong sương mù mặt quỷ, mở mắt quan sát toàn bộ diễn biến nhưng không ra tay, không rõ ý đồ.","anchor":"Chiến lão quỷ đang bị vây trong đám sương mù mặt quỷ đã sớm mở hai mắt"},{"mucCt":"vua","text":"Bước ra khỏi sương mù mặt quỷ, do dự giữa đuổi giết Vương Lâm và truy kích đạo nhân bảy màu bị trọng thương. Vì e dè cung Lý Quảng và tính cẩn thận nên không đánh cuộc, cuối cùng chọn truy kích đạo nhân bảy màu để dung hồn.","anchor":"do tính cách cẩn thận nên hắn không muốn đánh cuộc","bridge":true,"khoang":"@c1671"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Khuôn mặt của hắn là một trong hai khuôn mặt cực rõ nét còn lại trên cây đinh bảy màu, tỏa hắc quang hấp dẫn hắc khí.","anchor":"Chiến lão quỷ.người này tính tình đa nghi, đặt bẫy hắn rất khó khăn"},{"importance":"normal","mucCt":"ky","chuong":"@c1680","tieuDe":"Tu vi gần đạt mức Thất Thải Tiên Tôn","text":"Đuổi tới vùng đất cổ mộ tầng hai, thần thức cực cường quét ngang. Thân phát ánh sáng bảy màu do đã cắn nuốt đạo nhân bảy màu, hai hồn chưa dung hợp nhưng mang lại lợi ích lớn, tu vi gần đạt mức Thất Thải Tiên Tôn năm xưa. Bị Lam Mộng Đạo Tôn, Đồ Ti, Vân Dật Phong và Đường San hợp lực chặn lại.","anchor":"Bản thân Chiến lão quỷ là hạng người tu vi cao thâm, sau khi dung hợp lại cắn nuốt đạo nhân bảy màu, lúc này đã đạt tới rất gần Thất Thải Tiên Tôn năm đó!"},{"importance":"normal","mucCt":"ky","chuong":"@c1681","tieuDe":"Tách hồn phách Thất Thải Tiên Tôn khỏi thân","text":"Giao chiến với Lam Mộng Đạo Tôn và lão già họ Mã ở tầng thứ hai. Muốn đột phá xuống tầng cuối cùng giết Vương Lâm đoạt hồn thứ ba nhưng bị ngăn cản. Phất tay khiến Vân Dật Phong suýt chết, dùng chữ Chiến trên mi tâm phá vỡ lam quang. Bị phong tỏa bởi tiếng đàn cổ cầm và đại thần thông ngũ hành, vỗ mi tâm tách hồn phách Thất Thải Tiên Tôn ra khỏi thân thể chống cự — hư ảnh mặc áo choàng, hai tay gập chữ thập va chạm hai bàn tay khổng lồ.","anchor":"Một chữ Chiến từ trên mi tâm Chiến lão quỷ nhanh chóng bành trướng ra ngoài"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Khôi phục bá đạo, đối đầu Vương Lâm bị Tâm Động Lôi Âm áp chế","text":"Hồn phách Thất Thải Tiên Tôn phân ly khỏi thân, Chiến lão quỷ khôi phục bá đạo năm xưa, dùng hai chữ Chiến đánh trọng thương hai nam tử Ngũ Hành tinh. Ra lệnh Huyền Vũ và Chu Tước vào tầng cuối giết Vương Lâm. Sau đó dung hợp lại với hồn phách Thất Thải Tiên Tôn lao về phía Vương Lâm, nhưng bị thần thông tiếng tim đập dẫn động trái tim đau đớn, phải đặt tay lên ngực áp chế.","anchor":"Sắc mặt Chiến lão quỷ biến đổi, tay phải giơ lên đặt vào ngực, cố gắng áp chế không cho trái tim đập mạnh"},{"mucCt":"ky","text":"Giao chiến với Vương Lâm, bị Tâm Động Lôi Âm khống chế tim suýt vỡ, phải tự nhấn ngực chặn nhịp đập. Viết bảy chữ Chiến đón quyền Đạo cổ, sáu chữ vỡ nhưng chữ cuối nổ gây thương tích cho Vương Lâm. Bị Thần Chấn làm thiên địa xoay, sợ hãi cắn lưỡi phun máu nuốt quỷ Dĩ Ti. Bị Ma Đạo biến sức sống thành tử khí. Cuối cùng bị Đạo Cổ Vô Tiên hóa đá cùng hai hồn Thất Thải Tiên Tôn, nhưng phá vỡ đá thoát ra, hai hồn bị cưỡng ép dung nhập trở lại vào thân thể, phun máu hoảng sợ bỏ chạy. Nỗi sợ hãi giống như khi nhìn thấy cung Lý Quảng.","anchor":"Hắn sợ, cũng giống như lúc nhìn thấy cây cung Lý Quảng của Vương Lâm, sự sợ hãi tràn ngập tâm thần","bridge":true,"khoang":"@c1683"},{"importance":"bridge","mucCt":"gon","chuong":"@c1689","text":"Cố phá hạn chế xâm nhập thế giới đệ ngũ hoa, khi thế giới ký ức sụp đổ liền lao tới nhưng không đuổi kịp Vương Lâm.","anchor":"Chiến lão quỷ giống như đang nối giận, nhanh chóng phóng tới"},{"chuong":"@c1690","importance":"major","mucCt":"ky","tieuDe":"Giải thoát khỏi Thất Thải và cái chết","text":"Cảm nhận nguy cơ sinh tử từ phong ấn dung hợp khí tức Tiên Cương, uy hiếp Vương Lâm giao hồn thứ ba. Tấn công bằng chữ 'chiến' kim sắc cùng hư ảnh Thất Thải Tiên Tôn nhưng bị tám bổn nguyên chân thân Vương Lâm đẩy lui. Bỏ chạy nhưng không tránh được hai đạo phong ấn — lưỡng hồn Thất Thải trong thân bị phong ấn, cắt đứt liên hệ. Sau khi mất lưỡng hồn, minh mẫn trở lại, thú nhận giấc mộng cả đời là mở đại môn động phủ, năm đó độ Huyền Kiếp thất bại rồi bị hồn phách Thất Thải dung hợp, lẽ ra đã chết từ lâu. Cảm ơn Vương Lâm, thân thể tiêu tán, nửa còn lại hóa cầu vồng lao vào đại môn, tan thành mây khói — chết.","anchor":"Giấc mộng cả đời ta chính là muốn mở đại môn của động phủ này."}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được Chưởng Tôn nhắc đến khi giết Chiến Tinh Dã, là kẻ khiến Chưởng Tôn kiêng kỵ nhất","chuong":"@c1134"},{"text":"Hé lộ tiên duyên: khi độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát, bị hồn phách thứ hai của Thất Thải Tiên Tôn ký sinh","chuong":"@c1651"},{"text":"Cưỡng ép vái lạy anh hồn đồng đạo cũ, tiết lộ bí mật tiên duyên tại Côn Hư tinh vực","chuong":"@c1571"},{"text":"Cắn nuốt đạo nhân bảy màu, tu vi gần đạt mức Thất Thải Tiên Tôn, sau đó tách hồn phách Thất Thải Tiên Tôn khỏi thân thể","chuong":"@c1681"},{"text":"Khôi phục bá đạo năm xưa, giao chiến với Vương Lâm nhưng bị Tâm Động Lôi Âm áp chế","chuong":"@c1682"},{"text":"Tử vong trong biến cố giải thoát khỏi Thất Thải tại cổ mộ, khi cảm nhận nguy cơ sinh tử từ phong ấn dung hợp khí tức Tiên Cương","chuong":"@c1690"}]},"nguon":["@c1633","@c1649","@c1651","@c1653","@c1655","@c1656","@c1657","@c1658","@c1665","@c1667","@c1668","@c1670","@c1671","@c1674","@c1680","@c1681","@c1682","@c1683","@c1689","@c1690"],"aliases":["Chiến Không Liệt","Lão quái vật"],"trangThai":"song","gioiTinh":"nam","canhGioiCaoNhat":"Gần đạt mức Thất Thải Tiên Tôn năm xưa","tinhCach":"Ẩn nhẫn thâm trầm, thường quan sát từ xa trước khi hành động; bá đạo quyết liệt khi ra tay; tham lam trước pháp bảo và hồn thứ ba của Thất Thải; đa nghi cẩn trọng, biết giữ cân bằng thế lực giữa các phe","vaiTro":"Sư phụ Chiến Tinh Dã — cường giả Không Kiếp bị hồn phách Thất Thải Tiên Tôn ký sinh","blurb":"Chiến Lão Quỷ, bí danh Không Kiếp, là cường giả Không Kiếp Sơ Kỳ tương đương Địa Tiên, sư phụ của Chiến Tinh Dã và là kẻ khiến Chưởng Tôn kiêng kỵ nhất. Hắn ẩn trong Lôi Tiên Giới, nhiều lần bí mật theo dõi Vương Lâm cùng tứ đại chiến tướng trong cuộc truy tìm hồn thứ ba của Thất Thải Tiên Tôn, song bản thân cũng bị hồn phách Thất Thải ký sinh suốt từ khi độ huyền kiếp thất bại. Về sau hắn cắn nuốt đạo nhân bảy màu khiến tu vi gần đạt mức Thất Thải Tiên Tôn, tự tách hồn phách ký sinh và khôi phục bá đạo năm xưa, nhưng cuối cùng tử vong trong biến cố giải thoát khỏi Thất Thải tại cổ mộ."},{"id":"that-thai-tien-ton","name":"Thất Thải Tiên Tôn","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Hiện thân qua Chiến lão quỷ, nhận định thiên đạo có cực hạn","text":"Gào thét trong thân Chiến lão quỷ rồi chiếm quyền kiểm soát thân thể, tỏa khí tức riêng. Nhận định nắm thiên đạo trong động phủ giới chẳng khác nắm mọi thứ, nhưng thiên đạo cắn nuốt có cực hạn — Liên Đạo Phi từng tự bạo phân chia thoát được. Hỏi Vương Lâm có tìm được hồn thứ ba chưa, giọng khổ sở thê lương.","anchor":"Nắm trong tay thiên đạo chẳng khác nào nắm tất cả mọi thứ trong tay"},{"chuong":"@c1634","importance":"bridge","mucCt":"gon","text":"Được nhắc là chủ nhân động phủ giới Côn Hư tinh vực, người duy nhất được lão già hắc bào Quy Nhất Tông coi trọng.","anchor":"Cho dù hắn là Vương Lâm thì đã sao"},{"chuong":"@c1650","importance":"normal","mucCt":"vua","tieuDe":"Bị Liên Đạo Phi oanh kích vỡ nát, ba hồn bảy phách tán ra","text":"Trong huyễn cảnh tầng hai, bị Liên Đạo Phi oanh kích thân thể vỡ nát hoàn toàn, nguyên thần và hồn phách hóa thành ba hồn bảy phách tán ra bốn phương tám hướng. Bảy phách bảy màu lần lượt tiến vào luân hồi, bốn phách đầu được xác nhận danh tính: đỏ đậm (sát) là Thanh Thủy, xanh (tu vi) là Tư Đồ Nam, cam (chính khí) là Thanh Lâm, vàng (khí vận) là Tham Lang.","anchor":"Thân thể Thất Thải Tiên Tôn hoàn toàn vỡ nát, nguyên thần và hồn phách lần lượt thay đổi, hóa thành ba hồn bảy phách"},{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ chi tiết tam hồn thất phách","text":"Quá trình sụp đổ được hé lộ toàn diện. Phách thứ năm (lục) = bản năng, am hiểu thuật phân thân, hóa thành Tán Linh Thượng nhân. Phách thứ sáu (lam) = tình cảm yêu hận dành cho đạo lữ duy nhất Phàn San Mộng, hóa thành nữ tử — chính là Mộc Băng Mi, qua vô số luân hồi đều lần lượt ôn nhu rồi lạnh lùng. Phách thứ bảy (tím) = sự điên cuồng, phẫn nộ, không cam lòng trước khi sụp đổ, danh tính chưa rõ. Tam hồn: hồn thứ nhất lóe ánh sáng bảy màu bay ra giới ngoại hóa thành đạo nhân bảy màu, nhận được toàn bộ thần thông cả đời Tiên Tôn. Hồn thứ hai gào thét tiến vào luân hồi tại La Thiên Tinh Vực, hóa thành mãnh thú gặp Chiến lão quỷ — là tiên duyên của Chiến lão quỷ. Hồn thứ ba bay xa nhất, trải qua nhiều lần luân hồi xuyên tinh vực, cuối cùng tại Thanh Linh tinh luân hồi thành cá mấy trăm lần trong cùng con sông.","anchor":"Phách thứ sáu do tình hóa thành này ẩn chứa tâm tình phức tạp của Thất Thải Tiên Tôn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1654","tieuDe":"Nhắc tới thân phận tam hồn thất phách","text":"Tạ Thanh tiết lộ hồn thứ ba của Thất Thải Tiên Tôn chính là bản thân mình; tứ đại chiến tướng là thủ hạ cũ đã đổi tâm tư; trong bảy phách còn hai phách chưa chia cách.","anchor":"Hồn thứ ba của Thất Thải Tiên Tôn là ta"},{"chuong":"@c1666","importance":"bridge","mucCt":"vua","text":"Được nhắc đến là nguồn trí nhớ của Vương Lâm (hồn thứ ba) về Mục Ngư. Năm xưa đã đem một con Mục Ngư nhỏ vào ba trăm tàn giới nuôi dưỡng nhưng vì thân thể phân chia nên thành chuyện tiếc nuối.","anchor":"Năm đó hắn đã đem một con Mục Ngư còn nhỏ vào trong ba trăm tàn giới"},{"mucCt":"gon","text":"Hồn phách bị Chiến lão quỷ vỗ mi tâm tách ra, hiện hư ảnh mặc áo choàng mặt bị che kín, duỗi hai tay gập chữ thập va chạm hai bàn tay khổng lồ kim sắc và hắc sắc.","anchor":"Đó là hồn phách của Thất Thải Tiên Tôn lúc này đã chia lìa với thân thể Chiến lão quỷ","bridge":true,"khoang":"@c1681"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Hồn phách phân ly rồi dung hợp lại với Chiến lão quỷ","text":"Hồn phách phân ly khỏi thân Chiến lão quỷ, áo choàng bao phủ, song chưởng đánh tan thần thông cánh tay kim sắc của lão Mã và phong ấn cổ cầm của Lam Mộng. Sau đó được Chiến lão quỷ dung hợp trở lại thành một thể để đối đầu Vương Lâm.","anchor":"cánh tay kim sắc trên bầu trời lập tức sụp đổ"},{"mucCt":"vua","text":"Qua thế giới ký ức đệ ngũ hoa, lộ ra tên thật thời trẻ là Tô Đạo, thuộc một tông phái trên đại lục Tiên Cương. Thiên tư tuyệt hảo nhưng tính cách mềm yếu, sư tôn bế quan nên bị đồng môn đố kỵ bài xích, mười năm sau mới được sư tổ phát hiện tài năng. Dung mạo thời trẻ giống pho tượng bảy màu, chỉ thiếu vẻ tang thương.","anchor":"Thất Thải Tiên Tôn tính cách vốn rất mềm yếu, chứ không kiêu hùng như sau này","bridge":true,"khoang":"@c1684"},{"chuong":"@c1685","importance":"normal","tieuDe":"Ký ức bị Vương Lâm nghịch chuyển tại Đông Lâm Tông","text":"Ký ức hồn thứ ba được tái hiện: năm xưa tính cách nhu nhược, bị Chu Lập khinh thị và đàn áp, khi thi vận chuyển vân khí phải 20 nhịp thở vì sợ hãi, mây mù ít, bị hút hư ảnh, mất tư cách học Vân Đạo Thiên Thuật, chỉ nhận Thất Thải Tiên Thuật. Nay Vương Lâm nghịch chuyển toàn bộ kết cục này.","anchor":"Thất Thải Tiên Tôn năm đó tính cách nhu nhược, không nói những chuyện này ra","mucCt":"vua"},{"chuong":"@c1686","importance":"bridge","mucCt":"vua","text":"Ký ức được Vương Lâm hồi cố: năm xưa tại Đông Lâm Tông không đạt tư cách tu hành Vân Đạo Thiên Thuật, thi đấu thất bại, tâm lý vặn vẹo, sau được sư tổ giáo hóa tỉnh ngộ, bị khu trừ khỏi tông rồi tự sáng tạo Thất Đạo Tông, ngày thành đạo bắt giết Chu Lập.","anchor":"hóa thành sự tàn nhẫn và sát khí, cuối cùng tự sáng tạo ra Thất Đạo Tông, trở thành tông chủ Thất Thải Tiên Tôn"},{"chuong":"@c1687","importance":"bridge","mucCt":"gon","tieuDe":"Hồi ức bị Chu Lập ngược đãi tại đệ nhất quan","text":"Trong ký ức, năm xưa tại đệ nhất quan bị Chu Lập đoạt lệnh bài và ngược đãi tàn nhẫn, đây là nguyên nhân chính khiến tính cách biến đổi từ nhu nhược thành âm mưu thâm độc.","anchor":"Chính ở nơi này Tô Đạo cũng bị Chu Lập ngược đầi tàn nhẫn, tuy rằng không giết, nhưng loại thương tổn này cũng khiến Tô Đạo cả đời khó quên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1688","tieuDe":"","text":"Hồn thứ ba bị Vương Lâm nghịch chuyển ký ức trong đệ ngũ hoa, từ hỗn loạn chuyển sang hưng phấn, khiến thế giới ký ức sụp đổ hoàn toàn và khí tức bát môn hiển lộ.","anchor":"hồn thứ ba của Thất Thải trong sự hỗn loạn này đang trở nên hưng phấn"},{"mucCt":"vua","text":"Được Vương Lâm gọi bằng tên Tô Đạo, kêu gọi giúp tìm cánh cửa thật đổi lại việc hoàn thành tâm nguyện vào Đông Lâm Trì. Lộ thêm quá khứ: từng được sư tổ Đông Lâm Tông bồi dưỡng nhưng chưa từng vào được Đông Lâm Trì, bị khu trừ khỏi tông môn ngay khi đạt tư cách. Sự cố chấp khiến Đông Lâm Trì là vật duy nhất còn ổn định khi thế giới ký ức sụp đổ.","anchor":"Tô Đạo, ngươi lưu lại Đông Lâm Trì chẳng lẽ là muốn ta hoàn thành tâm nguyện của ngươi","bridge":true,"khoang":"@c1689"},{"chuong":"@c1706","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc: năm xưa Thất Đạo Tông của ông là tiểu phái chư hầu ở Thiên Ngưu Châu, được Đại Hồn Môn che chở nhờ quan hệ song tu đạo lữ với đệ tử Đại Hồn Môn và thiên tư kinh người.","anchor":"bảy mươi hai châu của Tiên Tộc trên Tiên Cương đại lục trên thực tế mỗi một châu đều là một trận pháp khổng lồ"}],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Đối đãi tốt nhưng thường xuyên bế quan"},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh tại Đông Lâm Tông","ghiChu":"Khinh thị Tô Đạo, uy hiếp trong cuộc thử thách vân khí"}],"tuViMoc":[],"diem":[{"text":"Từ bỏ đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật quý bên trong","chuong":"@c1586"},{"text":"Bị Liên Đạo Phi oanh kích thân thể vỡ nát, nguyên thần và tam hồn thất phách tán ra, mỗi phần hóa thành thực thể riêng biệt","chuong":"@c1650"},{"text":"Năm xưa đạt được một mảnh nhỏ thiên đạo, phát hiện thiên đạo và Thiên Nghịch, là người duy nhất nhìn thấy chân thân thiên đạo","chuong":"@c1631"},{"text":"Hồn phách hiện thân qua thân Chiến lão quỷ, chiếm quyền kiểm soát và nhận định thiên đạo có cực hạn","chuong":"@c1633"},{"text":"Lộ ra tên thật thời trẻ là Tô Đạo, thuộc tông phái trên đại lục Tiên Cương, từng bị Chu Lập khinh thị ngược đãi tại Đông Lâm Tông","chuong":"@c1684"},{"text":"Thất phách bị Thiên Vận Tử nuốt, phách nguyên thủy bị nuốt từ lần thức tỉnh sớm hơn ở thái cổ","chuong":"@c1627"}]},"nguon":["@c1633","@c1634","@c1650","@c1651","@c1654","@c1666","@c1681","@c1684","@c1685","@c1686","@c1687","@c1688","@c1689","@c1690","@c1682","@c1706"],"aliases":["Đạo nhân bảy màu","Thất Thải Tiên Tôn","Tô Đạo","Thất Thải đạo nhân"],"trangThai":"song","gioiTinh":"nam","cn":"七彩仙尊","tinhCach":"tâm cơ thâm trầm, không từ thủ đoạn; chấp nhất truy tìm thiên đạo và hồn phách; thời trẻ nhu nhược, từng chịu khinh thị; si tình đa tình","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"vaiTro":"Cường giả thượng cổ — chủ nhân động phủ giới Côn Hư, người duy nhất từng nhìn thấy chân thân thiên đạo","blurb":"Thất Thải Tiên Tôn, tên thật thời trẻ là Tô Đạo, xuất thân từ một tông phái trên đại lục Tiên Cương, từng bị khinh thị và ngược đãi tại Đông Lâm Tông. Về sau trở thành cường giả thượng cổ, chủ nhân động phủ giới Côn Hư tinh vực, người phát hiện thiên đạo cùng Thiên Nghịch và là người duy nhất được ghi nhận đã nhìn thấy chân thân thiên đạo. Sau khi bị Liên Đạo Phi oanh kích đến thân thể vỡ nát, tam hồn thất phách tán ra khắp nơi, kéo theo hàng loạt biến cố liên quan Chiến lão quỷ, Tạ Thanh, Thiên Vận Tử, Thất Đạo Tông và Đại Hồn Môn."},{"id":"dao-nhan-bay-mau","name":"Đạo nhân bảy màu","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Tập hợp đủ Cửu huyền huyết mạch, chuẩn bị truy tìm hồn thứ ba","text":"Trong Côn Hư, cầm chín huyết cầu lớn đã tập hợp đủ Cửu huyền huyết mạch. Định dùng lực lượng này huyễn hóa luân hồi để tìm hồn thứ ba đã trốn vào luân hồi năm xưa, cho rằng hồn thứ ba ở tại Côn Hư.","anchor":"Cửu huyền huyết mạch rốt cục đã tập hợp được toàn bộ"},{"mucCt":"ky","text":"Đã lục soát gần hết Côn Hư trừ Ngũ Hành tinh mà không tìm ra đầu mối hồn thứ ba. Nhớ trong mộng huyễn ở khe Vân Hải tinh vực thấy hồn thứ ba bay hướng Côn Hư nhưng bị Vương Lâm cắt ngang ảo thuật nên không rõ hồn có dừng lại không. Tay cầm giọt máu trong suốt chứa huyết mạch chúng sinh, chỉ phát hồng quang khi gặp sinh linh ngoại lai luân hồi vào động phủ giới. Hận Vương Lâm càng sâu. Cất bước tới Triệu Hà tiếp tục tìm kiếm.","anchor":"Nếu vậy ta sẽ đi khắp tứ đại tinh vực. Ta không tin là hồn thứ ba này có thể rời khỏi động phủ giới","bridge":true,"khoang":"@c1649"},{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ là hồn thứ nhất Thất Thải Tiên Tôn","text":"Được xác nhận là hồn thứ nhất của Thất Thải Tiên Tôn. Vừa xuất hiện đã lóe ánh sáng bảy màu, bay ra giới ngoại, nhận được toàn bộ thần thông cả đời Tiên Tôn.","anchor":"phương hướng bay đi mơ hồ là giới ngoại của vạn cổ năm tháng sau đó"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Từ nơi tiếp giáp với Triệu Hà bước ra La Thiên Tinh Vực, không có đầu mối, bắt đầu tìm kiếm.","anchor":"Hắn không có chút đầu mối, lúc này bắt đầu tìm kiếm trong La Thiên"},{"mucCt":"vua","text":"Đang tìm hồn thứ ba trong La Thiên, sắc mặt đại biến khi cảm nhận trung tâm động phủ mở ra. Phẫn nộ ngập trời vì có người tìm được hồn thứ ba trước, điên cuồng lao tới nơi động phủ mở ra.","anchor":"Hồn thứ ba, có người tìm được hắn rồi! Trung tâm động phủ mở ra!","bridge":true,"khoang":"@c1655"},{"mucCt":"vua","text":"Bước ra từ sương mù, thở phào khi thấy hồn thứ ba không rơi vào tay Chiến lão quỷ. Bị cơn lốc từ đại môn đẩy lui không thể tiến tới. Đưa điều kiện hấp dẫn hơn Chiến lão quỷ: hứa cho thê tử Vương Lâm sống lại, không cướp thiên đạo, tặng toàn bộ động phủ giới, suốt đời không quay lại — chỉ cần hồn thứ ba.","anchor":"ngươi cho ta hồn thứ ba thì bổn tôn có thể cho thê tử của ngươi sống lại","bridge":true,"khoang":"@c1656"},{"mucCt":"vua","text":"Ánh mắt bừng sáng tham lam khi thấy hồn thứ ba, sát khí trở nên nồng đậm, quyết phải giết Vương Lâm cho bằng được. Bị lốc đẩy lùi khi cửa mở, nhưng là người đầu tiên lao vào đại môn sau khi lốc tiêu tán.","anchor":"Sát khí trong mắt đạo nhân bảy màu trở nên nồng đậm, trong khi lui lại đã quyết phải giết Vương Lâm cho bằng được","bridge":true,"khoang":"@c1657"},{"chuong":"@c1658","importance":"bridge","mucCt":"gon","text":"Là người đầu tiên tiến vào động phủ sau khi đại môn mở, bay thẳng vào đại đỉnh mà đống đổ nát không phản ứng, khuôn mặt hiện trên sườn đỉnh bị hắc khí vờn quanh.","anchor":"Đạo nhân bảy màu là người đầu tiên tiến vào"},{"mucCt":"vua","text":"Đã đi qua gần trăm giới truy tìm Vương Lâm không được, sắc mặt âm trầm lo lắng. Xé không gian di chuyển, cuối cùng cảm nhận được khí tức Vương Lâm ở không xa, vô cùng kích động tiếp tục truy tới.","anchor":"Gần lắm rồi, ta có thể cảm nhận được hắn. Hắn ở không xa phía trước!","bridge":true,"khoang":"@c1662"},{"mucCt":"ky","text":"Xé dòng xoáy xâm nhập tàn giới, cảm nhận khí tức Vương Lâm và tuyên bố tìm được hắn. Bị đường đao mượn lực cả giới chém trúng, triệu Thất Thải Đạo Liên biến thành nụ hoa phòng ngự nhưng vẫn bị đánh vỡ hai cánh hoa. Đây là lần thứ ba trong đời cảm nhận nguy cơ, hai trong ba lần đều do Vương Lâm gây ra. Phản công bằng năm cánh hoa còn lại kết hợp đích thân lao tới, nhảy vào dòng xoáy chụp một trảo nhưng hụt, thề đuổi giết Vương Lâm rồi nhảy vào dòng xoáy đuổi theo.","anchor":"Vương Lâm, bổn tôn tìm được ngươi rồi. Lần này ta xem ngươi làm sao mà trốn","bridge":true,"khoang":"@c1664"},{"chuong":"@c1665","importance":"bridge","mucCt":"vua","text":"Liên tục truy kích Vương Lâm xuyên các tàn giới, phát hiện kế phá tấm màn ngăn cách và âm thầm củng cố tấm màn bằng ánh sáng bảy màu định tương kế tựu kế, nhưng thực tế đã rơi vào kế thứ hai của Vương Lâm, bị ảo thuật tấm buồm mặt quỷ và thói quen tiềm thức đánh lừa, truy kích theo hướng sai.","anchor":"Chút tiểu xảo này mà cũng dám dùng trước mặt bổn Tôn"},{"mucCt":"vua","text":"Xuyên phá vách ngăn từng giới truy tìm Vương Lâm nhưng khí tức đã tiêu tan, nổi giận thề giết. Đến tu chân tinh nhận ra mãnh thú ngủ say dưới lòng đất nên do dự, nhưng không thể cưỡng lại hồn thứ ba, lao vào tinh cầu và bị Phần Giới Cổ Tán bao vây.","anchor":"Vương Lâm, nếu không giết được ngươi, lão phu thề không bỏ qua!","bridge":true,"khoang":"@c1667"},{"mucCt":"ky","text":"Là người đầu tiên xông ra khỏi biển lửa nhờ cũng được truyền thừa thuật Phần Giới Cổ Tán. Dùng đài sen bảy màu chống đỡ nhưng bị trường thương bảy màu của Vương Lâm phá tan hoàn toàn, năm cánh hoa còn lại lần lượt vỡ, đài sen nổ tung. Triệu hồi trường thương bảy màu y hệt đối chọi, hai thương va chạm kinh thiên động địa. Chịu Khai Thiên Phủ tự hủy bạo phát, tóc rũ rượi mắt điên cuồng tiếp tục lao tới. Bị U Minh Thú làm hoảng sợ khoảnh khắc, thốt lên gọi Thiên Đạo. Tỉnh lại thì lập tức bị vòng tròn máu nổ tung bao vây kết hợp Mục Ngư thức tỉnh.","anchor":"trên mặt bảy màu lộ ra một vẻ âm trầm, hắn gần như không cần nghĩ ngợi, giơ tay phải lên vung tay áo, một thanh trường thương bảy màu giống y hệt hiện ra","bridge":true,"khoang":"@c1668"},{"mucCt":"ky","text":"Thi triển thần thông Lục bạt sơn hề triệu hoán cánh tay bảy màu khổng lồ, túm lấy con Mục Ngư thứ nhất lôi khỏi lòng đất ném xa khiến nó trọng thương. Bị tám con Mục Ngư còn lại đồng loạt vây đánh, cùng lúc bị Vương Lâm bắn tiễn Lý Quảng trúng ngực, kịp túm đuôi tên nên thân thể không bị xuyên thủng. Dữ tợn rút mũi tên khỏi ngực, máu tươi tung tóe, sắc mặt tái nhợt.","anchor":"Ở chỗ ngực của hắn bị máu tươi nhuốm đỏ, mũi tên Lý Quảng hung hăng đâm vào ngực hắn","bridge":true,"khoang":"@c1669"},{"chuong":"@c1670","importance":"normal","mucCt":"ky","tieuDe":"Bị trọng thương, thi triển chín mặt trời, lần đầu bỏ chạy","text":"Bị tiễn thứ hai của Vương Lâm xuyên thủng ngực, trọng thương. Bộc phát toàn bộ tu vi thi triển thần thông mạnh nhất — chín mặt trời chói lọi. Chín mặt trời va chạm tiễn thứ ba nổ tung tạo sức mạnh hủy diệt, phá hủy ba trăm tàn giới, giết Thanh Long chiến tướng. Lộ mưu đồ thật: hắn muốn Chưởng Tôn đưa cung Lý Quảng cho Vương Lâm để dụ Liên Đạo Phi ra và để Vương Lâm kết oán rồi dùng cung đả thương Chiến lão quỷ, vì cả hắn lẫn Chiến lão quỷ đều không dùng được cung do không hoàn chỉnh. Khi thấy Liên Đạo Phi xuất hiện, lần đầu tiên trong trận đánh với Vương Lâm chọn cách bỏ chạy.","anchor":"Hắn vốn có ý định khiến cho Vương Lâm dùng cây cung này để dụ Liên Đạo Phi ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Khuôn mặt trên cây đinh bảy màu mơ hồ rồi hoàn toàn tiêu tán, Vương Lâm nhận định hắn không còn đáng sợ.","anchor":"Đạo nhân bảy màu đã không còn khiến ta sợ hãi"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Hồn bị Chiến lão quỷ phóng ra từ thất khiếu dùng làm lớp phòng hộ, bị Đạo Cổ Vô Tiên hóa đá rồi bị cưỡng ép dung nhập trở lại vào thân Chiến lão quỷ.","anchor":"từ trong thất khiếu của hắn lập tức lan ra làn khói bảy màu, nhanh chóng ngưng tụ lại ở bên ngoài thân thể hắn, bất ngờ hóa thành hồn của đạo nhân bảy màu"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lộ diện tại chín đại lục trong Thái Cổ Tinh Thần, bàn mưu đồ thôn phệ hồn thứ ba cùng Chưởng Tôn","chuong":"@c1573"},{"text":"Được xác nhận là hồn thứ nhất của Thất Thải Thiên Tôn, nắm toàn bộ đạo thuật thần thông cả đời","chuong":"@c1600"},{"text":"Bị khí tức đại thiên tôn dọa đến mức phun máu, điên cuồng bỏ chạy khỏi khe Vân","chuong":"@c1610"},{"text":"Tập hợp đủ Cửu huyền huyết mạch tại Côn Hư, chuẩn bị huyễn hóa luân hồi truy tìm hồn thứ ba","chuong":"@c1633"},{"text":"Bị Vương Lâm bắn xuyên ngực trọng thương, bộc phát toàn bộ tu vi thi triển chín mặt trời rồi bỏ chạy","chuong":"@c1670"},{"text":"Hồn bị Chiến lão quỷ phóng ra làm lớp phòng hộ, bị Đạo Cổ Vô Tiên hóa đá và cưỡng ép dung hợp","chuong":"@c1683"}]},"nguon":["@c1633","@c1649","@c1651","@c1653","@c1655","@c1656","@c1657","@c1658","@c1662","@c1664","@c1665","@c1667","@c1668","@c1669","@c1670","@c1674","@c1682","@c1683"],"aliases":["Thất Thải Tiên Tôn","Thất Thải đạo nhân","Tô Đạo"],"trangThai":"tu-vong","canhGioiCaoNhat":"Thái Sơ cảnh","vaiTro":"Phản diện ẩn cấp cao — hồn thứ nhất của Thất Thải Tiên Tôn, sư tôn của Chưởng Tôn","tinhCach":"Thâm trầm mưu lược, sắp đặt kế hoạch xuyên suốt nhiều đời; tự tin tuyệt đối vào thần thông và quyền năng bản thân; coi mọi người như quân cờ phục vụ mưu đồ thôn phệ; hung tàn quyết đoán nhưng hoảng sợ bỏ chạy trước khí tức đại thiên tôn","blurb":"Đạo nhân bảy màu là hồn thứ nhất của Thất Thải Tiên Tôn, cường giả ẩn cư tại chín đại lục trôi nổi trong Thái Cổ Tinh Thần, nắm giữ toàn bộ đạo thuật thần thông cả đời của Thất Thải Tiên Tôn. Với tư cách sư tôn của Chưởng Tôn, lão bày bố huyết trận, mang tổ tiên viễn cổ mãnh thú từ Tiên giới, tập hợp Cửu huyền huyết mạch và truy tìm hồn thứ ba xuyên suốt Côn Hư, La Thiên cùng nhiều tàn giới nhằm thôn phệ rồi vượt qua Chiến lão quỷ. Sau khi bị Vương Lâm bắn xuyên ngực trọng thương, lão dần suy yếu và cuối cùng hồn bị Chiến lão quỷ phóng ra làm lớp phòng hộ rồi bị Đạo Cổ Vô Tiên hóa đá, cưỡng ép"},{"id":"thanh-nien-bi-an","name":"Thanh niên bí ẩn","aliases":["Huyền La Đại Thiên Tôn","Thanh niên bí ẩn","Thanh niên tóc đen trường sam đen"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện từ đám huyết sắc trong tinh không Côn Hư, không ai trong động phủ giới phát hiện. Phát hiện vị trí Vương Lâm, gọi hắn là đứa nhỏ, quyết định đi theo xem xét.","anchor":"Đứa nhỏ này ta chưa hiểu, cũng nên đi theo xem xét một phen","bridge":true,"khoang":"@c1635"},{"chuong":"@c1637","importance":"bridge","mucCt":"vua","text":"Đứng bên ngoài Ngũ Hành tinh quan sát trận chiến, lần đầu biết tên Vương Lâm, cười vui vẻ nhận xét hắn nhìn ra bí mật áo giáp danh tiếng ở tiên tộc là rất giỏi.","anchor":"Đứa nhỏ này hóa ra tên là Vương Lâm"},{"mucCt":"ky","text":"Trôi nổi bên ngoài tinh không Ngũ Hành tinh quan sát toàn bộ trận chiến, thần sắc dở khóc dở cười. Nhìn ra rõ ràng Thủy Tướng không hề luyện hóa Vương Lâm mà đang vô tình trợ giúp cảm ngộ thủy bổn nguyên. Nhận xét Vương Lâm có huyết mạch Đạo cổ, tiên nhân thuật, bảy đạo bổn nguyên, cấm chế bổn nguyên tồn tại trong tơ máu đồng tử hóa thành quy tắc — chưa từng thấy trên bất cứ ai. Kết luận: Đạo tiên song tu.","anchor":"đứa nhỏ này có huyết mạch Đạo cổ, lại có tiên nhân thuật, điểm này đúng là cực khó có được","bridge":true,"khoang":"@c1638"},{"mucCt":"vua","text":"Ở ngoài tinh không bên ngoài Ngũ Hành tinh chứng kiến toàn bộ, mỉm cười đắc ý khen Vương Lâm có gan hợp tính tình, gọi hắn là đứa nhỏ của Đạo cổ nhất tộc. Nhắc tới Quy Nhất tông, nói đám tiên nhân nơi này rất thú vị, thản nhiên biểu thị thực lực có thể phất tay diệt sạch sinh linh trên tu chân tinh.","anchor":"Tốt, quả nhiên là đứa nhỏ của Đạo cổ nhất tộc ta, có gan đối phó với tất cả những người dám mạo phạm hắn","bridge":true,"khoang":"@c1640"},{"mucCt":"ky","text":"Lơ lửng trong tinh không bên ngoài Ngũ Hành tinh quan sát trận pháp. Nhận định Cửu Chuyển Tâm Luân là danh trận Tiên Cương đại lục, cho rằng ngay cả Đạo cổ hoàng tôn đời này nếu chưa gặp cũng sẽ bị nhốt. Trong lòng có một tia chờ mong yếu ớt rằng Vương Lâm có thể phá, nhưng tự thấy kỳ vọng quá cao. Thất vọng khi Vương Lâm tới ngũ chuyển, giơ tay phải định ra tay cứu. Tới cửu chuyển thấy chuyển động chậm lại, hai mắt sững sờ, tay buông xuống không can thiệp, trái tim tĩnh lặng vạn cổ đập thình thịch.","anchor":"trái tim tĩnh lặng từ vạn cổ lúc này đập thình thịch","bridge":true,"khoang":"@c1642"},{"mucCt":"vua","text":"Quan sát toàn bộ quá trình Vương Lâm phá Cửu Chuyển Tâm Luân từ bên ngoài Ngũ Hành tinh, phân tích chính xác phương pháp thân tình dẫn tâm, nội tâm chấn động kịch liệt. Khi Vương Lâm nghịch chuyển trận pháp thì cười vang tán thưởng, khen hợp tính tình ta.","anchor":"Người này ta nhất định phải có!","bridge":true,"khoang":"@c1643"},{"chuong":"@c1644","importance":"bridge","mucCt":"vua","text":"Ở bên ngoài Ngũ Hành tinh, nghe thấy lời lão già tầng ba sỉ nhục Đạo Cổ nhất mạch, thần sắc âm trầm — cả đời chưa bao giờ gặp ai dám vũ nhục Đạo Cổ nhất mạch.","anchor":"Hắn cả đời này chưa bao giờ thấy ai dám vũ nhục Đạo cổ nhất mạch"},{"chuong":"@c1645","importance":"minor","mucCt":"gon","tieuDe":"Quan sát Đạo cổ bất diệt thể","text":"Quan sát Vương Lâm từ bên ngoài Ngũ Hành tinh, nhận xét Đạo cổ bất diệt thể cùng loại với tiên nhân bất diệt thể, thắc mắc Vương Lâm muốn làm gì.","anchor":"Đây là một loại thần thông cùng loại với tiên nhân bất diệt thể"},{"chuong":"@c1646","importance":"major","mucCt":"ky","tieuDe":"Giáng lâm Ngũ Hành tinh, chấn nhiếp toàn trường","text":"Thân ảnh mơ hồ giáng lâm Ngũ Hành tinh, chất vấn ai dám nói Đạo cổ nhất mạch đều là đám hoang dã. Uy áp kinh thiên khiến toàn bộ tu sĩ sợ hãi tột độ, ba nam tử trung niên phun máu bật bay, đại địa rung chuyển, mặt trời tắt sáng. Bóp cổ lão già mặc song hành khải, tay nhẹ vung phá nát bộ song hành giáp cường hãn như tờ giấy. Được lão già họ Mã run rẩy nhận diện danh tính.","anchor":"Người có thể tùy ý hủy diệt áo giáp của Quy Nhất tông như thế, chất vấn bá đạo như thế về chuyện bất kính với Đạo cổ nhất mạch thì chỉ có thể là một người"},{"importance":"normal","mucCt":"ky","chuong":"@c1647","tieuDe":"Thị uy Ngũ Hành tinh, đoạt giáp, đặt tiêu chí tuyển Vương Lâm","text":"Hiện thân ảnh mơ hồ trên Ngũ Hành tinh với uy áp cửu dương khiến mọi người không thể nhìn rõ diện mạo. Vuốt tay giết lão già mất áo giáp, phóng uy áp buộc tất cả quỳ gối. Khen Vân Dật Phong tâm trí cực cao nhưng tiếc không phải Đạo cổ nhất mạch. Phá tầng tháp thứ nhất, đoạt tấm áo giáp đen kịt, tuyên bố Quy Nhất tông nếu có tư cách thì cứ tới lấy lại. Ra lệnh bọn họ chưa được rời đi, phải làm hòn đá mài đao rèn luyện Vương Lâm. Bí mật theo Vương Lâm qua trận pháp ngân hà vào tiên giới, bị Vương Lâm thăm dò nhưng không lộ. Tổng kết đánh giá Vương Lâm qua bốn lần quan sát: bá đạo, minh ngộ, quyết đoán mưu trí, cẩn thận. Đặt tiêu chí cuối cùng cần kiểm chứng: trọng nghĩa tình. So sánh Vân Dật Phong với Vương Lâm, cho rằng Vân Dật Phong ưu tú hơn nhưng thuộc tiên tộc.","anchor":"Chẳng qua người ta muốn tuyển phải trọng nghĩa tình! Người này không biết có được hay không?"},{"chuong":"@c1648","importance":"bridge","mucCt":"vua","text":"Đứng trong ngọn núi quan sát Vương Lâm, phóng thần thức vào sương mù mộng ảo để xem, chứng kiến toàn bộ cảnh Vương Lâm nhập mộng nhớ Lý Mộ Uyển, trong lòng đau đớn cảm thán về nỗi bi ai khiến người ta phải vào mộng tìm hạnh phúc.","anchor":"Đây là nỗi nhớ nhung và bi ai gì mà có thể khiến người ta phải đi vào mộng ảo để tìm hạnh phúc"},{"mucCt":"vua","text":"Thấy Vương Lâm rơi vào vòng luẩn quẩn, điểm một ngón tay đưa ý niệm biến số vào đầu hắn. Tự suy tư thiên đạo huyền diệu, tiết lộ Cửu dương cũng đang tìm bước tiến tiếp theo nhưng chưa ai làm được, và thiên đạo xuất hiện đầu tiên ở Cổ Thần cảnh. Trên ngón trỏ có ấn ký màu đen giống hố đen xoay tròn tỏa khí tức thiên đạo.","anchor":"Thiên đạo, vật này xuất hiện đầu tiên ở cổ Thần cảnh, cổ Thần rất huyền ảo","bridge":true,"khoang":"@c1653"},{"importance":"normal","mucCt":"vua","chuong":"@c1654","tieuDe":"Kinh hãi nhận ra Không Diệt khí","text":"Đi theo Vương Lâm tới tu chân tinh, lần đầu tiên đại biến sắc mặt khi nhìn thấy thanh kiếm hư ảo bên người Vương Lâm. Nhận ra đó là khí tức của Không Diệt, vô cùng khiếp sợ.","anchor":"Không Diệt khí! Đây là khí tức của không diệt!"},{"mucCt":"gon","text":"Xuất hiện từ hư vô sau khi tất cả đã vào, trầm ngâm rồi thong dong tiến vào đại môn, tuyên bố khảo sát đối với Vương Lâm sẽ chấm dứt ở đây.","anchor":"Khảo sát đối với người này hẳn sẽ chấm dứt ở đây","bridge":true,"khoang":"@c1657"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát, lần đầu biết tên, đánh giá cao"}],"tuViMoc":[],"diem":[{"text":"Ẩn mình trong Triệu Hà tinh vực, thân thể mơ hồ không thể nhìn rõ, ngay cả Thiên Vận Tử cũng không phát hiện","chuong":"@c1571"},{"text":"Quan sát Vương Lâm từ bên ngoài Ngũ Hành tinh, nhận định Đạo cổ bất diệt thể cùng loại với tiên nhân bất diệt thể","chuong":"@c1645"},{"text":"Giáng lâm Ngũ Hành tinh, uy áp kinh thiên chấn nhiếp toàn trường, chất vấn ai dám sỉ nhục Đạo Cổ nhất mạch","chuong":"@c1646"},{"text":"Thị uy với uy áp cửu dương, đoạt giáp và đặt tiêu chí tuyển chọn Vương Lâm","chuong":"@c1647"},{"text":"Lần đầu đại biến sắc mặt khi nhận ra Không Diệt khí từ thanh kiếm hư ảo bên người Vương Lâm","chuong":"@c1654"},{"text":"Thong dong tiến vào đại môn, tuyên bố khảo sát đối với Vương Lâm","chuong":"@c1657"}]},"nguon":["@c1633","@c1635","@c1637","@c1638","@c1640","@c1642","@c1643","@c1644","@c1645","@c1646","@c1647","@c1648","@c1653","@c1654","@c1657"],"trangThai":"song","cn":"玄罗大天尊","gioiTinh":"nam","vaiTro":"Nhân vật bí ẩn từ viễn cổ tiên vực, liên hệ Đạo Cổ nhất mạch, theo dõi và khảo sát Vương Lâm","tinhCach":"Cao ngạo khinh thế, coi tu sĩ giới nội là sinh vật thấp kém; hành sự độc lập, ẩn mình quan sát không ai hay biết; trọng thị Đạo Cổ nhất mạch, nổi giận khi nghe sỉ nhục; thâm trầm mưu tính, chủ động đặt tiêu chí tuyển chọn Vương Lâm","blurb":"Nhân vật bí ẩn thân thể mơ hồ không ai nhìn rõ diện mạo, thoát ra từ viễn cổ tiên vực và ẩn mình trong tinh không, khinh miệt tu sĩ giới nội, gọi giới nội là động phủ của Thất Đạo Tông. Hắn âm thầm theo dõi Vương Lâm xuyên suốt từ Triệu Hà tinh vực tới Ngũ Hành tinh, nhận ra Đạo cổ bất diệt thể của Vương Lâm, rồi giáng lâm chấn nhiếp toàn trường để bảo vệ thanh danh Đạo Cổ nhất mạch, đồng thời đặt ra tiêu chí khảo sát và tuyển chọn Vương Lâm."},{"id":"u-minh-thu","name":"U Minh thú","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Phóng sương mù thiên đạo nuốt gần hết tiên nhân","text":"Mở miệng phóng sương mù tràn ngập tinh không mang khí tức tang thương, lực hút kinh thiên cuốn khoảng bảy tám mươi tiên nhân nuốt hết. Tứ đại chiến tướng nhận ra đây là thiên đạo. Sau đó truyền đạt cho Vương Lâm rằng rất khó nuốt được Chiến lão quỷ.","anchor":"Tinh không nếu ví là thiên địa thì thiên địa biến sắc, tinh thần nếu là phong vân thì phong vân cuồn cuộn"}],"diem":[{"text":"Bị Vương Lâm hoàn thành ba tầng phong ấn (phong ngoài, hồn phong bằng bảy tinh điểm Cổ Thần, phong ấn máu thịt), thu phục làm bổn mệnh thú","chuong":"@c1412"},{"text":"Mở U Minh Hồn Khẩu khổng lồ nuốt trọn cuồng phong chuông vàng, cứu nguy Vân Hải","chuong":"@c1419"},{"text":"Bộc lộ bản tính cổ quái — vọt về nép vào Vương Lâm như hài tử nép cha mẹ khi bị tu sĩ nhìn chằm chằm","chuong":"@c1420"},{"text":"Tái xuất huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, bao trùm Vô Danh Chuyển Luân trận","chuong":"@c1576"},{"text":"Phóng sương mù thiên đạo tràn ngập tinh không, lực hút kinh thiên nuốt gần hết tiên nhân","chuong":"@c1633"},{"text":"Được xác nhận là một bộ phận của Vương Lâm, sinh mệnh và sức sống tương thông với chủ nhân","chuong":"@c1631"}]},"nguon":["@c1633"],"vaiTro":"Bổn mệnh thú của Vương Lâm — linh thú cổ quái sở hữu U Minh Hồn Khẩu","tinhCach":"Hung hãn dữ tợn khi chiến đấu, uy lực kinh người; nhút nhát cổ quái, run rẩy sợ hãi khi bị đám đông chú ý, nép vào Vương Lâm như hài tử nép cha mẹ; tham ăn, nuốt cuồng phong rồi nhấm nháp thưởng thức","blurb":"Linh thú khổng lồ vốn ngủ trong cấm địa sương mù La Thiên, bị Vương Lâm hoàn thành ba tầng phong ấn thu phục làm bổn mệnh thú, sinh mệnh từ đó gắn liền chủ nhân. Sở hữu U Minh Hồn Khẩu uy lực đủ nuốt cả tinh không, từng nuốt trọn cuồng phong chuông vàng cứu nguy Vân Hải, huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, và phóng sương mù thiên đạo nuốt gần hết tiên nhân. Dẫu uy mãnh vô song, nó lại run rẩy sợ hãi mỗi khi bị người khác nhìn chằm chằm, bộc lộ bản tính vừa dữ tợn vừa ngờ nghệch."},{"id":"nap-da","name":"Nạp Đa","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1634","importance":"bridge","mucCt":"vua","text":"Được nhắc đã bế quan ngàn năm cùng tông chủ và trưởng lão Quy Nhất Tông. Vương Lâm tới Ngũ Hành tinh theo ước hẹn năm xưa nhưng không gặp được.","anchor":"Nạp Đa trưởng lão ngàn năm trước đã bế quan, không hỏi thế sự"},{"mucCt":"vua","text":"Ngồi trên tầng chín tháp Ngũ Hành tinh, nhận ra Vương Lâm từ tu sĩ Nguyên Anh đã vượt xa mình, tự nhận chỉ là hậu nhân bảo vệ nơi này. Nhận định Vương Lâm chỉ Không Linh trung kỳ, có thể qua Ngũ Hành nhưng không thể qua đệ tam chuyển. Khi thấy Vương Lâm thu cả trận linh thì nhíu mày nhưng vẫn tự tin còn tứ quan và cửu chuyển, ánh mắt lộ hàn quang, không còn giao tình.","anchor":"Năm đó hắn chỉ là một tu sĩ Nguyên Anh, hơn một ngàn năm đã đạt tới mức này","bridge":true,"khoang":"@c1635"},{"chuong":"@c1637","importance":"bridge","mucCt":"gon","text":"Bị tu sĩ Quy Nhất tông nhắc tên trong bài xuyên tạc, vu rằng Nạp Đa trưởng lão năm xưa tha mạng Vương Lâm nhưng bị vô ơn.","anchor":"Nạp Đa trưởng lão Quy Nhất tông được chúng ta kính trọng năm đó cũng là gặp phải lúc Vương Lâm giết hại phàm nhân mới ra tay ngăn cản"},{"mucCt":"vua","text":"Được Thủy Tướng cầu viện trong lúc nguy cấp. Từ bầu trời thủy trận truyền vào lực lượng Ngũ Hành hệ kim (kim sinh thủy), khiến quả cầu nước Càn Khôn Nhất Tích thêm mạnh mẽ.","anchor":"bầu trời trên thủy trận liền có một dòng xoáy xuất hiện","bridge":true,"khoang":"@c1638"},{"mucCt":"vua","text":"Từ tháp cao quan sát qua thần thức, tự tin Vương Lâm không thoát được, phân tích mục đích Vương Lâm là tìm hồn thứ ba. Mặc bộ áo giáp kim quang tu vi tăng mạnh, dẫn đầu mấy trăm tu sĩ phóng thần thức nhập trận đè ép. Sau khi Vương Lâm thu bổn nguyên, thần thức bị tống ra, mê man nhận ra Vương Lâm đã nhận thổ linh, khiến hỏa linh vái lạy, lại lấy cả thủy bổn nguyên.","anchor":"Hắn nhận được thổ linh, khiến hỏa linh vái lạy, lại lấy cả thủy bổn nguyên do Càn Khôn Nhất tích biến thành","bridge":true,"khoang":"@c1639"},{"chuong":"@c1641","importance":"bridge","mucCt":"vua","text":"Được Đệ Cửu lão tổ dùng bàn tay hư ảo túm đưa lên tầng chín, phủ phục xưng hậu bối tử tôn, kể hết những gì biết về Vương Lâm cho lão tổ.","anchor":"Hậu bối tử tôn Nạp Đa xin ra mặt đệ cửu lão tổ"},{"mucCt":"vua","text":"Sùng kính lão tổ kim bào, ôm quyền vái. Năm xưa từng bị nhốt trong đệ tam chuyển của Cửu Chuyển Tâm Luân đã hôn mê, được lão tổ cứu, tu dưỡng rất lâu mới hồi phục, từ đó kính sợ trận pháp này. Tới cửu chuyển cũng tươi cười nghĩ Vương Lâm thua, nhưng khi chuyển động chậm lại thì kinh hãi.","anchor":"Năm đó hắn ở trong đệ tam chuyển đã hôn mê, được lão tổ cứu, tu dưỡng rất lâu mới khôi phục được","bridge":true,"khoang":"@c1642"},{"mucCt":"vua","text":"Sợ hãi trước biến đổi của Vương Lâm. Khi bị Cửu Chuyển Tâm Luân nghịch chuyển đánh ngược, sự sợ hãi năm xưa tràn ngập tâm thần, miễn cưỡng chịu tới đệ tứ chuyển thì phun máu hôn mê.","anchor":"Sự sợ hãi năm đó lúc này lại tràn ngập tâm thần, khiến Nạp Đa suýt nữa là bị sợ hãi khiến trở nên điên cuồng","bridge":true,"khoang":"@c1643"},{"chuong":"@c1644","importance":"bridge","mucCt":"gon","text":"Nằm trên mặt đất Ngũ Hành tinh sau nghịch động, được Vương Lâm nhìn thấy từ trên bầu trời.","anchor":"Hắn muốn xem nơi này rốt cục tồn tại cường giả tới bậc nào"}],"nhanMach":[{"ten":"Đệ Cửu lão tổ","tag":"cap-tren","quanHe":"Lão tổ đời thứ chín trong tông môn, triệu hắn lên tầng chín hỏi về Vương Lâm","ghiChu":"@c1641"}],"tuViMoc":[],"diem":[{"text":"Xuất hiện với danh nghĩa 'thanh niên tà dị', đuổi theo Vương Lâm đòi lại túi trữ vật bị mất","chuong":"@c0223"},{"text":"Tiết lộ bí quyết Cực Cảnh rồi rời tinh cầu bằng la bàn đen; nổi giận muốn trả đũa nhưng phải nhịn trước Cấm Phiên của Vương Lâm","chuong":"@c0224"},{"text":"Anh Biến sơ kỳ, tự nhận chỉ đạt khoảng 3/10 sức mạnh thật","chuong":"@c0224"},{"text":"Bế quan ngàn năm cùng tông chủ và trưởng lão Quy Nhất Tông trên Ngũ Hành tinh","chuong":"@c1634"},{"text":"Được Đệ Cửu lão tổ túm lên tầng chín, phủ phục xưng hậu bối, kể lại những gì mình biết","chuong":"@c1641"},{"text":"Bị Cửu Chuyển Tâm Luân nghịch chuyển đánh ngược, cuối cùng nằm lại trên mặt đất Ngũ Hành tinh","chuong":"@c1644"}]},"nguon":["@c1634","@c1635","@c1636","@c1637","@c1638","@c1639","@c1641","@c1642","@c1643","@c1644"],"gioiTinh":"nam","cn":"纳多","vaiTro":"Nhân vật phụ — trưởng lão Quy Nhất Tông trên Ngũ Hành tinh","tinhCach":"Bộc trực, dễ nổi giận nhưng biết lùi khi gặp đối thủ vượt tầm; sùng kính bậc tiền bối tông môn; mang nỗi sợ hãi cũ khi đối diện Cửu Chuyển Tâm Luân","blurb":"Nạp Đa là tu sĩ Anh Biến sơ kỳ xuất thân Ngũ Hành tinh, ban đầu xuất hiện dưới danh nghĩa 'thanh niên tà dị' đuổi theo Vương Lâm đòi lại túi trữ vật và vô tình tiết lộ bí quyết đột phá Cực Cảnh. Ngàn năm sau hắn giữ vị trí trưởng lão Quy Nhất Tông, bế quan trên tháp Ngũ Hành tinh và chứng kiến Vương Lâm trở lại với thực lực đã vượt xa mình. Bị cuốn vào biến cố xoay quanh Cửu Chuyển Tâm Luân và lão tổ Đệ Cửu, cuối cùng hắn nằm lại trên mặt đất sau nghịch động."},{"id":"duan-dong","name":"Duẫn Đông Thân","cn":"","aliases":["Duẫn Đông"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Duẫn Đông là Yêu tướng thuộc Hỏa Yêu quận, sở hữu yêu lực gần ba mươi vạn. Trong trận vây diệt Vương Lâm tại Vạn Yêu sơn, hắn chủ động ôm quyền xin xuất chiến, hóa thành đạo thanh quang lao thẳng về phía Vương Lâm với sát khí dồn dập, và về sau đã tử vong.","vaiTro":"Yêu tướng Hỏa Yêu quận, tham chiến vây diệt Vương Lâm tại Vạn Yêu sơn","tinhCach":"Hiếu chiến, chủ động xin xuất trận; tự tin đến ngạo mạn, tự nhận thừa sức diệt tu sĩ Vấn Đỉnh; sát khí mạnh khi giao chiến","tabs":{"diem":[{"text":"Yêu lực gần ba mươi vạn, tự nhận thừa sức diệt tu sĩ Vấn Đỉnh","chuong":"@c0560"},{"text":"Ôm quyền xin xuất chiến, hóa thanh quang lao về phía Vương Lâm với sát khí dồn dập","chuong":"@c0560"},{"text":"Tử vong sau trận chiến","chuong":"@c0560"}],"kinhLich":[{"mucCt":"vua","text":"Đáp lời Vương Lâm khi hắn truyền âm vào Ngũ Hành tinh, tự xưng phó tông chủ. Nói Nạp Đa đã bế quan ngàn năm, từ chối cho Vương Lâm vào và cảnh báo sẽ khởi động Ngũ Hành Quy Nhất trận.","anchor":"Lão phu là phó tông chủ Quy Nhất Tông - Duẫn Đông Thân","bridge":true,"khoang":"@c1634"},{"mucCt":"gon","text":"Cùng ba trưởng lão khác họp bàn về Vương Lâm, đề xuất báo cho Nạp Đa.","anchor":"Giọng nói này chính là của Duẫn Đông Thân vừa đối thoại với Vương Lâm","bridge":true,"khoang":"@c1635"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách tìm tới Ngũ Hành tinh, Duẫn Đông Thân từ chối cho vào","ghiChu":"@c1634"},{"ten":"Nạp Đa","tag":"cap-tren","quanHe":"Trưởng lão Quy Nhất Tông, cấp trên của Duẫn Đông Thân","ghiChu":"@c1634"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng đối thoại và giám sát khi Vương Lâm xâm nhập Ngũ Hành tinh","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635"]},{"id":"de-cuu-lao-to","name":"Đệ Cửu lão tổ","cn":"","aliases":["Lão già mặc hắc bào","Lão già mặc kim bào","Lão già mặc áo đen"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn cường giả ngồi ở tầng thứ mười từ trên xuống trong tháp Quy Nhất Tông, sở hữu đôi mắt cực bá đạo và tự tin tuyệt đối vào Ngũ Hành đại trận cùng Cửu Chuyển Tâm Luân. Chủ động kích hoạt trận pháp thử sức Vương Lâm nhưng cuối cùng bị bẻ gãy cánh tay trong đối chưởng, và chứng kiến Vương Lâm phá nghịch chuyển tới đệ thất chuyển khiến y sợ hãi ngập trời.","vaiTro":"Cường giả tầng cao Quy Nhất Tông, đối thủ thử thách Vương Lâm trong tháp","tinhCach":"Bá đạo, tự tin tuyệt đối; khinh thường tu sĩ động phủ giới; dễ chuyển từ hưng phấn sang sợ hãi khi tình thế đảo ngược","tabs":{"diem":[{"text":"Ngồi tầng thứ mười từ trên xuống của tháp Quy Nhất Tông cùng ba cường giả khác","chuong":"@c1634"},{"text":"Phất tay áo tạo mặt gương quan sát và chủ động cho kích hoạt trận pháp thử sức Vương Lâm","chuong":"@c1635"},{"text":"Hưng phấn rồi sợ hãi ngập trời khi chứng kiến Vương Lâm thu bổn nguyên phá Càn Khôn Nhất Tích","chuong":"@c1639"},{"text":"Đối chưởng Vương Lâm qua dòng xoáy, bị bẻ gãy cánh tay phải, nhờ áo giáp nội liễm mới giữ mạng","chuong":"@c1641"},{"text":"Giải thích cơ chế Cửu Chuyển Tâm Luân — danh trận Tiên Cương đại lục — và tự tin người thông minh càng không thoát","chuong":"@c1642"},{"text":"Chống nghịch chuyển tới đệ thất chuyển mới suy kiệt, không thể tin tu sĩ động phủ giới phá được trận","chuong":"@c1643"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi ở tầng thứ mười từ trên xuống của tháp Quy Nhất Tông cùng ba người khác. Tuyên bố trong động phủ giới trừ Thất Thải Tiên Tôn chẳng ai đáng coi trọng, khẳng định Ngũ Hành đại trận ngay cả bản thân lọt vào cũng chỉ chống đỡ nửa nén nhang, Vương Lâm tuyệt đối không qua được ngũ quan.","anchor":"Cho dù hắn là Vương Lâm thì đã sao","bridge":true,"khoang":"@c1634"},{"mucCt":"gon","text":"Phất tay áo tạo mặt gương quan sát Vương Lâm, quyết định không cần đợi Nạp Đa mà cho kích hoạt trận pháp thử sức. Hoảng sợ khi thấy Vương Lâm thu trận linh.","anchor":"Lão phu đã quyết định rồi. Nạp Đa chưa chắc đã không biết việc này","bridge":true,"khoang":"@c1635"},{"importance":"bridge","mucCt":"gon","chuong":"@c1639","tieuDe":"Hưng phấn rồi sợ hãi trước kết cục Vương Lâm thu bổn nguyên","text":"Hưng phấn tin Càn Khôn Nhất Tích sẽ giết Vương Lâm, sau khi chứng kiến kết cục thì sợ hãi ngập trời nửa ngày không nói được lời nào.","anchor":"Nhất là lão già mặc áo đen đến nửa ngày cũng không thể nói gì, trong mắt trào dâng sự sợ hãi ngập trời."},{"mucCt":"vua","text":"Đối chưởng Vương Lâm qua dòng xoáy, bị bẻ gãy cánh tay phải phun máu tươi, nhờ áo giáp nội liễm trong cơ thể mới không tan xác. Nhận định Vương Lâm là người cổ tộc thuộc Đạo cổ nhất mạch, nghi đến từ Tiên Cương đại lục. Triệu Nạp Đa hỏi lai lịch Vương Lâm, giải thích nguyên lý Cửu Chuyển Tâm Luân — trận pháp hộ sơn Quy Nhất tông.","anchor":"Người cổ tộc. Lực lượng từ trong cơ thể hắn truyền ra thuộc về Đạo cổ nhất mạch!","bridge":true,"khoang":"@c1641"},{"mucCt":"vua","text":"Ngồi tầng tháp thứ chín giải thích cơ chế Cửu Chuyển Tâm Luân cho Nạp Đa, tự tin người thông minh càng không thoát nổi. Cúi nhìn cánh tay phải vẫn đau đớn dù vận chuyển tiên lực cũng không đỡ, lộ vẻ oán độc. Tới đệ cửu chuyển cười phá tuyên bố Vương Lâm chết chắc, rủ Nạp Đa đi nhặt xác. Nhưng chuyển động đột ngột chậm lại, hắn kinh hãi không thể tin.","anchor":"Cửu chuyển rồi, người này chết chắc rồi! Nạp Đa chuẩn bị theo lão phu đi nhặt xác người này!","bridge":true,"khoang":"@c1642"},{"importance":"normal","mucCt":"vua","chuong":"@c1643","tieuDe":"Chống nghịch chuyển tới đệ thất chuyển mới suy kiệt","text":"Không thể tin tu sĩ động phủ giới phá được Cửu Chuyển Tâm Luân, xác nhận đây là danh trận Tiên Cương đại lục. Khi bị trận pháp nghịch chuyển, cố điểm vào mi tâm bình tâm nhưng bị tiếng gào thét xung quanh quấy loạn, chống đỡ lâu nhất trong số tu sĩ Quy Nhất tông, phun máu héo rũ ở đệ thất chuyển.","anchor":"hắn tuyệt đối không thể ở đệ cửu chuyển mà đình chỉ sự vận chuyển của Cửu Chuyển Tâm Luân"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ xâm nhập Ngũ Hành tinh, bị lão già hắc bào khinh thường","ghiChu":"@c1634"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Người duy nhất được lão già hắc bào thừa nhận trong động phủ giới","ghiChu":"@c1634"},{"ten":"Nạp Đa","tag":"ho-hang","quanHe":"Hậu bối tử tôn trong tông môn, được triệu lên tầng chín hỏi về Vương Lâm","ghiChu":"@c1641"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Nhắc đến ba nghìn huyết mạch của Diệp Mịch khi phân tích lai lịch Vương Lâm","ghiChu":"@c1641"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635","@c1636","@c1639","@c1641","@c1642","@c1643"]},{"id":"nu-tu-trung-nien-quy-nhat","name":"Nữ tử trung niên (Quy Nhất Tông)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn cường giả ngồi ở tầng cao tháp Quy Nhất Tông, thần sắc khắc bạc, giọng the thé. Hi vọng Vương Lâm qua được ngũ quan để thấy cửu chuyển của Ngũ Hành quy nhất.","vaiTro":"Cường giả tầng cao Quy Nhất Tông","tinhCach":"Khắc bạc; thích thú trước thử thách","tabs":{"diem":[{"text":"Hi vọng Vương Lâm qua được ngũ quan để trận pháp thành Ngũ Hành quy nhất cửu chuyển","chuong":"@c1634"}],"kinhLich":[{"chuong":"@c1634","importance":"bridge","mucCt":"gon","text":"Ngồi cạnh lão già hắc bào ở tầng cao tháp Quy Nhất Tông, bày tỏ hi vọng Vương Lâm qua được ngũ quan.","anchor":"Ta thật sự là hi vọng hắn qua được ngũ quan"},{"mucCt":"gon","text":"Lộ thái độ thù hận liên quan đến Tư Đồ Nam, gọi hắn là kẻ phụ lòng người, muốn Vương Lâm chịu trừng phạt thay. Hai trưởng lão khác nhíu mày cảm thấy bất thường.","anchor":"Vương Lâm, ngươi quen biết với Tư Đồ Nam, hôm nay ngươi tiếp nhận sự trừng phạt thay cho kẻ phụ lòng người đó đi","bridge":true,"khoang":"@c1635"},{"chuong":"@c1636","importance":"bridge","mucCt":"gon","text":"Mong Vương Lâm bị thương trong hỏa trận nhưng chứng kiến hỏa linh quỳ bái hắn, sắc mặt tái mét lộ sợ hãi.","anchor":"Nàng hận Tư Đồ Nam lại càng hận tất cả những người quen biết với hắn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1639","tieuDe":"Thề nhắm Tư Đồ Nam rồi bàng hoàng trước thất bại","text":"Mong Vương Lâm chết để Tư Đồ Nam bi thương, thề Tư Đồ Nam sẽ là mục tiêu tiếp theo. Sau khi chứng kiến Vương Lâm thu bổn nguyên thì không thể thừa nhận kết quả.","anchor":"Người chết rồi Tư Đồ Nam kia sẽ bi thương. Hắn càng bi thương càng phẫn nộ ta lại càng được giải hận!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Kẻ xâm nhập Ngũ Hành tinh, nữ tử muốn xem hắn chịu được mấy chuyển","ghiChu":"@c1634"},{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Gọi Tư Đồ Nam là kẻ phụ lòng người, có tư thù tình cảm quá khứ","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635","@c1636","@c1639"]},{"id":"nam-tu-trung-nien-than-trong","name":"Nam tử trung niên (trưởng lão thận trọng, Quy Nhất tông)","gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn trưởng lão Quy Nhất tông canh giữ tầng dưới tháp Ngũ Hành tinh. Thận trọng, đề nghị không nên chọc Vương Lâm trước khi có chỉ thị của Nạp Đa.","vaiTro":"Trưởng lão Quy Nhất tông","tinhCach":"Thận trọng, cẩn thận","tabs":{"diem":[{"text":"Trưởng lão thận trọng nhất trong nhóm bốn, đề nghị chờ chỉ thị Nạp Đa","chuong":"@c1635"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1635","tieuDe":"Bàn bạc đối phó Vương Lâm","text":"Cau mày đề nghị không nên chọc vào Vương Lâm trước khi có chỉ thị của Nạp Đa trưởng lão.","anchor":"Ta cũng đề nghị là trước khi có chỉ thị của Nạp Đa trưởng lão thì không nên chọc vào Vương Lâm này"},{"chuong":"@c1636","importance":"normal","mucCt":"vua","tieuDe":"Khoác tiên tổ chiến giáp nghênh chiến","text":"Triệu xuất tiên tổ chiến giáp màu xanh nước biển tỏa sóng nước từ tầng thứ mười, tạo trường thương bằng sóng nước. Tuyên bố dùng Ngũ Hành thủy trận bức Vương Lâm ra khỏi trận pháp, tiến vào cửu chuyển, nhờ Nạp Đa áp trận rồi hóa hơi nước biến mất.","anchor":"Trận tiếp theo là Ngũ Hành thủy trận. Ta sẽ thử xem có thể bức hắn ra khỏi trận pháp, trực tiếp tiến vào cửu chuyển hay không"}],"tuViMoc":[],"nhanMach":[{"ten":"Nạp Đa","tag":"cap-tren","quanHe":"Nạp Đa trưởng lão, cấp trên trong Quy Nhất tông","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1635","@c1636"]},{"id":"thuy-tuong","name":"Thủy Tướng","aliases":["Ngũ tiên Thủy Tướng","Nam tử trung niên áo tím","Nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ hai (nhờ áo giáp đánh ra lực lượng bước thứ ba)","trangThai":"song","blurb":"Thủy Tướng là một trong Ngũ tiên trấn giữ tháp Ngũ Hành tinh của Quy Nhất tông, chịu trách nhiệm bảo vệ tầng chín. Hắn sở hữu sức mạnh bước thứ hai, nhờ áo giáp đặc thù có thể phát huy lực lượng bước thứ ba, thiện dùng trường thương nước và thần thông Càn Khôn Nhất Tích. Sau trận kịch chiến với Vương Lâm trong Ngũ Hành thủy trận, hắn bại trận và được Vương Lâm cứu mạng, mất đi áo giáp.","vaiTro":"Hộ vệ tầng chín tháp Ngũ Hành tinh, chiến binh thủy hệ của Quy Nhất tông","tinhCach":"Tự tin vào thực lực phe mình; kiên cường trong chiến đấu; biết tiến biết lui","tabs":{"diem":[{"text":"Tự nhận là hậu nhân bảo vệ tầng chín, tự tin chỉ cần lão tổ tầng trên thức tỉnh là đủ trấn áp đối thủ","chuong":"@c1635"},{"text":"Nổi lên từ biển trong Ngũ Hành thủy trận, dùng bốn bức tường nước vạn trượng và trường thương nước mưa bao vây đối thủ","chuong":"@c1637"},{"text":"Thi triển thần thông Càn Khôn Nhất Tích, lộ hình dạng thật và phản kích quyết liệt","chuong":"@c1638"},{"text":"Bại trận, được Vương Lâm cứu mạng bằng cách truyền sinh cơ vào mi tâm, mất áo giáp","chuong":"@c1640"},{"text":"Thần thức biến thành binh lính đóng vai trên bàn cờ tàn giới thứ ba, được hưởng lợi khi Vương Lâm tiến quân","chuong":"@c1662"}],"kinhLich":[{"mucCt":"gon","text":"Ngồi đối diện Nạp Đa trên tầng chín, tự nhận chỉ là hậu nhân, nói chỉ cần một lão tổ ở tầng trên thức tỉnh là đủ hóa giải tất cả.","anchor":"Chỉ cần một trong mấy lão tổ ở tầng trên thức tỉnh là có thể hóa giải tất cả","bridge":true,"khoang":"@c1635"},{"mucCt":"ky","text":"Nổi lên từ biển trong Ngũ Hành thủy trận, dùng bốn bức tường nước vạn trượng bao vây và trường thương nước mưa huyễn hóa nhấn chìm Vương Lâm cùng người khổng lồ lửa, chín Kỳ Lân trong đại hải. Kiêu ngạo tuyên bố mình là thần tiên trong Ngũ Hành đại trận. Bị Vương Lâm xuất hiện sau lưng vỗ chưởng truyền lực lượng bổn nguyên và khí tức hủy diệt Đạo cổ, ngũ tạng tan nát, xương cốt chia lìa, phun máu bị đánh bay. Nhờ áo giáp phóng sinh cơ khôi phục thương thế. Bí mật áo giáp bị Vương Lâm nhìn thấu: tu vi thực sự không tới bước thứ ba, áo giáp điều khiển ngược người mặc.","anchor":"Chỉ có chút tu vi đó sao.ở nơi này ta chính là Ngũ Hành thủy linh","bridge":true,"khoang":"@c1637"},{"importance":"normal","mucCt":"ky","chuong":"@c1638","tieuDe":"Thi triển Càn Khôn Nhất Tích, lộ hình dạng thật","text":"Bị Vương Lâm yêu cầu cởi giáp đổi mạng, từ chối và lùi xa chuẩn bị phản công. Ném trường thương vào biển, phun máu bắt quyết, dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ nhốt Vương Lâm, thi triển thần thông Càn Khôn Nhất Tích do tổ tiên truyền. Tuôn hết lực lượng áo giáp, thân thể héo rũ nổi đầy mụn mủ, lộ hình dạng thật — bản chất chỉ là tu sĩ thiên nhân tứ suy đã trải bốn lần suy kiếp. Dùng hết sức kêu gọi Nạp Đa trợ giúp, được lực lượng kim hệ bổ sung, tự tin tuyên bố Vương Lâm chết chắc nhưng thực tế đang vô tình giúp đối phương cảm ngộ thủy bổn nguyên.","anchor":"thân thể lập tức héo rũ, vẻ anh tuấn liền trở thành xấu xí, thân thể nổi đầy mụn mủ"},{"mucCt":"vua","text":"Dùng thần thông Càn Khôn Nhất Tích đè ép thủy cầu, phun máu tươi gia tốc co rút nhưng vô tình cung cấp thêm biến hóa bổn nguyên cho Vương Lâm minh ngộ. Sau khi Vương Lâm thu toàn bộ thủy bổn nguyên, run rẩy phun máu cười thảm lảo đảo, bị giữ lại một mình trong trận với Vương Lâm.","anchor":"Thân thể Thủy Tướng run lên, phun một ngụm máu tươi, cười thảm lảo đảo lui lại phía sau vài bước.","bridge":true,"khoang":"@c1639"},{"chuong":"@c1640","importance":"normal","mucCt":"vua","tieuDe":"Được Vương Lâm cứu mạng, mất áo giáp","text":"Bị Vương Lâm bắt lại khi bỏ chạy, được truyền sinh cơ vào mi tâm để ngăn áo giáp hút sạch sinh cơ cuối cùng. Áo giáp bị tháo khỏi thân thể bằng huyết kiếm, quá trình cực kỳ đau đớn. Sau khi tháo giáp, thân thể tràn đầy huyết vụ, cực kỳ suy yếu, biến mất trong Ngũ Hành thủy trận.","anchor":"mang theo vẻ buồn bã uể oải, biến mất trong Ngũ Hành thủy trận"},{"chuong":"@c1662","importance":"bridge","mucCt":"vua","text":"Binh lính do thần thức biến thành đóng vai binh trên bàn cờ tàn giới thứ ba, được hưởng lợi khi Vương Lâm tiến vào phân tán áp chế huyết mạch — binh lính tỏa kim quang, chiến lực tăng mạnh, kim quang ngưng tụ thành giáp vàng đơn giản.","anchor":"kim quang trên thân thể liền lóe lên hóa thành một bộ giáp màu vàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Nạp Đa","tag":"dong-minh","quanHe":"Cùng trấn giữ tầng chín tháp Ngũ Hành tinh, đồng hạng hậu nhân Quy Nhất tông","ghiChu":"@c1635"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tấn công trong thủy trận, bị Vương Lâm đánh bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1635","@c1636","@c1637","@c1638","@c1639","@c1640","@c1662"],"cn":"水将"},{"id":"lao-gia-tinh-niet-trung-ky","name":"Lão già Tịnh Niết trung kỳ","gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông tu vi Tịnh Niết trung kỳ, kích động đám đông bằng bài diễn thuyết xuyên tạc Vương Lâm là kẻ sát nhân tàn ác.","vaiTro":"Tu sĩ Quy Nhất tông, kẻ xuyên tạc kích động đám đông chống Vương Lâm","tinhCach":"Giọng khàn khàn, giỏi kích động; thống hận giả tạo, nước mắt chảy dài","tabs":{"diem":[{"text":"Kích động mấy trăm tu sĩ Quy Nhất tông bằng lời xuyên tạc Vương Lâm giết toàn tộc họ Đằng vì tham bảo vật, vô ơn với Nạp Đa","chuong":"@c1637"}],"kinhLich":[{"mucCt":"vua","text":"Kích động mấy trăm tu sĩ Quy Nhất tông bằng bài diễn thuyết xuyên tạc: vu cho Vương Lâm giết toàn tộc họ Đằng vì tham bảo vật, giết phàm nhân, vô ơn với Nạp Đa trưởng lão. Giọng khàn khàn, nước mắt chảy dài, khiến những tu sĩ không biết Vương Lâm dần tin lời và trở nên phẫn nộ.","anchor":"lão già có tu vi tới Tịnh Niết trung kỳ lúc này hướng về bốn phía rống to một tiếng","bridge":true,"khoang":"@c1637"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng bị xuyên tạc trước đám đông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1637"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1638","tieuDe":"Nhắc tặng giọt thủy bổn nguyên","text":"Được nhắc lại việc từng tặng Vương Lâm một giọt thủy bổn nguyên, trở thành một trong những chỉ dẫn tới đại đạo thủy bổn nguyên.","anchor":"lần trước Thiên Vận Tử tặng một giọt thủy bổn nguyên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được nhắc lại là một bộ phận của thiên đạo, trước kia đã cắn nuốt phách thứ bảy; Vương Lâm xác nhận phách thứ bảy không còn trong thiên đạo hiện tại sau khi U Minh thú nuốt Thiên Vận Tử.","anchor":"Thiên Vận Tử là một bộ phận của thiên đạo"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lần đầu xuất hiện cưỡi tảng đá khổng lồ như sao băng ngang Chu Tước tinh, cứu Vương Lâm khỏi lạc vào cảm ngộ thiên đạo luân hồi, thể hiện tu vi vượt Hóa Thần","chuong":"@c0241"},{"text":"Nhận Vương Lâm làm đệ tử chân chính trong đại thọ vạn năm, mở tâm thần thành thế giới bảy màu chứa 3600 phân thân cho Vương Lâm tự chọn cấm pháp thần thông","chuong":"@c0474"},{"text":"Chủ động hiến phân hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật — âm mưu hai ngàn năm bố cục nhằm chiếm cứ thân xác đệ tử","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: không phải tam hồn thất phách Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo","chuong":"@c1628"},{"text":"Hoàn thành thức tỉnh thứ chín mươi chín, thi triển Luân Hồi nhất thể thuật chiếm cứ phân thân Vương Lâm, nhưng bị Vương Lâm đoạt nửa la bàn bổn tôn và đánh bại","chuong":"@c1629"},{"text":"Bị vạch trần là khí linh La Bàn Định Giới, phản kháng lần cuối dưới dạng hạc đen rồi bị Vương Lâm bóp nát tiêu diệt hoàn toàn","chuong":"@c1975"}]},"nguon":["@c1638","@c1653"],"vaiTro":"Chưởng môn Thiên Vận Tông — bộ phận Thiên Đạo, bổn tôn là nửa nghịch la bàn / khí linh La Bàn Định Giới","tinhCach":"Giỏi tính toán thiên cơ và bố cục dài hạn qua hàng ngàn năm; điềm tĩnh uy nghi khi chủ trì tông môn, giảng đạo; tự tin quyết liệt trước cường địch; che giấu dã tâm thôn phệ dưới thân phận sư tôn","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông, thành viên Liên Minh Trưởng Lão Đoàn, từng nhận Vương Lâm làm đệ tử chân chính nhưng âm thầm bố cục qua lạc ấn, phân hồn và Luân Hồi Toàn Thể Thuật suốt hai ngàn năm. Chân tướng về sau phơi bày: hắn không phải tàn hồn Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải — bổn tôn là nửa nghịch la bàn, một bộ phận của Thiên Đạo, đồng thời là khí linh La Bàn Định Giới. Sau lần thức tỉnh thứ chín mươi chín và ý đồ chiếm cứ phân thân Vương Lâm, hắn bị Vương Lâm đoạt bổn tôn rồi tiêu diệt hoàn toàn."},{"id":"tu-do-nam","name":"Tư Đồ Nam","tabs":{"kinhLich":[{"mucCt":"gon","text":"Bị nữ tử trung niên Quy Nhất tông thề nhắm tới là mục tiêu tiếp theo sau Vương Lâm.","anchor":"Tư Đồ Nam người tiếp theo sẽ là ngươi!","bridge":true,"khoang":"@c1639"},{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ hai của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ hai (xanh) của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi không kiếp. Vương Lâm minh ngộ rằng thiên tư biến hóa kinh người của Tư Đồ Nam là do hắn là phách của Thất Thải Tiên Tôn.","anchor":"Hóa ra hắn là một phách của Thất Thải Tiên Tôn biến thành"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là một trong sáu phách đã biết, cùng Thanh Thủy thuộc nhóm chưa xảy ra biến số, chưa hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Còn Thanh Thủy và Tư Đồ Nam thì lại không có xảy ra biến số này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Thức tỉnh đả tọa, Lam Mộng muốn mượn hồn phách","text":"Trong tiên giới, thức tỉnh từ đả tọa, thần sắc âm trầm yên lặng nhìn phía trước. Nhận được truyền âm từ Lam Mộng Đạo Tôn muốn mượn hồn phách.","anchor":"Tư Đồ Nam thức tỉnh từ đả tọa, thần sắc âm trầm, yên lặng nhìn về phía trước"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Ở tiên giới trầm mặc chú ý tới sự kiện đại môn động phủ giới mở ra, hiểu rằng người đầu tiên đi ra có thể là Thất Thải Tiên Tôn mới.","anchor":"Một số ít người biết được bí ẩn như Tư Đồ Nam và Thanh Thủy thì ở trong tiên giới trầm mặc, chú ý tới nơi này"},{"mucCt":"ky","text":"Ngày thứ hai tới gặp Vương Lâm trên ngọn núi, bước trên gió lạnh, mang bầu rượu. Hỏi chuyển thế đầu thai có được làm vương gia phàm nhân trên Tiên Cương đại lục không. Cười ha hả quyết định rời đi, muốn tới Tiên Cương náo loạn một phen. Dặn Vương Lâm ngàn vạn lần đừng quên đi tìm hắn. Hai người chia sẻ bầu rượu trước lúc chia ly.","anchor":"Lấy thiên tư của lão tử, không đi tới Tiên Cương đại lục náo loạn một phen thì thật sự đáng tiếc","bridge":true,"khoang":"@c1694"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Tiết lộ thân phận cường giả lục cấp Chu Tước Quốc, bị truy sát thân hủy, tinh hoa Nguyên Anh ẩn vào Thiên Nghịch Châu theo sát Vương Lâm","chuong":"@c0047"},{"text":"Đoạt xá thành công thân đồng tử áo đỏ trong khối viêm băng, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh kỳ","chuong":"@c0411"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức trở thành tu sĩ bước thứ ba, tham chiến bảo vệ Chu Tước Tinh","chuong":"@c1520"},{"text":"Được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp","chuong":"@c1650"},{"text":"Được Vương Lâm gửi gắm trọng trách: nếu Vương Lâm chết, bố cáo thiên hạ sự thật và viết thành ngọc giản lưu truyền","chuong":"@c1588"},{"text":"Được Vương Lâm cứu thoát khỏi Đan Hải, chia tay huynh đệ trước biến cố lớn","chuong":"@c1752"}]},"nguon":["@c1639","@c1650","@c1653","@c1655","@c1657","@c1694","@c1697"],"trangThai":"song","cn":"司徒南","gioiTinh":"nam","vaiTro":"Huynh trưởng Vương Lâm — cường giả Chu Tước, phách thứ hai của Thất Thải Tiên Tôn","tinhCach":"Kiêu ngạo ngang tàng, hành sự bá đạo không kiêng nể; tàn nhẫn quyết đoán nhưng trọng nghĩa tình với huynh đệ; nóng nảy bốc đồng, dễ kích động vì người thân; phong lưu phóng khoáng, thích tự do không chịu ràng buộc","blurb":"Tư Đồ Nam vốn là cường giả lục cấp đệ nhất của Chu Tước Quốc, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu, từ đó theo sát Vương Lâm hàng trăm năm, vừa chỉ điểm tu luyện vừa nhiều lần xả thân bảo vệ. Sau khi đoạt xá thành công và phục hồi thực lực, ông trải qua Vấn Đỉnh, Tịnh Niết rồi được Thanh Lâm trợ giúp phá Không Môn bước vào bước thứ ba, cùng Vương Lâm chinh chiến tinh không trong cuộc đại chiến giới nội giới ngoại. Về sau được xác nhận chính là phách thứ hai màu xanh của Thất Thải Tiên Tôn, ẩn chứa toàn bộ tu vi Không "},{"id":"ke-la-dong-xoay-c1640","name":"Kẻ lạ trong dòng xoáy","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"khong-ro","vaiTro":"Nhân vật bí ẩn xuất hiện từ dòng xoáy trong Ngũ Hành thủy trận, uy áp kinh khủng, muốn đoạt áo giáp Thủy Tướng","tinhCach":"Hống hách; coi thường người khác","blurb":"Kẻ bí ẩn giọng già nua, xuất hiện từ dòng xoáy khi Ngũ Hành thủy trận sụp đổ, uy áp kinh khủng. Vươn cánh tay khô héo đoạt áo giáp nhưng bị Vương Lâm đạp nát tay, nhận ra Vương Lâm là tu sĩ cổ quốc.","tabs":{"diem":[{"text":"Uy áp kinh khủng khiến Ngũ Hành thủy trận sụp đổ, nhưng bị Vương Lâm đạp nát cánh tay khi muốn đoạt áo giáp","chuong":"@c1640"}],"kinhLich":[{"mucCt":"gon","text":"Xuất hiện từ dòng xoáy với uy áp kinh khủng, vươn cánh tay khô héo đoạt áo giáp Thủy Tướng nhưng bị Vương Lâm bùng nổ toàn lực đạp nát, xương gãy vụn, cánh tay nổ tung. Nhận ra Vương Lâm là tu sĩ cổ quốc, người cổ tộc.","anchor":"Tu sĩ cổ quốc! Ngươi là người cổ tộc!","bridge":true,"khoang":"@c1640"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đạp nát tay khi đoạt áo giáp","ghiChu":"@c1640"}],"tuiDo":{}},"nguon":["@c1640"]},{"id":"diep-mich","name":"Diệp Mịch","gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1641","importance":"bridge","mucCt":"gon","text":"Được Đệ Cửu lão tổ nhắc tới khi phân tích lai lịch Vương Lâm — lão cho rằng Vương Lâm không phải hậu nhân do ba nghìn huyết mạch của Diệp Mịch biến thành.","anchor":"Hắn không giống như hậu nhân do ba nghìn huyết mạch của Diệp Mịch biến thành"},{"chuong":"@c1672","importance":"normal","mucCt":"ky","tieuDe":"Nguyên thần đoạt xá thất bại, tiêu tán vĩnh viễn","text":"Nguyên thần huyết đầy đủ khiến nguyên thần Diệp Mịch ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm bằng cách hóa khói xông vào thất khiếu. Tuy nhiên Vương Lâm có hồn huyết được cổ Tổ tán thành nên Diệp Mịch không thể đối kháng, sau ba canh giờ tiêu tán hoàn toàn trở thành một bộ phận Đạo cổ truyền thừa của Vương Lâm. Huyền La Đại Thiên Tôn tiết lộ Diệp Mịch xưa rải máu tươi cài nguyên thần huyết nhằm đoạt xá hậu bối truyền thừa, bình thường không thể thất bại nhưng Vương Lâm là ngoại lệ.","anchor":"Diệp Mịch không thể đối kháng, từ từ tiêu tán trở thành một bộ phận của Đạo cổ truyền thừa của Vương Lâm"},{"mucCt":"gon","text":"Cánh tay trái của Diệp Mịch phong ấn trong Đông Lâm Trì đóng băng được Vương Lâm phát hiện và dung hợp thành công, nay Vương Lâm đã có cả hai cánh tay của hắn.","anchor":"Ta sau khi dung hợp cánh tay phải của Diệp Mịch, thuật Tê Thiên đủ để xé tan thân thể tu sĩ bước thứ ba","bridge":true,"khoang":"@c1673"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Cánh tay trái được Vương Lâm dung hợp hoàn toàn, trái tim vẫn nằm ở tầng sâu nhất cổ mộ, được Huyền La Đại Thiên Tôn xác nhận đây là nơi tử vong.","anchor":"Truyền thừa của Diệp Mịch ngoài mắt trái ra thì chỉ còn có trái tim thôi"},{"importance":"normal","mucCt":"vua","chuong":"@c1680","tieuDe":"Trái tim truyền thừa cho Vương Lâm","text":"Trái tim khổng lồ trăm trượng ở tầng cuối vùng đất cổ mộ là di thể của Diệp Mịch. Thần niệm thê lương mang oán hận cực độ đòi Vương Lâm trả mắt trái. Sau khi Vương Lâm hứa ba điều, trái tim chấp nhận đập cùng nhịp, truyền Đạo Cổ khí tức cho Vương Lâm.","anchor":"Trả mắt trái lại cho ta!"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ bùng phát từ chín quan tài trên tấm bia đá khổng lồ, biến đổi giữa ba dạng Cổ Thần – Cổ Ma – Cổ Yêu","chuong":"@c1576"},{"text":"Nguyên thần ẩn trong huyết ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn","chuong":"@c1672"},{"text":"Trái tim khổng lồ trăm trượng ở tầng cuối cổ mộ — di thể cuối cùng mang thần niệm thê lương oán hận — được truyền thừa cho Vương Lâm","chuong":"@c1680"},{"text":"Truyền thừa vẫn thiếu phần mắt trái chưa tìm được, khiến ký ức Vương Lâm nhận từ Diệp Mịch chưa trọn vẹn","chuong":"@c1729"},{"text":"Được Vương Lâm dùng làm mốc suy xét hệ thống lực lượng Cổ Tộc, thực lực được xem là tương đương Thiên Tôn","chuong":"@c1903"}]},"nguon":["@c1641","@c1645","@c1672","@c1673","@c1674","@c1680"],"vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, nguồn gốc sức mạnh thể chất mà Vương Lâm thừa kế","tinhCach":"kiên ngạnh bất khuất, dù thất bại vẫn lưu lại truyền thừa cho hậu nhân; mưu tính thâm viễn, ẩn giấu nguyên thần trong huyết mưu đoạt xá người thừa kế; oán niệm dai dẳng, thần niệm thê lương tồn tại đến tận di thể cuối cùng","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân vùng đất cổ mộ và nguồn gốc toàn bộ truyền thừa thể chất mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong cổ mộ, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh; di thể gồm đầu lâu, hai cánh tay, trái tim cùng lầu các địa phủ chứa ba thần hồn lần lượt được Vương Lâm dung hợp. Nguyên thần ẩn trong huyết từng mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn; trái tim khổng lồ trăm trượng ở tầng sâu nhất cổ mộ mang thần niệm oán hận trở thành di sản truyền th"},{"id":"ba-lao-gia-trong-thap","name":"Ba lão già trong tháp","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Ba cao thủ ẩn ở tầng thứ năm, sáu, bảy của ngọn tháp trên Ngũ Hành tinh. Đồng loạt xuất thủ phá vỡ Cửu Chuyển Tâm Luân đang bị nghịch chuyển, giải cứu tu sĩ Quy Nhất tông.","vaiTro":"Cao thủ ẩn trong tháp Quy Nhất tông trên Ngũ Hành tinh","tinhCach":"Ẩn mình không lộ diện; chỉ ra tay khi tình thế nguy cấp","tabs":{"diem":[{"text":"Ba thân ảnh từ ba tầng tháp đồng loạt lao ra phá trận, thực lực đủ phá Cửu Chuyển Tâm Luân đang nghịch chuyển","chuong":"@c1643"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1643","tieuDe":"Xuất thủ phá Cửu Chuyển Tâm Luân nghịch chuyển","text":"Từ tầng thứ bảy, sáu, năm của ngọn tháp trên Ngũ Hành tinh đồng loạt lao ra, vung tay áo cuốn tinh không phá vỡ trận pháp đang nghịch chuyển, giải cứu tu sĩ Quy Nhất tông.","anchor":"ba thân ảnh của ba lão già hóa thành cầu vồng gào thét lao ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1643"]},{"id":"van-dat-phong","name":"Vân Dật Phong","cn":"云逸风","aliases":["Thanh niên hắc y"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Vân Dật Phong là đệ tử trung tâm đứng thứ ba của Quy Nhất tông trên Tiên Cương đại lục, từng gặp Vương Lâm trong động phủ giới và tự xem hắn là đối thủ ngang sức. Sau khi rời động phủ giới, hắn tỏa sáng khắp bảy mươi hai tiên châu Tiên Tộc, xuất quan đánh bại toàn bộ đệ tử trọng yếu Đại Hồn Môn và được công nhận là đệ nhất cao thủ Thiên Ngưu Châu. Dưới uy áp Huyền La Đại Thiên Tôn vẫn kiên trì không quỳ, lập thề trở thành Đại Thiên Tôn, và liều mình chặn Chiến lão quỷ để trì hoãn cho Vương Lâm, suýt mất mạng.","vaiTro":"Đệ tử trung tâm thứ ba Quy Nhất tông Tiên Cương, đối thủ ngang sức Vương Lâm","tinhCach":"Trầm ổn, tự tin thâm hậu; kiên cường bất khuất trước cường giả; tranh thắng đường đường chính chính; nội tâm phức tạp, nặng tình nghĩa","tabs":{"diem":[{"text":"Dưới uy áp Huyền La Đại Thiên Tôn kiên trì không quỳ cho đến khi phun máu mới sụp xuống, lập thề trở thành Đại Thiên Tôn","chuong":"@c1647"},{"text":"Nuốt đan dược chặn Chiến lão quỷ để trì hoãn cho Vương Lâm, bị phất tay thương thế bộc phát suýt mất mạng","chuong":"@c1680"},{"text":"Xuất quan tu vi bất phàm, khiêu chiến thắng toàn bộ đệ tử trọng yếu Đại Hồn Môn, được công nhận đệ nhất cao thủ Thiên Ngưu Châu","chuong":"@c1706"},{"text":"Đường đường chính chính cưỡi đài khổng lồ đuổi theo Vương Lâm tự xưng tên thách đấu phân cao thấp","chuong":"@c1676"},{"text":"Nổi danh trong chiến tranh trăm năm của Thiên Ngưu Châu nhờ Bát đao thuật","chuong":"@c1816"}],"kinhLich":[{"mucCt":"ky","text":"Bước ra từ tầng thứ tư tháp cao Ngũ Hành tinh, chính là thanh niên Vương Lâm từng gặp trong thiên kiếp ở viễn cổ tiên vực. Thi triển Lục Hoa Ấn triệu sáu đóa hoa đen với sáu cánh tay trắng muốt, giao chiến ngang sức với Vương Lâm. Bị lực Đạo Cổ xâm nhập sinh ra hư ảnh Cổ Thần, Cổ Ma, Cổ Yêu cắn nuốt nguyên thần, phải dùng đan dược đen hóa giải nhưng chậm hơn Vương Lâm vài nhịp thở. Được hé lộ là đệ tử trung tâm thứ ba Quy Nhất tông Tiên Cương, trải vạn cổ trong động phủ giới, thực lực đủ tranh đệ nhất đệ tử.","anchor":"ở trong hàng đệ tử trung tâm đứng vị trí thứ ba","bridge":true,"khoang":"@c1644"},{"chuong":"@c1645","importance":"minor","mucCt":"vua","tieuDe":"Rút lui không can thiệp","text":"Nghe lời lão già trong tháp cao, nhíu mày nhìn Vương Lâm rồi thở dài bỏ đi, không hỏi tới chuyện này nữa. Nội tâm cuồng ngạo ăn sâu cốt tủy, coi việc dùng lời nhục mạ là hạ mình.","anchor":"thở dài một tiếng, thân thể uể oải rời đi, không hỏi tới chuyện này nữa"},{"chuong":"@c1646","importance":"normal","mucCt":"ky","tieuDe":"Phân tích thiên đạo và mục đích Vương Lâm","text":"Đứng bên cạnh lão già họ Mã trên Ngũ Hành tinh. Được hỏi ý kiến, phân tích thiên đạo đã bị phân chia nên Vương Lâm nắm giữ phần không hoàn chỉnh, không thể nuốt người tu vi cao thâm. Suy đoán Vương Lâm đến đây để bức lộ toàn bộ lực lượng ẩn giấu trước khi tìm kiếm hồn thứ ba, đánh giá đối phương là nhân vật đáng gờm. Khi Huyền La Đại Thiên Tôn xuất hiện, thần sắc đại biến, không dám cử động.","anchor":"Vãn bối không tin thiên đạo có thể nuốt được chúng ta"},{"importance":"normal","mucCt":"ky","chuong":"@c1647","tieuDe":"Bị uy áp Huyền La, thề trở thành Đại Thiên Tôn","text":"Dưới uy áp Huyền La Đại Thiên Tôn, kiên trì không quỳ cho đến khi phun máu mới sụp xuống. Được Huyền La khen kiên trì đáng nể nhưng tiếc không phải Đạo cổ nhất mạch. Sau khi Huyền La rời đi, nắm chặt tay thề sẽ trở thành Đại Thiên Tôn, mặt trời thứ mười một. Phân tích chính xác ý đồ Huyền La: đang khảo nghiệm Vương Lâm, muốn bọn họ làm hòn đá mài đao, nếu không tuân lệnh sẽ vĩnh viễn không rời được Ngũ Hành tinh.","anchor":"Sớm muộn gì cũng có ngày ta sẽ trở thành Đại Thiên Tôn, trở thành mặt trời thứ mười một!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1655","tieuDe":"Tiến về La Thiên, muốn phân cao thấp với Vương Lâm","text":"Đi phía sau lão già họ Mã tiến về La Thiên, tuyên bố muốn quyết định cao thấp với Vương Lâm tại trung tâm động phủ giới.","anchor":"Vương Lâm, trận đánh giữa ngươi và ta còn chưa phân thắng bại"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Hoảng sợ trước cung Lý Quảng","text":"Bề ngoài bình tĩnh nhưng nội tâm hoảng sợ khi lần đầu chứng kiến cung Lý Quảng, tự thấy may mắn vì ở Ngũ Hành Tinh không bức Vương Lâm dùng cung, nhận định bản thân hoàn toàn không có khả năng chống cự.","anchor":"đối với cây cung này hắn không có một chút khả năng chống cự dù chỉ là một tiễn"},{"mucCt":"ky","text":"Cưỡi đài khổng lồ bao phủ cầu vồng đuổi theo Vương Lâm, tự xưng tên thách đấu đường đường chính chính, yêu cầu không dùng âm mưu quỷ kế và cây cung Lý Quảng. Đưa thệ huyết cam kết nếu thua sẽ nghe lệnh. Thi triển Bát Đao Trảm Thần Hồn phân thân bảy, bảy đao nối thành đao thứ tám, nhưng bị Vương Lâm dùng Tê Thiên Thuật đại thành phá tan hoàn toàn. Thừa nhận thua, thệ huyết hoá lời thề ràng buộc. Nhận lệnh Vương Lâm uống đan dược thi triển lại Bát Đao Trảm Thần Hồn tấn công Chưởng Tôn, được Đường San thi triển bảy kim môn phòng hộ lên người.","anchor":"Vân Dật Phong cũng là một quân tử, hắn không hề có mánh khoé gì ở trên thệ huyết này","bridge":true,"khoang":"@c1676"},{"mucCt":"vua","text":"Thi triển Bát Đao Trảm Thần Hồn Thuật phối hợp Đường San tấn công Chưởng Tôn, bảy đao bị phá nhưng đao thứ tám xông qua. Bị Chưởng Tôn đánh bại, bảy kim môn sụp đổ, phun máu bị thương nặng. Sau khi thấy Huyền La biến kim ấn thành pháp bảo thực chất, mắt hiện vẻ hoảng sợ rồi vội vàng cúi đầu — biểu cảm bị Vương Lâm nhìn thấy rõ.","anchor":"trong mắt hắn hiện lên vẻ hoảng sợ, lập tức nghĩ tới điều đó, vội vàng cúi đầu","bridge":true,"khoang":"@c1677"},{"mucCt":"vua","text":"Thi triển thần thông hóa con khỉ màu tím tấn công Chưởng Tôn, ác hầu theo thất khiếu nhập thể hắn. Sau đó thi triển thần thông mạnh nhất, phun máu rơi xuống đất.","anchor":"thần thông của Vân Dật Phong hóa thành thừa dịp Chưởng Tôn đang đối kháng","bridge":true,"khoang":"@c1678"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang kéo dung hợp góp sức phong ấn Chưởng Tôn, khi Dĩ Ti hiện hình lộ vẻ hoảng sợ.","anchor":"Ngay cả Vân Dật Phong kia cũng hít sâu, ánh mắt lộ ra vẻ hoảng sợ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Nuốt đan dược chặn Chiến lão quỷ","text":"Cười khổ, nói Mã sư thúc cũng sẽ ra tay giúp Vương Lâm trì hoãn. Nuốt đan dược, tay phải chụp hư không hình thành áo giáp ngũ hành quang, ở lại chặn Chiến lão quỷ.","anchor":"xuất ra một nắm lớn đan dược, nuốt lấy, tay phải giơ lên chụp vào khoảng không một cái"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bị Chiến lão quỷ phất tay, thương thế bộc phát suýt mất mạng, hai mắt nhắm nghiền bất động.","anchor":"Vân Dật Phong sắc mặt xám như tro tàn, hai mắt nhắm nghiền không nhúc nhích"},{"chuong":"@c1690","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ, ánh mắt phức tạp nhìn Vương Lâm phong ấn lưỡng hồn Thất Thải.","anchor":"Bọn họ thật không ngờ Vương Lâm này lại còn một chiêu như vậy."},{"mucCt":"vua","text":"Nội tâm phức tạp, không phân biệt Tiên Cương hay Ngũ Hành Tinh là nhà. Lưu luyến nhìn bốn phía, ôm quyền hẹn Vương Lâm phân thắng bại ở Tiên Cương đại lục rồi bay vào kim môn.","anchor":"Vương huynh, bảo trọng! Trận đánh của ngươi và ta còn chưa chấm dứt, ở Tiên Cương đại lục hẹn sẽ phân thắng bại","bridge":true,"khoang":"@c1691"},{"chuong":"@c1701","importance":"bridge","mucCt":"gon","text":"Nổi bật như thiên tài trên bảy mươi hai tiên châu Tiên Tộc sau khi rời động phủ giới xuất hiện tại Thất Đạo Tông.","anchor":"Một trong số đó tên là Vân Dật Phong!"},{"importance":"bridge","chuong":"@c1702","text":"Là nhân tài đang tỏa sáng của Quy Nhất Tông và vẫn nhớ tới Vương Lâm.","anchor":"nhân tài đang tỏa sáng của Quy Nhất Tông Vân Dật Phong cũng nhớ tới Vương Lâm"},{"mucCt":"vua","text":"Xuất quan tu vi bất phàm, khiêu chiến thắng toàn bộ đệ tử trọng yếu Đại Hồn Môn. Mười năm trước một kiếm quét ngang đả thương chín đệ tử, ba trưởng lão Đại Hồn Môn. Tuyên bố dám đánh tứ đại thiên tài Đông Châu nhưng trước một tu sĩ tu đạo hơn hai ngàn năm thì không dám xuất kiếm, và người đó sẽ xuất hiện.","anchor":"Nhưng ở thiên địa này cũng là có một tu sĩ tu đạo hơn hai ngàn năm, ta ở trước mặt của hắn. Ta không dám xuất kiếm!","bridge":true,"khoang":"@c1706"},{"chuong":"@c1722","importance":"normal","mucCt":"vua","tieuDe":"Được Đỗ Thanh nhắc tới — đệ nhất cao thủ Thiên Ngưu Châu","text":"Được Đỗ Thanh giới thiệu với Vương Lâm là đệ nhất cao thủ Thiên Ngưu Châu (trừ lão quái), thiên phú tuyệt luân. Từng công khai tuyên bố trong thiên địa có người tu đạo hơn hai ngàn năm mà tu vi sâu không thể lường, đứng trước mặt người đó không dám xuất kiếm, tứ đại thiên tài Đông Châu không xứng xưng thiên tài.","anchor":"Người này từng nói trong thiên địa có người tu đạo hơn hai ngàn năm mà tu vi đã sâu không thể lường được"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ ngang sức","ghiChu":"Giao chiến ngang tay tại Ngũ Hành tinh"},{"ten":"Lão già tóc bạc tầng ba","tag":"cap-tren","quanHe":"Cấp trên trên Ngũ Hành tinh, được lão hỏi ý kiến phân tích"},{"ten":"Lão già họ Mã","tag":"cap-tren","quanHe":"Cấp trên / cường giả cùng phe trên Ngũ Hành tinh","ghiChu":"Đứng bên cạnh lão phân tích tình hình khi được hỏi ý kiến"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Đối thủ, nhận lệnh Vương Lâm tấn công","ghiChu":"Thi triển Bát Đao Trảm Thần Hồn nhằm vào Chưởng Tôn"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Đan dược màu đen","moTa":"Dùng để hóa giải lực Đạo Cổ xâm nhập nguyên thần, tốc độ chậm hơn Đạo Cổ bất diệt thể","nguon":"@c1644"}],"congPhap":[{"ten":"Lục Hoa Ấn","moTa":"Ấn quyết triệu sáu đóa hoa đen và sáu cánh tay, giao chiến ngang sức Vương Lâm","nguon":"@c1644"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1645","@c1646","@c1647","@c1655","@c1669","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1690","@c1691","@c1701","@c1702","@c1706","@c1722"]},{"id":"lao-gia-kim-bao","name":"Lão già kim bào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông trên Ngũ Hành tinh, bị thương nặng trong nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen. Khi nghe Vương Lâm nói thì thần sắc đại biến, khóe miệng tràn máu tươi.","vaiTro":"Tu sĩ Quy Nhất tông Ngũ Hành tinh, bị thương nặng","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Bị thương nặng trong nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen, khi nghe Vương Lâm nói thì thần sắc đại biến thổ huyết","chuong":"@c1644"}],"kinhLich":[{"chuong":"@c1644","importance":"bridge","mucCt":"vua","text":"Đã bị thương nặng sau nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen. Khi nghe Vương Lâm nói thần sắc đại biến, khóe miệng tràn máu tươi.","anchor":"thần sắc lão già kim bào bỗng nhiên đại biến"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Bị Vương Lâm khiêu chiến, thổ huyết khi nghe lời"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644"]},{"id":"ba-nam-tu-trung-nien-tien-cuong","name":"Ba nam tử trung niên Tiên Cương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Ba tu sĩ cổ đại từ Tiên Cương đại lục, tồn tại vô số năm trong tháp Ngũ Hành tinh, khí tức tang thương. Nhận ra Vương Lâm thuộc Đạo Cổ nhất mạch, đồng loạt ra tay nhưng bị lực trùng kích đẩy lui.","vaiTro":"Tu sĩ cổ đại Quy Nhất tông Tiên Cương ẩn trong tháp Ngũ Hành tinh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Ba người đồng loạt ra tay: một hóa cự long chín màu, một hóa quỷ ảnh khổng lồ, một thi triển Ngũ Hành — nhưng đều bị lực trùng kích từ hư ảnh Đạo Cổ sụp đổ đẩy lui","chuong":"@c1644"}],"kinhLich":[{"mucCt":"vua","text":"Nhận ra Vương Lâm thuộc Đạo Cổ nhất mạch, ba người đồng loạt ra tay — một hóa cự long chín màu, một hóa quỷ ảnh khổng lồ, một thi triển Ngũ Hành. Bị lực trùng kích từ hư ảnh Đạo Cổ sụp đổ đẩy lui mấy trăm trượng, không kịp ngăn Vương Lâm phá tháp.","anchor":"Ba người đồng thời cất bước, lao thẳng tới Vương Lâm","bridge":true,"khoang":"@c1644"},{"chuong":"@c1646","importance":"normal","mucCt":"gon","tieuDe":"Bị uy áp Đại Thiên Tôn đánh bật","text":"Bị uy áp Huyền La Đại Thiên Tôn khiến phun máu tươi, bật bay.","anchor":"Mới vừa rồi các ngươi dám nói Đạo cổ nhất mạch đều là đám người hoang dã sao"},{"mucCt":"vua","text":"Xuất hiện dưới dạng hư ảo ngồi khoanh chân đối diện Bạch Hổ chiến tướng trên bầu trời, thần sắc bối rối, trán đầy mồ hôi. Hóa thân thế tục là binh lính thiết giáp tàn phá phía đối địch. Mong thêm người đến để cùng giết Bạch Hổ chiến tướng.","anchor":"Đến đây đi, nhiều thêm vài người nói không chừng có thể g**t ch*t Bạch Hổ chiến tướng này!","bridge":true,"khoang":"@c1661"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Bị Vương Lâm đánh lui bằng lực trùng kích hư ảnh Đạo Cổ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1646","@c1661"]},{"id":"lao-gia-tang-thu-ba","name":"Lão già tầng thứ ba","cn":"","aliases":["Lão già tầng ba","Lão già họ Mã","Mã Lương"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (mạnh hơn Chưởng Tôn, đã trải qua mấy lần huyền kiếp)","trangThai":"song","blurb":"Cường giả ẩn trong ba tầng tháp gốc từ Tiên Cương, chưa lộ diện, chỉ phát ra giọng nói già nua uy nghiêm. Tự tin sỉ nhục Đạo Cổ nhất mạch là nhánh yếu nhất, gọi cả sư tôn Vương Lâm là đám tu sĩ thế tục hoang dã. Lời nói hóa thành pháp tắc, uy thế cực mạnh.","vaiTro":"Cường giả ẩn trong tháp gốc Ngũ Hành tinh, sỉ nhục Đạo Cổ nhất mạch","tinhCach":"Uy nghiêm; cao ngạo; coi thường Đạo Cổ nhất mạch","tabs":{"diem":[{"text":"Giọng nói uy nghiêm như sấm dậy, lời nói hóa thành pháp tắc — cho thấy thực lực cực kỳ mạnh","chuong":"@c1644"},{"text":"Sỉ nhục cả Đạo Cổ nhất mạch mà không biết Huyền La Đại Thiên Tôn đang nghe","chuong":"@c1644"},{"text":"Tinh thông mộc và thổ Ngũ Hành, dùng roi xanh biếc hấp thu sinh cơ cây cỏ bổ sung bổn nguyên làm vũ khí","chuong":"@c1645"},{"text":"Khoác áo giáp Quy Nhất tông (mộc + thổ) tu vi tăng vọt nhưng chịu phản phệ nhánh cây chui vào da thịt","chuong":"@c1645"}],"kinhLich":[{"mucCt":"vua","text":"Sau khi tháp bị Vương Lâm phá sập bốn tầng dưới, từ ba tầng gốc còn lại phát ra giọng nói già nua uy nghiêm, gọi Vương Lâm là tiểu bối hoang dã Đạo Cổ, sỉ nhục cả Đạo Cổ nhất mạch là nhánh yếu nhất, kể cả sư tôn Vương Lâm tới cũng chỉ là đám tu sĩ thế tục hỗn tạp hoang dã.","anchor":"Tiểu bối hoang dã Đạo cổ, ngươi là người của nhánh yếu nhất trong Đạo cổ nhất mạch","bridge":true,"khoang":"@c1644"}],"tuViMoc":[{"chuong":"@c1645","canhGioi":"Không Huyền trung kỳ bước ba","text":"Tu vi gốc Không Huyền trung kỳ bước ba, khoác áo giáp Quy Nhất tông tăng lên Không Huyền hậu kỳ đỉnh phong.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Sỉ nhục Vương Lâm và Đạo Cổ nhất mạch"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1645","@c1646"]},{"id":"lao-gia-mac-song-hanh-khai","name":"Lão già mặc song hành khải","aliases":["Lão già mất áo giáp"],"trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1636","importance":"normal","mucCt":"vua","tieuDe":"Thỉnh tiên tổ chiến giáp, chuẩn bị dùng thủy trận bức Vương Lâm","text":"Thỉnh tiên tổ chiến giáp — bộ áo giáp xanh nước biển lan sóng nước xuất hiện trên thân, triệu hồi thanh trường thương sóng nước. Tuyên bố dùng Ngũ Hành thủy trận bức Vương Lâm ra khỏi trận pháp tiến vào cửu chuyển, nhờ Nạp Đa áp trận rồi hóa hơi nước tiêu tán.","anchor":"Trận tiếp theo là Ngũ Hành thủy trận. Ta sẽ thử xem có thể bức hắn ra khỏi trận pháp, trực tiếp tiến vào cửu chuyển hay không."},{"chuong":"@c1646","importance":"normal","mucCt":"vua","tieuDe":"Bị Huyền La Đại Thiên Tôn bóp cổ, phá nát giáp","text":"Cung kính đứng im khi lão già họ Mã trầm ngâm. Bị Huyền La Đại Thiên Tôn bóp cổ, bộ song hành giáp trên người bị phá nát vỡ vụn như tờ giấy vì trước đó đã nói bất kính về Đạo cổ nhất mạch.","anchor":"Song hành giáp cường hãn trên người lão già này yếu ớt giống như một tờ giấy, ầm ầm vỡ vụn"},{"importance":"normal","mucCt":"gon","chuong":"@c1647","tieuDe":"Bị Huyền La Đại Thiên Tôn giết chết","text":"Bị Huyền La Đại Thiên Tôn vuốt tay giết chết, hóa thành máu huyết tiêu tán.","anchor":"Lão già đã mất đi áo giáp lúc này hóa thành một đám máu huyết tiêu tán trong tay Huyền La Đại Thiên Tôn"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1646","@c1647","@c1636"],"gioiTinh":"nam"},{"id":"ma-luong","name":"Mã Lương","aliases":["Lão già họ Mã","Lão già tóc bạc tầng ba"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1646","importance":"major","mucCt":"ky","tieuDe":"Huyền La Đại Thiên Tôn giáng lâm, Mã Lương hoảng sợ","text":"Sau khi Vương Lâm rời đi, sắc mặt âm trầm nhìn bầu trời, do dự muốn đuổi theo nhưng kiêng dè. Nghe Vân Dật Phong phân tích thiên đạo của Vương Lâm không hoàn chỉnh, không thể nuốt được người tu vi cao thâm, đồng ý đối phương có chuẩn bị khác. Đang muốn quay về tháp cao thì Huyền La Đại Thiên Tôn giáng lâm Ngũ Hành tinh — run rẩy nhận ra danh tính đối phương, phun máu tươi, sợ hãi ngập trời.","anchor":"Lão già họ Mã phun một ngụm máu tươi, thân thể lảo đảo lùi lại phía sau, sự sợ hãi trong mắt đã trở nên ngập trời"},{"mucCt":"vua","text":"Không chống nổi uy áp Huyền La Đại Thiên Tôn, quỳ gối bỏ cuộc. Phân tích rằng Diệp Mịch năm đó tử vong trong động phủ giới, ba nghìn máu tươi hóa thành tam tộc cổ, Vương Lâm đạt truyền thừa Diệp Mịch nên Huyền La mới chú ý. Nhận định kế hoạch Quy Nhất tông ở Ngũ Hành tinh đã thất bại hoàn toàn.","anchor":"Kết hợp với chuyện Diệp Mịch năm đó tử vong sau khi tiến vào động phủ giới, ba nghìn máu tươi hóa thành tam tộc cổ","bridge":true,"khoang":"@c1647"},{"importance":"bridge","mucCt":"gon","chuong":"@c1655","tieuDe":"Dẫn nhóm Ngũ Hành tinh tiến về La Thiên","text":"Cầm đầu nhóm người trên Ngũ Hành tinh ẩn thế, do dự rồi thầm than, dẫn đầu tiến về La Thiên.","anchor":"dưới sự cầm đầu của lão già họ Mã, đám người này sau khi do dự một chút liền thầm than"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Cầm đầu đám người Ngũ Hành tinh xuất hiện cuối cùng trước đại môn, khiến mọi người chấn động.","anchor":"đám người Ngũ Hành tinh do lão già họ Mã cầm đầu"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Cầm đầu nhóm người Ngũ Hành tinh, là nhóm cuối cùng miễn cưỡng tiến vào đại môn.","anchor":"Người Ngũ Hành tinh do lão già họ Mã cầm đầu"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Đang đào bộ giáp từ xác người khổng lồ Cự Ma tộc thì bỏ ngang để đuổi theo hạt châu phát sáng bay qua","chuong":"@c0101"},{"text":"Bị Hứa Hạo và Cát Dương phục kích; dâng túi trữ vật cầu sống nhưng vẫn bị Cát Dương giết chết, thân xác sau đó bị Vương Lâm đoạt xá","chuong":"@c0103"},{"text":"Vương Lâm dùng thân phận Mã Lương được Phượng Loan lão tổ Nguyên Anh sơ kỳ (Chiến Thần Điện) chính thức thu làm ký danh đệ tử","chuong":"@c0119"}]},"nguon":["@c1647","@c1655","@c1656","@c1657","@c1646"],"vaiTro":"Nhân vật phụ — đệ tử Chiến Thần Điện, thân xác bị Vương Lâm đoạt xá","tinhCach":"Nhiều kinh nghiệm chiến trường, dày dạn sinh tồn; tham lợi, bỏ mục tiêu hiện tại để đuổi theo bảo vật; tham sống sợ chết, sẵn sàng dâng hết tài sản cầu sống","blurb":"Mã Lương là đệ tử Chiến Thần Điện xuất thân từ Hỏa Phần Quốc, có hơn 30 năm kinh nghiệm tại chiến trường ngoại vực. Khi đang đào bộ giáp từ xác Cự Ma tộc, hắn bỏ giáp đuổi theo hạt châu phát sáng bay qua nhưng bị Hứa Hạo và Cát Dương phục kích, dâng cả túi trữ vật cầu sống vẫn bị giết. Thân xác hắn sau đó trở thành vật chủ cho Vương Lâm đoạt xá, và nhờ thân phận này Vương Lâm được Phượng Loan lão tổ thu làm ký danh đệ tử Chiến Thần Điện."},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Nằm hôn mê trong Tỵ Thiên Quan trên tiên giới, được Vương Lâm mở nắp vuốt ve khuôn mặt, nước mắt hắn rơi ướt y phục. Vương Lâm xác nhận một phần hồn phách của nàng đã bị mất, trong thiên kiếp cũng không tìm được, thề sẽ thu hồi bằng mọi giá. Trong mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại: nàng bị trưởng lão Tuyên Vũ Viên đuổi giết, tiểu đội mười ba người đều chết, y sam bị xé, nàng cầu cứu Vương Lâm và tiết lộ có Thiên Ly Đan để hắn có lý do ra tay. Sau khi được cứu, nàng sợ hãi trước sức mạnh áp đảo, lui hơn trăm trượng cúi đầu tạ ơn rồi rời đi.","anchor":"Một phần hồn phách của nàng đã bị mất.trong thiên kiếp cũng không","bridge":true,"khoang":"@c1648"},{"importance":"bridge","mucCt":"vua","chuong":"@c1649","tieuDe":"Say ngủ trong Tỵ Thiên Quan","text":"Đang say ngủ trong Tỵ Thiên Quan suốt đêm trăng, được Vương Lâm giữ bên cạnh, sáng sớm Vương Lâm thì thầm rồi thu Tỵ Thiên Quan lại.","anchor":"Tỵ Thiên Quan hóa thành một đám u quang tiêu tán trước mặt hắn, bị hắn trân trọng thu lại"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Được Vương Lâm hứa đánh thức ở Tiên Cương","text":"Được Vương Lâm nhớ tới khi nhìn kim môn, hứa sẽ khiến nàng thức tỉnh ở Tiên Cương đại lục.","anchor":"Uyển nhi, cánh cửa do đã bị ta mở ra rồi. Ở nơi đó ta sẽ có thể khiến nàng thức tỉnh"},{"chuong":"@c1692","importance":"major","mucCt":"vua","tieuDe":"Hồn không hoàn chỉnh, năm phần mười cơ hội sống","text":"Huyền La tiết lộ hồn nàng không hoàn chỉnh, một phần đã biến mất không dấu vết, không thể chuyển thế đầu thai. Chỉ có năm phần mười cơ hội được Vương Lâm mang trực tiếp tới Tiên Cương đại lục, thất bại thì cả hai tử vong.","anchor":"Có điều rất kỳ quái đó là hồn của nàng không hoàn chỉnh, có một phần đã biến mất"},{"chuong":"@c1693","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tuyên bố nếu không đồng sinh thì cộng tử, vô hối — khẳng định là người duy nhất không ai thay thế được ngoài mẫu thân.","anchor":"đối với Vương Lâm không ai có thể thay thế được vị trí của Lý Mộ Uyển"},{"chuong":"@c1700","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Hồn phách trong Tị Thiên Quan được Vương Lâm đặt sau lưng bảo vệ bằng toàn bộ lực lượng trong hành trình xuyên hư vô tới Tiên Cương đại lục.","anchor":"Nhất là mục đích của Vương Lâm là mang theo hồn phách của Lý Mộ Uyển đi ra cho nên hắn lại càng không thể để mình lạc lối"},{"chuong":"@c1701","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm bảo vệ phía sau suốt hành trình xuyên vùng hư không pháp tắc Tiên Cương.","anchor":"hắn phải bảo vệ thê tử ở phía sau, bảo vệ Lý Mộ Uyển"},{"importance":"bridge","chuong":"@c1702","text":"Nằm trong Tị Thiên Quan tràn ngập vết nứt, được Vương Lâm dùng thân thể bảo vệ giữa hư vô.","anchor":"hắn có thể cảm thấy sự tồn tại của Lý Mộ Uyển"},{"chuong":"@c1704","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm mang theo trong Tị Thiên Quan, cưỡi Văn Thú lao về cửa ra hư vô.","anchor":"Vương Lâm mang theo Lý Mộ Uyển trong Tị Thiên Quan đi sâu vào trong hư vô, hướng về cửa ra lao vút đi!"},{"chuong":"@c1705","importance":"bridge","mucCt":"vua","text":"Suốt hành trình hư vô được Vương Lâm dồn toàn bộ tu vi bảo vệ, nằm trong Tị Thiên Quan như say ngủ, được cõng trên lưng xông vào Tiên Cương đại lục.","anchor":"Nàng nằm trong Tị Thiên Quan giống như đang say ngủ."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công linh đan trong lúc động phủ bị mười tu sĩ Kết Đan kỳ công phá","chuong":"@c0127"},{"text":"Chia tay Vương Lâm sau bốn năm đồng hành tại Tu Ma Hải, để lại hơn 18.000 ngọc giản đan phương và bản mệnh tinh huyết kèm thần thức hộ thể","chuong":"@c0137"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt, thân xác hóa xương khô, kim đan nứt vỡ; nguyên anh đầu thai thành bé gái Chu Như qua bức tranh Sinh Tử Luân Hồi","chuong":"@c0313"},{"text":"Sau chín mươi năm trong thân Chu Như, thức tỉnh rồi tự đẩy nguyên anh ra, từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","chuong":"@c0381"},{"text":"Tàn hồn được Vương Lâm tách khỏi thân Tống Trí suốt gần hai năm, hồn phách hoàn chỉnh trở lại","chuong":"@c1929"},{"text":"Được hồi sinh nhờ Vương Lâm nghịch chuyển năm tháng, mở mắt tỉnh lại và cùng hắn rời đi sống bình thường","chuong":"@c1975"}]},"nguon":["@c1648","@c1649","@c1691","@c1692","@c1693","@c1700","@c1701","@c1702","@c1704","@c1705"],"cn":"李慕婉","aliases":["Uyển Nhi"],"vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp, sáng tạo linh hoạt trong chiến đấu; nặng tình sâu sắc với Vương Lâm, kiên trinh suốt trăm năm ly biệt; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải trước khi chia tay. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô; nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như, nhưng nàng tự đẩy nguyên anh ra để bảo toàn sinh mệnh Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt gần bảy trăm năm. Tàn hồn nàng sau đó được phát hiện dung nhập trong thân Tống Trí, trải qua gần hai n"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1648","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc đến trong lúc độc thoại bên Lý Mộ Uyển, xác nhận hắn đã tiếp nhận nàng nhưng mang cảm giác tội lỗi.","anchor":"Uyển Nhi, ta đã tiếp nhận Lý Thiến Mai rồi, xin lỗi nàng"},{"importance":"bridge","mucCt":"vua","chuong":"@c1649","tieuDe":"Lặng lẽ quan sát Vương Lâm rồi rời đi","text":"Cùng phụ thân đứng trên ngọn núi xa quan sát Vương Lâm bên Lý Mộ Uyển trong đêm trăng, quay người dần đi xa, bóng lưng cô độc.","anchor":"Thân ảnh nữ tử kia lại càng như thế"},{"importance":"normal","mucCt":"ky","chuong":"@c1694","tieuDe":"Hẹn ước với Vương Lâm, quyết chuyển thế đầu thai","text":"Mặc bạch y tới gặp Vương Lâm ngày thứ chín, gầy đi, thần sắc bi thương nhưng cố chấp. Ba lần hỏi có nên đi hay không, giọng run rẩy. Phụ thân không muốn rời đi, muốn ở lại với mẫu thân, nàng phân vân giữa ở lại với phụ thân hay đi chờ Vương Lâm. Khi Vương Lâm nắm tay và hứa sẽ tìm nàng trên Tiên Cương, giải khai ký ức bị che phủ, nước mắt nàng rơi, cuối cùng kiên định sẽ đi và chờ.","anchor":"Đợi ta tìm được nàng, đợi ta giải khai ký ức bị che phủ của nàng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1695","text":"Ngẩng đầu nhìn lại Mộc Băng Mi trên mặt đất rồi phóng theo Vương Lâm rời đi.","anchor":"Lý Thiến Mai ở bên trong ngẩng đầu nhìn lại Mộc Băng Mi trên mặt đất"},{"importance":"bridge","mucCt":"gon","chuong":"@c1696","tieuDe":"Bị Mộng Đạo Thuật phong ấn ký ức","text":"Nằm trong số mọi người bị Mộng Đạo Thuật của Vương Lâm bao phủ, nhắm mắt đắm chìm vào mộng.","anchor":"Dần dần, mọi người bao gồm cả Lý Thiến Mai toàn bộ đều nhắm hai mắt lại"},{"chuong":"@c1697","importance":"normal","mucCt":"vua","tieuDe":"Nguyện chờ trong luân hồi, chuyển thế đầu thai","text":"Là người cuối cùng rời đi, mỉm cười nói sẽ chờ Vương Lâm, nếu chàng không tìm được thì nàng sẽ ở trong luân hồi hết lần này tới lần khác. Bước vào đại môn chuyển thế.","anchor":"Ta sẽ chờ chàng. Nếu chàng không tìm được, ta sẽ ở trong luân hồi, hết lần này tới lần khác"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"Người yêu, hẹn ước tìm lại trên Tiên Cương đại lục","ghiChu":"Vương Lâm nắm tay hứa sẽ giải khai ký ức @c1694"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người cô thề chờ đợi trong luân hồi","ghiChu":"Từ biệt trước khi chuyển thế @c1697"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên, đạo, ý — khởi đầu mối tri kỷ xuyên suốt","chuong":"@c1096"},{"text":"Bất chấp tông lệnh và cảnh cáo đào ngũ, rời chiến trường Yêu Tông sau trăm năm chém giết mãnh thú để tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông vây khốn, phá trận pháp rời tông, bị đoạn tuyệt sư đồ vĩnh viễn","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã đến kiệt quệ mất trí nhớ","chuong":"@c1214"},{"text":"Nguyện chuyển thế đầu thai chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi với nụ cười","chuong":"@c1697"},{"text":"Sau khi đầu thai, cố ý ẩn mình không tản ấn ký, lặng lẽ chúc phúc Vương Lâm từ xa","chuong":"@c1969"}]},"nguon":["@c1648","@c1649","@c1694","@c1695","@c1696","@c1697"],"canhGioiCaoNhat":"khong-ro","vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi; tính đến chương gần nhất, Vương L","cn":"李倩梅"},{"id":"truong-lao-tuyen-vu-vien","name":"Trưởng lão Tuyên Vũ Viên","aliases":["Nam tử dâm tà trong mộng ảo"],"gioiTinh":"nam","trangThai":"tu-vong","vaiTro":"Trưởng lão Tuyên Vũ Viên song tu môn, bị Vương Lâm giết trong quá khứ khi đuổi giết Lý Mộ Uyển","tinhCach":"Dâm tà, tàn nhẫn, giết cả tiểu đội mười ba người để cướp Thiên Ly Đan","blurb":"Trưởng lão của Tuyên Vũ Viên song tu môn, mặt mày trắng trẻo vẻ dâm tà. Đuổi giết Lý Mộ Uyển hơn hai ngàn năm trước ở hải ngoại, giết cả tiểu đội mười ba người và xé y sam nàng để cướp Thiên Ly Đan, bị Vương Lâm chỉ liếc mắt phá tan phi kiếm rồi vỡ tung mà chết.","theLuc":[{"ten":"Tuyên Vũ Viên","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Trưởng lão dâm tà đuổi giết Lý Mộ Uyển vì Thiên Ly Đan, bị Vương Lâm giết chỉ bằng một cái liếc mắt","chuong":"@c1648"}],"kinhLich":[{"chuong":"@c1648","importance":"normal","mucCt":"gon","tieuDe":"Đuổi giết Lý Mộ Uyển, bị Vương Lâm giết","text":"Trong mộng ảo tái hiện quá khứ: đuổi giết Lý Mộ Uyển sau khi giết cả tiểu đội mười ba người và xé y sam nàng vì biết nàng có Thiên Ly Đan. Thi triển tám thanh phi kiếm tấn công Vương Lâm nhưng bị hắn liếc mắt phá tan, phun máu rồi bị lực vô hình cuốn vỡ tung chết.","anchor":"mặt mày trắng trẻo, vẻ mặt dâm tà, không nhanh không chậm đuổi theo nữ tử này"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"doi-thu","quanHe":"Mục tiêu truy sát vì Thiên Ly Đan"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm giết khi đang đuổi giết Lý Mộ Uyển"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1648"]},{"id":"thanh-thuy","name":"Thanh Thủy","aliases":["Triệu Thanh Thủy"],"tabs":{"kinhLich":[{"mucCt":"ky","text":"Đang dạy Hồng Điệp tu luyện trong sơn cốc phía bắc tiên giới, cảm ứng thần thức Vương Lâm lập tức tới gặp. Chủ động thừa nhận biết bản thân là do một phách của Thất Thải Tiên Tôn biến thành, nói đã tìm được đáp án ở Thất Thải Giới nhưng trước đây không muốn thừa nhận nên không mở miệng. Khoanh chân ngồi trước Vương Lâm, nói động thủ đi, toàn lực hỗ trợ. Bị Hồn Phiên mặt quỷ cắn nuốt cùng Vương Lâm, thần thức tiến vào thời vạn cổ truy tìm hồn thứ ba.","anchor":"Ta biết bản thân là do một phách biến thành.tha lỗi cho ta đã không nói chuyện này với ngươi","bridge":true,"khoang":"@c1649"},{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn","text":"Trong huyễn cảnh tầng một, tái hiện cảnh năm xưa Thanh Thủy tàn sát hoàng cung phàm gian đã hại gia đình hắn, giết lão già mặc hoàng bào, phóng hồng quang từ đôi mắt tiêu diệt mấy trăm tu sĩ thượng cổ. Sau khi đại cừu đã báo, hắn không hề sung sướng, nhắm mắt rơi nước mắt, sát khí tiêu tán. Được Vương Lâm an ủi, cùng chuyển sang tầng hai. Được xác nhận chính là phách thứ nhất (đỏ đậm) của Thất Thải Tiên Tôn, phách chủ sát, ẩn chứa sát lục cả đời.","anchor":"Thân ảnh đó đúng là Thanh Thủy"},{"chuong":"@c1652","importance":"normal","mucCt":"gon","tieuDe":"Tỉnh lại cùng Vương Lâm trong động phủ giới","text":"Ở tầng huyễn cảnh thứ nhất, mở mắt nhìn Vương Lâm thở dài. Sau ba bước lùi của Vương Lâm, huyễn cảnh sụp đổ hoàn toàn, cả hai đồng thời tỉnh lại trong động phủ giới trên đỉnh núi.","anchor":"Thanh Thủy mở đôi mắt, nhìn Vương Lâm, than nhẹ một tiếng."},{"importance":"bridge","mucCt":"vua","chuong":"@c1653","tieuDe":"Rời đi sau khi biết thân phận hồn thứ ba","text":"Đứng dậy nhìn Vương Lâm, biết thân phận hồn thứ ba và mối liên hệ với hắn, thầm than rồi cất bước rời đi. Được Vương Lâm liệt kê là một trong sáu phách đã biết, thuộc nhóm chưa xảy ra biến số, chưa hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Còn Thanh Thủy và Tư Đồ Nam thì lại không có xảy ra biến số này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Cảm nhận tiếng gọi, Lam Mộng muốn mượn hồn phách","text":"Trong tiên giới, đứng bên ngoài căn nhà nhìn bầu trời mờ đục, tâm thần cảm thấy tiếng kêu gọi xúc động. Nhận được truyền âm từ Lam Mộng Đạo Tôn muốn mượn hồn phách.","anchor":"Trong tâm thần hắn hình như có tiếng kêu gọi"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Cùng Tư Đồ Nam ở tiên giới trầm mặc chú ý, hiểu rằng nếu được như lời Vương Lâm thì kết thúc hoàn mỹ.","anchor":"Một số ít người biết được bí ẩn như Tư Đồ Nam và Thanh Thủy thì ở trong tiên giới trầm mặc"},{"importance":"normal","mucCt":"vua","chuong":"@c1694","tieuDe":"Quyết cùng Hồng Điệp chuyển thế đầu thai","text":"Cùng con gái Hồng Điệp tới gặp Vương Lâm, yên lặng. Nói về Hàm Yên, hy vọng trên Tiên Cương đại lục tìm được cách đưa nàng trở lại, cả nhà đoàn tụ. Xác nhận sẽ cùng nữ nhi chuyển thế đầu thai rời đi.","anchor":"Hàm Yên, trên Tiên Cương đại lục nhất định có phương pháp khiến nàng lại có thể ở bên cạnh tay"},{"importance":"normal","mucCt":"vua","chuong":"@c1696","tieuDe":"Nhờ Vương Lâm chiếu cố con gái rồi bước vào chuyển thế","text":"Gọi Vương Lâm là sư đệ, nhờ nếu tìm được con gái thì thay mình chiếu cố. Nhìn Hồng Điệp nhân từ rồi bước vào sương mù biến mất.","anchor":"Sư đệ, ta tới Tiên Cương đại lục chờ ngươi, nếu như ngươi có thể tìm thấy con gái ta, hãy thay ta chiếu cố cho nó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thái tử Thanh Thủy Quốc, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, bảy ngày đẫm máu tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân","chuong":"@c1462"},{"text":"Truyền thừa cho Vương Lâm hai tiên thuật đại tiên đế Hoán Vũ và Tát Đậu Thành Binh, công khai nhận Vương Lâm là sư đệ trước Lôi Tiên Điện","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá Không Niết Sơ Kỳ — bước thứ ba tu hành","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm bế quan trấn thủ đài chiến Vân Hải, bị Hư Thần Thiên Tôn trọng thương gần chết vì thay mặt sư đệ","chuong":"@c1516"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm chiếu cố nữ nhi","chuong":"@c1696"},{"text":"Sau chuyển thế, ấn ký tự tiêu tan, khôi phục ký ức kiếp trước, rời tông môn tìm đến Thất Đạo Tông và thề cứu thê tử Hàm Yên","chuong":"@c1961"}]},"nguon":["@c1649","@c1650","@c1652","@c1653","@c1655","@c1657","@c1694","@c1696"],"trangThai":"song","cn":"清水","gioiTinh":"nam","vaiTro":"Phách thứ nhất Thất Thải Tiên Tôn — sư huynh đồng mạch Bạch Phàm của Vương Lâm, Tiên Quân mang sát nghiệp viễn cổ","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm không tính được mất; sát phạt quyết liệt, mang sát nghiệp cùng cực từ viễn cổ; thận trọng đa nghi, không dễ tin người nhưng giữ chữ tín; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới; sau khi cố quốc bị diệt vong, trong tuyệt vọng bị truy sát đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, tự khôi phục ký ức kiếp trước và thề cứu thê tử Hàm "},{"id":"tu-dai-chien-tuong","name":"Tứ đại chiến tướng","tabs":{"kinhLich":[{"mucCt":"gon","text":"Kết trận pháp trong Vân Hải tinh vực, dùng hồ lô phun sương mù tạo Vụ thú truy tìm hồn thứ ba, hủy diệt toàn bộ sinh mạng trên đại lục hoang phế để Vụ thú hấp thu khí tức luân hồi, xác nhận hồn thứ ba từng luân hồi tại đây rồi tiến sang La Thiên.","anchor":"Nơi này tuy rằng không phải nhưng có thể khiến cho Vụ thú của tiên tôn dừng lại hấp thu thì hiển nhiên là hồn thứ ba của tiên tôn đại nhân đã từng ở nơi này luân hồi","bridge":true,"khoang":"@c1649"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Gào thét lao đi trong La Thiên Tinh Vực, theo Vụ thú tìm kiếm mục tiêu.","anchor":"tứ đại chiến tướng gào thét lao đi. Phía trước bọn họ là Vụ thú không ngừng ngẩng cái đầu khổng lồ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Điên cuồng lao về phía trung tâm động phủ","text":"Đã ở La Thiên Tinh Vực, hoảng sợ phát hiện có người tìm được hồn thứ ba trước mình, điên cuồng lao về phía khí tức động phủ mở ra.","anchor":"Bọn họ cho rằng tốc độ tìm kiếm của mình là nhanh nhất nhưng giờ phút này lại hoảng sợ phát hiện ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện đồng loạt trước đại môn, bị cơn lốc đẩy lui, nhận ra hồn thứ ba đã bị Vương Lâm lấy và hắn đang bị bao vây.","anchor":"bốn người bọn họ sau khi xuất hiện liền lập tức bị lực lượng của cơn lốc đẩy bật về phía sau"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Cầm đầu hơn trăm tiên nhân lao đi trong tinh không Triệu Hà tinh vực, ngưng tụ thần thức biến ảo truy tìm mục tiêu","chuong":"@c1631"},{"text":"Kết trận pháp trong Vân Hải tinh vực, dùng hồ lô phun sương mù tạo Vụ thú truy tìm hồn thứ ba, hủy diệt toàn bộ trên đường đi","chuong":"@c1649"},{"text":"Điên cuồng lao đi trong La Thiên Tinh Vực, hoảng sợ phát hiện có người tìm được hồn thứ ba trước mình","chuong":"@c1655"},{"text":"Xuất hiện trước đại môn động phủ nhưng bị đẩy lui, nhận ra hồn thứ ba đã bị Vương Lâm lấy mất","chuong":"@c1656"}]},"nguon":["@c1649","@c1653","@c1655","@c1656"],"vaiTro":"Bốn chiến tướng cấp cao của viễn cổ tiên vực, truy tìm hồn thứ ba","tinhCach":"Uy nghiêm, hành động có tổ chức bài bản; hung hãn điên cuồng khi bị tranh đoạt mục tiêu","blurb":"Bốn lão già cầm đầu hơn trăm tiên nhân từ viễn cổ tiên vực, xuyên suốt nhiều tinh vực dùng hồ lô xanh biếc cổ xưa phun sương mù tạo Vụ thú để truy tìm hồn thứ ba. Từ Triệu Hà tinh vực qua Vân Hải tinh vực đến La Thiên Tinh Vực, chúng hủy diệt trên đường đi nhưng cuối cùng chậm chân hơn Vương Lâm, để mất mục tiêu ngay trước mắt."},{"id":"hong-diep","name":"Hồng Điệp","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1649","tieuDe":"Tu luyện cùng Thanh Thủy trong sơn cốc","text":"Đang tu luyện trong sơn cốc phía bắc tiên giới cùng Thanh Thủy, nhờ thiên tư bất phàm liền lĩnh ngộ lời chỉ điểm, nhìn theo hướng phụ thân biến mất với ánh mắt lo lắng.","anchor":"Hồng Điệp vốn thiên tư bất phàm, nghe xong liền hiểu ra rất nhiều"},{"importance":"normal","mucCt":"vua","chuong":"@c1694","tieuDe":"Cùng phụ thân quyết định chuyển thế đầu thai","text":"Cùng phụ thân Thanh Thủy tới gặp Vương Lâm, đôi mắt ửng hồng, thần sắc bi ai. Quyết định cùng phụ thân chuyển thế đầu thai rời đi.","anchor":"Hai mắt Hồng Điệp bên cạnh hắn đôi mắt ửng hồng, thần sắc lộ vẻ bi ai và không nộ"},{"importance":"normal","mucCt":"vua","chuong":"@c1696","tieuDe":"Nước mắt hóa cầu vồng đỏ biến mất vào chuyển thế","text":"Mắt đỏ bừng nước mắt chảy, bước tới như muốn nói gì nhưng cắn môi không mở miệng. Nhìn Thanh Thủy biến mất, nước mắt hóa thành cầu vồng màu đỏ như con bướm biến mất vào đại môn động phủ.","anchor":"nước mắt không ngừng tuôn rơi, hóa thành một đạo cầu vồng màu đỏ như một con bướm biến mất"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Sở hữu Thiên Tiên Ngũ Linh thể, tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng cầm Vũ Tiên Thạch bay lên tiên giới rồi trở về với tu vi hao tổn","chuong":"@c0268"},{"text":"Giao chiến Vương Lâm nhiều lần, bị mất cánh tay phải bởi Cấm Khí Trường Thương và Tuế Nguyệt, từ chối dùng Đông Hải Chi Linh mọc lại tay để giữ ý chí","chuong":"@c0317"},{"text":"Đại chiến quyết tử tại Chu Tước quốc: triệu Băng Thần, hy sinh Anh Hài phát động Phân Thần Biến, lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi của Vương Lâm","chuong":"@c0339"},{"text":"Bị Kiền Phong đoạt tuyệt tình ý cảnh cùng tứ linh, biến thành con rối trống rỗng mắt vô thần, bị đổi tên thành Tuyệt Tình","chuong":"@c0340"},{"text":"Chết dưới chiến phủ Vương Lâm — chọn không chống cự, không né tránh, mỉm cười kiêu hãnh, thân thể nứt vỡ","chuong":"@c0428"},{"text":"Hồn phách được Hồn Truyền Tống Trận bảo toàn, chuyển thế tái sinh tại Tuyết Vực; sau cùng phụ thân Thanh Thủy chuyển thế đầu thai tại tiên giới","chuong":"@c1696"}]},"nguon":["@c1649","@c1694","@c1696"],"trangThai":"song","cn":"红蝶","gioiTinh":"nu","vaiTro":"Thiên chi kiêu nữ Tuyết Vực — đối thủ định mệnh và nhân duyên chưa dứt của Vương Lâm","tinhCach":"Kiêu hãnh bất khuất, giữ tôn nghiêm đến tận lúc chết; hiếu chiến cố chấp, nhiều lần chủ động khiêu chiến dù biết bất lợi; tàn nhẫn quyết đoán, sẵn sàng hy sinh pháp bảo và Anh Hài để phát động tuyệt chiêu; cương liệt trọng khí tiết, từ chối phục hồi cánh tay cụt để giữ ý chí","blurb":"Hồng Điệp là nữ tu thiên tài của Tuyết Vực quốc, sở hữu Thiên Tiên Ngũ Linh thể với tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn nghiêm trọng. Xuyên suốt nhiều lần giao tranh với Vương Lâm — từ đánh lén trên sa mạc, đấu pháp tại tế đàn đến đại chiến quyết tử tại Chu Tước quốc — nàng lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi, rồi bị Kiền Phong đoạt ý cảnh cùng tứ linh, biến thành con rối trống rỗng và cuối cùng chết dưới chiến phủ của Vương Lâm trong tư thế không chống cự, mỉm cười kiêu hãnh. Về sau nhờ Hồn Truyền Tống Trận mà hồn phác"},{"id":"thanh-lam","name":"Thanh Lâm","nguon":["@c1650","@c1653","@c1694","@c1696"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ ba của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ ba (cam) của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri. Giải thích vì sao Thanh Lâm cả đời bảo vệ Vũ tiên giới bất chấp bị Chưởng Tôn dụ hoặc và trọng thương.","anchor":"Trong nháy mắt khi phách này tiến vào luân hồi, Vương Lâm nhìn thấy thân ảnh bên trong chính là Thanh Lâm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ tư trong sáu phách đã biết, thuộc nhóm đã xảy ra biến số, tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Hai ngày trước thời hạn, cùng Thanh Sương và Chu Dật tới gặp Vương Lâm trong hoàng hôn, tràn ngập vẻ tang thương.","anchor":"Đứng giữa là một nam tử trung niên, tướng mạo bất phàm, tràn ngập vẻ tang thương của năm tháng"},{"mucCt":"vua","text":"Hào sảng ôm quyền chào Vương Lâm, nói sẽ gặp lại trên Tiên Cương đại lục. Ánh mắt lộ vẻ không đành lòng rồi từng bước đi vào sương mù biến mất, là người đầu tiên bước vào con đường chuyển thế.","anchor":"Vương Lâm, chúng ta sẽ gặp nhau trên Tiên Cương đại lục!","bridge":true,"khoang":"@c1696"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được xác nhận là Tiên Đế, cường giả đệ nhất Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi đệ tử sau tang thương","chuong":"@c1050"},{"text":"Hiện thân từ thức hải, đánh tan Cổ Ma Tháp Già và truyền thụ Quy tắc thân thể cho Vương Lâm","chuong":"@c1047"},{"text":"Thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ, lãnh đạo giới nội đánh trận giết tu sĩ giới ngoại","chuong":"@c1453"},{"text":"Được xác nhận là phách thứ ba (cam) của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri","chuong":"@c1650"},{"text":"Luân hồi thành phàm nhân thợ rèn ở thành trì Lâm Hóa Châu, có vợ, chọn quên đi quá khứ","chuong":"@c1960"}]},"trangThai":"song","cn":"青岚","gioiTinh":"nam","vaiTro":"Tiên Đế — phách thứ ba (cam) của Thất Thải Tiên Tôn, cường giả đệ nhất Tiên giới","tinhCach":"Mưu tính sâu xa, bố cục vượt thời gian; lạnh lùng quyết đoán với kẻ địch; che chở đệ tử và giới nội, trọng ân nghĩa; mang vẻ tang thương sau biến cố, ôn hòa với người thân cận","blurb":"Thanh Lâm là Tiên Đế, được công nhận là cường giả đệ nhất Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy và Hồ Quyên, đồng thời là phách thứ ba chứa chính khí và lương tri của Thất Thải Tiên Tôn. Sau khi thân thể bị Cổ Ma Tháp Già chiếm cứ, ông nhờ trận pháp hồi sinh mà thức tỉnh, truyền Quy tắc thân thể cho Vương Lâm và khai sinh Tân Vũ Giới, rồi bế quan chữa thương hàng trăm năm tại Vũ Tiên Giới, nhiều lần ra tay bảo vệ giới nội và tham chiến đại chiến giới ngoại. Cuối cùng ông luân hồi thành phàm nhân thợ rèn tại thành trì Lâm Hóa Châu, chọn cách quên đi quá khứ."},{"id":"tham-lang","name":"Tham Lang","nguon":["@c1650","@c1653","@c1684","@c1712"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ tư của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ tư (vàng) của Thất Thải Tiên Tôn, phách đại biểu khí vận và cơ duyên cả đời. Người mang phách này vận khí kinh thiên, được thiên địa ủng hộ, pháp bảo tự giáng xuống.","anchor":"Trong nháy mắt khi phách này tiến vào luân hồi, Vương Lâm mơ hồ nhìn thấy thân ảnh của Tham Lang"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là một trong sáu phách đã biết, thuộc nhóm bốn người đã xảy ra biến số, hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn, trở thành chúng sinh thật sự.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"bridge","mucCt":"gon","chuong":"@c1684","tieuDe":"","text":"Được nhắc tới: hình dạng Vương Lâm hóa thành trong đệ ngũ hoa giống pho tượng bảy màu lấy được từ Tham Lang.","anchor":"pho tượng bảy màu mà Vương Lâm lấy được từ Tham Lang"},{"chuong":"@c1712","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc tới, tin rằng đã ở Tiên Cương đại lục; Vương Lâm nghi vấn vì sao Tham Lang không cần chuyển thế như Thanh Thủy và Tư Đồ Nam mà có thể rời động phủ giới.","anchor":"Tham Lang hẳn là đã ở trên Tiên Cương đại lục"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Từng đạt Âm Hư chi cảnh, vượt trên Vấn Đỉnh và chỉ kém Dương Thật.","chuong":"@c0571"},{"text":"Khống chế Văn thú đầu đàn bằng Thất Ma Châm, dùng bầy Văn thú vây khốn Đại La Kiếm Tông.","chuong":"@c0602"},{"text":"Vì tham bảo vào Vân Hà Tinh đào Kim Viêm quáng mạch, chạm tới Nguyệt Hoa nên bị Vọng Nguyệt nuốt vào và mắc kẹt.","chuong":"@c0668"},{"text":"Thoát khỏi lạc ấn sau biến cố Vọng Nguyệt, rơi xuống một tinh cầu nguyên thủy trong tình trạng thân thể vỡ nát, nguyên thần bị thương.","chuong":"@c0674"},{"text":"Ở vùng đất Điên Lạc trở thành đại cung phụng nổi danh, nhờ lai lịch thần bí và số lượng pháp bảo lớn; sau đó đạt Toái Niết trung kỳ nhờ được Điên Lạc đại đế ban đan dược.","chuong":"@c1295"},{"text":"Được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, phách đại biểu khí vận và cơ duyên cả đời.","chuong":"@c1650"}]},"gioiTinh":"nam","vaiTro":"Lão tu sĩ lưu lạc — phách thứ tư của Thất Thải Tiên Tôn","tinhCach":"Tham bảo liều thân; tàn bạo cưỡng ép Văn thú; giỏi bỏ chạy giữ mạng; sợ hãi Vương Lâm","blurb":"Tham Lang là lão tu sĩ từng cư ngụ Chu Tước Tinh hơn vạn năm, về sau lưu lạc qua Đại La Kiếm Tông, La Thiên Tinh Vực, vùng đất Điên Lạc và Tiên Cương. Hắn nhiều lần vì tham bảo mà rơi vào hiểm địa, mất pháp bảo hoặc bị Vương Lâm truy đuổi, nhưng vẫn sống sót nhờ nhiều thủ đoạn bảo mệnh. Về sau Tham Lang được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, đại biểu khí vận và cơ duyên cả đời."},{"id":"lien-dao-phi","name":"Liên Đạo Phi","nguon":["@c1650","@c1670","@c1671","@c1685"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"bridge","mucCt":"gon","text":"Trong huyễn cảnh tầng hai, gầm rống khiến thiên đạo trọng thương sụp đổ, đồng thời oanh kích khiến Thất Thải Tiên Tôn vỡ nát.","anchor":"Liên Đạo Phi gầm rống, thiên đạo trọng thương sụp đổ, chia lìa tiêu tán"},{"chuong":"@c1670","importance":"normal","mucCt":"ky","tieuDe":"Bị triệu hồi ra trận, gây chấn động toàn trường","text":"Bị Vương Lâm triệu hồi từ không gian trữ vật ra giữa trận, đang ngủ say mặc quần áo lôi thôi. Có tiên nhân bất diệt thể hoàn chỉnh, sức mạnh hủy diệt lao vào mà lông tóc không hư tổn, chắn phần lớn lực hủy diệt cho Vương Lâm. Nửa tỉnh nửa mê phẫn nộ gào thét sẽ mách với ca ca rồi lại ngủ tiếp. Sự xuất hiện khiến đạo nhân bảy màu bỏ chạy, Chưởng Tôn suýt quỳ sụp gọi chủ nhân, Huyền Vũ và Chu Tước khiếp sợ, lão già họ Mã run rẩy kinh hoàng. Được Huyền La Đại Thiên Tôn nhận ra là đệ đệ của Liên Đạo Chân.","anchor":"người điên mặc quần áo lôi thôi, đang ngủ say ngáy khò khò bị hai tay Vương Lâm túm lấy trực tiếp xuất hiện ở phía trước hắn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1671","tieuDe":"Chống đỡ lực hủy diệt rồi ngủ say","text":"Chống đỡ lực hủy diệt ba trăm giới sụp đổ khiến suy yếu quá nửa, sau đó lăn ra ngủ khò khò, được Vương Lâm dẫn theo thoát thân.","anchor":"Có người điên chống đỡ, Vương Lâm"},{"chuong":"@c1685","importance":"normal","tieuDe":"Xuất quan truyền thụ Vân Đạo Thiên Thuật","text":"Xuất quan sau thời gian dài bế quan, xuất hiện từ dòng xoáy khói xanh trong tiếng chuông thứ ba, được gần trăm tu sĩ Đông Lâm Tông cung nghênh. Gọi Tô Đạo và Chu Lập vào đại điện, truyền thụ khẩu quyết nhập môn Vân Đạo Thiên Thuật để hai người thi tuyển. Tuyên bố Tô Đạo (Vương Lâm) có tư cách học Vân Đạo Thiên Thuật, truyền Thất Thải Tiên Thuật cho Chu Lập. Dặn Tô Đạo tu luyện chuẩn bị cho cuộc thi đấu Đông Lâm Tông năm tháng sau.","anchor":"Tô Đạo, từ nay về sau ngươi chính là đệ tử thuộc hệ của vi sư, là người có tư cách học tập Vân Đạo Thiên Thuật này!","mucCt":"vua"}],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Đệ tử, được truyền Vân Đạo Thiên Thuật (sau nghịch chuyển)","ghiChu":"Đối đãi tốt với Tô Đạo nhưng thường xuyên bế quan nên không biết Tô Đạo bị đối xử bất công"},{"ten":"Chu Lập","tag":"su-mon","quanHe":"Đệ tử, đại sư huynh Đông Lâm Tông","ghiChu":"Nhận Thất Thải Tiên Thuật sau nghịch chuyển"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Đệ tử, được chọn làm truyền nhân chính hệ Vân Đạo Thiên Thuật","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử (danh phận Tô Đạo)","ghiChu":"Chọn Tô Đạo làm người học Vân Đạo Thiên Thuật"}],"tuViMoc":[],"diem":[{"text":"Bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình đánh tứ đại chiến tướng, bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn sống","chuong":"@c1600"},{"text":"Được Vương Lâm triệu hồi ra trận, chống đỡ lực hủy diệt ba trăm giới sụp đổ khiến suy yếu quá nửa","chuong":"@c1671"},{"text":"Tái xuất trong trạng thái mất ký ức cũ, lúc nhận lúc không nhận ra Vương Lâm","chuong":"@c1874"},{"text":"Bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, là đường lui để đoạt xá, nhưng cuối cùng thoát khỏi","chuong":"@c1893"},{"text":"Được truyền thừa bí thuật đạt cảnh giới Đại Thiên Tôn","chuong":"@c1897"},{"text":"Trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc","chuong":"@c1970"}]},"trangThai":"song","aliases":["người điên","A Ngốc","Sư tôn Đông Lâm Tông"],"gioiTinh":"nam","canhGioiCaoNhat":"khong-ro","vaiTro":"Cường giả bí ẩn mang bất diệt thể — bằng hữu chí thân và ân nhân của Vương Lâm","tinhCach":"Điên cuồng ngạo mạn, dám một mình chiến quần hùng; dễ bị mỹ nhân dụ dẫn; trọng tình nghĩa, coi Vương Lâm như tri kỷ; ý chí kiên cường, nhờ bất diệt thể mà bất tử","blurb":"Liên Đạo Phi là cường giả bí ẩn sở hữu bất diệt thể và huyết mạch phản tổ của tiên tộc, đồng thời là bằng hữu chí thân và ân nhân lớn của Vương Lâm. Hắn từng bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình giao chiến tứ đại chiến tướng rồi bị thiên đạo nuốt mà không diệt vong, về sau bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, nhưng cuối cùng thoát khỏi đoạt xá, được truyền thừa bí thuật đạt Đại Thiên Tôn rồi trở thành Tiên Hoàng. Tính tới chương gần nhất, hắn vừa trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc.","cn":"连道非","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}]},{"id":"moc-bang-mi","name":"Mộc Băng Mi","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ nguồn gốc từ phách thứ sáu Thất Thải Tiên Tôn","text":"Được Vương Lâm nhận ra chính là thân ảnh trong phách thứ sáu (màu lam) của Thất Thải Tiên Tôn — phách do tình cảm yêu hận đối với Phàn San Mộng hóa thành nữ tử. Nàng qua vô số lần luân hồi đều lần lượt thay đổi giữa ôn nhu và lạnh lùng, tình cảm Vương Lâm dành cho nàng vô cùng phức tạp. Sắc mặt Vương Lâm tái nhợt khi nhận ra.","anchor":"Sắc mặt Vương Lâm tái nhợt. Hắn nhận ra thân ảnh mơ hồ đó là ai."},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ năm trong sáu phách đã biết, thuộc nhóm đã xảy ra biến số.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"normal","mucCt":"ky","chuong":"@c1694","tieuDe":"Xuất hiện ngày cuối cùng, gợi nhớ Liễu Mi","text":"Ngày cuối cùng, trong mưa phùn Tiên Giới, mặc bạch y cầm ô đi tới. Tóc dài đen nhánh, đẹp như tiên tử. Chương trực tiếp xác nhận trang phục và ánh mắt nàng khiến Vương Lâm nhớ tới Liễu Mi, không thể quên nổi.","anchor":"Mộc Băng Mi xinh đẹp này, hoặc có thể nói là Liễu Mi"},{"importance":"normal","mucCt":"ky","chuong":"@c1695","tieuDe":"Tiễn biệt Vương Lâm trong mưa, nhận thanh kiếm bổn nguyên","text":"Mộc Băng Mi cầm ô đứng trong mưa tiễn Vương Lâm, không chọn rời đi mà chỉ muốn nhìn hắn lần cuối. Nàng đáp nếu còn ở thế gian nhất định sẽ đón chàng. Nhận thanh kiếm bổn nguyên dung hợp bảy đạo bổn nguyên và khí tức Đạo Cổ mà Vương Lâm tặng, hai hàng nước mắt rơi, cầm kiếm nhẹ nhàng rời đi trong mưa.","anchor":"Nếu ta còn ở thế gian, nhất định sẽ đón chàng."},{"chuong":"@c1700","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Vương Lâm hồi tưởng trong hư vô — hình ảnh nàng cầm ô đứng trong mưa khi hắn ra đi, hắn không còn hận nàng.","anchor":"Hắn như lờ mờ có thể thấy được thân thể mềm mại của Mộc Băng Mi đang cầm ô đứng trong mưa"},{"importance":"bridge","chuong":"@c1702","text":"Vẫn là một trong số ít người không quên cái tên Vương Lâm khi năm tháng trôi qua.","anchor":"Mộc Băng Mi chính là như vậy"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Tuyên bố mọi thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng, thể hiện quyền uy tuyệt đối","chuong":"@c1011"},{"text":"Bị Thác Sâm đánh tan thân, nguyên thần trọng thương, dùng bí thuật Côn Hư thoát ra lưu lạc tới Vân Hải tinh vực","chuong":"@c1147"},{"text":"Xác nhận danh tính Liễu Mi — mẹ Vương Bình — và đạo tâm viên mãn, từ biệt Vương Lâm dưới ánh trăng","chuong":"@c1196"},{"text":"Được Vương Lâm phong làm tông chủ Thần Tông, chỉ huy bày binh bố trận tạo phòng tuyến giới nội trong đại chiến giới ngoại","chuong":"@c1440"},{"text":"Được hé lộ chính là phách thứ sáu (phách sinh từ tình) của Thất Thải Tiên Tôn","chuong":"@c1651"},{"text":"Tái ngộ Vương Lâm tại Tiên giới, đồng ý ước định Mộng Đạo trăm năm, cùng hắn rời Tiên giới","chuong":"@c1963"}]},"nguon":["@c1651","@c1653","@c1694","@c1695","@c1700","@c1702"],"trangThai":"song","cn":"木冰眉","gioiTinh":"nu","aliases":["Liễu Mi"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Côn Hư Thánh Nữ — mẹ Vương Bình, tông chủ Thần Tông, phách thứ sáu của Thất Thải Tiên Tôn","tinhCach":"Lạnh lùng quyền uy nhưng nặng tình với con và Vương Lâm, âm thầm chịu đựng chia ly giấu nỗi đau sau vẻ ngoài băng lãnh; bất khuất trước cường địch, không chịu khuất phục dù trọng thương hay bị giam cầm; kiên định trong đại chiến, sẵn sàng xông trận dù tuyệt vọng","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, mẹ của Vương Bình, từng nắm quyền điều khiển toàn bộ thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực. Sau khi Côn Hư cảnh bị Thác Sâm hủy diệt, nàng trọng thương lưu lạc tới Vân Hải tinh vực lấy thân phận Liễu Mi tái ngộ Vương Lâm, rồi về Thần Tông chịu giam cầm nhiều năm trước khi được Vương Lâm phong làm tông chủ, chỉ huy phòng tuyến giới nội trong đại chiến giới ngoại. Về sau nàng được hé lộ chính là phách thứ sáu — phách sinh từ tình — của Thất Thải Tiên Tôn, và trong Tiên giới đã tái ngộ Vương Lâm, đồng ý ước định Mộng Đạo trăm năm, là một trong số"},{"id":"phan-san-mong","name":"Phàn San Mộng","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ là đạo lữ duy nhất của Thất Thải Tiên Tôn","text":"Được xác nhận là đạo lữ duy nhất của Thất Thải Tiên Tôn dù hắn có nhiều phi tử. Tình cảm yêu hận của Tiên Tôn dành cho nàng đã hóa thành phách thứ sáu (lam), rốt cuộc biến thành Mộc Băng Mi.","anchor":"Cho dù hắn có nhiều phi tử nhưng hắn lại chỉ có một đạo lữ duy nhất"},{"chuong":"@c1706","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được giới thiệu nền là đệ tử Đại Hồn Môn, tu luyện nặng về Huyễn Thuật.","anchor":"Phàn San Mộng, chính là đệ tử của Đại Hồn Môn, nàng tu luyện nặng về Huyễn Thuật hơn."},{"chuong":"@c1722","importance":"bridge","mucCt":"gon","text":"Được Đỗ Thanh tiết lộ là đệ tử trung tâm Đại Hồn Môn, một trong song kiêu.","anchor":"Nàng là đệ tử trung tâm của Đại Hồn Môn, được xưng là một trong song kiêu của Đại Hồn Môn"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lộ diện từ thân xác Phàn San Lộ, xưng danh và tiết lộ bí mật Thái Cổ Thần Cảnh","chuong":"@c1599"},{"text":"Thi triển Đại Hồn chân ảo thuật từ xa nhằm biến Vương Lâm thành con rối, bị phá giải","chuong":"@c1604"},{"text":"Phản bội Thất Thải Thiên Tôn, câu dẫn Liên Đạo Phi dẫn ngoại nhân can thiệp","chuong":"@c1606"},{"text":"Được xác nhận là đạo lữ duy nhất của Thất Thải Thiên Tôn","chuong":"@c1651"},{"text":"Bị Vương Lâm chỉ mặt đòi làm nữ hầu trước mặt sư tôn Viêm Loan","chuong":"@c1735"},{"text":"Tư oán với Vương Lâm dần hóa giải, vẫn theo sư tôn Viêm Loan","chuong":"@c1898"}]},"nguon":["@c1651","@c1706","@c1722"],"gioiTinh":"nu","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"vaiTro":"Tỷ tỷ Phàn San Lộ — đệ tử hạch tâm Đại Hồn Môn, cựu đạo lữ duy nhất của Thất Thải Thiên Tôn","tinhCach":"Mưu mô thâm trầm, giỏi ẩn nhẫn chờ thời; phản trắc, sẵn sàng phản bội đồng minh để mưu lợi; tự phụ về trí mưu nhưng hay đánh giá thấp đối thủ; cam chịu khi thất thế, dần buông bỏ oán hận","blurb":"Phàn San Mộng là tỷ tỷ của Phàn San Lộ, đệ tử trung tâm Đại Hồn Môn và một trong song kiêu, tu luyện nặng về Huyễn Thuật, đồng thời là đạo lữ duy nhất của Thất Thải Thiên Tôn. Năm xưa nàng phản bội Thất Thải Thiên Tôn, câu dẫn Liên Đạo Phi can thiệp, rồi ẩn mình trong băng sơn ở Tiên Cương đại lục và từng ký sinh trong thân xác muội muội. Sau khi mưu kế biến Vương Lâm thành con rối bằng Đại Hồn chân ảo thuật bị phá giải, nàng rơi vào thế bị động, phải theo sư tôn Viêm Loan tới Viêm Mạch Phong và cuối cùng bị Vương Lâm sai khiến như nữ hầu, tư oán dần hóa giải theo thời gian."},{"id":"to-dao","name":"Tô Đạo","aliases":["Tạ Thanh","Thanh Thủy","Thất Thải Tiên Tôn"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ là hồn thứ ba Thất Thải Tiên Tôn luân hồi","text":"Hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tên Tô Đạo tại Chu Tước Tinh, Triệu quốc. Cả đời không tu đạo nhưng trở thành đại nho. Trong Mộng Đạo của Vương Lâm, Tô Đạo đã nhận Vương Lâm làm đệ tử — nhân quả sâu xa xuyên luân hồi. Cuối cùng vui vẻ nhìn tơ liễu, mỉm cười chết đi.","anchor":"Hắn không biết vì sao trong Mộng Đạo mình lại được đối phương nhận làm đệ tử"},{"chuong":"@c1685","importance":"normal","mucCt":"vua","tieuDe":"Mất tư cách học Vân Đạo Thiên Thuật","text":"Trong cuộc thi vân khí chọn truyền nhân, bị Chu Lập dùng ánh mắt uy hiếp khiến phân tâm, mất hai mươi nhịp thở mới hoàn thành, mây mù yếu ớt bị hút sạch. Sư tôn truyền Thất Thải Tiên Thuật thay vì Vân Đạo Thiên Thuật. Sau khi Vương Lâm nghịch chuyển ký ức, kết quả đảo ngược hoàn toàn.","anchor":"Thất Thải Tiên Tôn năm đó tính cách nhu nhược, không nói những chuyện này ra"},{"chuong":"@c1723","importance":"bridge","mucCt":"gon","text":"Vương Lâm nhớ lại ký ức của Tô Đạo về Đông Lâm Trì, cho rằng có thể phóng đại không ít.","anchor":"chỉ là ký ức của Thất Thải Tiên Tôn Tô Đạo, có lẽ phóng đại không ít"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người đang dung hợp hồn thứ ba của hắn, mượn thân phận hắn nghịch chuyển ký ức","ghiChu":""},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Đối đãi tốt nhưng thường bế quan nên Tô Đạo bị đãi ngộ bất công trong tông phái."},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh tại Đông Lâm Tông","ghiChu":"Bề ngoài ôn hòa nhưng khinh thị Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi."}],"tuViMoc":[],"diem":[{"text":"Đại nho nổi tiếng nhất Triệu quốc, đặt tên cho Tô thành và khiến nơi đây suýt trở thành kinh đô","chuong":"@c1500"},{"text":"Thu Vương Lâm làm môn sinh cuối cùng, luận đạo nhân quả và truyền dạy suốt mười năm","chuong":"@c1505"},{"text":"Hết thọ qua đời trên đỉnh Tô sơn vào mùa đông tuyết phủ","chuong":"@c1506"},{"text":"Bị Chu Lập uy hiếp khiến phân tâm, mất tư cách học Vân Đạo Thiên Thuật","chuong":"@c1685"},{"text":"Được xác nhận là hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tại Chu Tước Tinh","chuong":"@c1651"}]},"nguon":["@c1651","@c1685","@c1723"],"canhGioiCaoNhat":"khong-ro","trangThai":"tu-vong","vaiTro":"Bậc đại nho Triệu quốc — sư phụ cuối cùng của Vương Lâm trong Mộng Đạo, hồn thứ ba Thất Thải Tiên Tôn luân hồi","tinhCach":"Trọng tài hoa, sẵn lòng thu nạp kẻ xứng đáng dù đã muộn; điềm đạm luận đạo, lấy nhân quả làm gốc truyền dạy; ý chí kiên định nhưng dễ bị ngoại lực chi phối khi đối mặt áp chế vượt tầm","blurb":"Tô Đạo là bậc đại nho nổi tiếng nhất Triệu quốc, người đặt tên cho Tô thành và từng khiến nơi đây suýt trở thành kinh đô. Ông thu Vương Lâm làm môn sinh cuối cùng, truyền dạy suốt mười năm về đạo nhân quả trước khi hết thọ qua đời trên đỉnh Tô sơn. Thực chất ông là hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tại Chu Tước Tinh, đồng thời cũng là nhân vật do bản thể tu sĩ Vương Lâm tạo ra trong Mộng Đạo.","cn":"苏道","gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}]},{"id":"ngu-ong-thanh-linh","name":"Ngư ông (Thanh Linh tinh)","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Ngư ông phàm nhân tại Thanh Linh tinh, La Thiên Tinh Vực. Câu được con cá là hồn thứ ba Thất Thải Tiên Tôn luân hồi, nói vợ sắp sinh — ám chỉ hồn thứ ba chờ đầu thai thành con ông.","vaiTro":"Ngư ông phàm nhân câu được hồn thứ ba Thất Thải Tiên Tôn","tinhCach":"bình dị, vui vẻ","tabs":{"diem":[{"text":"Câu được con cá chính là hồn thứ ba Thất Thải Tiên Tôn đã luân hồi mấy trăm lần trong cùng con sông, chờ đợi khoảnh khắc này.","chuong":"@c1651"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1651","tieuDe":"Câu được hồn thứ ba luân hồi","text":"Xuất hiện ở cuối chương, câu được con cá (hồn thứ ba Thất Thải Tiên Tôn luân hồi mấy trăm lần), nói vợ sắp sinh — ám chỉ hồn thứ ba chờ đầu thai thành con ông.","anchor":"Vợ ta sắp sinh, hôm nay câu được con cá này mang về rồi!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1651"]},{"id":"ta-thanh","name":"Tạ Thanh","aliases":["Tô Đạo","Thanh Thủy"],"tabs":{"kinhLich":[{"chuong":"@c1652","importance":"major","mucCt":"ky","tieuDe":"Xác nhận là hồn thứ ba Thất Thải Tiên Tôn","text":"Được xác nhận chính là hồn thứ ba của Thất Thải Tiên Tôn. Cảnh chào đời trong kiếp luân hồi cuối cùng được hé lộ: cha là Tạ Đông Minh, mẹ là Tố Nhi. Hồn thứ ba từng luân hồi hàng trăm kiếp làm cá trong sông Thanh Linh Tinh trước khi sinh thành người. Câu nói năm xưa khi leo núi cầu đạo được giải mã: Tạ Thanh đã tự biết bản chất mình.","anchor":"Hồn thứ ba lại là Tạ Thanh!"},{"mucCt":"vua","text":"Được xác nhận là hồn thứ ba của Thất Thải Tiên Tôn, đệ tử của Vương Lâm. Đang ở sâu trong tu chân tinh phía đông La Thiên, hình như chủ động đợi sư phụ.","anchor":"Tạ Thanh là đệ tử của hắn. Hắn đối với Tạ Thanh có nhân quả","bridge":true,"khoang":"@c1653"},{"importance":"normal","mucCt":"ky","chuong":"@c1654","tieuDe":"Tiết lộ thân phận, trao phong ấn, tự nguyện chết","text":"Bái kiến sư tôn Vương Lâm tại u cốc hoa lan trên tu chân tinh phía đông La Thiên. Tiết lộ bản thân chính là hồn thứ ba của Thất Thải Tiên Tôn, nhưng khẳng định bản ngã là Tạ Thanh chứ không phải Tô Đạo hay Thất Thải Tiên Tôn. Sau khi trí nhớ thức tỉnh đã trốn tránh, do dự, cuối cùng ngộ ra bản ngã khi nhìn hoa lan. Dùng hồn tu lực ngưng tụ ba đạo phong ấn cho sư tôn: phong ấn thứ nhất khiến hồn thứ ba không luân hồi khi chết và mở trung tâm động phủ; hai phong ấn còn lại phối hợp lực Tiên Cương đại lục phong ấn hồn thứ nhất và hồn thứ hai. Tâm hồn hao tổn cực độ, ho ra máu. Tiết lộ trong bảy phách còn hai phách cực kỳ quan trọng với Vương Lâm. Tự nguyện nhắm mắt, nở nụ cười giải thoát, khí tuyệt thân vong. Hồn thứ ba từ thất khiếu lan ra được Vương Lâm thu lấy.","anchor":"Đệ tử Tạ Thanh bái kiến sư tôn"},{"importance":"major","mucCt":"gon","chuong":"@c1655","tieuDe":"Qua đời, hồn thứ ba xuất hiện trong thi thể","text":"Gọi tiếng sư tôn cuối cùng rồi mỉm cười qua đời. Hồn thứ ba của Thất Thải Tiên Tôn xuất hiện trong thi thể. Vương Lâm coi hồn thứ ba là Tạ Thanh chứ không phải Thất Thải Tiên Tôn, thề sẽ giúp ngưng tụ thành hồn thức tỉnh trí nhớ.","anchor":"Hắn trở mắt nhìn đệ tử Tạ Thanh gọi tiếng sư tôn cuối cùng, mỉm cười qua đời"},{"mucCt":"vua","text":"Thi thể vẫn quỳ trong sơn cốc. Được Vương Lâm bi ai an táng bằng thu lan biến thành ngôi mộ, hắn hứa sẽ tới đánh thức nàng. Từ đó mỗi mùa thu hoa lan ngập tràn tu chân tinh vô danh làm bạn với nàng.","anchor":"Ngươi thích thu lan trong dãy núi này, vậy thì an nghỉ ở đây đi","bridge":true,"khoang":"@c1656"},{"chuong":"@c1685","importance":"normal","tieuDe":"Lý do Vương Lâm nghịch chuyển ký ức","text":"Được Vương Lâm nhắc đến trong suy tư nội tâm: nếu dung hợp hoàn toàn với hồn thứ ba, Tạ Thanh sẽ tan biến vĩnh viễn, không bao giờ thức tỉnh. Đây là lý do then chốt Vương Lâm quyết định không thuận theo ký ức mà nghịch chuyển.","anchor":"Nếu như vậy thì Tạ Thanh sẽ không thể nào thức tỉnh được nữa","mucCt":"vua"},{"chuong":"@c1690","importance":"normal","mucCt":"vua","tieuDe":"Phong ấn di nguyện phát huy tác dụng","text":"Được hồi tưởng: là một lần luân hồi của hồn thứ ba Thất Thải Tiên Tôn, đã xả thân ngưng tụ ba đạo phong ấn trước khi chết. Hai đạo phong ấn chứa tâm huyết của Tạ Thanh được Vương Lâm kích hoạt, dung hợp khí tức Tiên Cương, phong ấn thành công lưỡng hồn Thất Thải Tiên Tôn.","anchor":"Phong ấn trong tay Vương Lâm hắn lờ mờ có thể thấy ánh mắt bi phẫn của Tạ Thanh."},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Được Vương Lâm hứa làm sống lại","text":"Được Vương Lâm nhớ tới trước kim môn, hứa nhất định sẽ làm sống lại.","anchor":"Tạ Thanh, ta hứa sẽ làm ngươi sống lại một lần nữa, nhất định thế"}],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Quỳ bái kiến, tận tâm hoàn thành ba đạo phong ấn trước khi chết"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Bản thể gốc (hồn thứ ba)","ghiChu":"Tạ Thanh là hồn thứ ba nhưng khẳng định bản ngã riêng"},{"ten":"Tạ Đông Minh","tag":"cha-me","quanHe":"Cha trong kiếp luân hồi cuối cùng","ghiChu":"@c1652"},{"ten":"Tố Nhi","tag":"cha-me","quanHe":"Mẹ trong kiếp luân hồi cuối cùng","ghiChu":"@c1652"}],"tuViMoc":[],"diem":[{"text":"Vì cầu đạo mà bái Vương Lâm làm sư tôn, được nhận làm ký danh đệ tử và giao núi Hoành Vân","chuong":"@c0798"},{"text":"Ngồi trên đỉnh Hoành Vân Sơn hơn tám trăm năm chờ sư tôn, chỉ tu ý cảnh thuần túy — không nguyên thần, không nguyên anh","chuong":"@c1389"},{"text":"Được xác nhận chính là hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi","chuong":"@c1652"},{"text":"Tiết lộ thân phận thật với sư tôn, trao ba đạo phong ấn rồi tự nguyện mỉm cười qua đời","chuong":"@c1655"},{"text":"Được Vương Lâm bi ai an táng bằng thu lan và hứa nhất định sẽ làm sống lại","chuong":"@c1691"},{"text":"Phong ấn di nguyện phát huy tác dụng — ba đạo phong ấn ngưng tụ từ việc xả thân","chuong":"@c1690"}]},"nguon":["@c1652","@c1653","@c1654","@c1655","@c1656","@c1685","@c1690","@c1691"],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","vaiTro":"Nhị đệ tử của Vương Lâm — hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi","tinhCach":"Trung thành tuyệt đối với sư tôn, kiên nhẫn phi thường khi ngồi chờ tám trăm năm; tự nguyện xả thân vì đại cục, đối diện cái chết bình thản mỉm cười","blurb":"Tạ Thanh là nhị đệ tử của Vương Lâm, vì cầu đạo mà bái sư, được giao núi Hoành Vân trên Thanh Linh Tinh thuộc La Thiên và đã ngồi đó hơn tám trăm năm chờ sư tôn trở lại. Hắn chính là hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi; sau khi gặp lại Vương Lâm, hắn tiết lộ thân phận thật, trao ba đạo phong ấn rồi mỉm cười qua đời. Vương Lâm an táng hắn bằng thu lan, thề nhất định sẽ làm hắn sống lại.","cn":"谢青","gioiTinh":"nam"},{"id":"ta-dong-minh","name":"Tạ Đông Minh","cn":"谢东明","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"khong-ro","blurb":"Cha của Tạ Thanh trong kiếp luân hồi cuối cùng của hồn thứ ba. Hán tử ba mươi tuổi dáng suy nhược nhưng thần sắc hào hiệp, giống văn nhân hơn ngư ông, từng đọc sách làm quan tạo phúc cho dân.","vaiTro":"Cha của Tạ Thanh trong kiếp cuối, văn nhân làm quan thanh liêm","tinhCach":"Hào hiệp, yêu thương gia đình; có chí khí bậc đại nho, thanh liêm chính trực","tabs":{"diem":[{"text":"Văn nhân ba mươi ba năm làm quan thanh liêm không thẹn lương tâm, đặt tên con Tạ Thanh mong con cao vút xuất trần như thanh trúc","chuong":"@c1652"},{"text":"Dáng suy nhược nhưng thần sắc hào hiệp, giống văn nhân hơn ngư ông, từng làm quan thanh liêm tạo phúc dân chúng.","chuong":"@c1652"},{"text":"Phàm nhân thanh liêm, từng đọc sách làm quan tạo phúc, mong con như thanh trúc cao vút xuất trần","chuong":"@c1652"}],"kinhLich":[{"chuong":"@c1652","importance":"normal","mucCt":"vua","tieuDe":"Tạ Thanh chào đời","text":"Đêm mưa bão, thê tử Tố Nhi sinh khó, Tạ Đông Minh lo lắng đấm tay vào vách trúc chảy máu, trách trời. Đứa trẻ chào đời bình an, đặt tên Tạ Thanh, mong con cao vút xuất trần như thanh trúc.","anchor":"Tạ Đông Minh ta thủa nhỏ đọc sách, hiểu đạo lý biết vạn vật làm quan tạo phúc cho dân chúng một phương"}],"tuViMoc":[],"nhanMach":[{"ten":"Tố Nhi","tag":"the-thiep","quanHe":"Thê tử, mẹ của Tạ Thanh"},{"ten":"Tạ Thanh","tag":"cha-me","quanHe":"Con trai, được đặt tên với kỳ vọng xuất trần"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1652"]},{"id":"to-nhi","name":"Tố Nhi","cn":"素儿","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"khong-ro","blurb":"Thê tử của Tạ Đông Minh, mẹ của Tạ Thanh trong kiếp luân hồi cuối cùng. Nữ tử mặc tố y dung nhan xinh đẹp, sinh khó trong đêm mưa bão nhưng cuối cùng mẫu tử bình an.","vaiTro":"Mẹ của Tạ Thanh trong kiếp cuối, thê tử Tạ Đông Minh","tinhCach":"Hiền lành, nhẫn nại","tabs":{"diem":[{"text":"Sinh khó trong đêm bão sấm chớp, cuối cùng mẫu tử bình an","chuong":"@c1652"},{"text":"Nữ tử mặc tố y dung nhan xinh đẹp, mang thai chờ chồng trong căn nhà cỏ giữa rừng trúc.","chuong":"@c1652"},{"text":"Phàm nhân xinh đẹp, sinh khó trong đêm bão nhưng mẫu tử bình an","chuong":"@c1652"}],"kinhLich":[{"chuong":"@c1652","importance":"normal","mucCt":"gon","tieuDe":"Sinh hạ Tạ Thanh","text":"Sinh khó trong đêm mưa bão, cuối cùng mẫu tử bình an.","anchor":"Là con trai."}],"tuViMoc":[],"nhanMach":[{"ten":"Tạ Đông Minh","tag":"the-thiep","quanHe":"Phu quân"},{"ten":"Tạ Thanh","tag":"cha-me","quanHe":"Con trai"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1652"]},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1653","text":"Vương Lâm nghĩ tới hắn như phân thân chưa chết của Thiên Vận Tử, có thể mang theo phách thứ bảy, nhưng không chắc chắn.","anchor":"Ta suýt quên một người là Thiên Vận Tử áo xám!"}],"diem":[{"text":"Lần đầu tiếp cận Vương Lâm tại Thiên Vận Tông, tiết lộ được đưa tới vì Sát Lục Tiên quyết và mời truyền pháp","chuong":"@c0474"},{"text":"Bị Tàn Dạ dồn tới chỉ còn tàn niệm, liều mạng hóa huyết kiếm từ căn nguyên khí Sát Lục rồi liên tiếp mở phong ấn chiến đấu","chuong":"@c1004"},{"text":"Đoạt máu thiên đạo từ Thanh Long Thánh Hoàng bằng cách nương lực tự bạo của ba phân thân rồi tẩu thoát","chuong":"@c1044"},{"text":"Bổn tôn Thiên Vận Tử tự sát để nuôi phân hồn áo xám, cho gần ba nghìn phân thân tự hủy hội tụ hồn phách nhằm chiếm cứ phân thân Vương Lâm","chuong":"@c1624"},{"text":"Hoàn thành lần thức tỉnh thứ chín mươi chín, thi triển Thiên đạo nhất thể nhưng bị U Minh Thú nuốt sạch","chuong":"@c1629"},{"text":"Hé lộ thực chất là đạo thần niệm của người bảo vệ la bàn chân chính lưu lại trên khí linh Thiên Vận Tử, đánh nốt ván cờ với Vương Lâm tại Cổ Đạo Sơn","chuong":"@c1976"}]},"nguon":["@c1653"],"vaiTro":"Phân thân áo xám của Thiên Vận Tử — nắm giữ Sát Lục Tiên quyết, thực chất mang thần niệm người bảo vệ la bàn","tinhCach":"Bí ẩn và tự chủ cao, hành xử tách biệt khỏi bổn tôn đến mức liếc lạnh khi bị triệu hồi; hiếu chiến nhưng tính toán, chỉ mở phong ấn khi bị dồn tới tuyệt cảnh; quyết liệt liều mạng, sẵn sàng hóa tàn niệm để tấn công; lạnh lùng chủ động, nhiều lần thăm dò và truy kích Vương Lâm xuyên suốt tứ đại tinh ","blurb":"Thiên Vận Tử áo xám là phân thân đặc biệt của Thiên Vận Tử, sở hữu Sát Lục Tiên quyết và sát khí cực mạnh, hoạt động với mức độ tự chủ cao — thậm chí từng liếc lạnh bổn tôn khi bị triệu hồi dung nhập. Hắn nhiều lần truy kích Vương Lâm xuyên suốt các biến cố tại Tiên Phủ Đông Hải và tứ đại tinh vực, bị thần thông Tàn Dạ dồn tới mức chỉ còn tàn niệm nhưng vẫn kiên cường mở liên tiếp các tầng phong ấn chiến đấu; sau đó đoạt máu thiên đạo từ Thanh Long Thánh Hoàng rồi tẩu thoát. Về sau bổn tôn Thiên Vận Tử tự sát để nuôi phân hồn áo xám, phân thân này hoàn thành lần thức tỉnh thứ chín mươi chín tr"},{"id":"tan-linh-thuong-nhan","name":"Tán Linh thượng nhân","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ sáu, thuộc nhóm đã xảy ra biến số.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"bridge","mucCt":"gon","chuong":"@c1689","text":"Được Vương Lâm nhắc đến khi so sánh tâm tình mở đại môn với việc Tán Linh thượng nhân đưa người ra ngoài bảy trăm vạn thiên địa bước vào Thái Cổ Tinh Thần.","anchor":"tâm tình của Tán Linh thượng nhân khi đưa người ở bảy trăm vạn thiên địa ra ngoài thế giới"}],"diem":[{"text":"Hiện thân sau khi Vương Lâm rời đi, xin mang thi thể tu sĩ Âm Hư, bộc lộ thân phận dị thường","chuong":"@c1264"},{"text":"Bị Vương Lâm phát hiện và phóng tia chớp hồng sắc xuyên mi tâm kích bản thể, lộ diện xưng danh Tán Linh, tiết lộ chân tướng bảy trăm vạn thiên địa","chuong":"@c1267"},{"text":"Tu vi đạt Thiên Nhân Tứ Suy sau vài ngàn năm điên cuồng tu luyện, lập Tán Linh Tông chiêu mộ tộc nhân phản kháng sấm sét bất diệt","chuong":"@c1268"},{"text":"Mở Tuyệt Thiên trận, dùng thân thể tộc nhân bị phong ấn làm mảng lưới ánh sáng chịu sấm sét bất diệt, trọng thương phun máu","chuong":"@c1271"},{"text":"Dẫn tộc nhân thoát khỏi bảy trăm vạn thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, tuyên thệ trung thành với Vương Lâm","chuong":"@c1273"},{"text":"Gặp lại Vương Lâm cùng bằng hữu ở giới ngoại","chuong":"@c1966"}]},"nguon":["@c1653","@c1689"],"trangThai":"khong-ro","vaiTro":"Thủ lĩnh Tán Linh Tông — cường giả bí ẩn phản kháng sấm sét bất diệt trong bảy trăm vạn thiên địa","tinhCach":"Hiền lành bề ngoài nhưng tự tin cao độ; bình thản, quan sát sắc bén trước cường giả; kiên định phản kháng, sẵn sàng hy sinh vì tộc nhân","blurb":"Thanh niên đầu trọc láng bóng, vẻ mặt hiền lành, tồn tại hơn vạn năm trong bảy trăm vạn thiên địa, tu vi đạt tới Thiên Nhân Tứ Suy — điều gần như bất khả trong thế giới bị phong tỏa bởi sấm sét bất diệt. Sau khi phá phong hộ tu chân tinh lần đầu nhìn thấy tinh không và phát hiện chân tướng thế giới, y lập Tán Linh Tông chiêu mộ tộc nhân phản kháng, mở Tuyệt Thiên trận đối đầu sấm sét bất diệt, dẫn tộc nhân thoát khỏi thiên địa đang sụp đổ vào Thái Cổ Tinh Thần và thề trung thành với Vương Lâm. Về sau gặp lại Vương Lâm ở giới ngoại."},{"id":"chuong-ton","name":"Chưởng Tôn","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ở đại điện giới ngoại, mở bừng mắt hoảng sợ khi cảm nhận đại biến, nhận ra hồn thứ ba thức tỉnh và trung tâm động phủ lại mở ra. Sắc mặt tái nhợt, lập tức lao thẳng về giới nội.","anchor":"Hồn thứ ba thức tỉnh! Trung tâm động phủ lại mở ra một lần nữa!","bridge":true,"khoang":"@c1655"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện bên ngoài đại môn, cuống quít lui lại bên cạnh đạo nhân bảy màu, nhìn Vương Lâm kinh nghi bất định.","anchor":"Thân ảnh Chưởng Tôn xuất hiện bên ngoài cánh cửa thân thể cuống quít lui lại phía sau"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Do dự rồi cắn răng tiến vào đại môn động phủ, là người thứ ba bước vào.","anchor":"Cả người hắn hóa thành một đạo tàn ảnh ngay lập tức tới gần đại môn ở bên ngoài hơi do dự rồi cắn răng tiến vào"},{"mucCt":"vua","text":"Là người thứ ba tiến vào, vừa muốn bước qua đống đổ nát thì thần sắc biến đổi, lập tức dừng lại bắt quyết ẩn thân trở nên vô hình. Sau khi thấy Lam Mộng Đạo Tôn đi qua đống đổ nát mà không sao, ẩn một bên nhíu mày.","anchor":"thần sắc biến đổi, lập tức dừng lại, ánh mắt lóe lên, tay phải bắt quyết","bridge":true,"khoang":"@c1658"},{"chuong":"@c1659","importance":"bridge","mucCt":"gon","text":"Ẩn thân bên cạnh đống đổ nát quan sát mọi người tiến vào, khóe miệng lộ nụ cười lạnh khi tơ máu kích hoạt.","anchor":"Chưởng Tôn bí mật ẩn thân ở cạnh đó lúc này hai mắt lóe sáng, khóe miệng lộ nụ cười lạnh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Xuất hiện mệt mỏi sau giao chiến","text":"Xuất hiện qua vòng xoáy thần sắc mệt mỏi, nhìn Lam Mộng Đạo Tôn với hàn ý — từng giao chiến trong ba trăm tàn giới.","anchor":"Thần sắc của hai người bọn họ có chút mệt mỏi, khi nhìn về phía đối phương đều nổi lên hàn ý"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Nhận ra U Minh Thú hoảng sợ","text":"Từ biển lửa ra, đứng ngây nhìn U Minh Thú sắc mặt trắng bệch. Nhớ lại chủ nhân hắn từng bị U Minh Thú nuốt năm xưa, hoảng sợ điên cuồng lui về phía sau.","anchor":"cảnh tượng năm đó chủ nhân của hắn bị nuốt khiến cho hắn rất khó có thể quên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Nhận diện Mục Ngư, kinh hãi cung Lý Quảng","text":"Nhận diện Mục Ngư là kỳ thú Tiên Cương, khi Vương Lâm bắn tiễn thì sắc mặt tái nhợt vội lui lại vì đã bị mũi tên này giết chết hai lần trước.","anchor":"Hắn đã bị mũi tên này g**t ch*t hai lần đã khắc cốt ghi tâm"},{"mucCt":"gon","text":"Tái nhợt hóa cầu vồng bỏ chạy khi sức mạnh hủy diệt lan ra. Khi thấy Liên Đạo Phi, thân thể run lên, suýt quỳ sụp gọi chủ nhân.","anchor":"suýt chút nữa trước những lời nói của người điên đã quỳ sụp xuống","bridge":true,"khoang":"@c1670"},{"importance":"bridge","mucCt":"gon","chuong":"@c1671","tieuDe":"Quan sát mánh khóe Vương Lâm","text":"Ở phía xa quan sát toàn bộ diễn biến, nhìn ra mánh khóe của Vương Lâm nhưng không nhắc nhở Chiến lão quỷ mà thầm tính kế riêng.","anchor":"mơ hồ nhìn ra mánh khóe, trái tim đập thình thịch"},{"importance":"bridge","mucCt":"vua","chuong":"@c1676","tieuDe":"Bị Vương Lâm và Vân Dật Phong giáp công","text":"Đạp không đi tới, trên thân hiện vầng mặt trời chống đỡ huyết kiếm của Vương Lâm nhưng bị đẩy lùi một bước, đồng thời đối mặt Bát Đao Trảm Thần Hồn của Vân Dật Phong.","anchor":"một thân ảnh mơ hồ đạp không đi tới"},{"importance":"normal","mucCt":"ky","chuong":"@c1677","tieuDe":"Thi triển Chưởng diệt tam đạo, kinh hãi trước thân phận Huyền La","text":"Xuất hiện tại vùng đất cổ mộ, nhờ thông tin từ Diệu Âm nên tới nhanh vượt trước. Phán đoán Vương Lâm cạn sức sau ba lần giương cung, quyết giết Vương Lâm đoạt hồn thứ ba. Dùng hào quang bảy màu phá Bát Đao của Vân Dật Phong, dùng kim quang phá chín phi kiếm của Đường San. Thi triển Chưởng diệt tam đạo ba tầng (diệt linh đạo, diệt quỷ đạo, diệt thần đạo) đối đầu Tê Thiên Thuật, kim ấn tầng ba vượt qua giáng xuống Vương Lâm. Nhưng Huyền La chỉ tay biến kim ấn thành pháp bảo thực chất — Chưởng Tôn kinh hãi tột cùng, nhận ra đây là năng lực chỉ cửu đại thiên tôn Tiên Cương Cửu Dương mới có, gọi Huyền La là ca ca của chủ nhân.","anchor":"Đây là ca ca của chủ nhân….Tiên Cương Cửu Dương, cửu đại thiên tôn mới có thể làm được"},{"importance":"normal","mucCt":"ky","chuong":"@c1678","tieuDe":"Bị bốn người vây đánh, lần đầu phun máu, thi triển Tình Trung Lao Nguyệt","text":"Tâm thần sụp đổ vì sự hiện diện của Huyền La, nghi ca ca của chủ nhân ẩn mình gần đó, bỏ ý định giết Vương Lâm điên cuồng bỏ chạy. Bị bốn người vây đánh, ác hầu tím nhập thể theo thất khiếu, bị cự long vàng nuốt, lần đầu phun máu tại đây. Cảm nhận khí tức Lam Mộng Đạo Tôn đang lao tới, biết nếu Lam Mộng động thủ thì chắc chắn chết. Phản kích bằng nguyên thần huyết màu vàng nhắm Vương Lâm nhưng bị Định Thân Thuật chặn, bị huyết kiếm xuyên vai phun máu. Thi triển đạo thuật Tình Trung Lao Nguyệt lấy đất làm giếng phản chiếu trời, mò ra ảo ảnh giết hồn.","anchor":"lần đầu tiên Chưởng Tôn ở nơi này phun ra một ngụm máu tươi"},{"importance":"normal","mucCt":"ky","chuong":"@c1679","tieuDe":"Mất nửa hồn, bị Vương Lâm thu giữ","text":"Thi triển Tĩnh Trung Lao Nguyệt biến mặt đất thành nước giếng phản chiếu thân ảnh bốn đối thủ. Bị Lam Mộng Đạo Tôn phối hợp ba người phong ấn toàn thân ba nhịp thở, dùng kim quang hộ thể phòng ngự. Bị Vương Lâm dùng Mộng Đạo xâm nhập hồn rồi tế hồn cho Dĩ Ti, mất nửa hồn, đau đớn điên cuồng. Lao tới định giết Vương Lâm nhưng bị Dĩ Ti hiện thân đánh bại trong sương đen, bị ném ra bất tỉnh. Cuối cùng bị Vương Lâm thu vào không gian trữ vật, để dành cho người điên năm đó quyết định sống chết.","anchor":"ngay khi bị phong ấn, toàn thân hắn đột nhiên bị một đám kim quang bao trùm"},{"importance":"major","mucCt":"vua","chuong":"@c1680","tieuDe":"Bị lấy nửa hồn, luân hồi nhân quả","text":"Bị Vương Lâm lấy nửa hồn, kết cục bi thảm. Vương Lâm cảm khái: một đời kiêu hùng nhưng chỉ là nô bộc người điên, sau bái đạo nhân bảy màu làm thầy, nay rơi vào luân hồi nhân quả từ việc năm xưa vây giết Phong Tôn.","anchor":"Kẻ giết người lại bị người ta giết!"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Dùng thần thông Thiên Địa Thái Sơ giết Chiến Tinh Dã đoạt chiến hồn, tiết lộ Thiên Đạo Kế","chuong":"@c1134"},{"text":"Liên thủ cùng người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới gần tử vong","chuong":"@c1238"},{"text":"Phát lệnh tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực, triển khai trận chiến giới ngoại","chuong":"@c1413"},{"text":"Bái kiến sư tôn đạo nhân bảy màu, lộ giao kèo và thân phận nô bộc bị thu phục","chuong":"@c1573"},{"text":"Bổn tôn lần đầu bước vào giới nội, bị mũi tên xuyên thấu phải dùng tam mệnh thuật bỏ trốn","chuong":"@c1561"},{"text":"Bị Vương Lâm lấy nửa hồn, rơi vào luân hồi nhân quả, kết cục bi thảm","chuong":"@c1680"}]},"nguon":["@c1655","@c1656","@c1657","@c1658","@c1659","@c1667","@c1668","@c1669","@c1670","@c1671","@c1676","@c1677","@c1678","@c1679","@c1680"],"trangThai":"khong-ro","cn":"掌尊","gioiTinh":"nam","vaiTro":"Lão tổ tông Nguyệt Tộc bước thứ ba — kẻ thù lớn của Vương Lâm tại giới ngoại Thái Cổ Tinh Thần","tinhCach":"Mưu tính thâm sâu, bày Thiên Đạo Kế và mai phục Thất Thải Giới cả vạn năm; tàn nhẫn quyết đoán, giết Chiến Tinh Dã đoạt chiến hồn, phát lệnh tàn sát Phong Giới; giỏi dụ lợi mua chuộc, dùng lợi ích lôi kéo Diệu Âm đạo tôn và Lam Mộng đạo tôn ra tay; ngoài mạnh trong yếu, nhiều lần hoảng sợ kinh hãi t","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, bị đạo nhân bảy màu thu phục làm sai vặt chiếm cứ giới ngoại. Hắn nhiều đời bố trí Thiên Đạo Kế, luyện Thất Thải Thần Không Đinh, liên thủ trọng thương Chủ nhân Phong Giới, phát lệnh tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực, đồng thời tách huyết mạch tiên nhân khỏi Vương Lâm và nhiều lần trực tiếp đối đầu. Trong các cuộc giao tranh với Vương Lâm, hắn liên tiếp bị phá cục, bị mũi tên xuyên thấu, đạo tâm sụp đổ, cuối cùng bị lấy nửa hồn và rơi vào luân hồi nhân quả, kết thúc một đời kiêu hùng chỉ là nô "},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","tabs":{"kinhLich":[{"mucCt":"vua","text":"Truyền giọng nói uy nghiêm vào tâm thần Tư Đồ Nam và Thanh Thủy, nói đã từng đáp ứng Vương Lâm giúp một tay. Không có huyết mạch Tiên Cương đại lục nên không thể tiến vào trung tâm động phủ, muốn mượn hồn phách hai người dùng một lát.","anchor":"Ta đã từng đáp ứng Vương Lâm sẽ giúp một tay","bridge":true,"khoang":"@c1655"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Lam quang lóe lên, chậm rãi bước ra, thân thể có chút bất đồng, bình tĩnh đối diện Chiến lão quỷ và đạo nhân bảy màu.","anchor":"Thần sắc Lam Mộng Đạo Tôn bình tĩnh, đứng ở nơi đó"},{"mucCt":"vua","text":"Thần sắc bình tĩnh, chậm rãi đi tới trước cửa, thầm than nhẹ rồi tiến vào. Là người duy nhất không có huyết mạch tiên cương mà vẫn vào được nhờ mượn hồn.","anchor":"Lam Mộng Đạo Tôn mượn hồn mà vào","bridge":true,"khoang":"@c1657"},{"mucCt":"vua","text":"Đi sau Chưởng Tôn tới trung tâm động phủ, nhìn đống đổ nát phía dưới rồi khóe miệng lộ nụ cười. Đơn giản cất bước dung nhập vào đại đỉnh mà đống đổ nát không biến hóa, khiến Chưởng Tôn đang ẩn thân phải nhíu mày.","anchor":"Lam Mộng Đạo Tôn đi tới, hai mắt sững lại, nhìn đống đổ nát phía dưới, khóe miệng đột nhiên lộ nụ cười","bridge":true,"khoang":"@c1658"},{"mucCt":"vua","text":"Xuất hiện thần sắc mệt mỏi sau khi giao chiến với Chưởng Tôn trong ba trăm tàn giới. Bị lực Phần Giới Cổ Tán ngăn ở bên ngoài — Vương Lâm cố ý bảo vệ, không muốn hắn dính vào trận giết chóc.","anchor":"Vương Lâm không rảnh phân tâm đi lo lắng cho Lam Mộng, nên muốn ngăn cản hắn ở bên ngoài","bridge":true,"khoang":"@c1667"},{"importance":"bridge","mucCt":"gon","chuong":"@c1678","text":"Khí tức đang từ xa nhanh chóng lao tới vùng đất cổ mộ, Chưởng Tôn cảm nhận nếu Lam Mộng động thủ thì hắn chắc chắn chết.","anchor":"khí tức của Lam Mộng Đạo Tôn cũng đang từ xa nhanh chóng lao tới"},{"mucCt":"vua","text":"Xuất hiện từ đám mây lam trên bầu trời, nhận lời Vương Lâm phong ấn Chưởng Tôn ba nhịp thở. Dùng tu vi cả đời hóa lam quang, phá giếng nước Chưởng Tôn, kéo Vân Dật Phong, Đường San, Thác Sâm dung hợp thành bốn ký hiệu phong ấn khắc lên người Chưởng Tôn.","anchor":"tu vi của hắn vốn không kém, mặc dù vẫn chưa phải là huyền kiếp, nhưng cũng có thể cùng với huyền kiếp đánh một trận","bridge":true,"khoang":"@c1679"},{"mucCt":"vua","text":"Nói kết thúc nhân quả với Vương Lâm: năm đó Vương Lâm trả truyền thừa giúp mặc lưu phân thần đại thành, nay giúp lại. Toàn thân tràn lam quang, bộc phát chiến ý kinh thiên, ở lại chặn Chiến lão quỷ.","anchor":"Lão phu đã đáp ứng là sẽ giúp ngươi, vậy thì lúc này ta vẫn sẽ giúp ngươi!","bridge":true,"khoang":"@c1680"},{"importance":"normal","mucCt":"ky","chuong":"@c1681","tieuDe":"Lấy cổ cầm chí bảo ra chiến đấu","text":"Cùng lão già họ Mã khổ chiến Chiến lão quỷ ở tầng thứ hai vùng đất cổ mộ, chủ yếu phòng ngự vì chưa độ Huyền Kiếp. Cắn lưỡi phun máu, dung hợp lam quang triệu ra cổ cầm chí bảo phong ấn nhiều năm trong máu — đòn sát thủ cuối cùng, cả đời mới dùng một lần. Đây là nguyên nhân chính thức Chưởng Tôn kiêng kỵ hắn. Lai lịch cổ cầm cực kỳ thần bí, mơ hồ không phải vật của động phủ giới. Tiếng đàn hóa sát khí phong tỏa bốn phía Chiến lão quỷ. Nhớ thê tử đang trong không gian trữ vật mà không thể khiến nàng hồi phục.","anchor":"Cả đời Lam Mộng Đạo Tôn mới chỉ dùng cổ cầm này một lần"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Phong ấn cổ cầm bị phá, trọng thương vẫn tiếp tục chiến đấu","text":"Bị hồn phách Thất Thải Tiên Tôn đánh tan phong ấn cổ cầm, phun máu trọng thương nhưng tiếp tục đánh đàn tấn công. Được Vương Lâm bảo nghỉ ngơi.","anchor":"phong ấn của cổ cầm của Lam Mộng Đạo Tôn trong tiếng ầm ầm này cũng lập tức bị đánh tan thành mây khói"},{"chuong":"@c1690","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ, chấn động khi chứng kiến Vương Lâm tự mình phong ấn lưỡng hồn Thất Thải mà không cần Huyền La Đại Thiên Tôn ra tay.","anchor":"Bọn họ thật không ngờ Vương Lâm này lại còn một chiêu như vậy."},{"importance":"bridge","mucCt":"vua","chuong":"@c1691","tieuDe":"Chần chừ trước kim môn","text":"Hiện hình bên ngoài kim môn. Chần chừ không biết nên rời đi hay lưu lại, dù biết nơi này chỉ là động phủ.","anchor":"ánh mắt Lam Mộng đạo tôn nhìn về kim môn có chút chần chừ"},{"chuong":"@c1692","importance":"bridge","mucCt":"vua","text":"Kinh ngạc khi Huyền La hiện thân, thần thức không phát hiện được. Đứng nghe Vương Lâm nói về tình cảm với Uyển Nhi, không phẫn nộ mà đồng tình và bi ai, nhớ tới thê tử của mình.","anchor":"Nhưng lúc này hắn lại không hề phẫn nộ, chỉ có đồng tình và bi ai"},{"chuong":"@c1693","importance":"bridge","mucCt":"gon","text":"Nghe Vương Lâm nói “vô hối”, ánh mắt ảm đạm nhìn về Tiên Giới trầm mặc, rồi cùng Vương Lâm rời chỗ Huyền La.","anchor":"Hai tiếng vô hối lọt vào tai Lam Mộng đạo tôn khiến ánh mắt hắn ảm đạm"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lộ diện lần đầu, tự xưng danh tính là chủ nhân bàn tay khổng lồ tấn công Thất Thải giới","chuong":"@c1156"},{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống thất bại, truyền ba thức thần thông gồm Phiên Thiên, Quang Ảnh Thuẫn và Dung biến đạo thuật","chuong":"@c1243"},{"text":"Xuất thủ chặn Vương Lâm theo ước định với Chưởng Tôn, ân đoạn nghĩa tuyệt","chuong":"@c1492"},{"text":"Tuyên bố đứng về phía Vương Lâm, tiết lộ bản thân là người sinh ra trong giới nội, kể bí mật ngũ phi","chuong":"@c1582"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày, tự xưng Thái Cổ Ngũ Tôn","chuong":"@c1583"},{"text":"Dùng tu vi cả đời phong ấn Chưởng Tôn ba nhịp thở, nói kết thúc nhân quả với Vương Lâm","chuong":"@c1679"}]},"nguon":["@c1655","@c1656","@c1657","@c1658","@c1667","@c1678","@c1679","@c1680","@c1681","@c1682","@c1690","@c1691","@c1692","@c1693"],"trangThai":"song","canhGioiCaoNhat":"Không rõ","vaiTro":"Thái Cổ Ngũ Tôn — lãnh đạo Lam Ti Tộc, người sinh ra trong giới nội","tinhCach":"Thâm trầm u buồn, nặng tình cảm gia đình; điềm tĩnh thận trọng, coi trọng nhân quả; trọng nghĩa khí, sẵn sàng xả thân hộ người thân; phức tạp nội tâm, hay hối hận và trầm mặc","blurb":"Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn, tu vi Không Huyền đại viên mãn, lãnh đạo Lam Ti Tộc tại Lam Sơn và được tiết lộ là người sinh ra trong giới nội. Ông từng chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thần thông, nhiều lần can thiệp hộ Vương Lâm trong các biến cố lớn, từ cuộc đối đầu Thiên Nghịch đến đại chiến Chưởng Tôn. Dù từng vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, về sau ông dứt khoát tuyên bố đứng về phía Vương Lâm, một mình đánh bại ba đạo tôn, và trở thành người mạnh nhất tọa trấn tân Tiên Giới cho đến khi bị Xích Hồn Giáo đánh trọng thư","gioiTinh":"nam","cn":"蓝梦道尊","aliases":["Lam Mộng"]},{"id":"tien-phi-thu-ba","name":"Tiên phi thứ ba","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tiên phi từng gặp Vương Lâm ở vùng đất cổ mộ, thần sắc phức tạp khi tái ngộ.","vaiTro":"Tiên phi giới ngoại, từng gặp Vương Lâm ở cổ mộ","tinhCach":"Phức tạp, khó đoán","tabs":{"diem":[{"text":"Từng gặp Vương Lâm ở vùng đất cổ mộ, tái ngộ thần sắc vô cùng phức tạp","chuong":"@c1656"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện cùng các tiên phi giới ngoại trước đại môn, thần sắc vô cùng phức tạp khi nhìn thấy Vương Lâm.","anchor":"Một nữ tử trong số đó khi nhìn thấy Vương Lâm thần sắc vô cùng phức tạp"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng gặp ở vùng đất cổ mộ, tái ngộ thần sắc phức tạp"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1656"]},{"id":"nu-tu-trieu-ha","name":"Nữ tử từ Triệu Hà","gioiTinh":"nu","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử thuộc Triệu Hà, từng bị Vương Lâm cự tuyệt liên thủ nên oán hận, cười lạnh khi thấy hắn bị bao vây.","vaiTro":"Tu sĩ Triệu Hà, đối thủ của Vương Lâm","tinhCach":"Sát khí, thù dai, cười lạnh khi đối thủ gặp nạn","tabs":{"diem":[{"text":"Từng bị Vương Lâm cự tuyệt liên thủ nên mang oán hận, cười lạnh khi thấy hắn bị quần hùng bao vây","chuong":"@c1656"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Đạp sương mù xuất hiện trước đại môn, mang sát khí nhìn Vương Lâm, cười lạnh khi thấy hắn bị bao vây.","anchor":"Nàng sớm đã có mâu thuẫn với Vương Lâm. Năm đó Vương Lâm cự tuyệt liên thủ với nàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng bị Vương Lâm cự tuyệt liên thủ, oán hận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1656"]},{"id":"lao-gia-that-dao-tong","name":"Lão già Thất Đạo Tông","aliases":["viễn cổ tiên nhân Thất Đạo Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (viễn cổ tiên nhân, tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông, tiên nhân viễn cổ tiên vực giới ngoại tu vi không cao. May mắn vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương rồi bị Vương Lâm giết trong tàn giới.","vaiTro":"Đệ tử Thất Đạo Tông, người đầu tiên xâm nhập tàn giới Vương Lâm","tinhCach":[{"text":"Tham lam khi thấy giọt sương liền vội dung nhập, thiếu cảnh giác"}],"tabs":{"diem":[{"text":"Tiên nhân viễn cổ tiên vực tu vi thấp, may mắn vượt qua đống đổ nát nhưng bị Vương Lâm giết ngay khi vào tàn giới","chuong":"@c1659"},{"text":"May mắn vượt đống đổ nát an toàn nhờ thân pháp, nhưng lập tức bị Vương Lâm giết khi dung nhập tàn giới.","chuong":"@c1659"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phục kích giết chết trong tàn giới","ghiChu":"@c1659"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi bị cấm phi hành, nhưng vẫn không thoát được huyết kiếm","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"nu-tu-bi-an-c1659","name":"Nữ tử bí ẩn (dòng xoáy)","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thân ảnh mơ hồ xuất hiện trong dòng xoáy mới ở tàn giới Vương Lâm cuối chương 1659, danh tính chưa rõ.","vaiTro":"Nhân vật bí ẩn cuối chương, danh tính chưa xác định","tinhCach":[],"tabs":{"diem":[{"text":"Thân ảnh nữ tử mơ hồ xuất hiện trong dòng xoáy tàn giới, mở mạch sự kiện mới","chuong":"@c1659"},{"text":"Xuất hiện dưới dạng thân ảnh mơ hồ trong dòng xoáy, chưa rõ danh tính và mục đích.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"bridge","mucCt":"gon","text":"Thân ảnh mơ hồ xuất hiện trong dòng xoáy ngay sau khi Vương Lâm giết ba đệ tử Thất Đạo Tông, danh tính chưa rõ.","anchor":"Bên trong dòng xoáy đó có một thân ảnh mơ hồ, không giống nam tử mà là một nữ tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"tu-ha","name":"Tử Hà","aliases":["Thất phi Thất Thải Tiên Tôn"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"bi-phong-an","tabs":{"kinhLich":[{"chuong":"@c1660","importance":"normal","mucCt":"ky","tieuDe":"Mắc bẫy tâm lý Vương Lâm, bị trọng thương","text":"Xuất hiện từ dòng xoáy tại tàn giới, biết rõ quy tắc ba trăm tàn giới (không di chuyển thì quy tắc không phát tác), đi vào hơn mười tàn giới đều đứng yên dùng thần thức dẫn đường. Giao chiến thăm dò với Vương Lâm: triệu phượng hoàng tím đối kháng huyết kiếm, hai bên ngang sức. Phóng phi kiếm tím thử thêm nhưng bị sáu đạo bổn nguyên chấn nát. Lấy ngọc giản định truyền tin gọi viện binh nhưng cân nhắc rằng tứ đại chiến tướng sẽ đoạt mất hồn thứ ba nên thu lại. Suy luận ngược rằng Vương Lâm trọng thương đang phô trương che giấu, bước ra khỏi dòng xoáy truy đuổi, dòng xoáy tiêu tán mất đường rút. Quy tắc tàn giới phát tác khiến thân thể rơi vụt xuống, bị huyết kiếm đánh trúng mi tâm, máu đen phun ra từ ngực, y phục rách nát, trọng thương. Tỵ Thiên Quan là của nàng, rất có thể biết bí mật nơi này.","anchor":"Tuyệt đối không sai rồi! Vương Lâm, lúc này ngươi trốn không thoát đâu!"},{"importance":"normal","mucCt":"ky","chuong":"@c1661","tieuDe":"Bị Vương Lâm đánh bại và bắt sống","text":"Bị huyết kiếm xuyên ngực, bị sáu đạo bổn nguyên đánh trọng thương cả thân thể lẫn nguyên thần, liên tục phun máu, thân thể nứt nẻ. Không kịp xuất pháp bảo hay bắt quyết. Bị Định thân thuật cố định hoàn toàn, bị chín chỉ phong ấn đại thành, cuối cùng bị thu vào tay áo Vương Lâm. Được giữ sống vì trên người còn nhiều thứ khiến Vương Lâm hứng thú.","anchor":"Tử Hà không bị Vương Lâm giết. Trên người nàng còn có rất nhiều thứ khiến Vương Lâm cảm thấy hứng thú"},{"chuong":"@c1666","importance":"bridge","mucCt":"vua","text":"Bị Vương Lâm triệu hồi ra và điểm chỉ lên mi tâm khống chế thân thể, buộc truyền thần niệm vào ngọc giản truyền âm rồi ngọc giản vỡ vụn, đóng vai mồi nhử dụ đạo nhân bảy màu và Chiến lão quỷ tới.","anchor":"vẻ chống cự trong mắt Tử Hà càng đậm nhưng nàng lại không có biện pháp nào khống chế tâm thần và thân thể mình"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu tím","trangThai":"hong","moTa":"Phi kiếm tốc độ cực nhanh, bị Vương Lâm một chỉ chấn nát hóa sương mù tím.","nguon":"@c1660"}],"khac":[{"ten":"Ngọc giản truyền tin","moTa":"Dùng để truyền tin gọi viện binh trong tàn giới, lấy ra nhưng cuối cùng thu hồi không dùng.","nguon":"@c1660"}]}},"nguon":["@c1660","@c1661","@c1666"]},{"id":"thanh-nien-dao-co","name":"Thanh niên Đạo cổ nhất tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Thanh niên bí ẩn tự xưng thuộc Đạo cổ nhất tộc, đến Thất Đạo Tông ở Tiên Cương đại lục để đón một hài tử về nhà.","vaiTro":"Thành viên Đạo cổ nhất tộc, đến Tiên Cương tìm hài tử cùng tộc","tinhCach":[{"text":"Uể oải nhưng mang nụ cười chờ mong, ấm áp khi nhắc đến người đồng tộc"}],"tabs":{"diem":[{"text":"Tự xưng thuộc Đạo cổ nhất tộc, đến Thất Đạo Tông đón hài tử về nhà","chuong":"@c1633"}],"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện tại Thất Đạo Tông đón hài tử Đạo cổ","text":"Xuất hiện tại Tiên Cương đại lục vùng tiên tộc, đến dãy núi nơi từng có Thất Đạo Tông. Thần sắc uể oải nhưng nở nụ cười chờ mong, tự xưng đến đón hài tử của Đạo cổ nhất tộc về nhà, nói đường về có lẽ gian nan. Mỉm cười tiến vào dãy núi.","anchor":"Hài tử của Đạo cổ nhất tộc chúng ta, ta tới đón ngươi về nhà"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1633"]},{"id":"lao-gia-toc-bac-tang-ba","name":"Lão già tóc bạc tầng ba","cn":"","aliases":["Lão già tầng thứ ba"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền hậu kỳ đỉnh phong (nhờ áo giáp)","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông đóng giữ tầng ba tháp cao trên Ngũ Hành tinh, tinh thông mộc và thổ Ngũ Hành, tu vi Không Huyền trung kỳ bước ba.","vaiTro":"Đối thủ tại tháp cao Ngũ Hành tinh, canh giữ tầng ba","tinhCach":[{"text":"Kiêu ngạo, thần sắc âm trầm khi đánh giá đối phương, quyết đoán khi dùng thủ đoạn mạnh bất chấp phản phệ"}],"tabs":{"diem":[{"text":"Tinh thông mộc và thổ Ngũ Hành, sở trường dùng roi — pháp bảo đặc trưng Quy Nhất tông","chuong":"@c1645"},{"text":"Khoác áo giáp Quy Nhất tông tăng tu vi vượt bậc nhưng chịu phản phệ đau đớn, nhánh cây chui vào da thịt","chuong":"@c1645"},{"text":"Tinh thông mộc và thổ Ngũ Hành, phía sau hiện hư ảnh đại thụ che trời và cơn lốc đất cát","chuong":"@c1645"},{"text":"Phán đoán sai Vương Lâm là người Đạo cổ nhất mạch từ Tiên Cương đại lục tới tìm Diệp Mịch","chuong":"@c1645"}],"kinhLich":[{"chuong":"@c1645","importance":"normal","mucCt":"ky","tieuDe":"Giao chiến Vương Lâm tại tháp cao","text":"Bước ra từ tầng ba tháp cao, lập phòng hộ quanh tháp tuyên bố bắt Vương Lâm. Phán đoán sai Vương Lâm là người Đạo cổ nhất mạch từ Tiên Cương đại lục tới tìm Diệp Mịch. Dùng roi xanh biếc mộc lực Ngũ Hành dài mười trượng tấn công, roi hấp thu sinh cơ cây cỏ bổ sung bổn nguyên. Bị Vương Lâm rút Côn Cực tiên đấu roi và giật đứt roi. Khoác áo giáp Quy Nhất tông hợp nhất mộc và thổ, tu vi tăng từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong nhưng chịu phản phệ đau đớn. Hút hết cây cỏ trên Ngũ Hành tinh ngưng thành mộc nhân mấy ngàn trượng đội trời đạp đất tấn công Vương Lâm.","anchor":"Xông vào Ngũ Hành đại trận, Cửu Chuyển Tâm Luân, thằng nhãi con này thật to gan"}],"tuViMoc":[{"chuong":"@c1645","canhGioi":"Không Huyền trung kỳ bước ba","text":"Tu vi cơ bản Không Huyền trung kỳ bước ba, tinh thông mộc và thổ Ngũ Hành. Khoác áo giáp Quy Nhất tông tăng tạm lên Không Huyền hậu kỳ đỉnh phong.","importance":"major"},{"chuong":"@c1645","canhGioi":"Không Huyền hậu kỳ đỉnh phong (nhờ áo giáp)","text":"Khoác áo giáp Quy Nhất tông hợp nhất mộc+thổ, tu vi tăng vọt nhưng chịu phản phệ thống khổ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Giao chiến tại tháp cao Ngũ Hành tinh, bị Vương Lâm áp đảo giật đứt roi"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Mục tiêu suy đoán","ghiChu":"Suy đoán nhóm Đạo cổ nhất mạch tới Ngũ Hành tinh để tìm Diệp Mịch"}],"tuiDo":{"phapBao":[{"ten":"Roi xanh biếc","moTa":"Mộc lực Ngũ Hành hóa thành, dài mười trượng, hấp thu sinh cơ cây cỏ bổ sung bổn nguyên. Bị Vương Lâm giật đứt, thu hồi tàn dư hợp nhất vào áo giáp.","trangThai":"hong","nguon":"@c1645"},{"ten":"Áo giáp Quy Nhất tông","moTa":"Hợp nhất mộc+thổ Ngũ Hành, tăng tu vi từ Không Huyền trung kỳ lên hậu kỳ đỉnh phong, nhưng phản phệ đau đớn nhánh cây chui vào da thịt.","trangThai":"dang-co","nguon":"@c1645"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1645"]},{"id":"ba-tien-nhan-that-dao-tong-ngay-6","name":"Ba tiên nhân Thất Đạo Tông (ngày thứ sáu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (người mạnh nhất trong nhóm)","trangThai":"tu-vong","blurb":"Ba đệ tử Thất Đạo Tông viễn cổ tiên vực gồm một Không Niết sơ kỳ và hai thiên nhân ngũ suy, bị Vương Lâm phục kích giết trong chưa tới ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới","tinhCach":[],"tabs":{"diem":[{"text":"Bị Vương Lâm giết cả ba trong chưa tới ba nhịp thở, người Không Niết sơ kỳ định đốt cây hương nhưng không kịp.","chuong":"@c1659"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết cả ba","ghiChu":"Bị phục kích giết trong tàn giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Cây hương","moTa":"Tiên nhân Không Niết sơ kỳ chụp từ hư không, định đốt lên (nghi tín hiệu cầu viện) nhưng không kịp do bị cấm phi hành.","nguon":"@c1659"}]}},"nguon":["@c1659"]},{"id":"lao-gia-that-dao-tong-vien-co","name":"Lão già Thất Đạo Tông (viễn cổ tiên nhân)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông, tiên nhân viễn cổ tiên vực giới ngoại, tu vi không cao. May mắn vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương nhưng bị Vương Lâm giết trong tàn giới.","vaiTro":"Tiên nhân viễn cổ tiên vực, đệ tử Thất Đạo Tông, nạn nhân đầu tiên của Vương Lâm trong tàn giới","tinhCach":[{"text":"Hoảng sợ khi nhận ra tơ máu ngăn cách phía sau, lập tức xông vào đại đỉnh tìm cơ duyên"}],"tabs":{"diem":[{"text":"May mắn vượt qua cấm chế đống đổ nát nhưng bị Vương Lâm phục kích giết trong tàn giới, huyết mạch và thần hồn bị tế cho cánh tay đen bí ẩn","chuong":"@c1659"},{"text":"May mắn vượt qua cấm chế tơ máu nhưng bước vào tàn giới Vương Lâm, trở thành vật thí nghiệm quy tắc cấm phi hành.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","mucCt":"vua","tieuDe":"Vượt cấm chế, bị giết trong tàn giới","text":"May mắn vượt đống đổ nát không kích hoạt cấm chế, bước vào đại đỉnh chọn giọt sương dung nhập tàn giới Vương Lâm. Bị quy tắc cấm phi hành khiến mất khả năng bay, dùng phất trần nâng thân nhưng bị huyết kiếm xuyên mi tâm nổ tung chết, nguyên thần bị đánh nát, huyết mạch và hồn phách bị tế cho thân thể kia.","anchor":"ngay cả nguyên thần cũng bị huyết kiếm đánh cho nát bấy, lập tức tử vong"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ phục kích giết hắn trong tàn giới","ghiChu":"@c1659"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi bị cấm phi hành, nhưng không cứu được mạng","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"thanh-nien-bi-an-that-dao-tong","name":"Thanh niên bí ẩn (Thất Đạo Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Thanh niên thần bí xuất hiện ở vùng núi Thất Đạo Tông trên Tiên Cương đại lục, tự xưng tới đón hài tử của Đạo cổ nhất tộc về nhà.","vaiTro":"Thành viên Đạo cổ nhất tộc, tới Thất Đạo Tông đón người.","tinhCach":[{"text":"Thần sắc uể oải nhưng đầy chờ mong, giọng ôn hòa."}],"tabs":{"diem":[{"text":"Tự xưng thuộc Đạo cổ nhất tộc, tới Thất Đạo Tông đón hài tử về nhà, mở ra tuyến mới liên quan tộc Đạo cổ.","chuong":"@c1633"}],"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện ở Thất Đạo Tông đón hài tử Đạo cổ nhất tộc","text":"Xuất hiện trong đêm trăng ở vùng núi Thất Đạo Tông trên Tiên Cương đại lục, thần sắc uể oải nhưng đầy chờ mong. Tự xưng tới đón hài tử của Đạo cổ nhất tộc về nhà, rồi mỉm cười tiến vào dãy núi.","anchor":"Hài tử của Đạo cổ nhất tộc chúng ta, ta tới đón ngươi về nhà"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1633"]},{"id":"lao-gia-tdat-c1659","name":"Lão già đệ tử Thất Đạo Tông (viễn cổ tiên nhân)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (viễn cổ tiên nhân, tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông từ viễn cổ tiên vực, tu vi không cao, may mắn vượt qua đống đổ nát vào đại đỉnh nhưng bị Vương Lâm phục kích giết trong tàn giới.","vaiTro":"Nạn nhân đầu tiên của Vương Lâm trong tàn giới","tinhCach":[{"text":"Thận trọng nhưng tham lam, thấy giọt sương liền dung nhập vào"}],"tabs":{"diem":[{"text":"May mắn vượt qua cấm chế tơ máu nhưng lại rơi vào tàn giới Vương Lâm, trở thành vật thí nghiệm quy tắc cấm phi hành","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","tieuDe":"Bị Vương Lâm giết trong tàn giới","text":"Vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương. Trong tàn giới bị quy tắc cấm phi hành khiến mất khả năng bay, dùng phất trần nâng thân nhưng bị huyết kiếm xuyên mi tâm nổ tung tử vong. Huyết mạch và nguyên thần bị cánh tay đen thu lấy tế cho thân thể.","mucCt":"vua","anchor":"huyết quang đã lóe qua mi tâm của hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết hắn","ghiChu":"Bị phục kích trong tàn giới"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi mất khả năng phi hành, nhưng không cứu được mạng","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"ba-tien-nhan-tdat-c1659","name":"Ba tiên nhân Thất Đạo Tông (nhóm ngày thứ sáu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (người mạnh nhất trong nhóm)","trangThai":"tu-vong","blurb":"Ba đệ tử Thất Đạo Tông viễn cổ tiên vực — một Không Niết sơ kỳ, hai thiên nhân ngũ suy chưa bước thứ ba — bị Vương Lâm phục kích giết sạch trong chưa đầy ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới","tinhCach":[{"text":"Không kịp phản ứng trước phục kích"}],"tabs":{"diem":[{"text":"Bị giết sạch trong chưa đầy ba nhịp thở, tiên nhân Không Niết sơ kỳ định đốt cây hương cầu viện nhưng không kịp","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","tieuDe":"Bị Vương Lâm phục kích giết trong tàn giới","text":"Xuất hiện qua dòng xoáy vào tàn giới, bị Vương Lâm ra tay cực nhanh: huyết kiếm chém đầu một người, chỉ điểm mi tâm giết người thứ hai, kích hoạt cấm phi hành khiến tiên nhân Không Niết sơ kỳ rơi xuống rồi huyết kiếm xuyên ngực kết hợp chưởng ấn đánh tan nát. Tiên nhân Không Niết định đốt cây hương cầu viện nhưng không kịp.","mucCt":"gon","anchor":"Giết ba người không cần tới ba nhịp thở!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết cả ba","ghiChu":"Bị phục kích trong tàn giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Cây hương","moTa":"Tiên nhân Không Niết sơ kỳ rút ra định đốt (nghi vật cầu viện) nhưng bị rơi xuống do cấm phi hành, không kịp đốt đã bị giết","nguon":"@c1659"}]}},"nguon":["@c1659"]},{"id":"ba-de-tu-that-dao-tong-dot-hai","name":"Ba đệ tử Thất Đạo Tông (đợt hai)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (mạnh nhất trong ba)","trangThai":"tu-vong","blurb":"Ba tiên nhân viễn cổ tiên vực mặc đạo bào Thất Đạo Tông, bị Vương Lâm phục kích giết sạch trong chưa tới ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới.","tinhCach":[{"text":"Không kịp phản ứng trước phục kích"}],"tabs":{"diem":[{"text":"Một Không Niết sơ kỳ và hai thiên nhân ngũ suy, bị Vương Lâm giết trong chưa tới ba nhịp thở ngay khi vừa xuất hiện qua dòng xoáy.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","mucCt":"gon","tieuDe":"Bị phục kích giết sạch trong tàn giới","text":"Vừa xuất hiện qua dòng xoáy liền bị Vương Lâm phục kích: huyết kiếm chém đầu người thứ nhất, điểm chỉ mi tâm giết người thứ hai, người Không Niết sơ kỳ bị cấm phi hành rơi xuống rồi bị huyết kiếm xuyên ngực và chưởng đánh tan nát.","anchor":"Giết ba người không cần tới ba nhịp thở!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phục kích giết chết","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"bach-ho-chien-tuong","name":"Bạch Hổ chiến tướng","cn":"白虎战将","aliases":["Bạch Hổ Thánh Hoàng"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1663","importance":"normal","mucCt":"ky","tieuDe":"Bại trận trong giới cờ trước Vương Lâm","text":"Dung nhập thần sắc vào chiến tướng bạch giáp, hiện hư ảnh mãnh hổ ngập trời. Lần va chạm đầu với Vương Lâm, vũ khí và ngựa đều hủy, bổn tôn phun máu hoảng sợ trước sát khí Vương Lâm. Từ chối nhận thua, tự đấm ngực phun máu dung hợp cho bạch giáp, phóng ngàn giọt huyết khí giết gần mười vạn binh lính không phân địch ta để tái tạo giáp và mã. Lần hai bạch mã hóa Bạch Hổ thật, cầm thương ba trượng xung phong nhưng bị Vương Lâm một đao chẻ đôi chiến tướng bạch giáp từ mi tâm. Bổn tôn phun máu, thần sắc ảm đạm. Bị Vương Lâm tuyên bố thu làm nô bộc.","anchor":"Bạch Hổ ta tuyệt đối sẽ không nhận thua"},{"mucCt":"vua","text":"Bị uy áp của Vương Lâm đè nặng như ngọn núi, buộc phải cúi đầu khuất phục do thân thể thần thức đã bị cắn nuốt và lời thề huyết mạch ràng buộc. Quy tắc Bạch Hổ bị đường đao đánh tan, phun máu tươi. Sau khi tàn giới hủy diệt, lời thề có hiệu lực, nhận mệnh lệnh đầu tiên từ Vương Lâm: bắt tu sĩ Ngũ Hành tinh.","anchor":"Lời thề của hắn đã có hiệu lực","bridge":true,"khoang":"@c1664"},{"mucCt":"vua","text":"Bị Vương Lâm phóng thích cùng tu sĩ trung niên Ngũ Hành Tinh. Sửng sốt được tha, ánh mắt cảm kích, vái sâu Vương Lâm rồi cùng Huyền Vũ và Chu Tước bay vào kim môn.","anchor":"Bạch Hổ chiến tướng sửng sốt, ánh mắt lộ vẻ cảm kích, hướng về phía Vương Lâm vái một cái thật sâu","bridge":true,"khoang":"@c1691"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1663","@c1664","@c1691"]},{"id":"tu-si-ngu-hanh-tinh","name":"Tu sĩ Ngũ Hành tinh","cn":"","aliases":["chiến tướng kim giáp"],"gioiTinh":"nam","vaiTro":"Tu sĩ hóa chiến tướng kim giáp trong giới cờ, quân cờ yếu nhất","tinhCach":"yếu đuối; hoảng sợ trước nguy hiểm","blurb":"Tu sĩ đến từ Ngũ Hành tinh, bị biến thành chiến tướng kim giáp trong ván cờ giới. Là quân cờ yếu nhất, bị Vương Lâm thôn phệ bằng bản năng thôn hồn.","trangThai":"song","tabs":{"diem":[{"text":"Quân cờ yếu nhất trong giới cờ, bị Vương Lâm thôn phệ bằng bản năng thôn hồn để tăng cường lực lượng.","chuong":"@c1663"}],"kinhLich":[{"mucCt":"gon","text":"Là quân cờ yếu nhất, hoảng sợ lui lại khi Vương Lâm nhắm tới, bị một chưởng phá nát kim giáp rồi bị thôn phệ bởi bản năng thôn hồn của thần thức Vương Lâm.","anchor":"chiến tướng này hét thảm một tiếng, kim giáp toàn thân lập tức tan nát","bridge":true,"khoang":"@c1663"},{"chuong":"@c1664","importance":"bridge","mucCt":"gon","tieuDe":"Bị lệnh bắt giữ","text":"Dưới uy áp của Vương Lâm kính sợ tái nhợt, bị Vương Lâm ra lệnh cho Bạch Hổ chiến tướng bắt giữ vì có chỗ quan trọng cần dùng.","anchor":"Bắt hắn, hắn đối với ta có chỗ quan trọng cần dùng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Đứng ngoài quan sát trận chiến","text":"Cùng đám người từ vòng xoáy đi ra, tới gần tu chân tinh nhưng khi đạo nhân bảy màu và Chiến lão quỷ xuất hiện thì đứng yên trong tinh không lạnh lùng quan sát.","anchor":"đám người lão già họ Mã ở Ngũ Hành Tinh vẫn đứng trong tinh không không hề nhúc nhích, lạnh lùng nhìn lại"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm thôn phệ trong giới cờ","ghiChu":"@c1663"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1663","@c1664","@c1667"]},{"id":"huyen-la-dai-thien-ton","name":"Huyền La Đại Thiên Tôn","gioiTinh":"nam","aliases":["Huyền La"],"theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"},{"ten":"Cửu Dương","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn (một trong Cửu Dương)","trangThai":"song","blurb":"Huyền La đại thiên tôn là cường giả thuộc Cổ quốc, từng giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết và tranh đoạt bảo vật Thái Cổ Thần Cảnh cùng Đạo Nhất đại thiên tôn. Sau khi cảm ứng hồn huyết ngưng tụ, ông dùng thuật bói toán truy tìm nguồn gốc, phong ấn tin tức rồi âm thầm bám theo Vương Lâm suốt hành trình khảo nghiệm, cuối cùng chính thức hiện thân mời Vương Lâm làm đệ tử duy nhất. Sự tồn tại của ông trở thành chỗ dựa bí mật cho Vương Lâm trong các cuộc đối đầu về sau, và ông vẫn theo dõi đệ tử từ nơi bế quan tại Đạo Cổ nhất tộc.","vaiTro":"Đại thiên tôn Cổ quốc — sư phụ duy nhất của Vương Lâm, cường giả giữ kỷ lục cổ Mạch Thương Khung Huyết","tinhCach":"Mưu lược thâm trầm, giỏi dùng thuật bói toán truy nguyên; quyết đoán khi phong ấn tin tức và đích thân hành động; kiên nhẫn quan sát, lấy thử thách làm phép khảo nghiệm đệ tử; bình thản trước biến cố nhưng vẫn có thể rung động trước sự kiện chưa từng có","tabs":{"diem":[{"text":"Giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết, một trong chín vầng mặt trời","chuong":"@c1611"},{"text":"Phong ấn tin tức hồn huyết, phân hóa mặt trời đỏ thành gần trăm vạn phần dung nhập vào thân tộc nhân Đạo cổ, đích thân tới Thất Đạo Tông đón Vương Lâm","chuong":"@c1615"},{"text":"Âm thầm bám theo Vương Lâm từ phía sau suốt cuộc truy kích, coi đây là lần khảo nghiệm đệ tử thay vì ra tay giúp","chuong":"@c1665"},{"text":"Chính thức hiện thân mời Vương Lâm làm đệ tử duy nhất, thần thức người khác không thể cảm nhận sự tồn tại củaông","chuong":"@c1692"},{"text":"Trở thành chỗ dựa bí mật cho Vương Lâm, thân phận đệ tử duy nhất của ông là bảo hộ ngầm trong các cuộc đối đầu","chuong":"@c1841"},{"text":"Tại nơi bế quan ở Đạo Cổ nhất tộc, nghe tin Vương Lâm vang danh Tiên Tộc thì vừa than thở vừa tự hào","chuong":"@c1866"}],"kinhLich":[{"mucCt":"vua","text":"Theo dõi toàn bộ cuộc truy kích Vương Lâm từ phía sau, quyết định không ra tay giúp mà coi đây là lần khảo nghiệm cuối cùng. Chứng kiến Vương Lâm dùng kế trong kế thoát thân, kinh ngạc khen ngợi là rồng trong cõi người.","anchor":"Để người này rèn luyện cần phải như thế. Nếu hắn có thể phát hiện ra sự tồn tại của ta thì ta mới ra tay","bridge":true,"khoang":"@c1665"},{"mucCt":"vua","text":"Là người duy nhất biết thần thông Mục Ngư mở mắt biến hóa. Thu lấy con Mục Ngư thứ năm. Nhận ra người điên là Liên Đạo Phi — đệ đệ của Liên Đạo Chân, ánh mắt lộ ra ánh sáng kỳ dị.","anchor":"Liên Đạo Phi Đệ đệ của Liên Đạo Chân hắn không ngờ cũng tới nơi này","bridge":true,"khoang":"@c1670"},{"mucCt":"vua","text":"Đứng nơi con Mục Ngư thứ tư biến mất, cười đắc ý nhìn Vương Lâm kinh ngạc. Đã thu tổng cộng sáu con Mục Ngư (năm con biến mất trước đó cộng con thứ tư trước mắt Vương Lâm).","anchor":"khóe miệng lộ nụ cười đắc ý","bridge":true,"khoang":"@c1671"},{"mucCt":"ky","text":"Ẩn trong thiên địa đóng băng quan sát Vương Lâm hấp thu nguyên thần huyết, chủ động gia cố tầng băng mạnh hơn ngàn vạn lần để tranh thủ thời gian. Nhận xét nữ Cổ Thần thuộc Đạo cổ nhất mạch, có thể bồi dưỡng làm thị thiếp cho đệ tử duy nhất. Đánh giá Diệp Mịch thiên tư không tồi nhưng không thể đoạt xá Vương Lâm do hồn huyết, chọn đứng về phía Vương Lâm.","anchor":"Ngươi muốn thời gian bao lâu ta sẽ cho ngươi bấy lâu","bridge":true,"khoang":"@c1672"},{"importance":"bridge","mucCt":"gon","chuong":"@c1673","text":"Ngạc nhiên khi ánh mắt Vương Lâm thoáng chạm vào hắn, sau đó chắp tay sau lưng đứng trên bầu trời hồ băng quan sát Vương Lâm phá băng dung hợp cánh tay trái Diệp Mịch, cười cười với ánh mắt cổ quái.","anchor":"Huyền La Đại Thiên Tôn chắp tay sau lưng, cũng nhìn về hồ nước này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1674","tieuDe":"Nhận ra nơi Diệp Mịch tử vong","text":"Đứng trên đài cao trong vùng đất cổ mộ, nhìn sương mù và than nhẹ rằng đây chính là nơi Diệp Mịch tử vong.","anchor":"Nơi này chính là nơi mà đứa nhỏ Diệp Mịch tử vong rồi"},{"mucCt":"ky","text":"Bình tĩnh quan sát Vương Lâm suốt trận chiến, cảm thấy vừa lòng với tâm trí và quyết đoán của Vương Lâm. Khi Vương Lâm lùi ba bước tới sau lưng hắn, ánh mắt hai người chạm nhau trong vô hình. Huyền La cười nói Thú vị, tùy ý giơ tay chỉ — dừng kim ấn giữa không trung rồi biến nó từ thần thông hư ảo thành pháp bảo thực chất. Chưởng Tôn kinh hãi xác nhận đây là năng lực thay trời đổi đất, lấy tạo hóa sinh vật chỉ cửu đại thiên tôn Tiên Cương Cửu Dương mới làm được, gọi Huyền La là ca ca của chủ nhân.","anchor":"Huyền La đột nhiên cười, hắn giơ tay phải lên rất tùy ý chỉ vào kim ấn đang từ trên không trung hạ xuống","bridge":true,"khoang":"@c1677"},{"importance":"bridge","mucCt":"gon","chuong":"@c1678","text":"Đứng trước Vương Lâm liếc nhìn đầy thâm ý rồi cười, sự hiện diện khiến Chưởng Tôn hoảng sợ tới cực điểm, không trực tiếp giao chiến.","anchor":"liếc nhìn Vương Lâm một cái đầy thâm ý, đột nhiên cười"},{"mucCt":"vua","text":"Ở trên mặt đất đằng xa, ngay khi Dĩ Ti xuất hiện liền nhận ra đây là khôi linh đã chuyển biến hai lần. Than rằng Thất Thải Tiên Tôn lòng dạ ác độc.","anchor":"quả nhiên chính là khôi linh, hơn nữa đã chuyển biến hai lần","bridge":true,"khoang":"@c1679"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra ngân mục do hồn huyết cổ Tổ","text":"Kích động khi thấy Vương Lâm có đôi mắt bạc, nhận ra đây là do hồn huyết cổ Tổ mang lại đệ nhất tượng trong cửu khúc — Ngân mục. Đây là lần thứ hai hắn thấy ngân mục.","anchor":"Hồn huyết của cổ Tổ. Khiến hắn có được đệ nhất tượng trong cửu khúc - Ngân mục"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Đứng xa quan sát trận chiến, khi nhìn thấy hư ảnh đầu lâu Cổ Tổ do Đạo Cổ Vô Tiên triệu ra thì chấn động sùng kính gọi Cổ tổ.","anchor":"Huyền La đứng ở đằng xa nhìn thấy cảnh tượng này thân thể chấn động"},{"mucCt":"vua","text":"Đã bám theo Vương Lâm từ Ngũ Hành Tinh tới Tiên Giới rồi tới trung tâm động phủ mà ẩn thân. Bị Vương Lâm gọi đích danh, buộc phải xuất hiện dưới dạng thân ảnh mơ hồ từ hư vô, kinh ngạc hỏi Vương Lâm sao biết tên mình.","anchor":"Ngươi làm sao biết được tên của bổn tôn","bridge":true,"khoang":"@c1691"},{"chuong":"@c1692","importance":"normal","mucCt":"ky","tieuDe":"Hiện thân, mời Vương Lâm làm đệ tử duy nhất","text":"Chính thức hiện thân trước Vương Lâm, Lam Mộng đạo tôn và Thác Sâm, thần thức không thể cảm nhận sự tồn tại của hắn. Tự suy đoán đúng cách Vương Lâm phát hiện thân phận mình, thừa nhận sơ sót việc Mục Ngư cảm nhận khí tức lẫn nhau. Xác nhận thân phận: một trong Cửu Dương, Đại Thiên Tôn của Đạo Cổ nhất mạch tại Tiên Cương đại lục. Xác định muốn Vương Lâm làm đệ tử duy nhất vì hắn vượt mọi kỳ vọng, đặc biệt chưa từng xin giúp đỡ. Giải thích quy tắc Tiên Cương: sinh linh không có huyết mạch bị hồn phi phách tán, bác bỏ tiếp dẫn giả (trừ Cửu Dương đồng thời ra tay). Phát hiện hồn Uyển Nhi không hoàn chỉnh, một phần biến mất không dấu vết. Đề xuất Thiên Dương luân hồi chuyển thế thuật cho bằng hữu Vương Lâm, riêng Uyển Nhi cho năm phần mười cơ hội mang trực tiếp, phải trả giá rất lớn nhưng không do dự.","anchor":"Theo ta trở về lãnh địa của Đạo Cổ nhất mạch tại Tiên Cương đại lục, trở thành đệ tử duy nhất của Huyền La ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng khảo nghiệm / theo dõi","ghiChu":"Âm thầm theo dõi cuộc truy kích, đặt điều kiện chỉ ra tay khi Vương Lâm phát hiện sự tồn tại của hắn. @c1665"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử duy nhất (đã mời, chưa chính thức nhận)","ghiChu":"Cực kỳ hài lòng, trả giá lớn giúp đỡ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1665","@c1670","@c1671","@c1672","@c1673","@c1674","@c1677","@c1678","@c1679","@c1682","@c1683","@c1690","@c1691","@c1692"],"cn":"玄罗大天尊"},{"id":"tam-phi","name":"Tam phi","aliases":["Đường San","Đệ tam phi","Tam phi"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1667","tieuDe":"Do dự trước bẫy Vương Lâm","text":"Thần sắc lạnh như băng, mục đích duy nhất là trở về Tiên Cương Đại Lục. Đối với Vương Lâm không biết là địch hay bạn, do dự rồi vẫn đến nhưng không bước vào tu chân tinh.","anchor":"Mục đích của nàng chỉ có một, đó chính là trở về nhà!"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Ở đằng xa, sắc mặt tái nhợt, thần sắc ngây ra khi thấy Liên Đạo Phi xuất hiện.","anchor":"bổn vương sẽ mách với ca ca, các ngươi thật là quá đáng"},{"mucCt":"vua","text":"Bay trong sương mù đệ tứ hoa, nhận ra đây là vùng đất cổ mộ. Hồi ức về lần gặp Vương Lâm năm đó ở nơi này, xác nhận hắn là người đầu tiên trong đời ra tay giúp nàng, trong lòng muốn báo đáp. Tưởng niệm sư tôn và muội muội, muốn về nhà.","anchor":"Hắn đã từng trợ giúp ta. Việc này phải báo đáp","bridge":true,"khoang":"@c1674"},{"mucCt":"ky","text":"Nhìn thấy u quang truyền tống trận trong sương mù, do dự hồi lâu rồi cắn răng bước vào tầng hai theo Vương Lâm. Bị tiếng gầm Dĩ Ti Chi Khôi tấn công, dùng kim môn phòng hộ chống đỡ nhưng liên tục bị phá vỡ, phun máu nhiều lần. Truyền âm tìm Vương Lâm, nói muốn trả ơn năm xưa. Khi Vương Lâm hiện thân chặn dư âm cho nàng rồi lạnh lùng từ chối giúp đỡ, đưa ra chuỗi hạt châu trên cổ tay do sư tôn ban tặng — có thể hóa thành bảy kim môn đồng thời hiện ra — đề nghị giúp hắn tiến vào ngọn núi nơi Dĩ Ti Chi Khôi ẩn náu.","anchor":"Vật này là do sư tôn của ta ban tặng nhưng có thể hóa thành bảy kim môn đồng thời hiện ra","bridge":true,"khoang":"@c1675"},{"importance":"normal","mucCt":"ky","chuong":"@c1676","tieuDe":"Tiết lộ tên thật, thi triển phòng hộ lên người khác","text":"Cho Vương Lâm biết tên thật là Đường San, nói muốn trả ơn năm xưa ở vùng đất cổ mộ. Khi Vân Dật Phong xuất hiện, mở Thất Diện Kim Môn phòng thân. Sau trận đấu, thi triển bảy kim môn phòng hộ lên cả Vân Dật Phong và Vương Lâm, khiến Vương Lâm cả đời lần đầu chứng kiến thần thông phòng hộ dùng cho người khác.","anchor":"đây là lần đầu tiên chứng kiến thần thông phòng hộ có thể thi triển lên người khác"},{"mucCt":"vua","text":"Thi triển bảy kim môn lên Vương Lâm và Vân Dật Phong vừa chữa trị vừa phòng hộ, đồng thời triệu chín thanh phi kiếm lập kiếm trận tấn công Chưởng Tôn. Chín phi kiếm bị kim quang phá nát, hạt châu màu vàng trên cổ tay và bảy kim môn chống đỡ nhưng bị phản lực, khóe miệng tràn máu lùi lại.","anchor":"Hạt châu màu vàng ở trên cổ tay Đường San nhanh chóng lóe lên","bridge":true,"khoang":"@c1677"},{"mucCt":"vua","text":"Vung hạt châu màu vàng trên cổ tay, kim môn xuất hiện, thất môn hợp nhất hóa cự long màu vàng lao tấn công Chưởng Tôn. Sau đó bị thương, khóe miệng tràn máu lùi ngàn trượng.","anchor":"con cự long màu vàng, từ trong kim môn kia lao ra","bridge":true,"khoang":"@c1678"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang kéo dung hợp góp sức phong ấn Chưởng Tôn, khi Dĩ Ti hiện hình sắc mặt tái nhợt liên tục lùi lại.","anchor":"sắc mặt Đường San liền lập tức tái nhợt, thân thể liên tục lùi lại phía sau mấy bước"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Triển bảy kim môn chặn Chiến lão quỷ","text":"Trầm mặc gật đầu khi Vương Lâm tuyên bố hai bên cân bằng. Vung tay triển khai bảy kim môn quanh bốn phía mọi người, ở lại chặn Chiến lão quỷ.","anchor":"Lập tức bốn phía mọi người đều hiện lên bảy kim môn."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bị cuồng phong đánh văng trọng thương, máu tươi tràn miệng.","anchor":"cuồng phong gào thét cuốn thân thể đệ tam phi Đường San đi"},{"chuong":"@c1682","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Nhảy lên lao tới định ngăn Huyền Vũ và Chu Tước xâm nhập tầng cuối nhưng chậm hơn tốc độ hai chiến tướng.","anchor":"Đường San lúc này không chút chần chừ. Nàng cắn răng nhảy lên"},{"importance":"normal","mucCt":"vua","chuong":"@c1691","tieuDe":"Từ biệt Vương Lâm qua kim môn","text":"Nhìn kim môn rơi nước mắt nhớ quê hương, tông môn, sư tôn. Bước tới kim môn cảm ơn Vương Lâm, trước khi biến mất quay đầu hỏi có thể gặp lại không, Vương Lâm không đáp, mắt nàng ảm đạm rồi biến mất trong kim quang.","anchor":"Chúng ta còn có thể gặp lại không"}],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân từng giúp đỡ tại vùng đất cổ mộ","ghiChu":"Muốn trả ơn, thi triển phòng hộ lên người Vương Lâm"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Cùng phe Vương Lâm sau thệ huyết","ghiChu":"Thi triển Thất Diện Kim Môn phòng hộ lên người Vân Dật Phong"}],"tuViMoc":[],"diem":[{"text":"Khoanh chân tu luyện trên đỉnh núi một tu chân tinh trong Thái Cổ Tinh Thần, chờ đợi cơ hội trở về Tiên Cương Đại Lục","chuong":"@c1589"},{"text":"Do dự hồi lâu rồi cắn răng bước vào truyền tống trận tầng hai, theo Vương Lâm vào hiểm cảnh","chuong":"@c1675"},{"text":"Tiết lộ tên thật là Đường San, nói muốn trả ơn năm xưa ở vùng đất cổ mộ cho Vương Lâm","chuong":"@c1676"},{"text":"Thi triển bảy kim môn hợp nhất hóa cự long màu vàng tấn công Chưởng Tôn, chiến đấu quyết liệt","chuong":"@c1678"},{"text":"Bị cuồng phong đánh văng trọng thương, máu tươi tràn miệng nhưng vẫn tiếp tục chiến đấu","chuong":"@c1681"},{"text":"Nhìn kim môn rơi nước mắt nhớ quê hương và sư tôn, cảm ơn Vương Lâm rồi bước vào kim môn từ biệt","chuong":"@c1691"}]},"nguon":["@c1667","@c1670","@c1674","@c1675","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1682","@c1691"],"trangThai":"song","canhGioiCaoNhat":"Không rõ","vaiTro":"Một trong bát phi tiên tôn — nữ tu bạch y bí ẩn trong Thái Cổ Tinh Thần","tinhCach":"Băng lạnh, thần sắc lạnh như băng; trọng ân nghĩa, chủ động trả ơn cứu mạng năm xưa; quả cảm, dám cắn răng bước vào hiểm cảnh; nặng lòng cố hương, rơi nước mắt trước kim môn về quê","blurb":"Tam phi, tên thật Đường San, là một trong bát phi của tiên tôn, dung nhan tuyệt mỹ, tính tình băng lạnh. Sau khi rời vùng đất cổ mộ, nàng khoanh chân chờ đợi trên đỉnh núi một tu chân tinh trong Thái Cổ Tinh Thần. Khi gặp lại Vương Lâm, nàng nhiều lần liều mình trợ chiến, thi triển bảy kim môn phòng hộ và chiến đấu, cuối cùng từ biệt Vương Lâm qua kim môn trở về Tiên Cương Đại Lục.","cn":"唐珊","gioiTinh":"nu","theLuc":[{"ten":"Thiên Môn Đạo","trangThai":"gan-bo"}]},{"id":"luc-phi","name":"Lục phi","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Theo chiến hương tới tu chân tinh","text":"Từng suýt chết dưới tay Vương Lâm, mắt lộ oán độc, cắn răng theo mùi hương tới tu chân tinh.","anchor":"Lục phi kia trong mắt lộ ra vẻ oán độc, năm đó nàng may mắn thoát khỏi tay Vương Lâm"},{"importance":"normal","mucCt":"gon","chuong":"@c1668","tieuDe":"Bị U Minh Thú nuốt","text":"Chật vật ra khỏi biển lửa thân thể trọng thương, bị lực hút U Minh Thú cuốn vào, gào thét không chống nổi, bị nuốt.","anchor":"lục phi kia trong tiếng gào thét chói tai không thể chống lại lực hút này, thân thể mềm mại trực tiếp bị cuốn vào bên trong cái miệng của u Minh Thú"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1667","@c1668"],"trangThai":"song"},{"id":"lao-gia-ao-vai-tho-xanh","name":"Lão già áo vải thô xanh","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thủ lĩnh đám đệ tử Thất Đạo Tông từ Viễn cổ Tiên Vực, bước ra từ tinh không giới nội khi ngửi thấy chiến hương.","vaiTro":"Thủ lĩnh đệ tử Thất Đạo Tông tại giới ngoại","tinhCach":"Cảnh giác; hành động nhanh","tabs":{"diem":[{"text":"Dẫn đầu đệ tử Thất Đạo Tông ở giới ngoại, lập tức hành động khi ngửi thấy chiến hương","chuong":"@c1667"}],"kinhLich":[{"mucCt":"gon","text":"Bước ra từ tinh không giới nội, ngửi thấy chiến hương, dẫn đầu đệ tử Thất Đạo Tông tới tu chân tinh của Vương Lâm.","anchor":"Ai đã đốt chiến hương vậy, chẳng lẽ đã có phát hiện gì","bridge":true,"khoang":"@c1667"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1667"]},{"id":"nam-tu-trung-nien-ao-tim","name":"Nam tử trung niên áo tím đạo bào","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ Thất Đạo Tông đang tìm kiếm trên tu chân tinh ở giới khác, lập tức rời đi khi cảm nhận mùi chiến hương.","vaiTro":"Đệ tử Thất Đạo Tông tại giới ngoại","tinhCach":"Phản ứng nhanh nhạy","tabs":{"diem":[{"text":"Không cần nghĩ ngợi lập tức biến mất khi cảm nhận mùi hương","chuong":"@c1667"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Theo chiến hương rời đi","text":"Đang tìm kiếm trên tu chân tinh ở giới khác, cảm nhận mùi chiến hương lập tức biến mất rời khỏi.","anchor":"hai mắt hắn lóe lên không cần nghĩ ngợi lập tức biến mất rời khỏi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1667"]},{"id":"lao-gia-ho-ma","name":"Lão già họ Mã","cn":"","aliases":["Lão già họ Mã (Ngũ Hành tinh)"],"gioiTinh":"nam","theLuc":[{"ten":"Ngũ Hành Tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão già họ Mã cầm đầu đám tu sĩ Ngũ Hành Tinh, ban đầu đứng xa quan sát trận chiến trên tu chân tinh mà không tham chiến. Sau bị Huyền La Đại Thiên Tôn ép bất đắc dĩ ra tay, thần thông bị hồn phách Thất Thải Tiên Tôn phá vỡ, chịu lực phản chấn nặng nề. Cuối cùng là người đầu tiên bước ra tiễn biệt Vương Lâm khi hắn rời đi.","vaiTro":"Thủ lĩnh đám tu sĩ Ngũ Hành Tinh — nhân vật phụ trong trận chiến tu chân tinh","tinhCach":"Thận trọng, biết đánh giá tình thế; dễ bị chấn động trước cường giả; có khí chất hiền từ, trọng nghĩa","tabs":{"diem":[{"text":"Cầm đầu đám tu sĩ Ngũ Hành Tinh đứng xa quan sát trận chiến, chấn động trước cung Lý Quảng","chuong":"@c1669"},{"text":"Kinh hoàng khi nhận ra Liên Đạo Phi xuất hiện, run rẩy trước thần thông Mục Ngư mở mắt","chuong":"@c1670"},{"text":"Bất đắc dĩ ra tay theo yêu cầu Huyền La Đại Thiên Tôn, bị ép không thể từ chối","chuong":"@c1681"},{"text":"Cánh tay kim sắc bị hồn phách Thất Thải Tiên Tôn phá, chịu phản chấn lui trăm trượng, khóe miệng tràn máu","chuong":"@c1682"},{"text":"Kinh hoàng trước tám bổn nguyên chân thân của Vương Lâm khi thế giới sụp đổ","chuong":"@c1690"},{"text":"Là người đầu tiên bước ra tiễn biệt Vương Lâm, mời hắn ngày sau tới Ngũ Hành Tinh","chuong":"@c1691"}],"kinhLich":[{"mucCt":"gon","text":"Cầm đầu đám tu sĩ Ngũ Hành Tinh đứng xa quan sát trận chiến, lần đầu thấy cung Lý Quảng cực kỳ chấn động, nhận ra Vương Lâm tới Ngũ Hành Tinh lần trước ngoài Thiên Đạo còn mang cả cung này.","anchor":"Cây cung của Lý Quảng không ngờ lại ở trong tay hắn","bridge":true,"khoang":"@c1669"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Kinh ngạc trước thần thông Mục Ngư mở mắt, run rẩy kinh hoàng khi thấy Liên Đạo Phi, không ngờ hắn ở nơi này.","anchor":"Hắn.không ngờ hắn lại ở chỗ này"},{"mucCt":"vua","text":"Bất đắc dĩ ra tay theo yêu cầu Huyền La Đại Thiên Tôn — nếu không ra tay thì cả đời không rời khỏi động phủ giới. Cùng Lam Mộng Đạo Tôn khổ chiến Chiến lão quỷ ở tầng thứ hai. Thi triển Ngũ hành kim tiên — Ngưng tụ kim thiên và Ngũ hành thổ tiên — Ngưng tụ hắc địa, triệu hai bàn tay khổng lồ kim sắc và hắc sắc đánh Chiến lão quỷ.","anchor":"Hắn không thể không ra tay","bridge":true,"khoang":"@c1681"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Thần thông bị phá, nhớ truyền thuyết cửu khúc tam tượng khi thấy ngân mục","text":"Cánh tay kim sắc bị hồn phách Thất Thải Tiên Tôn phá, chịu lực phản chấn lui trăm trượng, khóe miệng tràn máu nhưng cắn răng quay lại chiến đấu. Khi thấy Vương Lâm xuất hiện với đôi mắt bạc, nhớ tới truyền thuyết cửu khúc tam tượng của tiên tổ giáng trần: lưỡng khúc là ngân mục kim thân.","anchor":"Trong cửu khúc của lưỡng khúc là ngân mục kim thân"},{"chuong":"@c1690","importance":"normal","mucCt":"vua","tieuDe":"Kinh hoàng trước tám bổn nguyên chân thân","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ. Kinh hoàng khi nhìn thấy tám bổn nguyên chân thân Vương Lâm, giải thích trừ người mở thần cảnh hoặc trở thành Đại Thiên Tôn mới có bổn nguyên chân thân, mà Vương Lâm có tới tám cái.","anchor":"Người tầm thường có được một bổn nguyên đã là hiếm thấy, hắn. Hắn không ngờ lại có tới tám cái!"},{"mucCt":"vua","text":"Cảm khái nhìn Vân Dật Phong bằng ánh mắt hiền từ. Là người đầu tiên bước ra tiễn biệt Vương Lâm, mời hắn ngày sau tới Quy Nhất Tông ở Tiên Tộc rồi bay vào kim môn rời đi.","anchor":"Vương đạo hữu, lão phu xin đi trước một bước. Ngày sau nếu đi tới Tiên Tộc thì có thể tới Quy Nhất Tông một phen","bridge":true,"khoang":"@c1691"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng quan sát, kiêng dè","ghiChu":"Nhận ra Vương Lâm mang cung Lý Quảng, cực kỳ chấn động @c1669"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Cùng phe Ngũ Hành Tinh","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1669","@c1670","@c1681","@c1682","@c1690","@c1691"]},{"id":"van-na","name":"Vân Na","aliases":["nữ Cổ Thần"],"gioiTinh":"nu","theLuc":[{"ten":"Đông Lâm tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ Cổ Thần, thần trưởng lão Đông Lâm tông dưới trướng tiên tôn. Mi tâm có bảy tinh điểm Cổ Thần, ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch. Là sinh mệnh do sinh cơ của Thất Thải Tiên Tôn tạo ra, tồn tại trong đệ nhị hoa của Ngũ hoa bát môn.","vaiTro":"Thần trưởng lão Đông Lâm tông, nữ Cổ Thần ẩn chứa tâm thần huyết Diệp Mịch","tinhCach":"Trung thành với chủ nhân; bình tĩnh, chủ động đề nghị dung hợp tâm thần huyết","tabs":{"diem":[{"text":"Mi tâm có bảy tinh điểm Cổ Thần, ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch","chuong":"@c1671"},{"text":"Nhận ra Vương Lâm mang phân hồn Thất Thải Tiên Tôn, nhận hắn là chủ nhân mới của Đông Lâm tông","chuong":"@c1671"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1671","tieuDe":"Gặp Vương Lâm, nhận chủ nhân mới","text":"Ngồi khoanh chân trong tảng đá bình chùy giữa thế giới đóng băng đệ nhị hoa, mi tâm bảy tinh điểm Cổ Thần chuyển động. Tự giới thiệu là Vân Na, thần trưởng lão Đông Lâm tông dưới trướng tiên tôn. Tiết lộ nơi này do Thất Thải Tiên Tôn tạo dựa trên ký ức về Đông Lâm tông trên Tiên Cương đại lục, Thất Thải xưa là đệ tử bị khu trừ. Nhận ra Vương Lâm mang phân hồn chủ nhân, nhận hắn là chủ nhân mới, đề nghị dung hợp tâm thần huyết cuối cùng của Diệp Mịch trong cơ thể nàng để chữa thương cho Vương Lâm.","anchor":"Vân Na, Đông Lâm tông thần trưởng lão dưới trướng tiên tôn"},{"chuong":"@c1672","importance":"normal","mucCt":"ky","tieuDe":"Trao nguyên thần huyết, tiết lộ lai lịch Đông Lâm tông","text":"Đóng băng thiên địa phong bế kẻ xâm nhập, điểm vào mi tâm ngưng tụ giọt nguyên thần huyết cuối cùng của Diệp Mịch trao cho Vương Lâm, đổi lấy lời hứa giúp nàng rời khỏi động phủ giới; sau khi trao nàng suy yếu hẳn. Tiết lộ chủ nhân Diệp Mịch ngưng tụ máu huyết tạo ra nàng để bảo vệ Đông Lâm tông với vị trí thần trưởng lão; nhị vị trưởng lão Yêu, Ma đã tử vong trong giấc ngủ đóng băng. Bị uy áp nguyên thần Diệp Mịch ép quỳ vì trong cơ thể nàng cũng có máu huyết tầm thường của Diệp Mịch.","anchor":"Chủ nhân ngưng tụ máu huyết của Diệp Mịch hóa thành người thay chủ nhân bảo về Đông Lâm tông"},{"importance":"bridge","mucCt":"gon","chuong":"@c1673","text":"Phủ phục trước Vương Lâm khi hắn tỏa khí tức tổ tiên, cho biết nơi kêu gọi là hậu sơn Đông Lâm tông — Đông Lâm Trì do Thất Thải Tiên Tôn dựa trí nhớ sáng tạo ra, được Vương Lâm hứa sẽ đưa rời khỏi nơi này.","anchor":"Nơi đó trước kia là hậu sơn của Đông Lâm tông"},{"mucCt":"vua","text":"Đang đả tọa trong thế giới đóng băng đệ nhị hoa tại Đông Lâm Tinh. Khi Vương Lâm phá tầng băng, chủ động tách hồn phách, để lại thân thể Cổ Thần nuôi dưỡng nơi này báo ân chủ nhân sáng tạo. Hồn phách được Vương Lâm thu vào Không Gian trữ vật, chờ chuyển thế đầu thai.","anchor":"Ta lưu lại thân thể Cổ Thần, để lại tất cả sinh cơ ở nơi này, hóa thành lực lượng nuôi dưỡng nơi này","bridge":true,"khoang":"@c1693"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân mới (mang phân hồn Thất Thải Tiên Tôn)","gap":"@c1671"},{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân cũ, tiên tôn Đông Lâm tông (đã chết)","gap":"@c1671"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch trong cơ thể","gap":"@c1671"}],"tuiDo":{}},"nguon":["@c1671","@c1672","@c1673","@c1693"]},{"id":"thac-sam","name":"Thác Sâm","aliases":["Hoặc Đồ Ti","Cổ thần Đồ Ti","Đồ Ti"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1674","tieuDe":"Mở mắt khi Vương Lâm tới cổ mộ","text":"Ở đại điện trong vùng đất cổ mộ, bất ngờ mở mắt khi Vương Lâm tiến vào.","anchor":"Thác Sâm - Hoặc Đồ Ti mở mắt"},{"importance":"normal","mucCt":"ky","chuong":"@c1678","tieuDe":"Đồ Ti thức tỉnh trong thân Thác Sâm","text":"Xuất hiện từ vùng thiên địa vặn vẹo, nửa người màu đỏ mang vẻ bá đạo, đánh một quyền vào Chưởng Tôn gây chấn động. Bành trướng thân thể lên mấy vạn trượng cùng Vương Lâm phong tỏa Chưởng Tôn. Sau đó khí chất bá đạo tiêu tan, biến đổi thành Đồ Ti thức tỉnh — trầm ổn tỉnh táo, triệu thanh trường mâu khổng lồ đâm Chưởng Tôn. Bị Chưởng Tôn đánh lui trăm trượng nhưng không bị thương.","anchor":"người xuất hiện ở trước mắt chính là Đồ Ti"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang Lam Mộng kéo dung hợp, góp sức tạo một trong bốn ký hiệu phong ấn Chưởng Tôn, chấn động tâm thần khi thấy Dĩ Ti hiện thân.","anchor":"Dựa theo ký ức của Thất Thải Tiên Tôn, vật này một khi hiện thân sẽ có được tu vi đỉnh của Không Kiếp Sơ Kỳ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Ở lại chặn Chiến lão quỷ","text":"Thân hóa kích thước người thường, trầm mặc nhìn Vương Lâm rồi phát ra tiếng nổ, ngẩng đầu nắm tay, ở lại chặn Chiến lão quỷ.","anchor":"Hắn không nói gì nhưng thân thể lại phát ra những tiếng nổ bùng bùng, ngẩng đầu nắm tay."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Toàn thân tràn ngập hắc khí, bị phong ấn hoàn toàn không thể thoát ra.","anchor":"Thác Sâm lúc này toàn thân tràn ngập hắc khí, bị phong ấn hoàn toàn"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Phá phong ấn chữ Chiến, kinh sợ khi thấy Vương Lâm","text":"Gầm nhẹ đánh tan phong ấn chữ Chiến đã suy yếu, lao về phía Huyền Vũ và Chu Tước nhưng vẫn chậm hơn. Khi thấy Vương Lâm xuất hiện với chín tinh điểm mi tâm thì vô cùng khiếp sợ.","anchor":"Thác Sâm bị Chiến lão quỷ phong ấn lúc này gầm nhẹ, một quyền đánh tan phong ấn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1691","tieuDe":"Trầm mặc trước kim môn","text":"Hiện hình bên ngoài kim môn cùng những người sống sót. Trầm mặc nhìn kim môn, tâm thần uể oải, không rõ đang nghĩ gì.","anchor":"Thác Sâm hoặc là Đồ Ti cũng trầm mặc, nhìn kim môn nọ không biết đang nghĩ điều gì"},{"chuong":"@c1692","importance":"bridge","mucCt":"gon","text":"Kinh ngạc khi Huyền La hiện thân, đồng tử co rút, vẻ mặt ngưng trọng.","anchor":"thần sắc Lam Mộng đạo tôn và Thác Sâm biến đổi, đồng tử trong hai mắt co rút"},{"chuong":"@c1693","importance":"bridge","mucCt":"gon","text":"Do dự không biết có nên đầu thai chuyển thế hay không, mờ mịt đi vào tinh không suy nghĩ.","anchor":"hắn mang theo do dự không biết có nên đầu thai chuyển thế hay không"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa, thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao bảo vật cho Vương Lâm nhờ phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti","chuong":"@c0430"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực truy tìm Vương Lâm","chuong":"@c1147"},{"text":"Trong trận chiến định mệnh tại cổ mộ, lần đầu bỏ xưng bổn thần, quỳ gối nhận truyền thừa Đồ Ti từ Vương Lâm và nói hai chữ đa tạ","chuong":"@c1386"},{"text":"Hóa thành đứa trẻ ngủ say trên tu chân tinh ở giới ngoại tinh hải, đang dung hợp ký ức Đồ Ti tu luyện thần thông","chuong":"@c1969"}]},"nguon":["@c1674","@c1678","@c1679","@c1680","@c1681","@c1682","@c1691","@c1692","@c1693"],"trangThai":"song","gioiTinh":"nam","cn":"托森","tinhCach":"Xảo trá, dùng bảo vật làm mồi nhử dụ dỗ Vương Lâm phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy sát","vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần, qu"},{"id":"hon-thu-ba-vuong-lam","name":"Ác quỷ Dĩ Ti","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1680","tieuDe":"Theo Vương Lâm vào tầng cuối","text":"Đi theo phía sau Vương Lâm vào tầng cuối vùng đất cổ mộ, không bị tiếng tim ảnh hưởng, vẻ hung sát và nôn nóng ngày càng đậm.","anchor":"Đầu lưỡi nó vươn dài, vẻ hung sát trong mắt càng ngày càng đậm, mơ hồ tỏa ra cảm giác nôn nóng."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Ngồi chồm hỗm bên cạnh Vương Lâm tại tầng cuối cùng, vẻ hung sát và bạo ngược trong mắt càng đậm, liên tục gầm rống vô thức.","anchor":"Dĩ ti chi khôi như ác quỷ ngồi chồm hỗm ở đó, vẻ hung sát và bạo ngược trong mắt càng đậm"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Lao ra từ tầng cuối hút máu Chu Tước chiến tướng","text":"Từ tầng cuối lao ra với tiếng rít gào hung bạo, khát máu điên cuồng, đụng thẳng vào Chu Tước chiến tướng, ôm cổ cắn hút máu khiến đối phương héo rũ rồi đạp nện xuống đất, bay lên không lộ thân hình.","anchor":"mang theo nụ cười nanh ác, cắn lên cổ Chu Tước chiến tướng"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Hóa sương đen tấn công Chiến lão quỷ, bị hắn phun máu nuốt lấy một lần rồi thoát ra tiếp tục quấn lấy đối phương chiến đấu.","anchor":"con quỷ Dĩ Ti đã tới gần Chiến lão quỷ, trong đám hắc khí lượn lờ"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1680","@c1681","@c1682","@c1683"],"aliases":["Dĩ Ti","Dĩ Ti Chi Khôi","khôi linh","quỷ Dĩ Ti","Cổ thần Đồ Ti"],"tinhCach":[]},{"id":"chu-lap","name":"Chu Lập","cn":"朱立","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đại sư huynh của Tô Đạo tại Đông Lâm Tông trong thế giới ký ức Thất Thải Tiên Tôn. Thiên tư tuyệt hảo, bề ngoài ôn hòa nhưng khinh thị sư đệ, dùng uy hiếp giành lợi thế trong cuộc thi chọn truyền nhân.","vaiTro":"Đại sư huynh Đông Lâm Tông, đối thủ của Tô Đạo trong ký ức","tinhCach":"Bề ngoài ôn hòa nhưng bản chất khinh thị kẻ yếu; dùng ánh mắt uy hiếp sư đệ; thiên tư cao nhưng tâm tính hẹp hòi","tabs":{"diem":[{"text":"Thiên tư tuyệt hảo, bề ngoài ôn hòa nhưng khinh thị Tô Đạo, mặc kệ người khác khi nhục sư đệ","chuong":"@c1685"},{"text":"Bị Vương Lâm nghịch chuyển ký ức, từ người thắng trở thành kẻ thua, phun máu khi mây mù bị rồng nuốt sạch","chuong":"@c1685"},{"text":"Hận Tô Đạo vì tranh giành quyền học Vân Đạo Thiên Thuật, nhập môn trước nhưng bị Tô Đạo cướp cơ hội","chuong":"@c1688"},{"text":"Thiên tư tuyệt hảo, mặc kệ người khác khinh nhục sư đệ Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi — sau bị Vương Lâm nghịch chuyển đánh bại hoàn toàn.","chuong":"@c1685"},{"text":"Thiên tư tuyệt hảo, khoác vẻ ôn hòa nhưng khinh thị sư đệ, dùng ánh mắt uy hiếp trong cuộc thi chọn truyền nhân.","chuong":"@c1685"},{"text":"Thiên tư tuyệt hảo nhưng tính cách ngầm đàn áp sư đệ, bị Vương Lâm nghịch chuyển ký ức đánh bại hoàn toàn","chuong":"@c1685"}],"kinhLich":[{"chuong":"@c1685","importance":"normal","tieuDe":"Bị Vương Lâm đàn áp, mất tư cách Vân Đạo Thiên Thuật","text":"Trong cuộc thi tuyển trước mặt sư tôn, dùng ánh mắt uy hiếp Tô Đạo (Vương Lâm) nhưng bị đáp trả bằng hàn quang sát khí khiến tâm thần chấn động. Phải 20 nhịp thở mới miễn cưỡng hoàn thành vận chuyển vân khí, sương mù ít ỏi bị rồng mây của Vương Lâm nuốt sạch, phun máu. Bị chuyển sang học Thất Thải Tiên Thuật thay vì Vân Đạo Thiên Thuật.","anchor":"Một cái nuốt này khiến sương mù toàn thân Chu Lập bị nhanh chóng hấp thu vào trong mồm rồng","mucCt":"vua"},{"chuong":"@c1686","importance":"bridge","mucCt":"vua","text":"Trong ký ức hồn thứ ba: năm xưa đạt được Vân Đạo Thiên Thuật, xếp thứ chín cuộc thi Đông Lâm Tông, được vào Đông Lâm Trì tu hành, cuối cùng bị Thất Thải Tiên Tôn bắt giết vào ngày hắn thành đạo.","anchor":"Còn về phần Chu Lập thì vào ngày Thất Thải Tiên Tôn thành đạo đã bị hắn bắt"},{"mucCt":"vua","text":"Được chọn dự thi nhưng năm tháng qua nội tâm bị hành hạ, mắt đầy tơ máu. Tại quảng trường, ánh mắt cường giả chỉ lướt qua hắn, đại đa số ngưng tụ vào Vương Lâm — đố kị oán hận ngập trời.","anchor":"hai mắt lộ ra sự đố kị và oán hận ngập trời","bridge":true,"khoang":"@c1687"},{"mucCt":"vua","text":"Ẩn nấp trong ngọn núi với tám lệnh bài, bị Vương Lâm phá sập núi rồi đặt tay lên đỉnh đầu giết chết. Cái chết kích thích mạnh ký ức hồn thứ ba Thất Thải.","anchor":"Tô Đạo đáng chết, nếu không có hắn, Vân Đạo ThiênThuật phải là do ta học được mới đúng","bridge":true,"khoang":"@c1688"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi"},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Được sư tôn truyền Thất Thải Tiên Thuật (sau nghịch chuyển)"},{"ten":"Tần Mai","tag":"the-thiep","quanHe":"Đạo lữ (trong ký ức hồn thứ ba, sau cuộc thi sẽ thành đạo lữ)","ghiChu":"@c1687"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm (đóng vai Tô Đạo) giết trong ký ức tỷ thí","ghiChu":"@c1688"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Hận Tô Đạo (Thất Thải) vì tranh giành quyền học Vân Đạo Thiên Thuật","ghiChu":"@c1688"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị sư đệ, dùng ánh mắt uy hiếp trong cuộc thi."},{"ten":"Tô Đạo","tag":"doi-thu","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị và dùng ánh mắt uy hiếp trong cuộc thi","gap":"@c1685"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thất Thải Tiên Thuật","trangThai":"dang-co","moTa":"Nhận được sau khi ký ức bị nghịch chuyển (trong ký ức gốc là Vân Đạo Thiên Thuật)","nguon":"@c1685"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1685","@c1686","@c1687","@c1688"]},{"id":"thanh-nien-cam-o","name":"Thanh niên cầm ô","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đệ tử theo sau Vương Lâm (Tô Đạo) trong thế giới ký ức Thất Thải Tiên Tôn, sắc mặt xấu hổ, che ô cho sư huynh trong mưa.","vaiTro":"Đệ tử theo hầu Tô Đạo trong ký ức Đông Lâm Tông","tinhCach":"Rụt rè, xấu hổ, không dám nhìn ai","tabs":{"diem":[{"text":"Che ô cho Tô Đạo trong mưa, sắc mặt xấu hổ không dám nhìn ai, sư tôn thấy người này thì nhíu mày rồi nở cười","chuong":"@c1685"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"dong-hanh","quanHe":"Sư huynh, người được che ô","ghiChu":"Theo sau Tô Đạo trong mưa"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư huynh tại Đông Lâm Tông","ghiChu":"Che ô theo hầu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân (thân phận Tô Đạo)","ghiChu":"Che ô cho Vương Lâm trong mưa","gap":"@c1685"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1685"]},{"id":"tan-mai","name":"Tần Mai","cn":"秦梅","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử xinh đẹp tuyệt trần, đồng môn với Tô Đạo và Chu Lập trong Đông Lâm Tông. Từng có tình cảm qua lại với Tô Đạo nhưng theo ký ức hồn thứ ba, sau cuộc thi đấu sẽ trở thành đạo lữ của Chu Lập.","vaiTro":"Đồng môn Đông Lâm Tông, nhân vật tình cảm trong ký ức hồn thứ ba","tinhCach":"Xinh đẹp dịu dàng; chủ động bắt chuyện; dễ bị ấn tượng bởi khí chất mạnh mẽ","tabs":{"diem":[{"text":"Nữ tử tuyệt trần cùng hệ với Tô Đạo và Chu Lập, từng có tình ý với Tô Đạo nhưng cuối cùng trở thành đạo lữ Chu Lập theo ký ức hồn thứ ba.","chuong":"@c1687"}],"kinhLich":[{"chuong":"@c1687","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại khai mạc thi đấu Đông Lâm Tông","text":"Được sư tôn chọn dự thi cùng Tô Đạo (Vương Lâm) và Chu Lập. Chúc mừng Tô Đạo đạt tư cách tu Vân Đạo Thiên Thuật, ngạc nhiên vì hắn không còn ngại ngùng mà mỉm cười hào hiệp đầy mị lực.","anchor":"Tô Đạo vốn là người cực kỳ anh tuấn, lúc này lại mang theo nụ cười mỉm của Vương Lâm, tự nhiên có một luồng mị lực đặc biệt"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đồng môn (hắn đang giả Tô Đạo), từng có tình ý với Tô Đạo thật","ghiChu":"@c1687"},{"ten":"Chu Lập","tag":"the-thiep","quanHe":"Đạo lữ (theo quỹ đạo ký ức hồn thứ ba)","ghiChu":"@c1687"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1687"]},{"id":"con-bang","name":"Côn Bằng","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thiên tài Đông Lâm Tông trong ký ức hồn thứ ba Thất Thải, sở trường tốc độ, từng đứng thứ ba trong cửa thứ nhất tỷ thí.","vaiTro":"Thiên tài Đông Lâm Tông, đối thủ trong ký ức tỷ thí","tinhCach":"Tự tin vào tốc độ; hoảng sợ trước kẻ mạnh áp đảo","tabs":{"diem":[{"text":"Sở trường tốc độ, từng đứng thứ ba trong cửa thứ nhất tỷ thí Đông Lâm Tông","chuong":"@c1688"}],"kinhLich":[{"mucCt":"vua","text":"Bị Vương Lâm (đóng vai Tô Đạo) tìm đến, dù sở trường tốc độ vẫn không đủ nhanh. Hoảng sợ vứt bỏ hơn mười ngọc bội bỏ chạy.","anchor":"tốc độ của hắn triển khai thì như một đạo tàn ảnh","bridge":true,"khoang":"@c1688"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm (đóng vai Tô Đạo) đánh bại trong ký ức tỷ thí","ghiChu":"@c1688"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1688"]},{"id":"huyen-la","name":"Huyền La","cn":"玄罗","aliases":["Huyền La Đại Thiên Tôn"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn (Cửu Dương)","trangThai":"song","blurb":"Huyền La là Đại Thiên Tôn cảnh Cửu Dương trấn giữ động phủ giới tại La Thiên tinh vực, người mở con đường chuyển thế đầu thai thông tới Tiên Cương và nhận Vương Lâm làm đệ tử duy nhất, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch. Suốt nhiều năm ông âm thầm chú ý mọi chuyện của đệ tử, chuẩn bị tạo hóa và pháp bảo, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo, can thiệp trước hoàng quyền để bảo vệ hắn, và thậm chí trả giá lão hóa thân thể để xông vào Tổ Miếu cứu đệ tử. Sau khi chứng kiến Vương Lâm đột phá Đại Thiên Tôn và vượt qua tam phân thần Cổ Đạo, ông lặng lẽ rời đi","vaiTro":"Đại Thiên Tôn Cửu Dương — sư tôn duy nhất của Vương Lâm tại Cổ Tộc","tinhCach":"Uy nghiêm nhưng nội tâm trọng nghĩa tình, sẵn sàng trả giá vì đệ tử; kiên nhẫn âm thầm chờ đợi và che chở nhiều năm không cần đệ tử biết; thận trọng biết tiến thoái trước thân phận nhạy cảm giữa các thế lực; cương quyết bảo vệ người mình nhận trước hoàng quyền và cường giả","tabs":{"diem":[{"text":"Triệu hồi Tứ Đại Linh, hoàn thành con đường chuyển thế đầu thai thông tới Tiên Cương","chuong":"@c1696"},{"text":"Nhận Vương Lâm làm đệ tử duy nhất trên con đường mình rồng, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch","chuong":"@c1699"},{"text":"Âm thầm chuẩn bị ba nơi tạo hóa và pháp bảo cho đệ tử nhiều năm, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo","chuong":"@c1909"},{"text":"Can thiệp trước hoàng quyền Đạo Cổ, bảo vệ địa vị đệ tử duy nhất khi Thường Thị ép Vương Lâm quỳ","chuong":"@c1908"},{"text":"Trả giá lão hóa thân thể, vung quyền xông vào Tổ Miếu cứu Vương Lâm trong lúc phân thần","chuong":"@c1946"},{"text":"Lặng lẽ rời đi sau khi chứng kiến đệ tử vượt tam phân thần Cổ Đạo, ba năm sau đón Vương Lâm và nhận ngọc giản chuẩn bị chuyển thế","chuong":"@c1949"}],"kinhLich":[{"mucCt":"vua","text":"Giải thích cơ chế chuyển thế đầu thai cho người rời động phủ giới: cần vài năm hoặc ngàn năm, xuất hiện ở góc bất kỳ trên Tiên Cương đại lục, ký ức bị che mờ. Đánh giá Vương Lâm có nhân-nghĩa-tình, âm thầm quyết định hắn phù hợp yêu cầu bảo vệ Đạo Cổ nhất mạch tới vĩnh hằng. Hẹn một tháng sau làm phép chuyển thế đầu thai.","anchor":"Một người có nhân, có tình, có nghĩa như vậy","bridge":true,"khoang":"@c1693"},{"importance":"normal","mucCt":"ky","chuong":"@c1695","tieuDe":"Triệu hoán Long Hoàng thiên nhất, chuẩn bị phá quy tắc Tiên Cương","text":"Huyền La ngồi khoanh chân bên kim môn đại môn động phủ ở La Thiên tinh vực, uy áp kinh người. Thấy chưa tới hai mươi người do Vương Lâm mang tới thì nhẹ nhõm. Bắt quyết triệu hoán Long Hoàng thiên nhất — xuất hiện mặt trời huyết sắc phía sau, triệu ra con rồng sừng hình vương miện, lân phiến tím đậm, thân dài mấy vạn trượng, có lực lượng Không Kiếp trung kỳ. Giải thích đây là một trong cửu binh Long Hoàng thiên nhất, năm xưa hắn giết con rồng này ở vùng man hoang phía đông Tiên Cương đại lục, lấy hồn phách luyện lại thân thể, xương cốt tế thành binh khí — cây long tiên (roi) huyết sắc dài trăm trượng. Tuyên bố sẽ dùng cây roi mở quy tắc Tiên Cương đại lục, tạo lỗ hổng thiên địa cho mọi người chuyển thế đầu thai.","anchor":"Binh khí này là một cây roi, lão phu muốn dùng cây long tiên này mở quy tắc của Tiên Cương đại lục, cho các ngươi chuyển thế đầu thai, mở ra một lỗ hổng trong thiên địa!"},{"importance":"normal","mucCt":"ky","chuong":"@c1696","tieuDe":"Triệu hồi Tứ Đại Linh mở đường chuyển thế","text":"Lần lượt triệu hồi bốn đại linh để hoàn thành con đường chuyển thế đầu thai thông tới Tiên Cương. Dùng Hoàng Long Tiên (đại nhất linh) vung chín nhát xé tan sương mù mở con đường mình rồng. Triệu hồi Sơn Yêu (đại nhị linh) phủ băng trắng bảo vệ hồn phách khỏi mê chướng. Lấy Kiếm Tiên (đại tam linh) từ mi tâm, kiếm khí tràn ngập hộ tống dẫn đường. Cắn lưỡi phun máu hóa Phong Ma (đại tứ linh) phong ấn ký ức người chuyển thế và che giấu thân phận kiếp trước. Dùng Cửu Dương Đại Thiên Tôn lực tạo mặt trời đỏ như máu trao cho Vương Lâm để khuếch đại Mộng Đạo Thuật vô hạn, phong ấn ký ức mọi người vào mộng.","anchor":"Tu vi của hắn thông thiên, lại sớm đã có chuấn bị"},{"chuong":"@c1697","importance":"bridge","mucCt":"gon","text":"Ở lại ngoài tinh không cùng Vương Lâm, đồng ý đưa thêm người chuyển thế và chờ hắn năm ngày.","anchor":"Ta vốn tưởng rằng sẽ có hơn một ngàn người, hôm nay chỉ có chưa tới hai mươi người"},{"mucCt":"gon","text":"Khoanh chân ngồi trước đại môn màu vàng trong La Thiên tinh vực, chứng kiến Vương Lâm đưa tám toàn năng vào cổng, sau đó đứng lên bước vào theo.","anchor":"Huyền La đứng lên, thần sắc ngưng trọng, bước vào trong đại môn của động phủ","bridge":true,"khoang":"@c1698"},{"importance":"major","mucCt":"ky","chuong":"@c1699","tieuDe":"Nhận Vương Lâm làm đệ tử, dùng máu Cửu Dương bảo hộ","text":"Trên con đường mình rồng, Huyền La đề nghị nhận Vương Lâm làm đệ tử, muốn truyền y bát bảo vệ Đạo Cổ nhất mạch, thậm chí muốn giúp Vương Lâm tiến vào Thái Cổ Thần Cảnh trở thành mặt trời thứ mười. Vương Lâm gọi sư tôn, quan hệ sư đồ xác lập. Huyền La vỗ mi tâm phun máu tươi hóa huyết long cuốn Vương Lâm lao vào lỗ hổng, dùng máu Cửu Dương bảo vệ dọc đường đối phó pháp tắc Tiên Cương, hẹn mười năm chờ ở Tiên Cương. Tiếp nhận các sinh linh Vương Lâm thả ra từ Không Gian trữ vật. Ngăn Vương Lâm can thiệp vào quá trình lột xác Văn Thú, giải thích tổ tiên chúng từng sinh tồn nơi này. Cuối cùng kinh ngạc nhận ra Văn Thú có thể là một trong chín loài thú cùng sinh với Cổ Tổ và Tiên Tổ, có thể dung hợp pháp tắc Tiên Cương.","anchor":"Vi sư là một trong Cửu Dương, một ngụm máu tươi của ta sẽ bảo vệ cho ngươi dọc đường"},{"mucCt":"vua","text":"Phong kín lỗ hổng tầng băng sau khi Vương Lâm rời đi. Suy đoán Văn Thú có thể là hung thú truyền thuyết khi cổ tộc và Tiên Tộc sinh ra pháp tắc, nhận định Vương Lâm có khả năng thành Đại Thiên Tôn thứ 11, Đạo Cổ nhất mạch sẽ tồn tại vạn thế. Ngoài thân huyễn hóa mặt trời huyết sắc tỏa ánh sáng bảy màu, dùng lực lượng một người chống lại pháp tắc Tiên Cương trên con đường mình rồng hộ tống Vương Lâm.","anchor":"hắn. rất có khả năng dựa vào bản thân trở thành mặt trời thứ mười một của Tiên Cương đại lục","bridge":true,"khoang":"@c1700"},{"mucCt":"vua","text":"Huyễn hóa xuất hiện tại đại điện trên đỉnh núi Thất Đạo Tông ở Thiên Ngưu Châu. Xác nhận mọi người khác từ động phủ giới đã chuyển thế đầu thai an toàn, nói còn không tới bốn năm và đã làm hết sức giúp đỡ. Mi tâm có hồng quang lờ mờ dẫn đường cho Vương Lâm xuyên hư không.","anchor":"vi sư có thể giúp ngươi đến đâu thì đã làm hết sức rồi","bridge":true,"khoang":"@c1701"},{"text":"Chờ Vương Lâm trên đỉnh Hắc Sơn của Thất Đạo Tông tổng cộng mười lăm năm, thấy hồng ấn chỉ đường trên mi tâm mình hoàn toàn tiêu tan nên bi thảm tin rằng Vương Lâm đã chết. Khi hai mặt trời tiên khí kinh thiên động địa xuất hiện, hắn buộc phải rời đi, thầm dặn đồ nhi nếu chưa chết thì tới Đạo Cổ nhất mạch tìm mình rồi hóa huyết ảnh lao lên không trung. Sau đó hắn trở về Đạo Cổ nhất mạch với vẻ ảm đạm.","anchor":"tính cả thời gian trước đây, hắn đã đợi được mười lăm năm","bridge":true,"khoang":"@c1702"},{"mucCt":"gon","text":"Đang bế quan trong lúc đại biến Tiên Cương, bốn vị Đại Thiên Tôn hai mạch còn lại đều lao ra.","anchor":"Huyền La đang bế quan, còn cả tổng cộng bốn vị Đại Thiên Tôn của hai mạch còn lại toàn bộ đều lao ra","bridge":true,"khoang":"@c1704"},{"mucCt":"vua","text":"Đang bế quan trên tế đàn ở Thiên Không Quận thuộc hoàng tộc Đạo Cổ nhất mạch. Ngay khi kim ấn xuất hiện tại Thiên Ngưu Châu, lập tức cảm ứng, mở mắt nói \"Hắn tới rồi!\", tin rằng đệ tử mà hắn chọn nhất định sẽ đến được Tiên Cương đại lục.","anchor":"Hắn biết đệ tử mà hắn chọn nhất định sẽ không chết bên trong hư vô, nhất định sẽ đến được Tiên Cương đại lục!","bridge":true,"khoang":"@c1719"},{"mucCt":"vua","text":"Quyết định không tới Tiên Tộc vì thân phận nhạy cảm, tới nhiều lần sẽ gây rắc rối. Thương thế đã không đáng lo, tiếc nuối không còn, nhắm mắt bế quan thổ nạp, trong tâm nghĩ Tiên Cương đại lục là nhà của Vương Lâm, Đạo Cổ nhất mạch là cố hương, chờ đồ nhi trở về.","anchor":"Đồ nhi Vương Lâm, Tiên Cương đại lục là nhà của ngươi. Đạo Cổ nhất mạch là cố hương của ngươi. Vi sư ở nơi này chờ ngươi trở về.","bridge":true,"khoang":"@c1720"},{"chuong":"@c1724","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm cảm nhận vẫn đang chờ đợi nhiều năm tại di chỉ Thất Đạo Tông.","anchor":"còn có Huyền La đã nhiều năm chờ đợi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người được chọn bảo vệ Đạo Cổ nhất mạch","ghiChu":"Đánh giá có nhân-nghĩa-tình, tin rằng sẽ vô oán vô hối bảo vệ Đạo Cổ tới vĩnh hằng"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"Chính thức nhận làm đệ tử, muốn truyền y bát Đạo Cổ nhất mạch, giúp tiến vào Thái Cổ Thần Cảnh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1693","@c1695","@c1696","@c1697","@c1698","@c1699","@c1700","@c1701","@c1702","@c1704","@c1719","@c1720","@c1724"]},{"id":"phan-san-lo","name":"Phàn San Lộ","tabs":{"kinhLich":[{"chuong":"@c1693","importance":"bridge","mucCt":"gon","text":"Vương Lâm hướng về Vân Hải tinh vực đón nàng — người Tiên Cương đại lục, không cần chuyển thế đầu thai.","anchor":"Nàng là người của Tiên Cương đại lục, không cần chuyển thế đầu thai cũng có thể rời đi"},{"importance":"normal","mucCt":"vua","chuong":"@c1694","tieuDe":"Rời động phủ giới về quê hương","text":"Có huyết mạch Tiên Cương, tự mở đại môn động phủ rời đi trở về quê hương. Để lại chiếc thuyền khổng lồ cho Vương Lâm.","anchor":"Nhất Phi của Thất Thải Tiên Tôn này có huyết mạch Tiên Cương"}],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"the-thiep","quanHe":"Phu quân","ghiChu":"Là Nhất Phi của Thất Thải Tiên Tôn @c1694"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nhận chiếc thuyền khổng lồ khi nàng rời đi","ghiChu":"@c1694"}],"tuViMoc":[],"diem":[{"text":"Từ hắc động xuất thủ đỡ chỉ phong bảy màu cứu Vương Lâm, tiết lộ thân phận đệ tử Đại Hồn Môn và đề nghị hợp tác","chuong":"@c1597"},{"text":"Bị Vương Lâm vạch trần giả dạng Phàn San Mộng, buộc phải thừa nhận thân phận thật là Phàn San Lộ","chuong":"@c1603"},{"text":"Trao ngọc giản chứa bản đồ tế đàn và thuật thôn hồn cho Vương Lâm, lập thệ huyết liên minh","chuong":"@c1605"},{"text":"Nhờ huyết mạch Tiên Cương tự mở đại môn động phủ giới, rời đi trở về quê hương","chuong":"@c1694"},{"text":"Tu luyện tại Viêm Mạch Phong, mở động phủ địa hỏa chủ mạch tiếp đón Vương Lâm","chuong":"@c1727"},{"text":"Theo sư tôn Viêm Loan nghênh chiến Vương Lâm; tư oán năm xưa đã dần hóa giải","chuong":"@c1898"}]},"nguon":["@c1693","@c1694"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Đệ nhất phi Thất Đạo Tông — đệ tử hạch tâm Đại Hồn Môn, muội muội Phàn San Mộng","tinhCach":"Cẩn trọng, không dễ tin người từ Tiên Cương đại lục; kiên nhẫn chờ cơ hội báo thù; trọng lời hứa, giữ thệ ước; quyết đoán trong chiến đấu","blurb":"Phàn San Lộ là đệ nhất phi trong thất phi của Thất Đạo Tông, thân phận thật là muội của Phàn San Mộng và đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Bị Thất Thải Thiên Tôn truy sát, nàng ẩn náu trong hắc động khe sâu Yêu Tông cũ, sau đó xuất thủ cứu Vương Lâm và thiết lập thệ huyết liên minh, trao bản đồ tế đàn cùng thuật thôn hồn. Rời động phủ giới trở về Tiên Cương đại lục, nàng tu luyện tại Viêm Mạch Phong dưới trng sư tôn Viêm Loan; tư oán năm xưa với Vương Lâm dần được thời gian hóa giải.","cn":"樊珊露","gioiTinh":"nu","theLuc":[{"ten":"Thất Thải Tiên Tôn (Nhất Phi)","trangThai":"gan-bo"}]},{"id":"thap-tam","name":"Thập Tam","cn":"十三","gioiTinh":"nam","trangThai":"song","nguon":["@c1694","@c1697"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1694","tieuDe":"Quyết theo sư phụ chuyển thế đầu thai","text":"Tới gặp Vương Lâm, ý nghĩ đơn giản: sư phụ đi đâu hắn theo đó, dù chuyển thế đầu thai. Tính cách trầm ổn hơn trước, sát khí tiêu tán phân nửa nhưng chỉ ẩn đi, bùng lên thì thần tiên khiếp hãi. Yên tĩnh ngồi khoanh chân phía sau Vương Lâm.","anchor":"một đời làm thầy, đời đời kiếp kiếp vẫn là sư phụ hắn"},{"chuong":"@c1697","importance":"normal","mucCt":"vua","tieuDe":"Bái biệt sư tôn, bước vào luân hồi chuyển thế","text":"Quỳ trên hư không trước mặt Vương Lâm, thề rằng dù ký ức bị phong ấn, dù không thức tỉnh vẫn không quên ân truyền đạo của sư tôn. Rồi rời đi bước vào đại môn chuyển thế đầu thai.","anchor":"cho dù chuyển thế đầu thai, chuyện này nhất định sẽ không quên"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Chỉ tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi vẫn không cam lòng, mỗi đêm chịu đau luyện thể theo pháp Cự Ma Tộc, tự phát gần đạt yêu lực nhị tinh","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu, kích động quỳ đập đầu tôn Vương Lâm làm Lão tổ, thề cả đời trung thành","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu cho sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp nơi","chuong":"@c1440"},{"text":"Chuyển thế thành cô nhi Vương Thạch, được Vương Lâm khôi phục ký ức, tiếp tục theo sư tôn vào Tiên giới thi triển Cực Hỏa Đạo","chuong":"@c1955"}]},"vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, nguyện theo sư tôn dù chuyển thế đầu thai; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là đại đệ tử của Vương Lâm, trời sinh ngộ tính với Luyện Hồn Yêu Thuật — chỉ ba tháng đã đạt giai đoạn ba. Sau khi bị phế tu vi, gã không cam lòng mà tự phát luyện thể theo pháp Cự Ma Tộc, quỳ bái Vương Lâm làm Lão tổ, nhận truyền thừa Cự Linh Cửu Tu rồi trưởng thành thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, thân thể được rèn bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới mang theo pho tượng Vương Lâm khổ tìm sư tôn, cuối cùng nguyện theo sư phụ chuyển thế đầu thai, chuyển thế thành Vương Thạch rồi"},{"id":"thanh-suong","name":"Thanh Sương","cn":"清霜","gioiTinh":"nu","trangThai":"song","nguon":["@c1694","@c1696"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Cùng Thanh Lâm và Chu Dật tới gặp Vương Lâm, vẻ mặt lạnh lùng, không để ý Chu Dật phía sau.","anchor":"Bên cạnh hắn là Thanh Sương vẻ mặt lạnh lùng, nhìn về phía trước"},{"mucCt":"vua","text":"Thần sắc lạnh lùng bước theo cha Thanh Lâm vào con đường chuyển thế. Trước khi biến mất quay đầu nhìn Chu Dật nói lời lạnh nhưng ẩn chứa thâm ý rồi biến mất vào sương mù.","anchor":"Hy vọng sau này đừng tới làm phiền ta nữa","bridge":true,"khoang":"@c1696"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Từng bày kế áp chế đối thủ khi động phủ mở ra và là người duy nhất có thể tiến vào động phủ thứ năm — cấm địa bế quan tuyệt mật của Thanh Lâm","chuong":"@c0952"},{"text":"Thân thể bị Cổ Ma Tháp Già chi phối và tranh đoạt sau khi đứng dậy trong tầng chín của tiên tháp","chuong":"@c0996"},{"text":"Hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới, hóa băng sơn","chuong":"@c1046"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Thần sắc lạnh lùng bước theo Thanh Lâm vào con đường chuyển thế, quay đầu nhìn Chu Dật trước khi biến mất","chuong":"@c1696"},{"text":"Không chọn tu tiên, chuyển thế nhiều lần như phàm nhân, cuối cùng ở bên Chu Dật hạnh phúc","chuong":"@c1961"}]},"vaiTro":"Tiên quân Vũ Tiên Giới — con gái Tiên Đế Thanh Lâm","tinhCach":"mưu lược, từng bày kế áp chế đối thủ và bố trí cấm địa bế quan tuyệt mật; nặng tình nhưng ẩn nhẫn, nén đau đớn trước Chu Dật; lạnh lùng, ít để lộ cảm xúc","blurb":"Thanh Sương là Tiên quân của Vũ Tiên Giới, con gái Tiên Đế Thanh Lâm — vị Tiên Đế chí tôn từng bước vào bước tu đạo thứ ba. Di thể nàng được Chu Dật gửi gắm cho Vương Lâm mang theo với hy vọng phục sinh, trải qua nhiều biến cố bị Cổ Ma Tháp Già chi phối trước khi hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới. Sau khi được thu hồi vận mệnh trong mặt trời thứ chín, nàng trở lại tiên giới với ký ức chưa hoàn toàn phục hồi, rồi bước theo Thanh Lâm vào con đường chuyển thế, không chọn tu tiên mà sống như phàm nhân qua nhiều kiếp, cuối cùng ở bên Chu"},{"id":"chu-dat","name":"Chu Dật","cn":"褚逸","gioiTinh":"nam","trangThai":"song","nguon":["@c1694","@c1696"],"tabs":{"kinhLich":[{"mucCt":"ky","text":"Đi phía sau Thanh Sương, ánh mắt nhớ nhung nhìn nàng. Nhìn khuôn mặt quen thuộc nhưng là con người khác, trong lòng đau đớn như muốn xé tan thân thể. Muốn bỏ cuộc nhưng cũng muốn tiếp nhận.","anchor":"Nhìn khuôn mặt quen thuộc, nhưng lại là một con người khác, trong lòng Chu Dật dâng lên sự đau đớn như muốn xé tan thân thể","bridge":true,"khoang":"@c1694"},{"mucCt":"vua","text":"Đau khổ trầm mặc khi thấy Thanh Sương ra đi. Được Vương Lâm giữ lại, đặt ấn ký phong ấn ký ức của Thanh Sương lên trán tạo liên hệ sau chuyển thế. Được Vương Lâm xóa ký ức đau khổ. Ôm quyền từ biệt rồi bóng lưng cô đơn mang vẻ cố chấp bước vào đại môn biến mất.","anchor":"Bóng lưng của hắn cô đơn. mang theo một vẻ mê man, mang theo một vẻ cố chấp","bridge":true,"khoang":"@c1696"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc chết, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm","chuong":"@c0293"},{"text":"Nguyên Thần nhập kiếm, hóa thành Kiếm Tiêu Chi Hồn trong Vũ Chi Tiên Kiếm","chuong":"@c0294"},{"text":"Bị phong ấn trăm năm trong Luyện Tiên Hóa Ma đại trận, linh thể hao tổn chỉ còn sót lại, vẫn cứu Vương Lâm","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh thẳng Hư Không Tử, dẫn phát thương thế cũ của đối phương, linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Nhìn Thanh Sương phủ nhận và quên lãng mình, vẫn ngồi bên cạnh không rời mắt — bi kịch si tình ngàn năm","chuong":"@c1046"},{"text":"Cuối cùng đạt viên mãn hạnh phúc bên Thanh Sương sau nhiều năm khổ luyện và chờ đợi","chuong":"@c1961"}]},"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân bảo hộ Vương Lâm","tinhCach":"Si tình bền bỉ, ngàn năm không đổi dù người xưa đã quên lãng; trọng nghĩa xả thân, sẵn sàng thiêu đốt Nguyên Thần vì người; kiên nghị chịu phong ấn trăm năm không oán hận; trầm mặc bi ai trước bi kịch tình duyên không trọn nhưng vẫn thủ hộ lặng lẽ","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông xuất thân Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, cả đời mang theo nữ thi tiên nhân Đình Nhi và ôm mối si tình ngàn năm với Thanh Sương. Vì cứu Đình Nhi, y thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm rồi Nguyên Thần nhập kiếm hóa thành Kiếm Tiêu Chi Hồn. Từ đó, Chu Dật dĩ thân phận kiếm linh nhiều lần trợ chiến bảo hộ Vương Lâm qua vô số kiếp nạn, chịu phong ấn trăm năm không oán, đánh thương Hư Không Tử để hộ chủ, lặng lẽ theo sau T"},{"id":"hong-sam-tu","name":"Hồng Sam Tử","cn":"洪衫子","gioiTinh":"nam","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Chọn chuyển thế đầu thai rời đi.","anchor":"những người lựa chọn rời đi so với những người ở lại thật sự quá ít"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, lệnh Huyền Bỉnh đi tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải từ tinh không bất ngờ xuất hiện tiếp viện giới nội trong đại chiến","chuong":"@c1425"},{"text":"Lộ danh hiệu Huyết Sam Đồng Tử, phá sát giới mấy vạn năm, một mình đối đầu nhiều cao thủ bước thứ ba giới ngoại","chuong":"@c1427"},{"text":"Bị phong ấn tại Thất Thải Giới trong đại chiến thứ hai, sau đó được Vương Lâm giải cứu khỏi đạo quả giam cầm","chuong":"@c1469"},{"text":"Chọn chuyển thế đầu thai, sau đó được Vương Lâm dùng tinh quang điểm mi tâm khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận "},{"id":"nam-van-tu","name":"Nam Vân Tử","cn":"南云子","gioiTinh":"nam","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Sau khi đấu tranh rất lâu, cuối cùng chọn ở lại động phủ giới.","anchor":"những người lựa chọn rời đi so với những người ở lại thật sự quá ít"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận bảo vệ Vân Hải, đồng thời đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công kẻ địch, thể hiện trình độ trận pháp cao thâm","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh, trợ giúp Vương Lâm mở Không Môn","chuong":"@c1520"},{"text":"Chọn ở lại tân Tiên Giới trấn giữ, thân thể bị đánh tan vỡ chỉ còn nguyên thần","chuong":"@c1961"},{"text":"Được Vương Lâm dùng sức mạnh thiên địa ngưng tụ thân thể mới từ nguyên thần","chuong":"@c1964"}]},"vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan rồi phục hồi, ông cầm đầu lực lượng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vương Lâm xuất chinh. Về sau ông"},{"id":"chien-khong-liet","name":"Chiến Không Liệt","cn":"战空烈","gioiTinh":"nam","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Chọn ở lại động phủ giới, không rời đi.","anchor":"Chiến Không Liệt, Viêm Lôi Tử cũng lựa chọn ở lại động phủ giới này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Gặp Vương Lâm tại Lôi Trì, suy đoán hắn là tiền bối ẩn tu rồi cung kính bái kiến","chuong":"@c0733"},{"text":"Được Vương Lâm chỉ ra chiến ý Chiến gia thiếu niềm tin bất khuất, chấn động ngộ đạo","chuong":"@c0809"},{"text":"Tu vi đạt Tịnh Niết viên mãn, chỉ huy gần trăm tu sĩ kéo tu chân tinh chuẩn bị chiến tranh Ngoại Vực","chuong":"@c1388"},{"text":"Sẵn sàng tự bạo cùng Tây Tử Phượng và Thân Công Hổ khi màn sáng sụp đổ","chuong":"@c1559"},{"text":"Được tiết lộ là người duy nhất trong lịch sử động phủ vượt tám lần huyền kiếp bằng thân phận tu sĩ bên trong","chuong":"@c1568"},{"text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn, hồn chứa ý cảnh và bổn nguyên lực","chuong":"@c1600"}]},"vaiTro":"Tu sĩ Chiến gia — hồn thứ hai Thất Thải Thiên Tôn, truy tùy trung thành của Vương Lâm","tinhCach":"thận trọng biết thời thế, suy đoán sắc bén trước cường giả; cung kính cầu đạo, sùng kính Vương Lâm sau khi chứng kiến uy lực; mang chiến ý bất khuất cố hữu của Chiến gia; trung thành kiên định, sẵn sàng tự bạo vì đại cục","blurb":"Chiến Không Liệt là tu sĩ Chiến gia xuất thân từ Lôi Tiên Giới, ban đầu ở cảnh Dương Thực viên mãn, về sau đạt tới Tịnh Niết viên mãn và vượt qua tám lần huyền kiếp — là người duy nhất trong lịch sử động phủ dựa vào thân phận tu sĩ bên trong mà đạt tới mốc này. Hắn gặp Vương Lâm tại Lôi Trì, từ nghi ngờ chuyển sang cung kính bái kiến, được Vương Lâm chỉ điểm về niềm tin bất khuất của chiến ý Chiến gia, rồi theo Vương Lâm suốt hành trình từ tranh đoạt phong hào đến chiến tranh Ngoại Vực. Về sau bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lự"},{"id":"viem-loi-tu","name":"Viêm Lôi Tử","cn":"炎雷子","gioiTinh":"nam","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Chọn ở lại động phủ giới, không rời đi.","anchor":"Chiến Không Liệt, Viêm Lôi Tử cũng lựa chọn ở lại động phủ giới này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, triệu hồi nguyên thần các cấp thiên tiên, tiên vương và Tiên Quân quy vị vào trận","chuong":"@c0745"},{"text":"Chủ trì nghi thức Phong Tiên: phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực","chuong":"@c0828"},{"text":"Bộc lộ tu vi thật vượt Toái Niết hậu kỳ trong trận chiến với Cực Hiền Thiên ở phía Bắc Liên Minh","chuong":"@c0864"},{"text":"Giao chiến một ngày với thượng cổ tu sĩ áo đỏ chưa phân thắng bại, sau đó bị dư uy Diệt Thần Mâu trọng thương nặng, được Lỗ Phu Tử cứu","chuong":"@c1066"},{"text":"Tiết lộ bản thân từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, mang mối thù truyền kiếp với Trọng Huyền Tử vốn là đạo hữu chí cốt","chuong":"@c1408"},{"text":"Bị tu sĩ Toái Niết giới ngoại truy sát do thương thế khiến tu vi thụt lùi, được Vương Lâm cứu thoát","chuong":"@c1452"}]},"vaiTro":"Điện chủ Lôi Tiên Điện — chỉ huy cấp cao La Thiên, cựu trưởng lão Tu Chân Liên Minh","tinhCach":"trọng dụng nhân tài, sẵn sàng chấp nhận tổn thất để chiêu nạp cao thủ; quyết đoán trong đại cục, dám hiến tinh huyết nguyên thần mở thông đạo; bình tĩnh trước chất vấn và biến cố bất ngờ; mang mối thù truyền kiếp với Tu Chân Liên Minh, không chịu dừng tay khi chiến sự chưa ngã ngũ","blurb":"Viêm Lôi Tử là Điện chủ Lôi Tiên Điện, một trong những nhân vật chỉ huy then chốt của La Thiên trong cuộc đại chiến với Tu Chân Liên Minh. Vốn từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, ông sở hữu tu vi vượt Toái Niết hậu kỳ, từng kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, chủ trì nghi thức Phong Tiên phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực, rồi trực tiếp giao chiến với các đại tu sĩ hàng đầu như Cực Hiền Thiên, Võ Đông Thiện và thượng cổ tu sĩ áo đỏ. Trải qua đại chiến thứ ba v"},{"id":"chu-nhu","name":"Chu Như","cn":"朱茹","gioiTinh":"nu","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Quyết định chuyển thế đầu thai rời đi, tới bên cạnh Vương Lâm.","anchor":"những người lựa chọn rời đi so với những người ở lại thật sự quá ít"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn Hạnh Hoa Thôn, chuyển sinh thành Chu Như với tư chất bách mạch đều thông","chuong":"@c0314"},{"text":"Hồn phách bị Lý Mộ Uyển chấn ra khỏi nhục thân, được Vương Lâm triệu hồi sống sót, từ đó tồn tại với thân phận độc lập","chuong":"@c0381"},{"text":"Ký ức phong ấn được giải phóng tại đỉnh Chu Tước Sơn khi mở túi trữ vật Vương Lâm lưu lại","chuong":"@c0663"},{"text":"Tái ngộ Vương Lâm tại Côn Hư cảnh sau thời gian dài xa cách, đau lòng nhìn tóc bạc trắng của hắn","chuong":"@c1053"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín, thoát khỏi sự chi phối của thiên mệnh","chuong":"@c1540"},{"text":"Chuyển thế đầu thai thành thiếu nữ hơn mười tuổi tại sơn thôn Sơn Nhạc Châu, từ chối tu tiên, sống giản dị cùng cha mẹ","chuong":"@c1956"}]},"vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — nghĩa nữ được Vương Lâm bảo hộ suốt nhiều kiếp","tinhCach":"Quyến luyến sâu sắc, nhiều lần bất chấp tìm kiếm Vương Lâm và không nỡ rời xa; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; dã tính phóng khoáng, gắn bó với hổ Tiểu Bạch như bạn đồng hành; chí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển chuyển sinh tại Hạnh Hoa Thôn, mang tư chất tuyệt hảo bách mạch đều thông, từ nhỏ được Vương Lâm âm thầm bảo hộ rồi nuôi dưỡng trong Tiên Ngọc Bảo Tháp. Sau khi hồn phách được tách khỏi Nguyên Anh Lý Mộ Uyển và ký ức bị xóa, nàng đoàn tụ phụ mẫu rồi tự mình tu luyện đến cảnh Anh Biến, suốt đời lấy việc tìm lại thúc thúc Vương Lâm làm tâm nguyện duy nhất. Trải qua nhiều lần tái ngộ và chia ly, Chu Như cuối cùng được thu hồi vận mệnh trong mặt trời thứ chín, ở bên Vương Lâm như cô con gái trước khi quyết định chuyển thế đầu thai, tái sinh th"},{"id":"than-cong-ho","name":"Thân Công Hổ","cn":"申公虎","gioiTinh":"nam","trangThai":"song","nguon":["@c1694"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1694","tieuDe":"","text":"Quyết định chuyển thế đầu thai rời đi, tới bên cạnh Vương Lâm.","anchor":"những người lựa chọn rời đi so với những người ở lại thật sự quá ít"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dâng đạo hồn quỳ bái Vương Lâm, tự nguyện xưng Tôn Chủ và trở thành tuỳ tùng","chuong":"@c0681"},{"text":"Kiên quyết tiến cử Hứa Mộc có tư cách tranh đệ nhất nhân La Thiên Tinh Vực","chuong":"@c0808"},{"text":"Từ chối bước vào Thăng Tiên trì, giữ con đường tu đạo bản thân thay vì đổi ý cảnh thành tiên nguyên","chuong":"@c0826"},{"text":"Quyết định chuyển thế đầu thai, tới bên cạnh Vương Lâm trước khi rời đi","chuong":"@c1694"},{"text":"Sau chuyển thế lại trở thành tông chủ một tông phái","chuong":"@c1955"}]},"vaiTro":"Tuỳ tùng trung thành của Vương Lâm — Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên","tinhCach":"biết nắm thời cơ nương tựa cường giả, dâng đạo hồn quy phục không do dự; sùng kính Vương Lâm đến mức cuồng nhiệt, lấy đó làm tín niệm tu hành; kiên định với con đường tu đạo bản thân, từ chối cơ duyên đổi ý cảnh; phản ứng nhanh nhạy khi lâm nguy","blurb":"Thân Công Hổ là tu sĩ Thân Công tộc ở nam vực La Thiên, Nhị cấp sứ giả Lôi Tiên Điện, tự xưng tu vi Dương Thật. Sau khi bị uy thế Vương Lâm áp chế tại Lôi Trì trong Lôi Ngục, hắn dâng đạo hồn xin nương tựa, từ đó trở thành tuỳ tùng trung thành theo Vương Lâm quan chiến và tham chiến qua nhiều biến cố lớn từ Lôi Tiên Giới sụp đổ đến tranh đoạt phong hào Nam vực. Hắn kiên quyết giữ con đường tu đạo bản thân khi từ chối bước vào Thăng Tiên trì, cuối cùng quyết định chuyển thế đầu thai và sau đó lại trở thành tông chủ một tông phái."},{"id":"chu-tuoc-doi-thu-hai","name":"Chu Tước đời thứ hai","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1695","text":"Vương Lâm nhắc Chu Tước chiến tướng đã rời đi, suy đoán quan hệ phân thân với Chu Tước đời đầu.","anchor":"Chu Tước chiến tướng rời đi nhưng trong vùng đất Điên Lạc còn có Chu Tước đời đầu tiên"}],"diem":[{"text":"Ngồi câu bên hồ trên Đại Đế tinh, câu được Viêm long và lấy máu rồng mời Vương Lâm uống","chuong":"@c1310"},{"text":"Kiểm tra thiên linh Vương Lâm, phát hiện hắn mang năm đạo bổn nguyên khác nhau, xác nhận là tiểu bối Chu Tước đời thứ sáu","chuong":"@c1311"},{"text":"Công khai bao che Vương Lâm trước các đại năng, gọi hắn là tiểu bối nhà mình và dùng hư hỏa bảo vệ","chuong":"@c1313"},{"text":"Chủ trì thí luyện thiếu đế, hô dâng hương khiến ba cây hương Thiên, Địa, Nhân hiện ra","chuong":"@c1314"},{"text":"Liều mạng lấy toàn bộ viêm huyết tinh hoa trên đỉnh đầu Viêm long truyền vào Địa Phương hương để trợ Vương Lâm thức tỉnh Chu Tước lần bốn","chuong":"@c1321"},{"text":"Được Vương Lâm nhớ lại với tiếng cười sang sảng, bắt rồng lấy máu, nhiều lần trợ giúp và truyền Phần Giới Cổ Tán","chuong":"@c1341"}]},"nguon":["@c1695"],"vaiTro":"Tiền bối Chu Tước đời thứ hai — chủ trì thí luyện thiếu đế, che chở và trợ lực Vương Lâm","tinhCach":"Tinh tường, nhìn thấu căn cơ và bổn nguyên người khác; che chở tiểu bối cùng tộc một cách công khai và quyết đoán; dám vi phạm quy định thí luyện để cứu viện khi biến cố xảy ra; tính tình hào sảng, cười sang sảng giữa nguy nan","blurb":"Chu Tước đời thứ hai là một lão giả thường ngồi câu bên hồ trên Đại Đế tinh, có thể câu lên và áp chế Viêm long, lấy máu rồng mời khách uống. Lão kiểm tra thiên linh Vương Lâm, xác nhận hắn là tiểu bối Chu Tước đời thứ sáu mang năm đạo bổn nguyên khác nhau, sau đó công khai bao che hắn trước các đại năng và đưa hắn vào thí luyện thiếu đế. Khi thí luyện sinh biến nghiêm trọng, lão nhiều lần vi phạm quy định để cứu viện, thậm chí liều mạng lấy toàn bộ viêm huyết tinh hoa của Viêm long truyền vào cây hương nhằm trợ Vương Lâm thức tỉnh Chu Tước lần bốn."},{"id":"lao-to-cam-dia-chu-tuoc","name":"Lão Tổ Cấm Địa Chu Tước","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1695","text":"Vương Lâm nhắc Chu Tước đời đầu vẫn còn ở vùng Điên Lạc, suy đoán nếu là phân thân của chiến tướng thì lúc này cũng đã tiêu tán.","anchor":"Chu Tước chiến tướng rời đi nhưng trong vùng đất Điên Lạc còn có Chu Tước đời đầu tiên"}],"diem":[{"text":"Ra lệnh Kiền Phong nuốt Hồng Điệp làm mồi luyện, sai Liễu Mi truy tìm Vương Lâm để đoạt Thiên Nghịch Châu và Tinh La Bàn","chuong":"@c0340"},{"text":"Triệu tám Tiên vệ và Tiên đế nghênh chiến Vương Lâm nhưng Tiên vệ áo đen bị hắn một chỉ Tịch Diệt diệt sát","chuong":"@c0577"},{"text":"Giảng giải bản chất Phá Không Ngũ Chỉ và con đường Niết Không bước thứ ba cho Vương Lâm","chuong":"@c1327"},{"text":"Ngầm lưu hư hỏa trên người Tư Mặc Tử qua ba cái tát, bố cục giúp Vương Lâm lập uy danh khi khiêu chiến","chuong":"@c1330"},{"text":"Truyền thụ Phần Giới Cổ Tán — thuật mạnh nhất Chu Tước tộc — với gần hai trăm vạn ấn ký qua bốn lần ấn quyết","chuong":"@c1336"},{"text":"Được Vương Lâm giải phong ấn tại vùng đất Điên Lạc, không còn bị nhốt vĩnh viễn, có thể tùy ý đi ra","chuong":"@c1966"}]},"nguon":["@c1695"],"vaiTro":"Lão tổ đời thứ hai của Chu Tước tộc — thế lực bí ẩn trong cấm địa Chu Tước Sơn","tinhCach":"Thủ đoạn lạnh lùng, xem sinh linh làm mồi luyện; toan tính thâm sâu, bố cục nhiều tầng từ trong cấm địa; trọng nhân tài, sẵn lòng truyền thụ tuyệt học cho kẻ xứng đáng; hành sự khó lường, khi cười đắc ý khi âm trầm ngưng trọng","blurb":"Lão tổ đời thứ hai của Chu Tước tộc, toàn thân phát hồng quang, ẩn cư trong cấm địa phía sau Chu Tước Sơn. Thuở đầu nuôi Hồng Điệp làm mồi cho Kiền Phong, ra lệnh truy tìm Vương Lâm để đoạt Thiên Nghịch Châu cùng Tinh La Bàn, thậm chí sai Tiên vệ và Tiên đế nghênh chiến hắn; về sau nhận ra tài năng của Vương Lâm nên chuyển sang trợ giúp — giảng giải con đường Niết Không bước thứ ba, trao Cổ Hồn Cấm, truyền thụ Phần Giới Cổ Tán tuyệt học mạnh nhất của Chu Tước tộc, và ngầm bố cục để hắn lập uy danh trước Tư Mặc Tử. Sau này gặp lại Vương Lâm tại Đan Hải, bị kiếm ý chấn thương và được hắn đưa tho"},{"id":"xich-hon-tu","name":"Xích Hồn Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1695","text":"Vương Lâm nhắc Xích Hồn Tử đã được thả ra, chưa rõ tung tích hiện tại.","anchor":"Còn Xích Hồn Tử được ta thả ra"}],"diem":[{"text":"Được Vương Lâm dùng máu Đạo Cổ giải phong ấn từ Hắc Tháp, gào thét điên cuồng hiện huyết ảnh và nuốt Tiên Phi","chuong":"@c1491"},{"text":"Cười điên cuồng phá tan phong ấn Tĩnh Trung Lao Nguyệt, thiên địa chấn động, tuyên bố ân oán triệt tiêu rồi thoát đi tự do","chuong":"@c1492"},{"text":"Lộ thân thế là hồn phách bị Diệp Mịch phong ấn năm xưa, khôi phục tu vi đỉnh phong và vây khốn Tiên giới","chuong":"@c1962"},{"text":"Phá vỡ trận pháp bảo hộ Tiên giới sau mấy ngày ăn mòn, mở lỗ thủng khổng lồ","chuong":"@c1964"},{"text":"Tâm thần sụp đổ hoàn toàn, viện dẫn quan hệ bạn cũ với La Minh nhưng bị Vương Lâm hủy diệt","chuong":"@c1966"}]},"nguon":["@c1695"],"vaiTro":"Linh hồn cực mạnh bị phong ấn trong Hắc Tháp — cựu thù của Diệp Mịch, kẻ thù cuối cùng bị Vương Lâm hủy diệt","tinhCach":"Điên cuồng, mất kiểm soát sau vô số năm bị giam cầm; thù hận Diệp Mịch cực sâu; kiêu ngạo bất tuân; tâm thần bất ổn, không chấp nhận được thực tại","blurb":"Xích Hồn Tử là linh hồn cực mạnh bị Đạo cổ Diệp Mịch phong ấn trong Hắc Tháp qua vô số năm. Được Vương Lâm dùng máu Đạo Cổ giải phóng trong sinh tử kiếp Chướng Tôn, hắn nuốt Tiên Phi rồi phá tan phong ấn Tĩnh Trung Lao Nguyệt mà thoát đi. Sau khi khôi phục tu vi đỉnh phong, hắn vây khốn Tiên giới và phá vỡ trận pháp bảo hộ, nhưng cuối cùng tâm thần sụp đổ và bị chính Vương Lâm hủy diệt hoàn toàn."},{"id":"cuu-thien-ma-ton","name":"Cửu Thiên ma tôn","aliases":["Cửu Thiên"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1697","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm phong ấn thu vào trữ vật","text":"Đang trị thương trên tu chân tinh hình trăng lưỡi liềm phía đông Thái Cổ Tinh Thần, trước đó bị Lam Mộng đánh trọng thương — chặt đứt Hương Hỏa giới, tâm thần tổn thương, dùng tử khí hồi phục. Khi Vương Lâm xuất hiện, bỏ chạy vào lòng đất, cầu xin tha mạng nhưng bị Vương Lâm dùng Tê Thiên Thuật xé đôi toàn bộ tu chân tinh, đánh vỡ mọi thần thông pháp bảo. Bị đặt tay lên mi tâm phong ấn thu vào không gian trữ vật, toàn bộ chỉ mất vài nhịp thở.","anchor":"Ngươi không đuối cùng giết tận không được sao! Ta hoàn toàn không có thâm cừu đại hận gì với ngươi!"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Từng lẻn vào Điên Lạc Địa, trọng thương rút lui và thề không bao giờ quay lại","chuong":"@c1284"},{"text":"Ngồi trên đài mộ cấp bảy trong bản đồ thứ tám của cổ mộ, thi triển đạo thuật truy sát nhưng bị Vương Lâm áp chế, toàn bộ phân thân tử vong","chuong":"@c1377"},{"text":"Bị nhốt trong cổ mộ sau khi Vương Lâm thu Địa Phù","chuong":"@c1386"},{"text":"Được Chưởng Tôn giải cứu khỏi cổ mộ, bại trận trước Lam Mộng Đạo Tôn, hương hỏa giới bị hủy diệt và tâm thần tổn thương","chuong":"@c1583"},{"text":"Cùng Diệu Âm Đạo Tôn và Thất Phi vây Vương Lâm, bị mũi tên cung Lý Quảng đánh nổ thân thể, nguyên thần bị bắt gọn","chuong":"@c1596"},{"text":"Bị Vương Lâm phong ấn thu vào trữ vật khi đang trị thương trên tu chân tinh","chuong":"@c1697"}]},"nguon":["@c1697"],"vaiTro":"Đại năng ma đạo — đối thủ dai dẳng của Vương Lâm trong cổ mộ và ngoại giới","tinhCach":"tự phụ thực lực, dám đơn độc xâm nhập hiểm địa; biết tiến biết lui, thề không tái phạm khi trọng thương; mưu mô toan tính, sẵn sàng kết thỏa thuận vì lợi ích; thù dai, thương thế chưa hồi phục vẫn quyết trả thù","blurb":"Cửu Thiên Ma Tôn là đại năng ma đạo từng nổi danh vì dám lẻn vào Điên Lạc Địa, song trọng thương rút lui và lập thề không quay lại. Trong cổ mộ nhiều tầng bản đồ, hắn ngồi trên đài mộ cấp bảy thi triển đạo thuật truy sát đối thủ nhưng liên tục bị Vương Lâm áp chế — phân thân toàn diệt, bổn tôn hoảng sợ, cuối cùng bị nhốt trong cổ mộ. Sau khi được Chưởng Tôn giải cứu, hắn bại trận trước Lam Mộng Đạo Tôn mất hương hỏa giới, rồi vây đánh Vương Lâm bị bắt gọn nguyên thần, và cuối cùng bị Vương Lâm phong ấn thu vào trữ vật."},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","aliases":["Diệu Âm"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1697","importance":"normal","mucCt":"vua","tieuDe":"Trị thương dưới đáy biển, Vương Lâm tuyên chiến","text":"Đang trị thương dưới đáy biển sâu nhất của thủy tinh phía tây Thái Cổ Tinh Thần, hấp thụ hải xà để hồi phục, tu vi đã giảm xuống Không Linh. Vương Lâm xuất hiện trên không, tuyên bố đưa hắn đi đầu thai.","anchor":"Vương Lâm, Lam Mộng, hai ngươi sẽ không được chêt tử tê đâu!"},{"mucCt":"vua","text":"Ẩn dưới đáy biển vàng nhưng biết không thể chạy thoát, gào thét chất vấn Vương Lâm. Khi nghe nói sẽ bị đưa đi đầu thai tới Tiên Cương đại lục, đau khổ buông xuôi phản kháng, bị phong ấn thu vào Không Gian trữ vật, phân thân dung hợp lại thành một.","anchor":"Diệu Âm tâm thần chấn động, đau khổ buông xuôi hết thảy những sự phản kháng vô dụng","bridge":true,"khoang":"@c1698"}],"nhanMach":[],"tuViMoc":[{"chuong":"@c1697","canhGioi":"Không Linh","text":"Tu vi giảm xuống Không Linh do bị Lam Mộng đánh trọng thương, trăm năm cũng không hồi phục đỉnh tu vi.","importance":"minor"}],"diem":[{"text":"Từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa","chuong":"@c1193"},{"text":"Lấy âm bổn nguyên đại thành phá cửa ải Không Niết, đạt bước thứ ba; dung hợp âm–thủy đại chiến nhưng bị trọng thương gần chết, bị Đại Hoang Thượng Nhân đoạt xá","chuong":"@c1365"},{"text":"Mấy vạn năm ẩn dưới đáy tử hải ôm oán hận, mở mắt trở lại khi khe cổ mộ tái xuất","chuong":"@c1378"},{"text":"Cùng Cửu Thiên Ma Tôn và Đại Hoang Thượng Nhân hợp lực đánh Lam Mộng Đạo Tôn ba ngày, bại trận trọng thương","chuong":"@c1583"},{"text":"Bị Vương Lâm bắt gọn nguyên thần bằng mũi tên cung Lý Quảng","chuong":"@c1596"},{"text":"Tu vi giảm xuống Không Linh do bị Lam Mộng đánh trọng thương, đang trị thương dưới đáy biển thì bị Vương Lâm tuyên chiến, không còn đường thoát","chuong":"@c1697"}]},"nguon":["@c1697","@c1698"],"gioiTinh":"nam","vaiTro":"Cường giả cổ tu — một trong Thái Cổ Ngũ Tôn, bản thể ẩn tu dưới đáy hải dương","tinhCach":"Nhàn nhã phóng túng, thường nằm mây ăn đào quan sát thế cục; tham lam dã tâm, lộ rõ tham niệm khi thấy bảo vật; âm trầm khó lường, bề ngoài thiếu niên xinh xắn nhưng bản thể là lão già tóc bạc tu luyện dưới đáy hải dương","blurb":"Diệu Âm Đạo Tôn là một trong Thái Cổ Ngũ Tôn, bản thể là lão già tóc bạc ẩn tu dưới đáy hải dương ở tu chân tinh trung tâm, từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa. Y lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết lên bước thứ ba, phái phân thân thiếu niên tham gia tranh đoạt tại cổ mộ và giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc để cướp tứ phẩm đạo linh. Sau đại chiến dung hợp âm–thủy, y bị trọng thương rồi bị Đại Hoang Thượng Nhân đoạt xá; mấy vạn năm sau ẩn dưới đáy tử hải ôm mối oán hận, mở mắt trở lại khi khe cổ mộ tái xuất, nhưng bị Vươ"},{"id":"hu-than-thien-ton","name":"Hư Thần thiên tôn","cn":"虚神天尊","aliases":["Hư Thần"],"gioiTinh":"nam","vaiTro":"Một trong Thái Cổ Ngũ Tôn — cường giả giới ngoại thèm khát thân thể bất diệt của Vương Lâm","tinhCach":"Tham lam, nhiều lần mưu đồ đoạt xá thân thể tiên nhân của Vương Lâm; tàn nhẫn, chuyên tập kích lúc đối phương suy yếu; cao ngạo khinh thường hậu bối nhưng dễ kinh sợ trước sức mạnh ngoài dự liệu; quyết đoán, đích thân ra tay khi thủ hạ bất lực","blurb":"Hư Thần Thiên Tôn là một trong Thái Cổ Ngũ Tôn từ giới ngoại, xuất hiện dưới dạng thân ảnh toàn thân sương mù màu tím, tu vi phân thân đạt Không Huyền sơ kỳ. Nhiều lần mưu đồ đoạt xá thân thể bất diệt của Vương Lâm nhưng liên tiếp thất bại — lần đầu bị cung cổ Lý Quảng tiêu diệt phân thân, lần sau đích thân phá trận Chu Tước Tinh rồi thi triển Vạn Hà Hư Thần Đạo để trấn áp, cuối cùng phân thân vẫn bị Vương Lâm xé nát, bản thể trọng thương bỏ chạy, về sau bị Vương Lâm bắt đưa đi đầu thai.","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toàn năng bước thứ ba","trangThai":"song","tabs":{"diem":[{"text":"Xuất hiện dưới dạng thân ảnh sương mù, tự xưng Thái Cổ Ngũ Tôn, đánh Vương Lâm rơi xuống Chu Tước Tinh","chuong":"@c1488"},{"text":"Đoạt xá thân thể bất diệt của Vương Lâm thất bại, phân thân bị mũi tên cung cổ Lý Quảng tiêu diệt","chuong":"@c1490"},{"text":"Đích thân phá trận pháp Chu Tước Tinh, quở trách thủ hạ bất lực, kinh hãi trước sáu đạo bổn nguyên","chuong":"@c1522"},{"text":"Thi triển Vạn Hà Hư Thần Đạo mở khe khổng lồ trấn áp Vương Lâm, phân thân bị chém đôi lộ bản thể","chuong":"@c1528"},{"text":"Phân thân bị Vương Lâm xé nát, bản thể trọng thương bỏ chạy, kinh sợ Cung Lý Quảng","chuong":"@c1529"},{"text":"Bị Vương Lâm tìm đến khi đang bế quan, tuyệt vọng cầu xin tha mạng, bị bắt đưa đi đầu thai","chuong":"@c1698"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1698","tieuDe":"Bị Vương Lâm bắt đưa đi đầu thai","text":"Đang bế quan trên đá vụn phía nam Thái Cổ Tinh Thần thì Vương Lâm xuất hiện. Tuyệt vọng cầu xin tha mạng, phản bác rằng không thể giết hết thiên tài tương lai. Cuối cùng cười thảm buông xuôi, bị thu vào Không Gian trữ vật đưa đi đầu thai.","anchor":"Hư Thần thiên tôn cười thảm, buông xuôi không chống cự nữa"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phong ấn bắt đi đầu thai tới Tiên Cương đại lục","ghiChu":"@c1698"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1698"]},{"id":"lao-to-thuong-vien-toc","name":"Lão tổ Thương Viên Tộc","aliases":[],"gioiTinh":"nam","vaiTro":"Lão tổ bước thứ ba của Thương Viên Tộc, bị Vương Lâm phong ấn bắt đi đầu thai","tinhCach":"Không kịp phản kháng trước sức mạnh áp đảo của Vương Lâm","blurb":"Nam tử trung niên, toàn năng bước thứ ba của Thương Viên Tộc. Đang ngồi trong đại điện trên đỉnh núi thì Vương Lâm bất ngờ xuất hiện, phong ấn tâm thần mang đi đầu thai.","theLuc":[{"ten":"Thương Viên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toàn năng bước thứ ba","trangThai":"song","tabs":{"diem":[{"text":"Toàn năng bước thứ ba của Thương Viên Tộc, bị Vương Lâm phong ấn bắt đi đầu thai tới Tiên Cương đại lục","chuong":"@c1698"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1698","tieuDe":"Bị Vương Lâm phong ấn bắt đi đầu thai","text":"Đang ngồi trong đại điện trên đỉnh núi cao nhất của Thương Viên Tộc thì Vương Lâm bất ngờ xuất hiện, đặt tay lên vai phong ấn tâm thần, mang đi đầu thai.","anchor":"một sức mạnh khiến cho hắn hãi hùng từ trong bàn tay trên vai nhập vào trong cơ thể hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phong ấn bắt đi đầu thai","ghiChu":"@c1698"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1698"]},{"id":"van-thu","name":"Văn Thú","aliases":["Văn Thú Vương","Văn Vương"],"trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1699","tieuDe":"Lột xác tiến hóa trong pháp tắc Tiên Cương","text":"Được Vương Lâm thả ra từ Không Gian trữ vật, Văn Thú Vương cầm đầu đàn Văn Thú phát cuồng lao vào lỗ hổng ra hư vô nơi có pháp tắc Tiên Cương. Thân thể bành trướng, đại bộ phận nổ tung hóa sương máu tử vong, trải qua quá trình lột xác đau đớn thích ứng lại nơi tổ tiên từng sinh tồn. Cuối cùng Văn Thú Vương tiến hóa thành công, thân thể to bằng một tu chân tinh, chín con Văn Thú vàng sống sót to lớn vạn trượng mỗi con tương đương Văn Thú Vương cũ ở Phong Tiên Giới. Huyền La kinh ngạc nghi ngờ chúng là một trong chín loài thú cùng sinh với Cổ Tổ và Tiên Tổ, có thể dung hợp pháp tắc Tiên Cương.","anchor":"tổ tiên của chúng hình như đã sinh tồn ở nơi này"},{"chuong":"@c1700","importance":"normal","mucCt":"vua","tieuDe":"Hộ vệ Vương Lâm xuyên hư vô","text":"Mười Văn Thú còn lại cùng khởi hành, chín con vạn trượng bay hộ vệ. Trong hư vô áp lực pháp tắc tăng dần, tới năm thứ tư-năm chín con không chịu nổi, được Vương Lâm thu vào Không Gian trữ vật. Văn Vương vẫn duy trì tốc độ cực nhanh mang Vương Lâm tiến tới, không hề suy giảm.","anchor":"Nhưng Văn Vương dưới thân Vương Lâm lại không có vẻ gì không tốt, tốc độ vẫn cực nhanh như trước"},{"chuong":"@c1701","importance":"normal","mucCt":"ky","tieuDe":"Bị cưỡng ép chia tay, quyết tiến hóa đỉnh phong","text":"Mang Vương Lâm tiến trong hư không suốt nhiều năm đã mệt mỏi vô cùng, tốc độ chậm lại. Khi Vương Lâm bảo ở lại vì nơi đây là nhà của nó, lần đầu tiên không muốn nghe lời, gào thét muốn dù chết cũng hộ tống chủ nhân. Bị Vương Lâm bùng phát Đạo Cổ lực giam cầm cưỡng ép tách ra, gào thét bi ai truy tìm không được. Cuối cùng xoay người bay ngược lại, quyết dung hợp thêm khí tức Tiên Cương, nhanh chóng tiến hóa tới đỉnh phong để có tốc độ tìm lại chủ nhân. Quê hương có thể chính là Tiên Cương đại lục, thích ứng nơi đây hơn Vương Lâm nhiều.","anchor":"Nó không muốn rời khỏi Vương Lâm. Cho dù có chết nó cũng muốn chết bên cạnh chủ nhân."},{"importance":"normal","chuong":"@c1702","tieuDe":"Lột xác hóa sương tìm chủ nhân","text":"Nổi giận vì bị Vương Lâm ngăn không cho đi theo, nó dẫn chín con Văn Thú đồng bạn điên cuồng dung hợp với pháp tắc Tiên Cương ẩn trong hư vô, mười năm lột xác năm lần và mỗi lần hùng mạnh hơn gấp mấy lần. Sau lần lột xác thứ năm, thân thể nó hóa thành đám sương khói mơ hồ như con muỗi bước ra từ tranh thủy mặc, không còn thân thể thực nhưng hung sát đạt đỉnh điểm. Nó nuốt chín con văn thú đồng bạn dung hợp thành một thể rồi dấy sương mù vô biên lao vào sâu hư vô để tìm chủ nhân Vương Lâm.","anchor":"Nó muốn đi tìm Vương Lâm, đi tìm chủ nhân của nó"},{"chuong":"@c1703","importance":"major","mucCt":"ky","tieuDe":"Hi sinh thân thể đưa giọt máu Vương Lâm vào đài cao, đánh thức chủ nhân","text":"Bất chấp nguy hiểm lột xác năm lần, cắn nuốt đồng bạn để tiến hóa, phân thành mười vạn phần hóa làn khói tìm kiếm Vương Lâm trong hư vô. Tìm được thi thể chủ nhân tỏa bạch quang cùng quan tài trôi lơ lửng, gào thét thê lương, mười vạn con tụ lại hóa thành Văn Thú Vương. Nhiều lần cố đánh thức Vương Lâm nhưng thất bại, cuốn hắn và quan tài bay đi tìm đài cao hình cánh cung dựa vào ký ức mơ hồ sau năm lần lột xác về pháp tắc Tiên Cương. Tìm được đài cao, lao qua vách ngăn nhưng Vương Lâm và quan tài bị chặn. Hút giọt máu tươi từ tim Vương Lâm, lấy thân bảo vệ lao vào vách, ngưng tụ toàn thân sức mạnh phun giọt máu qua vách ngăn, thân thể tiêu tan hơn phân nửa, còn lại một tia máu rơi lên đài cao, hoàn thành cơ duyên kinh thiên cho chủ nhân.","anchor":"mười vạn con Văn Thú đã toàn bộ xuất hiện. Chúng ngưng tụ lại với nhau, bất ngờ hóa thành Văn Thú Vương"},{"mucCt":"ky","text":"Đoàn tụ Vương Lâm, cọ vòi rít vui sướng. Thân thể nhỏ đi nhiều, mơ hồ như vùng sương mù tùy lúc có thể tiêu tán nhưng tràn ngập sinh cơ. Qua dung hợp thần thức, ký ức lộ ra: đã điên cuồng lột xác tiến hóa, cắn nuốt chín đồng bọn, hóa mười vạn phần tràn ngập hư vô để tìm chủ nhân. Trí nhớ cho biết xác đá giống xác đá khi tổ tiên nó sinh ra. Được Vương Lâm coi như thân nhân. Nâng Vương Lâm bay cực nhanh hướng cửa ra hư vô.","anchor":"Thân thể Văn Vương so với lúc trước đã nhỏ đi nhiều, giờ phút này nhìn lại mơ hồ như một vùng sương mù","bridge":true,"khoang":"@c1704"},{"chuong":"@c1705","importance":"normal","mucCt":"ky","tieuDe":"Kiệt sức dẫn đường hư vô, hóa dấu ấn","text":"Hóa sương mù bao phủ toàn thân Vương Lâm, gào thét cuốn hắn bay trong hư vô suốt khoảng mười ba năm, dựa trí nhớ mơ hồ và cảm ứng tìm cửa ra. Dọc đường hưng phấn thỉnh thoảng quay đầu kêu vui sướng, cảm giác như được đi theo cha mẹ. Cuối hành trình kiệt sức, gắng đưa Vương Lâm vào khe nhưng thân thể hóa sương mù khó định hình lại. Được Vương Lâm đau lòng chụp lấy, hóa thành một dấu ấn trên cánh tay hắn.","anchor":"gắng gượng muốn mang Vương Lâm tiến vào cái khe đó nhưng cuối cùng thân thể lại hóa thành sương mù"},{"importance":"bridge","mucCt":"vua","chuong":"@c1707","tieuDe":"Ấn ký mở mắt cùng Vương Lâm","text":"Khi Vương Lâm tỉnh lại giữa trận luyện khôi lỗi, ấn ký hình Văn Thú như thủy mặc trên tay phải hắn cũng đột nhiên mở bừng đôi mắt, hiện lên vẻ lạnh lùng tàn nhẫn đáng sợ.","anchor":"ấn ký hình Văn Thú như thủy mặc trên tay phải hắn cũng đột nhiên mở bừng đôi mắt"},{"chuong":"@c1711","importance":"bridge","mucCt":"gon","text":"Vương Lâm nghĩ hình dáng Văn Thú quá đặc biệt, không tiện triệu hồi ở Tiên Cương đại lục.","anchor":"hình dáng Văn Thú quá đặc biệt, cũng không tiện triệu hồi ở nơi này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1721","tieuDe":"Được triệu ra cưỡi Vương Lâm bỏ xa Đỗ Thanh","text":"Được Vương Lâm triệu từ hắc vụ, hiện hình khổng lồ toàn thân gai sắc, tiếng rít chói tai khiến Đỗ Thanh chấn kinh, cưỡi Vương Lâm lao đi tốc độ kinh người.","anchor":"Bên trong hắc vụ, Văn Vương nhoáng lên, bộ dáng dữ tợn hiện ra"},{"chuong":"@c1722","importance":"bridge","mucCt":"vua","text":"Sau tiến hóa, tốc độ cực kinh khủng, bay liên tục nửa tháng đưa Vương Lâm tới Thương Long Tông, trong lúc phi hành hấp thu khí tức Tiên Cương đại lục để tự thổ nạp, Đỗ Thanh không đuổi kịp.","anchor":"Văn Vương sau khi tiến hóa, tốc độ đã cực kỳ kinh khủng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đột phá từ hạ phẩm linh cấp lên trung phẩm linh cấp, tương đương Nguyên Anh hậu kỳ đại viên mãn.","chuong":"@c0266"},{"text":"Được xác nhận là hung thú đến từ tinh không, sống bằng cắn nuốt vạn vật và hung tính vượt xa yêu thú tu chân.","chuong":"@c0479"},{"text":"Sau trăm năm tế luyện bằng lượng nguyên tinh khổng lồ, lột xác thành công với khí tức ngang Tịnh Niết.","chuong":"@c1153"},{"text":"Tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới rồi xác lập vương quyền trong đàn Văn Thú.","chuong":"@c1169"},{"text":"Bất chấp nguy hiểm lột xác nhiều lần, hi sinh thân thể để đưa giọt máu của Vương Lâm vào đài cao và đánh thức chủ nhân.","chuong":"@c1703"},{"text":"Sau khi tới Tiên Cương đại lục, tiếp tục hiện thân làm tọa kỵ, nhiều lần chở Vương Lâm di chuyển và thoát thân.","chuong":"@c1773"}]},"nguon":["@c1699","@c1700","@c1701","@c1702","@c1703","@c1704","@c1705","@c1707","@c1711","@c1721","@c1722"],"cn":"蚊兽","gioiTinh":"khac","canhGioiCaoNhat":"Văn Thú Vương (sau năm lần lột xác)","vaiTro":"Linh thú tọa kỵ trung thành của Vương Lâm","tinhCach":"Trung thành hộ chủ; hung mãnh khát máu; nặng tình đồng tộc; kiên quyết tìm chủ","blurb":"Văn Thú, còn được gọi là con muỗi khổng lồ, là hung thú đến từ tinh không và trở thành tọa kỵ, linh thú hộ chủ lâu dài của Vương Lâm. Nó trải qua nhiều lần lột xác, khuất phục các đàn Văn Thú tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới và tiếp tục theo Vương Lâm qua hư vô đến Tiên Cương đại lục."},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1699","tieuDe":"","text":"Được Vương Lâm thả ra từ Không Gian trữ vật, gửi Huyền La đưa tới Tiên Cương.","anchor":"Hứa Lập Quốc, Lưu Kim Bưu. Văn Thú cùng toàn bộ những sinh linh có trong Không Gian trữ vật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc, ép nguyên thần thành ma đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết, chiến đấu tới kiệt sức","chuong":"@c0338"},{"text":"Phản chủ chém đứt cánh tay trái Cự Ma lão tổ rồi tự nguyện quay về theo Vương Lâm","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa ba năm liên tục kháng cự, thực lực tăng mạnh","chuong":"@c1018"},{"text":"Khôi phục ký ức tiền kiếp trước lúc rời Tổ Thành, nhận lại Vương Lâm làm chủ nhân","chuong":"@c1881"}]},"nguon":["@c1699"],"vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo, hay lải nhải đòi đảo chủ tớ nhưng luôn bị trấn áp khuất phục; si mê nữ sắc tới mức mất tự chủ; nhát gan tính toán phản bội song cuối cùng vẫn quay về theo chủ; thực dụng giỏi nịnh nọt để tự bảo toàn","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc rồi ép nguyên thần thành ma đầu. Trải qua hàng loạt biến cố, hắn lần lượt làm tay sai giám sát, kiếm hồn trong tiên kiếm, được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Về sau hắn được đưa tới Tiên Cương, trải qua đầu thai chuyển thế mất rồi khôi phục ký ức, tiếp tục nhận Vương Lâm làm chủ và đi theo tới Tiên giới."},{"id":"vong-nguyet","name":"Vọng Nguyệt","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1699","tieuDe":"","text":"Được thả từ Không Gian trữ vật, thân thể quá lớn cũng muốn lao ra khỏi lỗ hổng.","anchor":"Vọng Nguyệt thân thể quá lớn cũng muốn lao ra khỏi lỗ hống kia"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1699"]},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1699","tieuDe":"","text":"Được Vương Lâm thả ra từ Không Gian trữ vật, gửi Huyền La đưa tới Tiên Cương.","anchor":"Hứa Lập Quốc, Lưu Kim Bưu. Văn Thú cùng toàn bộ những sinh linh có trong Không Gian trữ vật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng ngọc giản phóng khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông, tống tiền cả tông môn","chuong":"@c1158"},{"text":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, xâm nhập thánh địa trên Hỏa Tước tinh","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, quỳ dập đầu đến trán đầm đìa máu, bắt đầu làm nô bộc ngàn năm","chuong":"@c1474"},{"text":"Chuyển thế tại Tiên Cương, khôi phục ký ức hai đời và thức tỉnh nhận thức mới về đạo lừa gạt — hiểu lừa mình chính là bước thứ hai","chuong":"@c1848"},{"text":"Con rắn nhỏ Hải Long trên vai khôi phục bản thể, gào rít chặn đứng Xích Hồn Tử tại Tiên giới","chuong":"@c1964"}]},"nguon":["@c1699"],"vaiTro":"Kẻ lừa đảo kỳ cựu — nô bộc ngàn năm của Vương Lâm, người ngộ đạo lừa gạt","tinhCach":"Xảo quyệt, chuyên giả mạo khí tức cường giả để tống tiền tông môn; Tham lợi nhưng biết sợ cường giả, quỳ gối cầu sinh không chút do dự; Dai dẳng theo đuổi đạo lừa gạt đến mức tự lừa chính bản thân, ký ức và nguyên thần cũng bị ảnh hưởng; Linh hoạt nương theo Vương Lâm để sinh tồn, dần chuyển từ kẻ b","blurb":"Lưu Kim Bưu, bí danh Kim Bưu Tử, là tu sĩ tu vi thực chỉ ở tầng Âm Hư nhưng nhờ ngọc giản chứa khí tức Toái Niết mà tung hoành lừa gạt các tông môn, từ Thiên Cương Tông tới Quy Nguyên Tông, cho đến khi bị Vương Lâm truy kích, mất bảo vật, rồi bị tước tự do làm nô bộc ngàn năm. Sau khi chuyển thế tại Tiên Cương dưới danh Kim Bưu đại tiên, lão khôi phục ký ức hai đời, thức tỉnh nhận thức mới về đạo lừa gạt — hiểu rằng lừa mình mới là cảnh giới cao nhất — rồi tiếp tục theo Vương Lâm xuyên suốt hành trình từ Đông Lâm Tông qua Tổ Thành đến Tiên giới, với con rắn nhỏ Hải Long trên vai trở thành vật "},{"id":"hoang-ton-dao-co","name":"Hoàng tôn Đạo Cổ nhất mạch","cn":"","aliases":["Nam tử mặc hoàng bào","Ca của Đạo Phi"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hoàng tôn của Đạo Cổ nhất mạch, tự nhận vai thủ hộ tộc khi Huyền La vắng mặt. Hắn nắm giữ hồn phách bí ẩn mà quốc sư cho rằng có thể giúp hắn thống trị toàn bộ Tiên Cương đại lục, đồng thời âm thầm theo dõi nhất cử nhất động của Huyền La và tiến hành tuyển hậu bằng phương thức dung nhập tàn hồn.","vaiTro":"Hoàng tôn Đạo Cổ nhất mạch — mưu đồ nắm quyền Tiên Cương đại lục","tinhCach":"Kiêu ngạo, khinh thường tu sĩ động phủ giới; tham vọng quyền lực, tính toán thâm sâu; quyết đoán tàn nhẫn","tabs":{"diem":[{"text":"Lộ diện tại hoàng cung, tay cầm quả cầu chứa hồn phách đang ngủ say, mưu đồ nắm Tiên Cương","chuong":"@c1700"},{"text":"Thấy Huyền La trở về một mình, âm thầm cười lạnh và bỏ ý định truy tìm nữ tử năm đó","chuong":"@c1702"},{"text":"Tiến hành tuyển hậu bằng cách để nữ tử dung nhập tàn hồn, liên tiếp thất bại","chuong":"@c1866"}],"kinhLich":[{"chuong":"@c1700","importance":"major","mucCt":"ky","tieuDe":"Lộ diện tại hoàng cung, mưu đồ nắm Tiên Cương","text":"Đứng trên lầu các cao nhất hoàng cung Đạo Cổ, tay cầm quả cầu ánh sáng chứa hồn phách đang ngủ say. Khinh thường Huyền La vì rời đi giúp tu sĩ động phủ giới, tự nhận là người thủ hộ Đạo Cổ nhất mạch. Theo lời quốc sư, hồn phách trong quả cầu có thể giúp hắn nắm cả Tiên Cương đại lục. Quyết định tìm nữ tử dung hợp với hồn phách, ra lệnh cho Diệp Đạo thực hiện.","anchor":"Một hồn phách nho nhỏ mà vì sao quốc sư lại nói nó có thể giúp ta nắm cả Tiên Cương đại lục"},{"importance":"bridge","chuong":"@c1702","text":"Thấy Huyền La trở về Đạo Cổ nhất mạch một mình liền âm thầm cười lạnh, bỏ ý định đi tìm nữ tử năm đó.","anchor":"Đạo Cổ hoàng tôn kia thấy Huyền La trở về một mình"}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La","tag":"cap-tren","quanHe":"Đại Thiên Tôn của Đạo Cổ nhất mạch","ghiChu":"Khinh thường vì rời đi giúp tu sĩ động phủ giới"},{"ten":"Diệp Đạo","tag":"khac","quanHe":"Thuộc hạ","ghiChu":"Nhận lệnh tìm nữ tử dung hợp hồn phách"}],"tuiDo":{"phapBao":[{"ten":"Quả cầu ánh sáng (chứa hồn phách bí ẩn)","trangThai":"dang-co","moTa":"Chứa hồn phách đang ngủ say, theo lời quốc sư có thể giúp nắm Tiên Cương đại lục","nguon":"@c1700"}]}},"nguon":["@c1700","@c1702"]},{"id":"diep-dao","name":"Diệp Đạo","cn":"","gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hắc bào lão giả phục vụ dưới trướng Đạo Cổ hoàng tôn, phụ trách truy tìm nữ tử có hồn phách dung hợp với hạt châu đỏ bí ẩn, đồng thời truyền đạt lời tiên tri của quốc sư. Trong đại lễ phong hậu tại Đạo Cổ hoàng cung, Diệp Đạo cố ý ép Tống Trí nhận danh phận hoàng hậu nhằm kích động Vương Lâm, thể hiện sự ghen ghét sâu sắc. Sau khi hoàng tôn bị diệt, Diệp Đạo bị Diệp Vi luận tội, bà thừa nhận hắn đáng chết nhưng cho rằng thân phận hoàng tôn khiến hắn không thể bị giết tùy tiện.","vaiTro":"Thuộc hạ trung thành của Đạo Cổ hoàng tôn — hắc bào lão giả","tinhCach":"Trung thành với hoàng tôn; cẩn trọng khi báo cáo; ghen ghét Vương Lâm; cố ý khiêu khích để kích động đối phương","tabs":{"diem":[{"text":"Báo cáo hoàng tôn đã tra khắp cổ quốc không tìm thấy nữ tử có hồn phách trong hạt châu, thuật lại lời tiên tri quốc sư","chuong":"@c1615"},{"text":"Quỳ nhận lệnh hoàng tôn tại hoàng cung Đạo Cổ, đi tìm nữ tử dung hợp với hồn phách bí ẩn trong quả cầu","chuong":"@c1700"},{"text":"Cố ý gọi Tống Trí là hoàng hậu và ép nàng tới gần để kích động Vương Lâm, bộc lộ sự ghen ghét","chuong":"@c1919"},{"text":"Bị Diệp Vi luận tội, thừa nhận đáng chết nhưng cho rằng thân phận hoàng tôn không thể bị giết tùy tiện","chuong":"@c1922"}],"kinhLich":[{"chuong":"@c1700","importance":"normal","mucCt":"gon","tieuDe":"Nhận lệnh hoàng tôn tìm nữ tử dung hợp hồn phách","text":"Quỳ xuống tại hoàng cung Đạo Cổ, nhận lệnh hoàng tôn đi tìm nữ tử dung hợp với hồn phách bí ẩn trong quả cầu.","anchor":"Một năm tử bị bao phủ bởi sương mù màu đen quỳ xuống thấp giọng nói"}],"tuViMoc":[],"nhanMach":[{"ten":"Hoàng tôn Đạo Cổ nhất mạch","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Nhận lệnh tìm nữ tử dung hợp hồn phách"}],"tuiDo":{}},"nguon":["@c1700"]},{"id":"quoc-su-dao-co","name":"Quốc sư Đạo Cổ nhất mạch","cn":"","gioiTinh":"khong-ro","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Quốc sư của Đạo Cổ nhất mạch, được hoàng tôn nhắc lại lời nói rằng hồn phách bí ẩn có thể giúp nắm cả Tiên Cương đại lục. Chưa trực tiếp xuất hiện.","vaiTro":"Quốc sư Đạo Cổ nhất mạch, cố vấn hoàng tôn","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Nói với hoàng tôn rằng hồn phách trong quả cầu có thể giúp nắm cả Tiên Cương đại lục.","chuong":"@c1700"}],"kinhLich":[{"chuong":"@c1700","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được hoàng tôn nhắc lại lời: hồn phách trong quả cầu có thể giúp nắm cả Tiên Cương đại lục.","anchor":"Một hồn phách nho nhỏ mà vì sao quốc sư lại nói nó có thể giúp ta nắm cả Tiên Cương đại lục"}],"tuViMoc":[],"nhanMach":[{"ten":"Hoàng tôn Đạo Cổ nhất mạch","tag":"khac","quanHe":"Hoàng tôn, người được cố vấn","ghiChu":"Nói với hoàng tôn về công dụng hồn phách"}],"tuiDo":{}},"nguon":["@c1700"]},{"id":"hoang-ton-tien-hoang-nhat-mach","name":"Hoàng tôn tiên hoàng nhất mạch","gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hoàng tôn của tiên hoàng nhất mạch truyền thừa từ Tiên Tổ, trên danh nghĩa thống trị các tông phái bảy mươi hai châu Tiên Tộc. Xuất quan sau mấy vạn năm, nửa Tiên Cương bị tiên khí bao phủ.","vaiTro":"Hoàng tôn tiên hoàng, nhân vật cấp cực cao Tiên Tộc","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Xuất quan sau mấy vạn năm, nửa Tiên Cương đại lục bị tiên khí bao phủ, trên danh nghĩa thống trị bảy mươi hai châu.","chuong":"@c1701"}],"kinhLich":[{"chuong":"@c1701","importance":"normal","mucCt":"gon","tieuDe":"Xuất quan sau mấy vạn năm","text":"Hoàng tôn của tiên hoàng nhất mạch xuất quan sau mấy vạn năm, nửa Tiên Cương bị tiên khí bao phủ.","anchor":"hoàng tôn của tiên hoàng nhất mạch truyền thừa từ Tiên Tổ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1701"]},{"id":"duong-san","name":"Đường San","gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Người trên Tiên Cương đại lục vẫn nhớ tới Vương Lâm","blurb":"Người của Tiên Cương đại lục, thuộc số ít người vẫn không quên cái tên Vương Lâm sau khi hắn biệt tích trong hư vô.","mucCt":"gon","tabs":{"diem":[{"text":"Thuộc số ít người trên Tiên Cương đại lục vẫn nhớ tới Vương Lâm","chuong":"@c1702"}],"kinhLich":[{"importance":"bridge","chuong":"@c1702","text":"Vẫn nhớ tới Vương Lâm trong khi phần lớn người khác đã quên cái tên này.","anchor":"Đường San của Tiên Cương đại lục cũng thế"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người vẫn nhớ tới Vương Lâm","ghiChu":"Thuộc số ít người không quên tên Vương Lâm"}],"tuiDo":{}},"nguon":["@c1702"]},{"id":"tien-to","name":"Tiên Tổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tồn tại thượng cổ, đã tiêu tán)","trangThai":"tu-vong","blurb":"Tiên Tổ là thủy tổ của Tiên Tộc, một tồn tại sinh ra trong hư vô từ thượng cổ, từng một mình trấn áp Lục Ma, phong ấn bảy mươi hai sinh linh thiên ngoại, giao chiến với tu sĩ thiên ngoại họ Mạnh và đánh bại Ma Hạt đại nhân, để lại vô số di sản gồm Tiên Cực Kiếm, Thiên Tôn Niết, Bát Cực Đạo, ấn quyết truyền thừa cùng nhiều phong ấn khắp Tiên Cư. Dù đã tiêu tán trong hư không từ vô số vạn năm trước, dấu tích của ông vẫn ảnh hưởng sâu rộng: sợi tóc hóa kinh mạch mang tiên khí trong thân Vương Lâm, đầu lâu khổng lồ ẩn trong cấm cung chứa thế giới truyền thừa, và Trớ Thuật bố trí trước khi chết trở","vaiTro":"Thủy tổ Tiên Tộc — tồn tại thượng cổ sinh ra từ hư vô, đã tiêu tán","tinhCach":"quyết liệt trấn áp ngoại địch, từng một mình trấn áp Lục Ma và phong ấn hàng chục sinh linh thiên ngoại; chú trọng truyền thừa, sáng tạo Thiên Tôn Niết và lưu lại ấn quyết, phân ảnh, cảm ngộ cho hậu nhân; đặt nặng quy củ và trật tự Tiên Tộc, định ra lễ nghi người Tiên Tộc gặp Tiên Hoàng chỉ vái khôn","tabs":{"diem":[{"text":"Phong ấn bảy mươi hai sinh linh thiên ngoại, đánh bại và trấn áp tu sĩ thiên ngoại họ Mạnh cùng Lục Ma Hạt Hồn","chuong":"@c1841"},{"text":"Sáng tạo Thiên Tôn Niết bắt chước Thái Cổ thần cảnh, để lại ấn quyết và Bát Cực Đạo cho hậu nhân tu luyện","chuong":"@c1826"},{"text":"Sợi tóc hóa thành kinh mạch trong thân Vương Lâm, mang tiên khí và bộc phát tiên lực khi cần","chuong":"@c1810"},{"text":"Đầu lâu ẩn trong cấm cung chứa thế giới truyền thừa, trở thành trung tâm tranh đoạt và nguồn lực lượng trấn áp","chuong":"@c1888"},{"text":"Bố trí Trớ Thuật trước khi chết, sau vô số vạn năm vẫn chi phối chiến cục và phong ấn giam cầm Điệu Vong Tộc","chuong":"@c1892"},{"text":"Hư ảnh kim bào tái xuất lần đầu sau vô số vạn năm kể từ khi tiêu tán trong hư không","chuong":"@c1704"}],"kinhLich":[{"chuong":"@c1704","importance":"normal","mucCt":"vua","tieuDe":"Hư ảnh tái xuất sau vô số vạn năm","text":"Hư ảnh Tiên Tổ tái xuất lần đầu sau vô số vạn năm kể từ khi tiêu tán trong hư không: người mặc kim bào đội mũ cao đứng trong dòng xoáy giữa thiên địa, tiên khí lượn quanh. Kim thiên hắc địa bao phủ ba mươi bảy châu Trung Châu, toàn bộ Đại Thiên Tôn Tiên Tộc vái sâu.","anchor":"hư ảnh lại xuất hiện một lần nữa trên Tiên Cương trên đại lục"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1704"]},{"id":"co-to","name":"Cổ Tổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tồn tại thượng cổ)","trangThai":"khong-ro","blurb":"Thủy tổ của Cổ Tộc, tồn tại sinh ra trước khi thiên địa hình thành, thề hủy diệt Tiên Tộc vì chúng muốn nô dịch hắn. Cảnh giới được xếp ngang hàng Tiên Tổ, vượt trên Đại Thiên Tôn; từng giao hồn huyết cho hậu nhân và bố trí hơn mười vạn đại trận trong Đạo Cổ hoàng cung, để lại cấm chế cùng trận pháp chờ người kế thừa. Hồn huyết, ký ức và ý chí của ông tiếp tục ảnh hưởng sâu sắc đến Vương Lâm, nhiều lần hiện hư ảnh trợ chiến và trở thành chuẩn mực sức mạnh tối thượng của Cổ Tộc.","vaiTro":"Thủy tổ Cổ Tộc — nguồn gốc huyết mạch và ý chí nghịch tiên","tinhCach":"Ngạo nghễ bá đạo, không chấp nhận bị nô dịch; ý chí nghịch thiên bất khuất; mưu tính thâm viễn, bố cục xuyên thời đại","tabs":{"diem":[{"text":"Xuất hiện trong mộng Vương Lâm dưới hình dạng nam tử tướng mạo tầm thường, thân thể khổng lồ, lộ nguồn gốc sinh trước thiên địa và ý chí thề diệt Tiên Tộc","chuong":"@c1616"},{"text":"Ngân nhãn tái hiện trên ba mươi sáu quận Cổ Quốc, ngân quang phủ khắp, nhìn về phía Tiên Tộc","chuong":"@c1704"},{"text":"Ký ức được kích phát qua ngọc giản: Cổ Tổ từng một chỉ nghiền nát dị thú, thể hiện sức mạnh vượt xa tầm hiểu biết","chuong":"@c1915"},{"text":"Hư ảnh xuất hiện trong Cửu Khúc, đồng bộ động tác với Vương Lâm để giết Diệp Đạo, rồi điểm một chỉ vào ngọn núi","chuong":"@c1921"},{"text":"Được xác nhận là người bố trí hơn mười vạn đại trận trong Đạo Cổ hoàng cung, mưu tính bao trùm toàn bộ lãnh địa cũ của Cổ Tộc","chuong":"@c1922"},{"text":"Từng bắt sinh mệnh sương mù và phong ấn thành U Quận theo truyền thuyết Cổ Tộc","chuong":"@c1904"}],"kinhLich":[{"chuong":"@c1704","importance":"normal","mucCt":"vua","tieuDe":"Ngân nhãn tái hiện trên Cổ Quốc","text":"Đôi mắt màu bạc hiện trong dòng xoáy đen trên ba mươi sáu quận Cổ Quốc, nhìn về phía Tiên Tộc, ngân quang ngập trời. Con dân Cổ Quốc nhất mạch kích động quỳ lạy.","anchor":"Đó là một đôi mắt màu bạc, nhìn về phía Tiên Tộc, ngân quang ngập trời!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1704"]},{"id":"nguoi-dien","name":"Liên Đạo Phi","aliases":["Đạo Phi thân vương","Đạo Phi"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1705","importance":"bridge","mucCt":"gon","text":"Đang nằm trong Không Gian trữ vật của Vương Lâm, có huyết mạch Tiên Cương nên dù không gian bất ổn trong hư vô cũng không sao.","anchor":"còn có người điên và ngân y nữ tử"},{"chuong":"@c1712","importance":"normal","mucCt":"vua","tieuDe":"Bị cuốn vào khe sụp đổ Không Gian trữ vật","text":"Khi Vương Lâm mở Không Gian trữ vật cũ, người điên cùng nữ tử áo bạc ở gần các khe nứt nhất, trực tiếp bị cuốn vào bên trong biến mất. Anh của Đạo Phi tại hoàng đô Tiên Tộc trung châu cho biết quốc sư tính toán Đạo Phi mất tích không nguy hiểm tính mạng, còn gặp tạo hóa.","anchor":"người điên cùng với nữ tử áo bạc ở cách những cái khe gần nhất, trực tiếp bị cuốn vào bên trong biển mất không thấy"},{"chuong":"@c1713","importance":"normal","mucCt":"vua","tieuDe":"Được ca cứu chữa trong hoàng cung","text":"Bị nam tử mặc hoàng bào kéo ra từ vòng xoáy cùng ngân y nữ tử trong trạng thái hôn mê. Được dùng tiên lực đả thông kinh mạch bế tắc, khơi dậy huyết mạch, xua tan uế khí tích tụ vô số năm. Tỉnh dậy kêu “Ca!” rồi phun máu lại bất tỉnh, được lệnh đưa đi nghỉ ngơi.","anchor":"Đạo Phi đã mất tích nhiều năm, không biết đã xảy ra chuyện gì, không ngờ lại bị thương nặng như vậy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện trong Thất Thải Giới, cho Vương Lâm uống máu mình để cứu mạng, nhiều lần phun máu dùng ấn ký trên tay phải hồi phục thân thể Vương Lâm","chuong":"@c1441"},{"text":"Truyền thụ Dịch Linh Ấn hoàn chỉnh cùng ba thần thông cho Vương Lâm, quỳ dập đầu bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt","chuong":"@c1450"},{"text":"Chân tướng viễn cổ được Vương Lâm xác nhận: vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, thân phận và lai lịch liên quan tới tiên tộc thời thượng cổ","chuong":"@c1628"},{"text":"Lao vào Thất Thải Thương cứu Vương Lâm, thân phát kim quang nồng đậm, cả hai bị hắc động nuốt vào hư vô","chuong":"@c1493"},{"text":"Được ca ca mặc hoàng bào kéo ra từ vòng xoáy và dùng tiên lực cứu chữa trong hoàng cung khi đang hôn mê","chuong":"@c1713"},{"text":"Hôn mê trong địa cung, toàn thân bị chín sợi xích xuyên qua, về sau hoá thành núi trong không gian xếp chồng dưới hoàng cung Tổ Thành","chuong":"@c1883"}]},"nguon":["@c1705","@c1712","@c1713"],"vaiTro":"Tu sĩ tiên tộc viễn cổ mang huyết mạch Tiên Cương — đệ tử của Vương Lâm","tinhCach":"Cô độc đến điên loạn, thường tự xưng bổn vương và nói lảm nhảm; Trọng nghĩa, nhiều lần dùng máu và thân mình cứu Vương Lâm; Tự phụ giữ thể diện nhưng dễ hoảng sợ trước nguy hiểm; Nặng tình với ca ca và ba nương","blurb":"Liên Đạo Phi là tu sĩ mang huyết mạch Tiên Cương, vốn là kẻ ngỗ ngược trên Tiên Cương đại lục từ thời viễn cổ, bị nhốt trong Thất Thải Giới bên trong U Minh Thú không rõ bao nhiêu năm, cô độc đến phát điên. Hắn cứu Vương Lâm bằng máu và tiên lực của mình, truyền Dịch Linh Ấn cùng ba thần thông, rồi quỳ bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt. Sau khi rời Thất Thải Giới, hắn nhiều lần bị cuốn vào biến cố quanh Vương Lâm, từng lao vào Thất Thải Thương cứu sư phụ, được ca ca cứu chữa trong hoàng cung, về sau hôn mê bị chín sợi xích xuyên thân trong địa cung và hoá thành núi dư"},{"id":"ngan-y-nu-tu","name":"Ngân y nữ tử","gioiTinh":"nu","trangThai":"mat-tich","tabs":{"kinhLich":[{"chuong":"@c1705","importance":"bridge","mucCt":"gon","text":"Đang nằm trong Không Gian trữ vật của Vương Lâm, có huyết mạch Tiên Cương nên ở trong hư vô cũng không có vấn đề gì.","anchor":"Hai người này hiển nhiên có huyết mạch Tiên Cương"},{"chuong":"@c1712","importance":"normal","mucCt":"gon","tieuDe":"Bị cuốn vào khe sụp đổ Không Gian trữ vật","text":"Cùng người điên bị cuốn vào khe nứt khi Vương Lâm mở Không Gian trữ vật cũ, biến mất.","anchor":"người điên cùng với nữ tử áo bạc ở cách những cái khe gần nhất, trực tiếp bị cuốn vào bên trong biển mất không thấy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được Vương Lâm thu vào không gian trữ vật","chuong":"@c1293"},{"text":"Sở hữu huyết mạch Tiên Cương, có thể tồn tại trong hư vô không bị ảnh hưởng","chuong":"@c1705"},{"text":"Bị cuốn vào khe nứt hư vô khi không gian trữ vật sụp đổ, biến mất cùng Liên Đạo Phi","chuong":"@c1712"}]},"nguon":["@c1705","@c1712"],"vaiTro":"Nhân vật phụ — nữ tử bí ẩn mang huyết mạch Tiên Cương, bị thu trongữ vật của Vương Lâm","blurb":"Ngân y nữ tử là một nữ tu sở hữu huyết mạch Tiên Cương, được Vương Lâm thu vào không gian trữ vật. Sau đó nàng cùng Liên Đạo Phi bị cuốn vào hư vô khi không gian trữ vật sụp đổ, hiện vẫn mất tích trong khe không gian."},{"id":"dua-be-vuong-gia","name":"Đứa bé muốn làm vương gia","gioiTinh":"nam","trangThai":"song","vaiTro":"Đứa trẻ hơn mười tuổi trong huyện thành Tiên Tộc, chấp nhất muốn làm vương gia, nghi là Tư Đồ Nam chuyển thế","tinhCach":"Chấp nhất; bướng bỉnh; ra vẻ vương gia","blurb":"Đứa bé hơn mười tuổi ở huyện thành Tiên Tộc trên Tiên Cương đại lục, chống nạnh vung gậy gỗ ra vẻ vương gia, đang dự khảo hạch thu đệ tử tông môn. Nội tâm chấp nhất muốn làm vương gia, nghi là Tư Đồ Nam chuyển thế (chưa có câu xác nhận).","tabs":{"diem":[{"text":"Chấp nhất muốn làm vương gia, vung gậy gỗ ra vẻ vương gia dù chỉ là đứa trẻ hơn mười tuổi","chuong":"@c1705"}],"kinhLich":[{"mucCt":"vua","text":"Chống nạnh ra vẻ vương gia, vung gậy gỗ, cùng đám trẻ dự khảo hạch thu đệ tử của một tông môn trong huyện thành Tiên Tộc. Nội tâm vang vọng chấp nhất muốn làm vương gia.","anchor":"Lão tử sau này muốn làm vương gia!","bridge":true,"khoang":"@c1705"}],"tuViMoc":[{"chuong":"@c1705","canhGioi":"Phàm nhân","text":"Đứa trẻ hơn mười tuổi, chưa tu luyện, đang dự khảo hạch nhập môn.","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1705"]},{"id":"thieu-nien-lua-gat","name":"Thiếu niên lừa gạt dáng tiên đồng","gioiTinh":"nam","trangThai":"song","vaiTro":"Thiếu niên nhỏ tuổi dáng tiên đồng hành nghề lừa gạt trong nhà giàu, nghi là Lưu Kim Bưu chuyển thế","tinhCach":"Xảo quyệt; tự đắc; dí dỏm; giỏi lừa gạt","blurb":"Thiếu niên nhỏ tuổi mặc đạo bào dáng tiên đồng trên Tiên Cương đại lục, tự xưng tu hành ba ngàn năm phản lão hoàn đồng, tỏa khí tức tang thương khiến phàm nhân run rẩy tin phục. Thực chất trong lòng tự đắc thuật lừa gạt, nghi là Lưu Kim Bưu chuyển thế (chưa có câu xác nhận).","tabs":{"diem":[{"text":"Tự xưng tu sĩ chuyển thế, thuật lừa gạt vô sự tự thông, tự nhận nếu có đời trước thì tất là tên lừa đảo kinh thiên động địa","chuong":"@c1705"}],"kinhLich":[{"mucCt":"vua","text":"Mặc đạo bào dáng tiên đồng, trong nhà giàu một huyện thành, tự xưng tu hành ba ngàn năm phản lão hoàn đồng cần chín lần chuyển thế, tỏa khí tức tang thương khiến phàm nhân run rẩy cung kính. Trong lòng tự đắc thuật lừa gạt vô sự tự thông, định ở lại đòi gấp trăm lần phí tổn mấy tháng hầu hạ thi thể trong mộ.","anchor":"thuật lừa gạt của tiếu gia đúng là vô sự tự thông","bridge":true,"khoang":"@c1705"}],"tuViMoc":[{"chuong":"@c1705","canhGioi":"Phàm nhân","text":"Thiếu niên nhỏ tuổi chưa có tu vi thật, chỉ dùng thủ đoạn lừa gạt.","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1705"]},{"id":"khang-nhan","name":"Khang Nhân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đệ tử đời thứ ba Thương Long Tông ở Thiên Ngưu Châu, chuyên săn giết tu sĩ ngoài châu để đoạt bảo. Trên đường ra biên giới, hắn phát hiện thi thể chết giả của Vương Lâm và định luyện khôi lỗi, nhưng trận pháp nổ tung rồi bản thân bị Vương Lâm chế trụ, ký ức của hắn về sau giúp Vương Lâm biết về Lục Ma Châu.","vaiTro":"Đệ tử đời thứ ba Thương Long Tông, kẻ săn mồi đoạt bảo ở biên giới Thiên Ngưu Châu","tinhCach":"Giảo hoạt tàn nhẫn, tham lam; ánh mắt cực độc biết nhìn con mồi; hưng phấn khi phát hiện bảo vật nhưng dễ sợ hãi tuyệt vọng khi lâm đại họa","tabs":{"diem":[{"text":"Chứng kiến bầu trời nứt ra một khe khi đang ra biên giới Thiên Ngưu Châu săn tu sĩ ngoài châu","chuong":"@c1706"},{"text":"Phát hiện Vương Lâm nằm chết giả trên ngọn núi sụp, nhận định không phải Cổ Thần/Cổ Tộc/Cổ Quốc","chuong":"@c1707"},{"text":"Hưng phấn tế luyện trận pháp luyện khôi lỗi từ thi thể Vương Lâm thì địa hỏa bùng phát, trận pháp nổ tung","chuong":"@c1708"},{"text":"Sợ hãi tuyệt vọng khi thấy Triệu trưởng lão bị Vương Lâm đánh bay, nhận ra mình mang đại họa về rồi bị Vương Lâm chế trụ","chuong":"@c1709"},{"text":"Ký ức của hắn giúp Vương Lâm biết Lục Ma Châu là nơi khiến người ta sợ hãi","chuong":"@c1746"}],"kinhLich":[{"mucCt":"vua","text":"Đang trên đường ra biên giới Thiên Ngưu Châu săn tu sĩ ngoài châu thì chứng kiến bầu trời nứt ra một khe, u quang lóe lên, một thân ảnh sau lưng dường như có quan tài rơi xuống đất. Nhớ môn quy Thương Long Tông, xuất pháp bảo hộ thân lao tới. Thấy thanh niên tóc bạc nằm bất động trong đá vụn, thân thể cực mạnh, nổi lòng tham cẩn thận tiến lại gần.","anchor":"Hai mắt Khang Nhân lộ vẻ tham lam, cẩn thận tới gần.","bridge":true,"khoang":"@c1706"},{"mucCt":"ky","text":"Phát hiện Vương Lâm nằm chết giả trên ngọn núi sụp, nhận định không phải Cổ Thần/Cổ Tộc/Cổ Quốc, thân thể cường đại hiếm thấy. Ném ngọc giản uy lực Tịnh Niết thử — Vương Lâm vô tổn. Nhìn thấy nữ tử ngủ say trong Tị Thiên Quan, nổi tà niệm muốn luyện nàng thành khôi lỗi hầu hạ. Tung lưới phong ấn bao trùm cả Vương Lâm lẫn quan tài, hóa hắc phong cuốn về sơn môn Thương Long Tông. Đóng cửa động phủ, bày chín khôi lỗi giữ cửa, dốc toàn bộ mười phần tài liệu và kích hoạt trận pháp hút địa hỏa luyện chế khôi lỗi. Mong trở thành bậc toàn năng có hỏa bổn nguyên.","anchor":"Mặc kệ ngươi là ai, rơi vào tay ta thì phải trở thành khôi lỗi của Khang Nhân ta!","bridge":true,"khoang":"@c1707"},{"mucCt":"vua","text":"Đang hưng phấn tế luyện trận pháp luyện khôi lỗi từ thi thể Vương Lâm thì địa hỏa bùng phát, trận pháp nổ tung, chín khôi lỗi nổ tan, hai khôi lỗi gỗ sụp đổ. Được Vương Lâm phóng u quang bảo vệ nên thoát chết, kinh hãi tới mức ngây ngốc.","anchor":"Ta. Ta đã mang về kẻ nào thế này","bridge":true,"khoang":"@c1708"},{"chuong":"@c1709","importance":"bridge","mucCt":"vua","text":"Sợ hãi tuyệt vọng khi chứng kiến Triệu trưởng lão bị Vương Lâm đánh bay, nhận ra mình mang đại họa về. Bị Vương Lâm dùng thần thức quét ký ức.","anchor":"Đây đâu phải là cơ may gì, đây rõ ràng là một tiểu tổ tông mà"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng bị luyện khôi lỗi","ghiChu":"Phát hiện chết giả trên núi sụp, mang về trận luyện"},{"ten":"Hư Vân","tag":"doi-thu","quanHe":"Đồng môn Thương Long Tông, có oán thù riêng","ghiChu":"Bị Hư Vân dò hỏi ở cốc khẩu, hai bên có tư oán"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1706","@c1707","@c1708","@c1709"]},{"id":"thanh-nien-toc-bac-mang-quan-tai","name":"Thanh niên tóc bạc mang quan tài","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thân ảnh bí ẩn bay ra từ khe nứt trên bầu trời Thiên Ngưu Châu, sau lưng dường như có một cái quan tài, rơi xuống đụng sụp hơn phân nửa lưng chừng núi. Danh tính chưa lộ.","vaiTro":"Nhân vật bí ẩn xuất hiện từ khe nứt không gian tại Thiên Ngưu Châu, danh tính chưa lộ","tinhCach":["Chưa rõ, nằm bất động"],"tabs":{"diem":[{"text":"Thân thể cực mạnh, rơi từ khe nứt không gian đụng sụp hơn phân nửa lưng chừng núi mà vẫn nguyên vẹn.","chuong":"@c1706"}],"kinhLich":[{"chuong":"@c1706","importance":"normal","mucCt":"gon","tieuDe":"Xuyên khe nứt rơi xuống Thiên Ngưu Châu","text":"Bay ra từ khe nứt trên bầu trời, sau lưng dường như có quan tài, rơi xuống đụng sụp hơn phân nửa lưng chừng núi, nằm bất động trong đá vụn.","anchor":"trong đám đá vụn lộ ra một thanh niên tóc bạc nằm không nhúc nhích"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1706"]},{"id":"do-thanh","name":"Đỗ Thanh","cn":"杜青","aliases":["Thiếu niên anh tuấn"],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Huyền Kiếp (bảy lần, chưa tới Không Kiếp sơ kỳ)","trangThai":"song","blurb":"Đỗ Thanh là người sáng lập kiêm thái thượng trưởng lão Thương Long Tông, một khôi lỗi thân thể con rối đối ngoại xưng Không Kiếp sơ kỳ nhưng thực tế tu vi chỉ dừng ở bảy lần Huyền Kiếp. Khi xuất ngoại trở về phát hiện tông phái bị hủy diệt, ông rống giận kinh thiên và truy sát Vương Lâm suốt hơn hai mươi ngày, cuối cùng bị bảy đạo bổn nguyên cùng kim ấn mang khí tức Đại Thiên Tôn trấn áp nên từ bỏ ý truy sát, chuyển sang hộ pháp cho Vương Lâm. Về sauông trở thành trưởng lão mới của Đại Hồn Môn.","vaiTro":"Sáng lập kiêm thái thượng trưởng lão Thương Long Tông — khôi lỗi tu vi bảy lần Huyền Kiếp","tinhCach":"Phẫn nộ dữ dội và truy sát không ngừng khi tông phái bị hủy; biết đánh giá tình thế, chịu khuất phục trước thực lực áp đảo; trọng lời hứa, chuyển từ đối đầu sang hộ pháp tận tâm; cẩn trọng suy đoán lai lịch đối phương qua manh mối pháp thuật","tabs":{"diem":[{"text":"Người đầu tiên của Thương Long Tông đạt cảnh giới Không Kiếp (đối ngoại), thực chất bảy lần Huyền Kiếp","chuong":"@c1715"},{"text":"Trở về phát hiện tông phái bị hủy diệt, rống giận kinh thiên, phát lệnh truy sát Vương Lâm","chuong":"@c1711"},{"text":"Truy kích Vương Lâm hơn hai mươi ngày, nội tâm liên tục dao động trước các manh mối pháp thuật","chuong":"@c1715"},{"text":"Bị bảy đạo bổn nguyên và kim ấn Đại Thiên Tôn trấn áp, từ bỏ ý truy sát","chuong":"@c1718"},{"text":"Chuyển sang hộ pháp cho Vương Lâm, chứng kiến ngưng tụ bổn nguyên chân thân và trấn áp long hồn","chuong":"@c1720"},{"text":"Trở thành trưởng lão mới của Đại Hồn Môn, thân thể là con rối chứ không phải huyết nhục","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1706","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc là thái thượng trưởng lão sáng lập Thương Long Tông, người đầu tiên đạt Không Kiếp, bản thân là khôi lỗi, lưu lại môn quy cho đệ tử.","anchor":"thái thượng trưởng lão Đỗ Thanh là một khôi lỗi"},{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Được nhắc qua ký ức Khang Nhân: lão tổ Thương Long Tông tu vi Không Kiếp sơ kỳ, đang xuất ngoại.","anchor":"Tông chủ Không Huyền sơ kỳ, lão tổ Không Kiếp sơ kỳ - Đỗ Thanh"},{"chuong":"@c1711","importance":"normal","mucCt":"ky","tieuDe":"Trở về tông phái bị hủy, phát lệnh truy sát Vương Lâm","text":"Trở về Thương Long Tông, phát hiện tông phái bị hủy diệt, rống giận kinh thiên, khí tức bộc phát giết mấy ngàn đệ tử gần nhất. Soát hồn một thanh niên đệ tử (giết chết người đó) để lấy hình dáng Vương Lâm. Biến trưởng lão Tôn Mộng thành khôi lỗi trừng phạt vì tội không tự bạo Nguyên Thần ngăn cản. Ra lệnh phát động toàn tông truy tìm Vương Lâm trong ba tháng, thông cáo cả Thiên Ngưu Châu.","anchor":"Cho tới bây giờ chưa có người nào dám hủy tông phái của Đỗ Thanh ta!"},{"mucCt":"vua","text":"Phẫn nộ vì Thương Long Tông bị thiêu đốt, đích thân tản thần thức quét khắp bốn phía truy tìm Vương Lâm nhưng không phát hiện do cấm chế quá bất phàm. Thiên Ngưu Châu quá rộng lớn nên khả năng đích thân tới chỗ Vương Lâm không lớn.","anchor":"lửa giận của lão tổ Thương Long Tông là Đỗ Thanh lại càng bốc thêm","bridge":true,"khoang":"@c1712"},{"mucCt":"vua","text":"Chậm ba ngày tới vùng núi đầu tiên, dùng cánh tay gỗ trăm trượng phá sập ngọn núi nhưng Vương Lâm đã rời đi, tính nhờ Đại Hồn Môn trợ giúp truy tìm. Hai ngày sau tới vùng núi thứ hai, dùng thần thức thăm dò phát hiện chi địa hỏa mạch hoàn toàn khô héo tử vong, sắc mặt đại biến hoảng sợ vì trên Tiên Cương chưa từng có ai hấp thu được địa hỏa mạch.","anchor":"Ánh mắt Đỗ Thanh lộ vẻ hoảng sợ.","bridge":true,"khoang":"@c1714"},{"mucCt":"ky","text":"Truy kích Vương Lâm suốt hơn hai mươi ngày, nội tâm liên tục dao động khi thấy từng địa hỏa mạch khô héo. Tự bộc lộ tu vi thật: đối ngoại tuyên bố Không Kiếp sơ kỳ nhưng thực tế chỉ bảy lần Huyền Kiếp, tự tin thân thể khôi lỗi có thể sánh tu sĩ Cổ Quốc. Dùng hạc giấy đỏ (chỉ dẫn Đại Hồn Môn) dẫn đường truy kích. Khi đuổi kịp Vương Lâm tại tử mạch, tiếng gầm long hồn dẫn động hỏa bổn nguyên trong thân bùng ra, thân thiếu niên nứt hiện nguyên hình khôi lỗi gỗ — lửa vờn quanh nhưng không tổn thương thân khôi lỗi. Nhìn thấy cảnh quần long nhất tước của Vương Lâm, cảm giác như đối mặt ngọn núi cao.","anchor":"Ta đối với bên ngoài tuyên bố là Không Kiếp sơ kỳ nhưng trên thực tế mới chỉ là bảy lần Huyền Kiếp","bridge":true,"khoang":"@c1715"},{"mucCt":"ky","text":"Lao vào biển lửa định tấn công Vương Lâm lúc đang cắn nuốt địa hỏa mạch. Triệu ra cánh tay gỗ khổng lồ từ dòng xoáy đối kháng chưởng ấn Vương Lâm, cả hai bên đều tan nát, bị đẩy lui ba bước. Phát hiện Vương Lâm mượn lực phản kích của mình để đẩy nhanh cắn nuốt long hồn. Chất vấn Vương Lâm về việc phá hủy Thương Long Tông, nói mấy ngàn đệ tử đã chết. Khi Vương Lâm thi triển Dịch Linh Ấn, nhận ra là đại thủ ấn Thế Giới Tông. Thấy Thất Thải Thuật, nhận ra là của Đông Lâm Tông. Thấy Phần Giới Cổ Tán, nhận ra là đạo thuật bất truyền của Tùng Vân Đạo — da đầu tê dại, sắc mặt tái nhợt, hỏi Vương Lâm rốt cục là ai.","anchor":"Sắc mặt Đỗ Thanh tái nhợt","bridge":true,"khoang":"@c1716"},{"chuong":"@c1717","importance":"normal","mucCt":"ky","tieuDe":"Triển khai ba đạo bổn nguyên đè sụp Vương Lâm","text":"Đỗ Thanh liên tục hoảng sợ khi suy đoán lai lịch Vương Lâm qua pháp thuật Thế Giới Tông, Đông Lâm Tông và Tùng Vân Đạo, cân nhắc hai khả năng nhưng vì đã đuổi quá lâu không thể lui. Hắn lộ thân khôi lỗi gỗ bốc lửa rồi triển khai đủ ba đạo bổn nguyên: tử hỏa từ tử khí thân khôi lỗi, thổ bổn nguyên rút khí tức đại địa biến bốn phía thành hoang mạc, và trọng bổn nguyên — bổn nguyên cực hiếm ở Tiên Cương mà hắn mò ra nhờ thân khôi lỗi chứa một tia trọng bổn nguyên, cũng là lý do Đại Hồn Môn che chở hắn. Trọng bổn nguyên khiến hỏa có trọng lượng uy lực tăng vô số lần, thổ bổn nguyên như nắm cả đại lục. Ba đạo bổn nguyên đè sụp toàn bộ bốn thần thông của Vương Lâm và hỏa long hồn, biến thành hỏa cầu khổng lồ bao phủ đối thủ. Khi định truy kích đòn trí mạng thì nghe Vương Lâm hỏi ngược về số bổn nguyên, Đỗ Thanh chấn động tâm thần.","anchor":"Lão phu dùng ba đạo bổn nguyên ngạnh kháng Huyền Kiếp, sao có thể bị một đạo bổn nguyên của ngươi dọa lui!"},{"chuong":"@c1718","importance":"major","mucCt":"ky","tieuDe":"Bị bảy bổn nguyên và kim ấn Đại Thiên Tôn trấn áp, bỏ ý truy sát","text":"Lần lượt bị Vương Lâm triệu hoán bảy đạo bổn nguyên trấn áp tâm lý: sửng sốt vì hai bổn nguyên, chấn động vì năm đạo, kinh hoàng vì sát lục bổn nguyên hiếm hơn trọng bổn nguyên, da đầu tê dại vì bảy đạo tổng cộng. Khi kim ấn Đại Thiên Tôn xuất hiện, tự thương tâm thần phun máu. Nhận ra pháp bảo này là do Đại Thiên Tôn dùng thiên địa thuật thực chất hóa thần thông ngưng tụ — đổi chủ không do chủ nhân trao thì tan vỡ — tức Vương Lâm được một Đại Thiên Tôn đích thân bảo hộ. Gào lên mắng Vương Lâm gian xảo, tuyên bố nếu biết sớm thì cho dù giết cả Thương Long Tông cũng coi như không thấy, hoàn toàn bỏ ý truy sát.","anchor":"Chết tiệt, ngươi có Pháp Bảo như vậy sao không lấy ra sớm một chút hả"},{"mucCt":"ky","text":"Bị kim ấn mang khí tức Đại Thiên Tôn trấn áp, bỏ hết ý truy sát. Nhận ra Vương Lâm tu vi cao thâm lại có Pháp Bảo do Đại Thiên Tôn ban, coi đây là cơ duyên hiếm có, tính toán theo Vương Lâm để không phải kiêng kị Đại Hồn Môn, không phải nộp bảo bối. Quay lại nói dối là hiểu lầm, xin hộ pháp, dùng thệ phù mượn pháp tắc Tiên Cương chứng thề không có tà tâm. Được Vương Lâm đồng ý. Nghiêm túc hộ pháp ba ngày. Ngày thứ năm chứng kiến quả cầu lửa co rút, nhận ra Vương Lâm có thể đang ngưng tụ chân thân bổn nguyên — thứ cả đời hắn chỉ thấy trên lão tổ Đại Hồn Môn.","anchor":"Chẳng lẽ hắn muốn ngưng tụ chân thân của bổn nguyên!","bridge":true,"khoang":"@c1719"},{"importance":"normal","mucCt":"ky","chuong":"@c1720","tieuDe":"Chứng kiến ngưng tụ chân thân, kiềm chế long hồn","text":"Hộ pháp cho Vương Lâm trong Thiên Ngưu Châu, lần đầu chứng kiến quá trình ngưng tụ bổn nguyên chân thân, coi đây là cơ duyên lớn mở ra con đường tu luyện rõ ràng. Tu vi hiện tại còn trong bảy lần Huyền Kiếp, chưa tới Không Kiếp sơ kỳ, không dám vượt lần thứ tám, thứ chín. Được Vương Lâm giao kiềm chế một long hồn mạch con trong nửa canh giờ, cắn răng hóa thân hình khôi lỗi gỗ lao về phía long hồn.","anchor":"Đỗ Thanh, cho ngươi một cơ hội, kiềm chế một long hồn trong nửa canh giờ!"},{"mucCt":"ky","text":"Thi triển trọng bổn nguyên phát tử quang trấn áp long hồn mạch con xuống mặt đất. Kinh hãi trước uy lực kim ấn Đại Thiên Tôn và uy áp bổn nguyên chân thân của Vương Lâm. Nhận ra hư ảnh phía sau Vương Lâm giống hiện tượng của lão tổ Đại Hồn Môn. Hứa phát động đệ tử Thương Long Tông tìm địa hỏa mạch và xuất động trưởng lão tìm long hồn. Ngầm tăng tốc thăm dò tu vi Vương Lâm, phán đoán hắn trông như Không Linh đỉnh phong nhưng thực lực chưa rõ, mục đích thật sự muốn thông qua Vương Lâm tiếp xúc Đại Thiên Tôn. Bị tiếng rít Văn Vương khiến tâm thần chấn kinh, kinh khiếp trước tốc độ.","anchor":"nhìn như Không Linh đỉnh phong nhưng lại có thể tiếp hai thức thần thông của ta mà giống như chưa dốc toàn lực","bridge":true,"khoang":"@c1721"},{"mucCt":"ky","text":"Đuổi theo Vương Lâm chật vật nửa tháng, tự an ủi rằng Vương Lâm giàu có là nhờ Đại Thiên Tôn ban cho. Về tới Thương Long Tông, giới thiệu Vương Lâm là chí giao đạo hữu có đại ân, dẫn vào động phủ hậu sơn xa hoa. Tiết lộ truyền thuyết thiên ngoại ngưu tinh bị Tiên Tổ giết, thân hóa Thiên Ngưu Châu, Nguyên Thần bị trấn áp dưới hỏa mạch. Cho biết địa hỏa chủ mạch nằm ở Đại Hồn Môn, lão tổ là Thanh Ngưu chân nhân có bổn nguyên chân thân. Tiết lộ bản thân là trưởng lão ngoại môn Đại Hồn Môn, tộc có tiền bối là trưởng lão nội môn. Kể về Phàn San Mộng (song kiêu Đại Hồn Môn) và Vân Dật Phong (đệ nhất cao thủ Thiên Ngưu Châu). Khi kể lời Vân Dật Phong về người tu hơn hai ngàn năm, đột nhiên liên hệ tới Vương Lâm, sinh ra nghi ngờ lớn.","anchor":"Đồng tử trong mắt hắn co rút lại, đột nhiên một ý niệm lớn mật hiện lên trong đầu hắn.","bridge":true,"khoang":"@c1722"},{"mucCt":"vua","text":"Cung cấp thông tin về lôi mạch và Đông Lâm Tông cho Vương Lâm, hạ lệnh toàn Thương Long Tông tìm địa hỏa mạch với ba đại trưởng lão cầm đầu đi ba hướng, thả trưởng lão bị biến khôi lỗi cho lập công. Quan sát Vương Lâm bảy tháng, nội tâm dần khinh thường cho rằng hắn không biết tự lượng sức, cuối cùng sợ hãi đứng phắt dậy khi phân thân Vương Lâm bừng tỉnh.","anchor":"Thật là không biết tự lượng sức","bridge":true,"khoang":"@c1723"},{"mucCt":"vua","text":"Hoảng sợ khi thần thức Vương Lâm biến mất khỏi hậu sơn, tìm kiếm khắp nơi không thấy dấu vết. Phát hiện tuyết xanh Thiên Sơn dưới chân Vương Lâm, chứng minh hắn đã di chuyển tức thời cực xa, toàn bộ sự khinh thường bảy tháng qua tan thành mây khói, sinh ra nỗi sợ hãi sâu sắc. Mang hỏa hồn và ngọc giản bản đồ tử mạch tới bái kiến nhưng không đi báo tin vì còn mưu đồ riêng với Vương Lâm.","anchor":"tất cả những sự khinh thường của hắn đối với Vương Lâm suốt bảy tháng qua toàn bộ đều tan thành mây khói","bridge":true,"khoang":"@c1724"}],"tuViMoc":[{"chuong":"@c1706","canhGioi":"Không Kiếp","text":"Người đầu tiên của Thương Long Tông đạt tu vi Không Kiếp, được nhắc qua lời giới thiệu nền.","importance":"major"},{"chuong":"@c1711","canhGioi":"Không Kiếp sơ kỳ","text":"Tu vi Không Kiếp sơ kỳ, ngang Thất Thải đạo nhân và Chiến lão quỷ.","importance":"major"},{"chuong":"@c1715","canhGioi":"Bảy lần Huyền Kiếp (thực tế)","text":"Tự thừa nhận đối ngoại xưng Không Kiếp sơ kỳ nhưng thực tế chỉ bảy lần Huyền Kiếp, thân thể khôi lỗi gỗ cường hãn có thể sánh tu sĩ Cổ Quốc.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ hủy diệt Thương Long Tông, mục tiêu truy sát","ghiChu":"@c1711"},{"ten":"Tôn Mộng","tag":"cap-tren","quanHe":"Trưởng lão dưới quyền, bị biến thành khôi lỗi trừng phạt","ghiChu":"@c1711"},{"ten":"Triệu trưởng lão","tag":"cap-tren","quanHe":"Trưởng lão dưới quyền (nam tử trung niên mất đôi tay)","ghiChu":"@c1711"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Chủ động xin hộ pháp cho Vương Lâm, lập thệ phù thề trung thành","ghiChu":"@c1719"},{"ten":"Thanh Ngưu chân nhân","tag":"cap-tren","quanHe":"Lão tổ Đại Hồn Môn, Đỗ Thanh là trưởng lão ngoại môn dưới quyền","ghiChu":"@c1722"},{"ten":"Vân Dật Phong","tag":"khac","quanHe":"Đệ nhất cao thủ Thiên Ngưu Châu (Quy Nhất Tông), Đỗ Thanh từng tiếp xúc và nhận xét bất phàm","ghiChu":"@c1722"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1706","@c1709","@c1710","@c1711","@c1712","@c1714","@c1715","@c1716","@c1717","@c1718","@c1719","@c1720","@c1721","@c1722","@c1723","@c1724"]},{"id":"hu-van","name":"Hư Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên anh tuấn nhưng lưng gù, đệ tử Thương Long Tông gác cốc khẩu. Phát hiện Khang Nhân mang bảo bối về, lưu khôi lỗi thế chỗ gác rồi bám theo, quỳ báo sư tôn xin đoạt lấy.","vaiTro":"Đệ tử Thương Long Tông, gác cốc khẩu, mưu đồ chiếm bảo bối","tinhCach":"Ánh mắt ác độc; tinh ranh mưu mô; dạ chiếm đoạt; cung kính sư tôn","tabs":{"diem":[{"text":"Lưng gù nhưng anh tuấn, ánh mắt ác độc khi nhìn theo Khang Nhân","chuong":"@c1707"},{"text":"Lưu khôi lỗi thế chỗ gác, bổn tôn bám theo Khang Nhân rồi quỳ báo sư tôn xin đoạt bảo","chuong":"@c1707"}],"kinhLich":[{"mucCt":"vua","text":"Gác cốc khẩu Thương Long Tông, chặn hỏi Khang Nhân về cái lưới phong ấn nhưng bị gạt phắt. Nhận định có bảo bối, lưu khôi lỗi thế chỗ gác rồi bổn tôn bay theo vào sơn cốc. Quỳ báo sư tôn (lão già tóc bạc Không Niết sơ kỳ), xin sư tôn ra tay đoạt khôi lỗi ban cho mình.","anchor":"Có chuyện, có điều cổ quái, có bảo bối!","bridge":true,"khoang":"@c1707"},{"importance":"bridge","mucCt":"gon","chuong":"@c1708","tieuDe":"Chứng kiến địa hỏa bùng phát","text":"Đang cùng sư tôn tới gần động phủ Khang Nhân thì địa hỏa bùng phát, buộc phải lùi xa.","anchor":"Hỏa biến này là do hắn luyện chế khôi lỗi gây nên"},{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Được nhắc gián tiếp qua danh xưng — sư tôn của Hư Vân (Tôn Mộng) trợn mắt không tin khi Triệu trưởng lão bị đánh bay.","anchor":"nhất là sư tôn của Hư Vân trợn trừng hai mắt"}],"tuViMoc":[],"nhanMach":[{"ten":"Khang Nhân","tag":"doi-thu","quanHe":"Đồng môn Thương Long Tông, có oán thù riêng","ghiChu":"Dò hỏi lưới phong ấn, mưu đoạt bảo bối Khang Nhân mang về"},{"ten":"Tôn Mộng","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Quỳ báo sư tôn về bảo bối, xin sư tôn đoạt lấy ban cho mình"}],"tuiDo":{}},"nguon":["@c1707","@c1708","@c1709"]},{"id":"ton-mong","name":"Tôn Mộng","cn":"","aliases":["Lão già tóc bạc","Sư tôn Hư Vân"],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ","trangThai":"song","blurb":"Tôn Mộng là lão già tóc bạc tu vi Không Niết sơ kỳ, sư tôn của Hư Vân tại Thương Long Tông. Đang bế quan thì cảm nhận trận luyện khôi lỗi hút quá nhiều địa hỏa, lập tức dẫn đệ tử đi tra xét, phát hiện biến cố liên quan tới Khang Nhân và nhận ra tu vi thực sự của Vương Lâm. Sau đó bị tông chủ Đỗ Thanh quy tội không tự bạo Nguyên Thần ngăn cản, bị thi triển thần thông trừng phạt.","vaiTro":"Trưởng bối Thương Long Tông, sư tôn của Hư Vân","tinhCach":"Nghiêm khắc với đệ tử; cảnh giác nhạy bén trước dị biến; quyết đoán hành động khi phát hiện nguy cơ","tabs":{"diem":[{"text":"Đang bế quan, cảm nhận trận luyện khôi lỗi lấy quá nhiều địa hỏa, vụt dậy dẫn đệ tử đi xem xét","chuong":"@c1707"},{"text":"Nhận ra dị biến liên quan tới Khang Nhân mang về hai thi thể, lui mấy trăm trượng tránh nguy","chuong":"@c1708"},{"text":"Phán đoán tu vi Vương Lâm ở tầng Không Huyền hoặc cao hơn từ quy tức trong lời nói, cắn răng lao ra cùng các trưởng lão","chuong":"@c1709"},{"text":"Bị tông chủ Đỗ Thanh quy tội không tự bạo Nguyên Thần ngăn cản, bị thi triển thần thông trừng phạt","chuong":"@c1711"}],"kinhLich":[{"mucCt":"vua","text":"Đang bế quan, ban đầu trách Hư Vân quấy rầy. Nhưng cảm nhận trận luyện khôi lỗi Khang Nhân lấy quá nhiều địa hỏa, lượng bất thường, liền đứng vụt dậy dẫn Hư Vân đi xem tận nơi. Hư Vân quỳ xin sư tôn đoạt bảo ban cho mình.","anchor":"Thôi, ngươi đi theo ta một chuyến, xem hắn rốt cục luyện chế khôi lỗi gì!","bridge":true,"khoang":"@c1707"},{"mucCt":"vua","text":"Cảm nhận biến cố vội lui mấy trăm trượng. Chỉ ra nguyên nhân dị biến liên quan tới Khang Nhân mang về hai thi thể, yêu cầu Triệu trưởng lão điều tra.","anchor":"Hỏa biến này là do hắn luyện chế khôi lỗi gây nên","bridge":true,"khoang":"@c1708"},{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Nhận ra lời nói Vương Lâm mang quy tức, đoán tu vi Không Huyền hoặc cao hơn, cắn răng lao ra cùng các trưởng lão ngăn cản.","anchor":"Đây là tu vi đã đạt tới cảnh giới Không Huyền, thậm chí có thể cao hơn"},{"mucCt":"gon","text":"Giải thích sự việc cho tông chủ Đỗ Thanh, bị quy tội không tự bạo Nguyên Thần ngăn cản, bị thi triển thần thông ánh sáng xám biến thành khôi lỗi, nuốt vào dòng xoáy dưới đất phong ấn trừng phạt.","anchor":"toàn thân lóe lên ánh sáng màu xám. Tràn vào thân thể Nguyên Thần lão già kia","bridge":true,"khoang":"@c1711"}],"tuViMoc":[{"chuong":"@c1707","canhGioi":"Không Niết sơ kỳ","text":"Tu vi Không Niết sơ kỳ, lộ ra khi dao động lan từ thân thể","importance":"major"}],"nhanMach":[{"ten":"Hư Vân","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"Hư Vân quỳ báo về bảo bối Khang Nhân, xin sư tôn đoạt lấy"},{"ten":"Khang Nhân","tag":"khac","quanHe":"Đệ tử cùng tông, có oán thù với đệ tử mình","ghiChu":"Nhắc Khang Nhân và Hư Vân có tư oán"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cường giả bí ẩn trong động phủ, nhận ra tu vi Không Huyền trở lên","gap":"@c1709"},{"ten":"Đỗ Thanh","tag":"cap-tren","quanHe":"Tông chủ, người biến mình thành khôi lỗi trừng phạt","ghiChu":"@c1711"}],"tuiDo":{}},"nguon":["@c1707","@c1708","@c1709","@c1710","@c1711"]},{"id":"trieu-truong-lao","name":"Triệu trưởng lão","cn":"","aliases":["Nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Linh hậu kỳ","trangThai":"song","blurb":"Triệu trưởng lão là trưởng lão của Thương Long Tông, tu vi Không Linh hậu kỳ, thuộc nhóm cường giả đứng đầu Thiên Lôi Tinh. Khi địa hỏa bùng phát trong tông môn, ông chủ động xông vào điều tra và chỉ huy sơ tán đệ tử. Sau khi bị Vương Lâm đánh bay, ông âm thầm quan sát cục diện và phân tích mối quan hệ giữa lão tổ Đỗ Thanh với Vương Lâm.","vaiTro":"Trưởng lão Thương Long Tông — cường giả Không Linh hậu kỳ, bước thứ ba","tinhCach":"Kiêu ngạo, tự phụ về tu vi; quyết đoán khi xử lý biến cố; thận trọng quan sát và phân tích cục diện","tabs":{"diem":[{"text":"Chủ động xông vào biển lửa điều tra dị biến địa hỏa, hạ lệnh đệ tử sơ tán","chuong":"@c1708"},{"text":"Dùng giọt nước hộ thể tiến vào ngọn lửa, bị Vương Lâm quát một tiếng đánh bay","chuong":"@c1709"},{"text":"Chứng kiến Tôn Mộng bị tông chủ Đỗ Thanh biến thành khôi lỗi, thầm nhận xét về tính cách tông chủ","chuong":"@c1711"},{"text":"Khôi phục thương thế, phân tích rằng lão tổ Đỗ Thanh rất có khả năng đã giao thủ với Vương Lâm","chuong":"@c1722"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1708","tieuDe":"Xông vào biển lửa điều tra dị biến địa hỏa","text":"Xuất hiện khi địa hỏa bùng phát tại Thương Long Tông, hạ lệnh đệ tử sơ tán, cho biết tông chủ và lão tổ đi Đại Hồn Môn. Hóa giọt nước ba trượng bao thân lao vào biển lửa, tiến vào động phủ nhìn thấy Khang Nhân run rẩy kinh hãi.","anchor":"Hắn đối với tu vi của mình rất kiêu ngạo"},{"mucCt":"vua","text":"Dùng giọt nước hộ thể tiến vào ngọn lửa trong động phủ Khang Nhân, bị Vương Lâm quát một tiếng đánh bay hơn ngàn trượng, phun ba ngụm máu trọng thương. Sau đó sợ lão tổ Đỗ Thanh nổi giận khi trở về, hạ lệnh bốn trưởng lão và cả vạn đệ tử thi triển Đạo Hồn Thuật ngăn Vương Lâm rời đi.","anchor":"tu vi đã đạt tới Không Linh hậu kỳ, vị trí ở Thương Long Tông một người trên vạn người","bridge":true,"khoang":"@c1709"},{"chuong":"@c1711","importance":"bridge","mucCt":"gon","text":"Chứng kiến Tôn Mộng bị tông chủ Đỗ Thanh biến thành khôi lỗi, thầm nhận xét Tôn Mộng không hiểu tính cách tông chủ, âm thầm thở dài.","anchor":"Tôn Mộng này tiến vào Thương Long Tông thời gian không dài, hoàn toàn không biết tính cách của tông chủ rồi"},{"chuong":"@c1722","importance":"bridge","mucCt":"gon","text":"Song chưởng đã khôi phục, thầm phân tích rằng lão tổ Đỗ Thanh rất có khả năng đã giao thủ với Vương Lâm nhưng không địch lại.","anchor":"Lão tổ rất có khả năng đã giao thủ với người này nhưng không địch lại."}],"tuViMoc":[{"chuong":"@c1709","canhGioi":"Không Linh hậu kỳ","text":"Tu vi Không Linh hậu kỳ, thuộc nhóm cường giả đứng đầu Thiên Ngưu Châu.","importance":"minor"}],"nhanMach":[{"ten":"Khang Nhân","tag":"khac","quanHe":"Đệ tử đời thứ ba cùng tông, gây ra biến cố địa hỏa"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Xâm nhập động phủ, bị Vương Lâm quát đánh bay trọng thương","gap":"@c1709"},{"ten":"Đỗ Thanh","tag":"cap-tren","quanHe":"Lão tổ Thương Long Tông, Triệu trưởng lão cực kỳ kính sợ","gap":"@c1709"},{"ten":"Lệ Trường Thiên","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông, được Triệu trưởng lão ra lệnh cùng ngăn cản Vương Lâm","gap":"@c1709"},{"ten":"Đóa Mộng Đắc","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông","gap":"@c1709"},{"ten":"Hàn Tâm","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông","gap":"@c1709"}],"tuiDo":{}},"nguon":["@c1708","@c1709","@c1710","@c1711","@c1722"]},{"id":"le-truong-thien","name":"Lệ Trường Thiên","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Một trong bốn đại trưởng lão bước thứ ba của Thương Long Tông, tham gia thi triển Đạo Hồn Thuật ngăn cản Vương Lâm.","vaiTro":"Trưởng lão Thương Long Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Một trong bốn đại trưởng lão bước thứ ba Thương Long Tông, được gọi tên cùng ngăn cản Vương Lâm","chuong":"@c1709"}],"kinhLich":[{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Được Triệu trưởng lão gọi tên ra lệnh cùng ngăn cản Vương Lâm, thi triển Đạo Hồn Thuật.","anchor":"Lệ Trường Thiên, Đóa Mộng Đắc. Hàn Tâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Triệu trưởng lão","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông","gap":"@c1709"}],"tuiDo":{}},"nguon":["@c1709"]},{"id":"doa-mong-dac","name":"Đóa Mộng Đắc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Một trong bốn đại trưởng lão bước thứ ba của Thương Long Tông, tham gia thi triển Đạo Hồn Thuật ngăn cản Vương Lâm.","vaiTro":"Trưởng lão Thương Long Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Một trong bốn đại trưởng lão bước thứ ba Thương Long Tông, được gọi tên cùng ngăn cản Vương Lâm","chuong":"@c1709"}],"kinhLich":[{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Được Triệu trưởng lão gọi tên ra lệnh cùng ngăn cản Vương Lâm, thi triển Đạo Hồn Thuật.","anchor":"Lệ Trường Thiên, Đóa Mộng Đắc. Hàn Tâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Triệu trưởng lão","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông","gap":"@c1709"}],"tuiDo":{}},"nguon":["@c1709"]},{"id":"han-tam","name":"Hàn Tâm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Một trong bốn đại trưởng lão bước thứ ba của Thương Long Tông, tham gia thi triển Đạo Hồn Thuật ngăn cản Vương Lâm.","vaiTro":"Trưởng lão Thương Long Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Một trong bốn đại trưởng lão bước thứ ba Thương Long Tông, được gọi tên cùng ngăn cản Vương Lâm","chuong":"@c1709"}],"kinhLich":[{"chuong":"@c1709","importance":"bridge","mucCt":"gon","text":"Được Triệu trưởng lão gọi tên ra lệnh cùng ngăn cản Vương Lâm, thi triển Đạo Hồn Thuật.","anchor":"Lệ Trường Thiên, Đóa Mộng Đắc. Hàn Tâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Triệu trưởng lão","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Thương Long Tông","gap":"@c1709"}],"tuiDo":{}},"nguon":["@c1709"]},{"id":"nu-tu-dong-hanh-lao-to-thuong-long","name":"Nữ tử thiên kiều bá mị","cn":"","aliases":[],"gioiTinh":"nu","trangThai":"song","vaiTro":"Đồng hành cùng lão tổ Thương Long Tông","blurb":"Nữ tử thiên kiều bá mị đi cùng lão tổ Thương Long Tông trở về, thấy cảnh đổ nát liền sợ hãi tránh xa lão tổ.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1710","importance":"minor","mucCt":"gon","tieuDe":"Cùng lão tổ trở về Thương Long Tông","text":"Cùng lão tổ lao tới bằng cầu vồng, thấy cảnh đổ nát liền sắc mặt đại biến, tránh xa thiếu niên.","anchor":"vừa nhìn thấy đống đổ nát phía dưới thần sắc nàng liền đại biến, không chút do dự liền tránh xa thiếu niên kia một chút"}],"tuViMoc":[],"nhanMach":[{"ten":"Đỗ Thanh","tag":"dong-hanh","quanHe":"Đồng hành cùng lão tổ Thương Long Tông"},{"ten":"Lão tổ Thương Long Tông","tag":"khac","quanHe":"Đồng hành","ghiChu":"Cùng trở về Thương Long Tông"}],"tuiDo":{}},"theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"nguon":["@c1710"],"tinhCach":[{"text":"Cảnh giác, biết sợ cơn giận của lão tổ","chuong":"@c1710"}]},{"id":"nam-tu-mac-long-bao","name":"Nam tử mặc hoàng bào","cn":"","aliases":["Ca của Đạo Phi"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Tộc trung châu hoàng thất","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nam tử trung niên ngồi trên long ỷ trong đại điện hoàng đô Tiên Tộc trung châu, đồng tử giống mặt trời, khí tức huyết mạch tôn quý cực điểm. Nhắc tới Đạo Phi mất tích gặp tạo hóa và khí tức tại thần táng chỉ hư.","vaiTro":"Hoàng thất Tiên Tộc trung châu, anh của Đạo Phi","tinhCach":"Uy nghiêm; quyết đoán","tabs":{"diem":[{"text":"Đồng tử giống mặt trời, khí tức huyết mạch tôn quý đến cực điểm, ngồi trên long ỷ trong đại điện vạn trượng.","chuong":"@c1712"}],"kinhLich":[{"chuong":"@c1712","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại hoàng đô Tiên Tộc trung châu","text":"Ngồi trên long ỷ trong đại điện xa hoa vạn trượng tựa thiên cung. Nhắc tới quốc sư đã tính toán Đạo Phi mất tích không nguy hiểm tính mạng, còn gặp tạo hóa; khí tức xuất hiện tại thần táng chỉ hư liên tiếp truyền lại. Giơ tay túm về phía hư vô.","anchor":"đồng tử của hắn giống như là mặt trời, tỏa ra một khí tức huyết mạch tôn quý đến cực điểm"},{"mucCt":"vua","text":"Ngồi trên long ỷ trong đại điện hoàng cung, dùng thần thông mở vòng xoáy kéo người điên và ngân y nữ tử ra. Thi triển tiên lực vô biên hai lần cứu chữa Đạo Phi, triển khai hư ảnh mặt trời hoàng kim trên không trung. Ra lệnh cho hai nữ tử đưa Đạo Phi và ngân y nữ tử đi nghỉ, trầm tư về việc Đạo Phi mất tích nhiều năm và bị thương nặng, huyết mạch ít đi.","anchor":"Ca! Ngay lúc này, sắc mặt người điên trở nên hồng hào","bridge":true,"khoang":"@c1713"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Phi","tag":"ho-hang","quanHe":"Em (Đạo Phi thân vương)","ghiChu":"Nhắc tới Đạo Phi mất tích gặp tạo hóa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1712","@c1713"]},{"id":"dao-phi","name":"Đạo Phi","cn":"","aliases":["Đạo Phi thân vương"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Tộc trung châu hoàng thất","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"mat-tich","blurb":"Thân vương Tiên Tộc trung châu, bị mất tích. Quốc sư tính toán mất tích lần này không nguy hiểm tính mạng, ngược lại còn gặp tạo hóa.","vaiTro":"Thân vương Tiên Tộc trung châu, em của nam tử mặc long bào","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Thân vương mất tích, quốc sư tính toán không nguy hiểm mà còn gặp tạo hóa.","chuong":"@c1712"}],"kinhLich":[{"chuong":"@c1712","importance":"normal","mucCt":"gon","tieuDe":"Được nhắc mất tích, gặp tạo hóa","text":"Anh của Đạo Phi tại hoàng đô Tiên Tộc trung châu cho biết quốc sư tính toán Đạo Phi mất tích không nguy hiểm tính mạng, còn gặp tạo hóa; khí tức xuất hiện tại thần táng chỉ hư.","anchor":"Quốc sư đã từng tính toán Đạo Phi mất tích lần này không nguy hiểm đến tính mạng, ngược lại còn gặp được tạo hóa"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam tử mặc hoàng bào","tag":"ho-hang","quanHe":"Anh","ghiChu":"Nhắc tới Đạo Phi mất tích"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1712"]},{"id":"quoc-su-tien-toc-trung-chau","name":"Quốc sư Tiên Tộc trung châu","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Tộc trung châu hoàng thất","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Quốc sư của Tiên Tộc trung châu, đã tính toán việc Đạo Phi mất tích không nguy hiểm tính mạng, còn gặp tạo hóa.","vaiTro":"Quốc sư Tiên Tộc trung châu","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Tính toán được việc Đạo Phi mất tích không nguy hiểm, còn gặp tạo hóa.","chuong":"@c1712"}],"kinhLich":[{"chuong":"@c1712","importance":"bridge","mucCt":"gon","text":"Được nhắc tên, đã tính toán Đạo Phi mất tích không nguy hiểm tính mạng.","anchor":"Quốc sư đã từng tính toán Đạo Phi mất tích lần này không nguy hiểm đến tính mạng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1712"]},{"id":"ngan-y-luyen-thi","name":"Ngân Y Luyện Thi","cn":"","aliases":["ngân y nữ tử"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1713","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Bị kéo ra từ vòng xoáy cùng người điên trong trạng thái hôn mê, nam tử hoàng bào không quan tâm, lệnh đưa đi nghỉ cùng Đạo Phi.","anchor":"Đưa Đạo Phi thân vương đi nghỉ ngơi Còn nữ tử này cũng đưa đi cùng!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị gọi ra trong cung điện phong kín, tỉnh lại rồi phản kháng dữ dội bằng lốc xoáy","chuong":"@c0931"},{"text":"Lần đầu tiên mở miệng nói chuyện với giọng đứt quãng, nhắc lại lời Hoa Phù cứu nguy trận pháp","chuong":"@c1046"},{"text":"Mơ hồ nhớ lại ký ức, tự thi triển và giải trừ Sinh Tử Cấm thành thạo hơn cả lão bà","chuong":"@c1125"},{"text":"Tự mở khe không gian trữ vật bước ra ngoài sự khống chế của Vương Lâm, bắt nuốt kim tuyến Lan Phi và cảnh báo hương hỏa là âm mưu","chuong":"@c1251"},{"text":"Thủy Đạo Tử nhìn thấy liền lập tức nhận ra thân phận, tâm thần chấn động","chuong":"@c1206"},{"text":"Vương Lâm xác nhận thân phận nàng là nữ tử của một vị tiên tôn","chuong":"@c1545"}]},"nguon":["@c1713"],"vaiTro":"Luyện thi áo bạc của Vương Lâm — nữ tử của một vị tiên tôn","tinhCach":"ban đầu phản kháng dữ dội, về sau trung thành bám sát hộ vệ Vương Lâm; trầm mặc ít nói, giọng đứt quãng như mới học nói; chiến đấu quyết đoán sắc bén; có ý chí tự chủ tiềm ẩn, nhiều lần hành động ngoài khống chế","blurb":"Ngân Y Luyện Thi là nữ thi áo bạc tu vi Tịnh Niết sơ kỳ, bị Vương Lâm gọi ra trong cung điện phong kín và dần trở thành hộ vệ thủy chung theo sát hắn qua vô số biến cố. Nàng từng mơ hồ nhớ lại ký ức cũ, tự thi triển Sinh Tử Cấm, nhiều lần tự ý hành động ngoài sự khống chế của Vương Lâm, đồng thời được Thủy Đạo Tử nhận ra thân phận ngay khoảnh khắc nhìn thấy. Về sau Vương Lâm xác nhận nàng chính là nữ tử của một vị tiên tôn, mang lai lịch liên hệ tới những bí mật thượng cổ."},{"id":"thanh-nguu-chan-nhan","name":"Thanh Ngưu chân nhân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi cao thâm, có bổn nguyên chân thân)","trangThai":"song","blurb":"Thanh Ngưu chân nhân là lão tổ Đại Hồn Môn, được nhắc tới là tu vi cao thâm, có bổn nguyên chân thân và nắm giữ nơi có địa hỏa chủ mạch Thiên Ngưu Châu. Ông nhận ra Vương Lâm liên quan đến tiên đoán của tổ tiên, đưa hắn vào bố cục của Đại Hồn Môn bằng đạo thuật, ngọc giản và các nhiệm vụ nặng nề. Về sau ông vẫn bế quan, đồng thời để lại lệnh giữ ngọn núi từng ban cho Vương Lâm làm cấm địa.","vaiTro":"Lão tổ Đại Hồn Môn — người nắm địa hỏa chủ mạch Thiên Ngưu Châu","tinhCach":"Kiên nhẫn chờ đợi người trong tiên đoán; nhìn xa và biết trọng dụng Vương Lâm; thận trọng quan sát biến cục; cứng rắn khi giao nhiệm vụ","tabs":{"diem":[{"text":"Được xác nhận là lão tổ Đại Hồn Môn, tu vi cao thâm, có bổn nguyên chân thân và nắm giữ địa hỏa chủ mạch Thiên Ngưu Châu","chuong":"@c1722"},{"text":"Dùng hàn bổn nguyên chân thân chờ Vương Lâm trên Thiên Sơn, trực tiếp yêu cầu hắn","chuong":"@c1732"},{"text":"Bổn tôn tại Đại Hồn Môn kích động nhận ra Vương Lâm chính là người tổ tiên từng tiên đoán","chuong":"@c1734"},{"text":"Hiện thân phân xử giữa Vương Lâm và Viêm Loan, dung hợp bổn nguyên chân thân với bổn tôn và để lộ khí tức Không Kiếp hậu kỳ","chuong":"@c1735"},{"text":"Giải thích bí mật tầng chín, tầng mười Tàng Hồn Các và xác nhận công lao Đan Hải của Vương Lâm","chuong":"@c1758"},{"text":"Vẫn bế quan và để lại lệnh giữ ngọn núi từng ban cho Vương Lâm làm cấm địa","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1722","importance":"normal","mucCt":"gon","tieuDe":"Được Đỗ Thanh nhắc tới với Vương Lâm","text":"Được Đỗ Thanh tiết lộ là lão tổ Đại Hồn Môn, tu vi cao thâm, có bổn nguyên chân thân, nắm giữ nơi có địa hỏa chủ mạch Thiên Ngưu Châu.","anchor":"lão tổ của Đại Hồn Môn là Thanh Ngưu chân nhân. Người này tu vi cao thâm, cũng có được bổn nguyên chân thân giống như ngươi"}],"tuViMoc":[],"nhanMach":[{"ten":"Đỗ Thanh","tag":"khac","quanHe":"Trưởng lão ngoại môn Đại Hồn Môn","ghiChu":"@c1722"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1722"]},{"id":"lao-to-thuong-long-tong","name":"Lão tổ Thương Long Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thương Long Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vượt Không Niết (chưa rõ cụ thể)","trangThai":"song","blurb":"Lão tổ Thương Long Tông, ngoại hình thiếu niên anh tuấn, tu vi vượt Không Niết, trở về phát hiện tông phái gần bị hủy.","vaiTro":"Lão tổ tối cao của Thương Long Tông, tu vi khiến cảnh Không Niết không chịu nổi cơn giận của ông.","tinhCach":[{"text":"Dữ tợn, sát khí nặng, trầm mặc đáng sợ khi tức giận","chuong":"@c1710"}],"tabs":{"diem":[{"text":"Ngoại hình thiếu niên môi hồng răng trắng mày kiếm mắt sáng, nhưng thần sắc dữ tợn đầy sát khí khi phẫn nộ.","chuong":"@c1710"}],"kinhLich":[{"chuong":"@c1710","importance":"normal","mucCt":"vua","tieuDe":"Trở về thấy tông phái gần bị hủy","text":"Một nén nhang sau khi Vương Lâm rời đi, phát ra tiếng gầm phẫn nộ dập tắt toàn bộ ngọn lửa trên mặt đất Thương Long Tông. Xuất hiện dưới hình dáng thiếu niên anh tuấn, tốc độ cực nhanh gần xé rách thiên địa, trầm mặc nhìn cảnh đổ nát gây áp lực kinh khiếp cho tứ đại trưởng lão.","anchor":"Cơn giận của lão tổ thì dù là tu vi Không Niết cũng không thể nào chịu nổi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ phá hủy tông phái","ghiChu":"Vương Lâm phá nát Thương Long Tông trước khi lão tổ trở về"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1710"]}]};
